// UNIT 1: ¡Hola! — Greetings & Goodbyes (A1.1)
// 8 lessons, 18+ steps each
// ══════════════════════════════════════════════════════════════
{n:1,lang:"es",track:"v1",title:"¡Hola!",sub:"Greetings & Goodbyes",icon:"👋",level:"A1.1",color:"#7B5EE8",lessons:[
// ===== L1: First Greetings =====
{id:"esp1l1",title:"¡Buenos días!",icon:"☀️",xp:15,board:true,steps:[
{type:"intro",title:"¡Buenos días!",desc:"Your first Spanish words! Learn to greet people at any time of day.",goals:["Say hello in Spanish","Use time-appropriate greetings","Know when to use each greeting"]},
{type:"teach",kind:"word",nl:"Hola",en:"Hello",phonetic:"OH-la",example:"A: ¡Hola!\nB: ¡Hola! ¿Qué tal?",exampleEn:"A: Hello!\nB: Hello! How are you?",note:"Universal greeting. Works any time of day, with anyone."},
{type:"teach",kind:"phrase",nl:"Buenos días",en:"Good morning",phonetic:"BWEH-nos DEE-as",example:"A: ¡Buenos días!\nB: ¡Buenos días! ¿Cómo estás?",exampleEn:"A: Good morning!\nB: Good morning! How are you?",note:"Used from sunrise until around noon or lunchtime."},
{type:"teach",kind:"phrase",nl:"Buenas tardes",en:"Good afternoon",phonetic:"BWEH-nas TAR-des",example:"A: ¡Buenas tardes, señora!\nB: ¡Buenas tardes!",exampleEn:"A: Good afternoon, ma'am!\nB: Good afternoon!",note:"Used from lunchtime until sunset. BuenAS because tarde is feminine."},
{type:"teach",kind:"phrase",nl:"Buenas noches",en:"Good evening / Good night",phonetic:"BWEH-nas NO-ches",example:"A: ¡Buenas noches!\nB: ¡Buenas noches! Hasta mañana.",exampleEn:"A: Good evening!\nB: Good evening! See you tomorrow.",note:"Used from sunset onward. Also means good night when saying goodbye."},
{type:"tip",title:"Buenos vs Buenas",text:"Buenos días uses buenos (masculine) because día is masculine.\nBuenas tardes and buenas noches use buenas (feminine) because tarde and noche are feminine.\nThis is your first taste of gender agreement!",icon:"💡"},
{type:"mc",q:"Which greeting works at ANY time of day?",opts:["Buenos días","Buenas tardes","Hola","Buenas noches"],ans:"Hola",hint:"One greeting has no time restriction at all."},
{type:"mc",q:"At 3 PM, you would say:",opts:["Buenos días","Buenas tardes","Buenas noches","Buenas mañanas"],ans:"Buenas tardes",hint:"Afternoon falls between lunch and sunset."},
{type:"mc",q:"Why is it 'buenAS tardes' but 'buenOS días'?",opts:["Tarde is feminine, día is masculine","It is random","Tardes is plural","Días is shorter"],ans:"Tarde is feminine, día is masculine",hint:"The adjective matches the gender of the noun it describes."},
{type:"fb",s:"¡{1} días!",a:"Buenos",opts:["Buenos","Buenas","Bueno","Buena"],hint:"Morning greeting uses the masculine form."},
{type:"fb",s:"¡Buenas {1}!",a:"tardes",opts:["tardes","días","noches","mañanas"],hint:"This greeting is for the afternoon hours."},
{type:"teach",kind:"word",nl:"el señor",en:"sir / Mr.",phonetic:"seh-NYOR",example:"A: ¡Buenos días, señor García!\nB: ¡Buenos días!",exampleEn:"A: Good morning, Mr. García!\nB: Good morning!",note:"Formal address for a man. Used with or without the last name."},
{type:"teach",kind:"word",nl:"la señora",en:"ma'am / Mrs.",phonetic:"seh-NYOR-a",example:"A: ¡Buenas tardes, señora López!\nB: ¡Buenas tardes!",exampleEn:"A: Good afternoon, Mrs. López!\nB: Good afternoon!",note:"Formal address for a woman. Señorita is used for young women."},
{type:"mc",q:"To greet a woman formally in the evening:",opts:["¡Buenos noches, señor!","¡Buenas noches, señora!","¡Hola, señorita noches!","¡Buenos tardes, señora!"],ans:"¡Buenas noches, señora!",hint:"Evening + formal female address. Remember the feminine form."},
{type:"match",pairs:[{nl:"Hola",en:"Hello (anytime)"},{nl:"Buenos días",en:"Good morning"},{nl:"Buenas tardes",en:"Good afternoon"},{nl:"Buenas noches",en:"Good evening"}]},
{type:"mc",q:"At 9 PM, arriving at a restaurant, you say:",opts:["¡Buenos días!","¡Buenas tardes!","¡Buenas noches!","¡Buenas mañanas!"],ans:"¡Buenas noches!",hint:"9 PM is well after sunset."},
{type:"fb",s:"¡Buenas {1}, señora!",a:"noches",opts:["noches","tardes","días","hola"],hint:"This greeting is used after sunset."},
{type:"mc",q:"Which word changes form to match masculine or feminine?",opts:["Hola","Buenos/Buenas","Días","Señor"],ans:"Buenos/Buenas",hint:"This adjective switches its ending based on the noun that follows."},
]},
// ===== L2: Goodbyes =====
{id:"esp1l2",title:"¡Hasta luego!",icon:"👋",xp:15,board:true,steps:[
{type:"intro",title:"¡Hasta luego!",desc:"Learn to say goodbye in different ways and situations.",goals:["Say goodbye formally and informally","Use different farewell expressions","Know when each goodbye is appropriate"]},
{type:"teach",kind:"word",nl:"Adiós",en:"Goodbye",phonetic:"ah-DYOS",example:"A: Me voy. ¡Adiós!\nB: ¡Adiós! ¡Cuídate!",exampleEn:"A: I'm leaving. Goodbye!\nB: Goodbye! Take care!",note:"The standard goodbye. Works in any situation, formal or informal."},
{type:"teach",kind:"phrase",nl:"Hasta luego",en:"See you later",phonetic:"AHS-ta LWEH-go",example:"A: ¡Hasta luego!\nB: ¡Hasta luego! ¡Que te vaya bien!",exampleEn:"A: See you later!\nB: See you later! Hope it goes well!",note:"Very common casual goodbye. Literally: until later."},
{type:"teach",kind:"phrase",nl:"Hasta mañana",en:"See you tomorrow",phonetic:"AHS-ta ma-NYAH-na",example:"A: ¡Hasta mañana, compañeros!\nB: ¡Hasta mañana!",exampleEn:"A: See you tomorrow, colleagues!\nB: See you tomorrow!",note:"Used when you know you will see the person the next day."},
{type:"teach",kind:"phrase",nl:"Hasta pronto",en:"See you soon",phonetic:"AHS-ta PRON-to",example:"A: Fue un placer. ¡Hasta pronto!\nB: ¡Hasta pronto!",exampleEn:"A: It was a pleasure. See you soon!\nB: See you soon!",note:"Used when you expect to see someone again soon but not sure exactly when."},
{type:"teach",kind:"phrase",nl:"Nos vemos",en:"See you / We'll see each other",phonetic:"nos VEH-mos",example:"A: ¡Nos vemos!\nB: ¡Nos vemos el lunes!",exampleEn:"A: See you!\nB: See you on Monday!",note:"Casual and friendly. Literally: we see each other."},
{type:"tip",title:"The 'hasta' pattern",text:"Hasta means 'until'. You can combine it with many words:\n\nHasta luego = until later\nHasta mañana = until tomorrow\nHasta pronto = until soon\nHasta la vista = until the seeing",icon:"💡"},
{type:"mc",q:"'Hasta' in Spanish means:",opts:["Hello","Until","Goodbye","See"],ans:"Until",hint:"It starts a phrase that indicates when you will meet again."},
{type:"mc",q:"Leaving work on Friday, not returning until Monday:",opts:["Hasta mañana","Nos vemos","Hasta luego","Buenos días"],ans:"Hasta luego",hint:"You will not see them tomorrow, so the general farewell fits."},
{type:"fb",s:"¡Hasta {1}!",a:"mañana",opts:["mañana","luego","pronto","adiós"],hint:"This farewell specifies the next day."},
{type:"teach",kind:"phrase",nl:"Chao",en:"Bye (informal)",phonetic:"CHOW",example:"A: Me voy. ¡Chao!\nB: ¡Chao! ¡Nos vemos!",exampleEn:"A: I'm leaving. Bye!\nB: Bye! See you!",note:"Very informal, borrowed from Italian ciao. Common in Latin America among friends."},
{type:"teach",kind:"phrase",nl:"¡Que te vaya bien!",en:"Hope it goes well!",phonetic:"keh teh VA-ya BYEN",example:"A: ¡Adiós!\nB: ¡Que te vaya bien!",exampleEn:"A: Goodbye!\nB: Hope it goes well!",note:"A warm farewell wish. Often said when someone is leaving."},
{type:"mc",q:"Among close friends, a casual goodbye would be:",opts:["Adiós, señor","¡Chao!","Hasta la vista","Buenas noches"],ans:"¡Chao!",hint:"This short, borrowed word is the most casual option."},
{type:"mc",q:"The shopkeeper says 'Hasta luego'. You reply:",opts:["Buenos días","¡Hasta luego!","Me llamo Pedro","Buenas"],ans:"¡Hasta luego!",hint:"Mirror the farewell you received."},
{type:"match",pairs:[{nl:"Adiós",en:"Goodbye (standard)"},{nl:"Hasta luego",en:"See you later"},{nl:"Hasta mañana",en:"See you tomorrow"},{nl:"Nos vemos",en:"See you (casual)"},{nl:"Chao",en:"Bye (informal)"}]},
{type:"fb",s:"¡{1} vemos!",a:"Nos",opts:["Nos","Los","Mis","Les"],hint:"This pronoun means 'us' or 'each other'."},
{type:"mc",q:"'Hasta pronto' is best translated as:",opts:["See you tomorrow","See you later","See you soon","Goodbye forever"],ans:"See you soon",hint:"Pronto means soon, indicating a short time gap."},
{type:"mc",q:"Which goodbye is a warm wish for the other person?",opts:["Adiós","Chao","¡Que te vaya bien!","Hasta luego"],ans:"¡Que te vaya bien!",hint:"This farewell is a wish that things go well for them."},
]},
// ===== L3: How Are You? =====
{id:"esp1l3",title:"¿Cómo estás?",icon:"😊",xp:15,board:true,steps:[
{type:"intro",title:"¿Cómo estás?",desc:"Learn to ask how someone is doing and respond naturally.",goals:["Ask 'how are you?' formally and informally","Respond with how you feel","Use estoy + adjective"]},
{type:"teach",kind:"phrase",nl:"¿Cómo estás?",en:"How are you? (informal)",phonetic:"KO-mo es-TAS",example:"A: ¡Hola! ¿Cómo estás?\nB: ¡Bien, gracias! ¿Y tú?",exampleEn:"A: Hello! How are you?\nB: Good, thanks! And you?",note:"Informal. Use with friends, family, and people your age."},
{type:"teach",kind:"phrase",nl:"¿Cómo está usted?",en:"How are you? (formal)",phonetic:"KO-mo es-TA oos-TED",example:"A: Buenos días. ¿Cómo está usted?\nB: Muy bien, gracias. ¿Y usted?",exampleEn:"A: Good morning. How are you?\nB: Very well, thanks. And you?",note:"Formal. Use with strangers, elders, and authority figures."},
{type:"teach",kind:"phrase",nl:"¿Qué tal?",en:"How's it going?",phonetic:"keh TAL",example:"A: ¡Hola! ¿Qué tal?\nB: Todo bien. ¿Y tú?",exampleEn:"A: Hello! How's it going?\nB: All good. And you?",note:"Very casual. Common among friends."},
{type:"teach",kind:"word",nl:"Bien",en:"Good / Well",phonetic:"BYEN",example:"A: ¿Cómo estás?\nB: Bien, gracias.",exampleEn:"A: How are you?\nB: Good, thanks.",note:"The most common response. Often followed by gracias."},
{type:"teach",kind:"phrase",nl:"Muy bien",en:"Very well",phonetic:"mwee BYEN",example:"A: ¿Cómo estás?\nB: ¡Muy bien! Acabo de comer.",exampleEn:"A: How are you?\nB: Very well! I just ate.",note:"Emphatic positive response. Muy = very."},
{type:"teach",kind:"word",nl:"Mal",en:"Bad / Not well",phonetic:"MAL",example:"A: ¿Cómo estás?\nB: Mal. Estoy enfermo.",exampleEn:"A: How are you?\nB: Bad. I am sick.",note:"Honest negative response. Not rude to say, just honest."},
{type:"teach",kind:"phrase",nl:"Así así",en:"So-so",phonetic:"ah-SEE ah-SEE",example:"A: ¿Qué tal?\nB: Así así. Nada especial.",exampleEn:"A: How's it going?\nB: So-so. Nothing special.",note:"Middle response. Not great, not terrible."},
{type:"teach",kind:"word",nl:"Regular",en:"Okay / So-so",phonetic:"reh-goo-LAR",example:"A: ¿Cómo estás?\nB: Regular. Un poco cansado.",exampleEn:"A: How are you?\nB: Okay. A little tired.",note:"Similar to así así. A neutral response."},
{type:"mc",q:"To ask a stranger how they are, you say:",opts:["¿Cómo estás?","¿Qué tal?","¿Cómo está usted?","¿Cómo eres?"],ans:"¿Cómo está usted?",hint:"Strangers require the formal address form."},
{type:"mc",q:"You feel great. You respond:",opts:["Mal","Regular","¡Muy bien, gracias!","Así así"],ans:"¡Muy bien, gracias!",hint:"The most enthusiastic positive response."},
{type:"fb",s:"¿Cómo {1}?",a:"estás",opts:["estás","eres","estoy","está"],hint:"Informal 'you' form of the verb for states and feelings."},
{type:"mc",q:"'¿Qué tal?' is best described as:",opts:["Very formal greeting","Casual 'how's it going?'","A farewell","A polite request"],ans:"Casual 'how's it going?'",hint:"This is the most relaxed way to ask."},
{type:"fb",s:"Estoy {1}. No me siento muy bien.",a:"mal",opts:["mal","bien","regular","muy bien"],hint:"The response matches not feeling well."},
{type:"match",pairs:[{nl:"Bien",en:"Good"},{nl:"Muy bien",en:"Very well"},{nl:"Mal",en:"Bad"},{nl:"Así así",en:"So-so"},{nl:"Regular",en:"Okay"}]},
{type:"mc",q:"After 'Bien, gracias', you ask back with:",opts:["¿Y tú?","¿Y yo?","¿Y él?","¿Cómo?"],ans:"¿Y tú?",hint:"Return the question with 'and' plus the informal 'you'."},
{type:"mc",q:"Which response means neither good nor bad?",opts:["Muy bien","Bien","Así así","Mal"],ans:"Así así",hint:"This doubled word expresses a middle, neutral feeling."},
{type:"fb",s:"¿{1} estás?",a:"Cómo",opts:["Cómo","Qué","Cuándo","Dónde"],hint:"This question word asks about manner or state."},
]},
// ===== L4: Polite Words =====
{id:"esp1l4",title:"Por favor y gracias",icon:"🙏",xp:15,board:true,steps:[
{type:"intro",title:"Por favor y gracias",desc:"Essential polite words that you will use every single day in Spanish.",goals:["Say please and thank you","Apologize and excuse yourself","Use basic polite expressions"]},
{type:"teach",kind:"phrase",nl:"Por favor",en:"Please",phonetic:"por fa-VOR",example:"A: ¿Me puede ayudar, por favor?\nB: ¡Claro que sí!",exampleEn:"A: Can you help me, please?\nB: Of course!",note:"Essential politeness. Can go at the beginning or end of a sentence."},
{type:"teach",kind:"word",nl:"Gracias",en:"Thank you",phonetic:"GRA-syas",example:"A: Aquí tiene su café.\nB: ¡Gracias!",exampleEn:"A: Here is your coffee.\nB: Thank you!",note:"The most important polite word. Use it constantly."},
{type:"teach",kind:"phrase",nl:"Muchas gracias",en:"Thank you very much",phonetic:"MOO-chas GRA-syas",example:"A: Le ayudo con las bolsas.\nB: ¡Muchas gracias! Muy amable.",exampleEn:"A: I'll help you with the bags.\nB: Thank you very much! Very kind.",note:"Emphatic thanks. Muchas = many."},
{type:"teach",kind:"phrase",nl:"De nada",en:"You're welcome",phonetic:"deh NA-da",example:"A: ¡Gracias por tu ayuda!\nB: ¡De nada!",exampleEn:"A: Thanks for your help!\nB: You're welcome!",note:"Literally: of nothing. The standard response to gracias."},
{type:"teach",kind:"word",nl:"Perdón",en:"Sorry / Excuse me",phonetic:"per-DON",example:"A: ¡Perdón! No te vi.\nB: No pasa nada.",exampleEn:"A: Sorry! I didn't see you.\nB: No worries.",note:"Used to apologize or to get someone's attention. Very versatile."},
{type:"teach",kind:"phrase",nl:"Lo siento",en:"I'm sorry",phonetic:"lo SYEN-to",example:"A: Mi abuela está enferma.\nB: Lo siento mucho.",exampleEn:"A: My grandmother is sick.\nB: I'm very sorry.",note:"Deeper apology or expressing sympathy. Literally: I feel it."},
{type:"teach",kind:"phrase",nl:"Con permiso",en:"Excuse me (to pass by)",phonetic:"kon per-MEE-so",example:"A: Con permiso, necesito pasar.\nB: ¡Adelante!",exampleEn:"A: Excuse me, I need to pass.\nB: Go ahead!",note:"Used when you need to physically get past someone."},
{type:"mc",q:"Someone gives you a gift. You say:",opts:["De nada","Lo siento","¡Muchas gracias!","Con permiso"],ans:"¡Muchas gracias!",hint:"Express strong appreciation for something received."},
{type:"mc",q:"You accidentally bump into someone:",opts:["Gracias","¡Perdón!","De nada","Por favor"],ans:"¡Perdón!",hint:"A quick apology for a minor accident."},
{type:"fb",s:"¡Muchas {1}!",a:"gracias",opts:["gracias","perdón","nada","favor"],hint:"The word that expresses thankfulness."},
{type:"mc",q:"Someone says 'Gracias'. You respond:",opts:["Gracias","Lo siento","De nada","Por favor"],ans:"De nada",hint:"The standard reply to someone who thanks you."},
{type:"fb",s:"{1} favor, ¿dónde está el baño?",a:"Por",opts:["Por","De","Con","Lo"],hint:"This preposition starts the polite request phrase."},
{type:"teach",kind:"phrase",nl:"No pasa nada",en:"No worries / It's nothing",phonetic:"no PA-sa NA-da",example:"A: ¡Perdón por llegar tarde!\nB: No pasa nada.",exampleEn:"A: Sorry for arriving late!\nB: No worries.",note:"Casual way to accept an apology. Literally: nothing happens."},
{type:"mc",q:"A friend's pet died. You say:",opts:["Perdón","De nada","Lo siento mucho","No pasa nada"],ans:"Lo siento mucho",hint:"Express deep sympathy, not just a quick apology."},
{type:"match",pairs:[{nl:"Por favor",en:"Please"},{nl:"Gracias",en:"Thank you"},{nl:"De nada",en:"You're welcome"},{nl:"Perdón",en:"Sorry"},{nl:"Lo siento",en:"I'm sorry (deep)"}]},
{type:"mc",q:"Squeezing past people on a bus:",opts:["Lo siento","Por favor","Con permiso","Perdón"],ans:"Con permiso",hint:"This phrase specifically asks for physical passage."},
{type:"fb",s:"Lo {1} mucho.",a:"siento",opts:["siento","sé","nada","favor"],hint:"This verb means 'I feel' in a sympathy expression."},
]},
// ===== L5: Introductions =====
{id:"esp1l5",title:"Me llamo...",icon:"🤝",xp:15,board:true,steps:[
{type:"intro",title:"Me llamo...",desc:"Learn to introduce yourself and ask someone's name.",goals:["Say your name","Ask someone's name","Use mucho gusto and encantado/a"]},
{type:"teach",kind:"phrase",nl:"Me llamo...",en:"My name is...",phonetic:"meh YA-mo",example:"A: ¡Hola! Me llamo María.\nB: ¡Mucho gusto, María!",exampleEn:"A: Hello! My name is María.\nB: Nice to meet you, María!",note:"Literally: I call myself. The most common way to give your name."},
{type:"teach",kind:"phrase",nl:"¿Cómo te llamas?",en:"What's your name? (informal)",phonetic:"KO-mo teh YA-mas",example:"A: ¿Cómo te llamas?\nB: Me llamo Carlos. ¿Y tú?",exampleEn:"A: What's your name?\nB: My name is Carlos. And you?",note:"Informal. Use with peers, children, people your age."},
{type:"teach",kind:"phrase",nl:"¿Cómo se llama usted?",en:"What's your name? (formal)",phonetic:"KO-mo seh YA-ma oos-TED",example:"A: ¿Cómo se llama usted?\nB: Me llamo Doctor Rodríguez.",exampleEn:"A: What is your name?\nB: My name is Doctor Rodríguez.",note:"Formal. Use with strangers, elders, professionals."},
{type:"teach",kind:"phrase",nl:"Mucho gusto",en:"Nice to meet you",phonetic:"MOO-cho GOOS-to",example:"A: Me llamo Ana.\nB: Mucho gusto, Ana. Yo soy Pedro.",exampleEn:"A: My name is Ana.\nB: Nice to meet you, Ana. I'm Pedro.",note:"Literally: much pleasure. The universal nice to meet you."},
{type:"teach",kind:"phrase",nl:"Encantado / Encantada",en:"Delighted to meet you",phonetic:"en-kan-TA-do / en-kan-TA-da",example:"A: Soy la profesora García.\nB: Encantada de conocerla.",exampleEn:"A: I am Professor García.\nB: Delighted to meet you.",note:"Encantado if you are male. Encantada if you are female."},
{type:"mc",q:"To tell someone your name, you say:",opts:["Te llamo...","Me llamas...","Me llamo...","Se llama..."],ans:"Me llamo...",hint:"The reflexive form with 'me' means 'I call myself'."},
{type:"mc",q:"To ask a child their name:",opts:["¿Cómo se llama usted?","¿Cómo te llamas?","¿Cómo me llamo?","¿Cómo nos llamamos?"],ans:"¿Cómo te llamas?",hint:"Children get the informal address form."},
{type:"fb",s:"¿Cómo {1} llamas?",a:"te",opts:["te","se","me","le"],hint:"The informal reflexive pronoun for 'yourself'."},
{type:"teach",kind:"phrase",nl:"Soy...",en:"I am...",phonetic:"SOY",example:"A: ¿Quién eres?\nB: Soy Miguel. Soy estudiante.",exampleEn:"A: Who are you?\nB: I'm Miguel. I'm a student.",note:"Short form using ser. Soy = I am (identity)."},
{type:"teach",kind:"phrase",nl:"¿Y tú?",en:"And you?",phonetic:"ee TOO",example:"A: Me llamo Julia. ¿Y tú?\nB: Me llamo Roberto.",exampleEn:"A: My name is Julia. And you?\nB: My name is Roberto.",note:"Used to return a question to the other person."},
{type:"mc",q:"A woman introducing herself says 'Encantada' because:",opts:["She is happy","The -a ending matches feminine","It is always -a","She is speaking formally"],ans:"The -a ending matches feminine",hint:"Spanish adjectives change ending to match the speaker's gender."},
{type:"mc",q:"Meeting your friend's grandfather, you ask:",opts:["¿Cómo te llamas?","¿Qué tal?","¿Cómo se llama usted?","Me llamo..."],ans:"¿Cómo se llama usted?",hint:"Elders require the formal form of address."},
{type:"fb",s:"¡Mucho {1}!",a:"gusto",opts:["gusto","gracias","bien","hola"],hint:"This word means pleasure or taste."},
{type:"match",pairs:[{nl:"Me llamo...",en:"My name is..."},{nl:"¿Cómo te llamas?",en:"What's your name? (informal)"},{nl:"Mucho gusto",en:"Nice to meet you"},{nl:"Encantado/a",en:"Delighted to meet you"},{nl:"Soy...",en:"I am..."}]},
{type:"mc",q:"After 'Mucho gusto', you can reply:",opts:["De nada","Igualmente","Perdón","Lo siento"],ans:"Igualmente",hint:"This word means 'likewise' or 'same to you'."},
{type:"fb",s:"Me {1} Ana. ¿Y tú?",a:"llamo",opts:["llamo","llamas","llama","llamamos"],hint:"First person form of the verb llamarse."},
{type:"mc",q:"'Soy Pedro' uses SER because:",opts:["A temporary state","Identity","Location","An emotion"],ans:"Identity",hint:"Who you ARE is expressed with this verb."},
]},
// ===== L6: Yo soy... =====
{id:"esp1l6",title:"Yo soy...",icon:"🧑",xp:15,board:true,steps:[
{type:"intro",title:"Yo soy...",desc:"Learn to say who you are: nationality, profession, and personal pronouns.",goals:["Use yo, tú, él, ella","Say your profession","Use ser for identity"]},
{type:"teach",kind:"grammar",nl:"Yo",en:"I",phonetic:"YO",example:"A: ¿Quién habla español aquí?\nB: Yo. Yo hablo español.",exampleEn:"A: Who speaks Spanish here?\nB: Me. I speak Spanish.",note:"First person pronoun. Often dropped because the verb ending already shows 'I'."},
{type:"teach",kind:"grammar",nl:"Tú",en:"You (informal)",phonetic:"TOO",example:"A: ¿Tú hablas inglés?\nB: Sí, yo hablo inglés y español.",exampleEn:"A: Do you speak English?\nB: Yes, I speak English and Spanish.",note:"Informal you. Has an accent mark to distinguish from tu (your)."},
{type:"teach",kind:"grammar",nl:"Él / Ella",en:"He / She",phonetic:"EL / EH-ya",example:"A: ¿Quién es él?\nB: Él es mi profesor. Ella es mi amiga.",exampleEn:"A: Who is he?\nB: He is my teacher. She is my friend.",note:"Él has an accent (he). El without accent means 'the'."},
{type:"tip",title:"Pronouns are often optional",text:"The verb ending tells you who is speaking:\nSoy = I am (yo is optional)\nEres = you are (tú is optional)\nEs = he/she is (él/ella clarifies)\nUse the pronoun only for emphasis or clarity.",icon:"💡"},
{type:"teach",kind:"grammar",nl:"Soy / Eres / Es",en:"I am / You are / He-She is",phonetic:"SOY / EH-res / ES",example:"A: ¿Eres estudiante?\nB: Sí, soy estudiante. Él es profesor.",exampleEn:"A: Are you a student?\nB: Yes, I am a student. He is a teacher.",note:"Ser present tense:\nYo soy, Tú eres, Él/Ella es.\nUsed for identity, profession, origin."},
{type:"teach",kind:"word",nl:"el estudiante / la estudiante",en:"student",phonetic:"es-too-DYAN-teh",example:"A: ¿Eres estudiante?\nB: Sí, soy estudiante de español.",exampleEn:"A: Are you a student?\nB: Yes, I am a Spanish student.",note:"Same word for both genders. Only the article changes."},
{type:"teach",kind:"word",nl:"el profesor / la profesora",en:"teacher / professor",phonetic:"pro-feh-SOR / pro-feh-SO-ra",example:"A: ¿Quién es ella?\nB: Es la profesora de matemáticas.",exampleEn:"A: Who is she?\nB: She is the math teacher.",note:"Masculine: profesor. Feminine: profesora."},
{type:"teach",kind:"word",nl:"el médico / la médica",en:"doctor",phonetic:"MEH-dee-ko / MEH-dee-ka",example:"A: ¿Es usted médico?\nB: Sí, soy médica.",exampleEn:"A: Are you a doctor?\nB: Yes, I am a doctor (female).",note:"Masculine: médico. Feminine: médica."},
{type:"mc",q:"'Soy estudiante' means:",opts:["You are a student","I am a student","He is a student","She is a student"],ans:"I am a student",hint:"Soy is the first person (I) form of ser."},
{type:"mc",q:"Él with an accent mark means:",opts:["The","He","You","She"],ans:"He",hint:"The accent distinguishes the pronoun from the article."},
{type:"fb",s:"Ella {1} profesora.",a:"es",opts:["es","soy","eres","está"],hint:"Third person form of ser for identity."},
{type:"mc",q:"Why say 'Soy estudiante' without 'yo'?",opts:["It is incorrect without yo","The verb ending already shows first person","Yo is only for emphasis","Students never use yo"],ans:"The verb ending already shows first person",hint:"The -oy ending only exists for the first person."},
{type:"fb",s:"¿Tú {1} médico?",a:"eres",opts:["eres","soy","es","somos"],hint:"Second person informal form of ser."},
{type:"match",pairs:[{nl:"Yo soy",en:"I am"},{nl:"Tú eres",en:"You are (informal)"},{nl:"Él es",en:"He is"},{nl:"Ella es",en:"She is"}]},
{type:"mc",q:"A female doctor says 'Soy ___':",opts:["médico","médica","médicos","médice"],ans:"médica",hint:"Feminine professions use the -a ending."},
{type:"fb",s:"{1} soy profesor.",a:"Yo",opts:["Yo","Tú","Él","Ella"],hint:"First person pronoun, often optional."},
{type:"mc",q:"'Es' can mean he is, she is, OR:",opts:["I am","You are (formal)","We are","They are"],ans:"You are (formal)",hint:"Usted also uses the third person verb form."},
]},
// ===== L7: ¿De dónde eres? =====
{id:"esp1l7",title:"¿De dónde eres?",icon:"🌍",xp:15,board:true,steps:[
{type:"intro",title:"¿De dónde eres?",desc:"Talk about where you are from and nationalities.",goals:["Ask where someone is from","Say your nationality","Use ser + de for origin"]},
{type:"teach",kind:"phrase",nl:"¿De dónde eres?",en:"Where are you from? (informal)",phonetic:"deh DON-deh EH-res",example:"A: ¿De dónde eres?\nB: Soy de México.",exampleEn:"A: Where are you from?\nB: I'm from Mexico.",note:"Uses ser because origin is permanent identity. De = from."},
{type:"teach",kind:"phrase",nl:"Soy de...",en:"I am from...",phonetic:"soy deh",example:"A: ¿De dónde eres?\nB: Soy de España. ¿Y tú?",exampleEn:"A: Where are you from?\nB: I'm from Spain. And you?",note:"Ser + de + country/city. Always ser for origin."},
{type:"teach",kind:"word",nl:"español / española",en:"Spanish (nationality)",phonetic:"es-pa-NYOL / es-pa-NYO-la",example:"A: ¿Eres española?\nB: Sí, soy española. De Madrid.",exampleEn:"A: Are you Spanish?\nB: Yes, I'm Spanish. From Madrid.",note:"Masculine: español. Feminine: española. NOT capitalized in Spanish!"},
{type:"teach",kind:"word",nl:"mexicano / mexicana",en:"Mexican",phonetic:"meh-hee-KA-no / meh-hee-KA-na",example:"A: ¿Es él mexicano?\nB: Sí, es mexicano. De Guadalajara.",exampleEn:"A: Is he Mexican?\nB: Yes, he's Mexican. From Guadalajara.",note:"Masculine: mexicano. Feminine: mexicana."},
{type:"teach",kind:"word",nl:"estadounidense",en:"American (from the USA)",phonetic:"es-ta-do-oo-nee-DEN-seh",example:"A: ¿Eres estadounidense?\nB: Sí, soy de Nueva York.",exampleEn:"A: Are you American?\nB: Yes, I'm from New York.",note:"Same form for both genders. Americano/a is also used casually."},
{type:"teach",kind:"word",nl:"inglés / inglesa",en:"English (British)",phonetic:"een-GLES / een-GLEH-sa",example:"A: ¿De dónde es ella?\nB: Es inglesa. De Londres.",exampleEn:"A: Where is she from?\nB: She's English. From London.",note:"Masculine: inglés. Feminine: inglesa. Also means the English language."},
{type:"tip",title:"Nationalities are lowercase!",text:"In Spanish, nationalities and languages are NOT capitalized:\nespañol, mexicano, inglés, francés.\nOnly country names are capitalized:\nEspaña, México, Inglaterra, Francia.",icon:"💡"},
{type:"mc",q:"'Soy de México' uses SER because:",opts:["Mexico is nice","Origin is permanent identity","You are currently there","It is temporary"],ans:"Origin is permanent identity",hint:"Where you come FROM is who you are."},
{type:"mc",q:"How do you write 'Mexican' in Spanish?",opts:["Mexicano (capital M)","mexicano (lowercase m)","MEXICANO","MeXicano"],ans:"mexicano (lowercase m)",hint:"Nationalities in Spanish never get a capital letter."},
{type:"fb",s:"Soy {1} España.",a:"de",opts:["de","en","a","por"],hint:"The preposition meaning 'from' for origin."},
{type:"teach",kind:"word",nl:"francés / francesa",en:"French",phonetic:"fran-SES / fran-SEH-sa",example:"A: ¿Hablas francés?\nB: Sí, soy francesa.",exampleEn:"A: Do you speak French?\nB: Yes, I'm French.",note:"Masculine: francés. Feminine: francesa."},
{type:"mc",q:"A woman from England says 'Soy ___':",opts:["inglés","inglesa","Inglaterra","inglésa"],ans:"inglesa",hint:"The feminine form drops the accent and adds -a."},
{type:"fb",s:"¿De {1} eres?",a:"dónde",opts:["dónde","cómo","qué","cuándo"],hint:"This question word asks about place."},
{type:"match",pairs:[{nl:"español/a",en:"Spanish"},{nl:"mexicano/a",en:"Mexican"},{nl:"inglés/a",en:"English"},{nl:"francés/a",en:"French"},{nl:"estadounidense",en:"American"}]},
{type:"mc",q:"'Estadounidense' is the same for:",opts:["Only men","Only women","Both men and women","Only formal use"],ans:"Both men and women",hint:"Some nationalities have one form for all genders."},
{type:"fb",s:"Ella es {1}. De París.",a:"francesa",opts:["francesa","francés","Francia","francesas"],hint:"Feminine singular nationality for a woman from France."},
{type:"mc",q:"To ask formally where someone is from:",opts:["¿De dónde eres?","¿De dónde es usted?","¿Dónde estás?","¿De dónde estás?"],ans:"¿De dónde es usted?",hint:"Formal requires usted and the third person verb form."},
]},
// ===== L8: Review & Practice =====
{id:"esp1l8",title:"¡Conversación!",icon:"💬",xp:20,board:true,steps:[
{type:"intro",title:"¡Conversación!",desc:"Put everything from Unit 1 together in real conversations.",goals:["Complete a full greeting conversation","Introduce yourself naturally","Use all Unit 1 vocabulary"]},
{type:"tip",title:"Your first conversation",text:"A complete Spanish meeting follows this pattern:\n1. Greeting (Hola, Buenos días)\n2. How are you? (¿Cómo estás?)\n3. Introductions (Me llamo...)\n4. Where from? (Soy de...)\n5. Farewell (Hasta luego)",icon:"🗣️"},
{type:"mc",q:"Morning meeting. First you say:",opts:["Adiós","¡Buenos días!","Me llamo...","Lo siento"],ans:"¡Buenos días!",hint:"Always start with a time-appropriate greeting."},
{type:"fb",s:"¡Hola! Me {1} Roberto.",a:"llamo",opts:["llamo","llamas","llama","llamamos"],hint:"First person: I call myself."},
{type:"mc",q:"Someone says 'Mucho gusto'. You reply:",opts:["De nada","Igualmente","Lo siento","Adiós"],ans:"Igualmente",hint:"Return the pleasure of meeting someone."},
{type:"fb",s:"Soy {1} Colombia.",a:"de",opts:["de","en","a","por"],hint:"Preposition of origin."},
{type:"mc",q:"A professor says 'Soy la profesora Martínez'. You respond:",opts:["¡Hola, tú!","Encantado/a de conocerla","¿Qué tal, amiga?","Chao"],ans:"Encantado/a de conocerla",hint:"A professor warrants a formal, respectful response."},
{type:"match",pairs:[{nl:"¡Hola!",en:"Hello!"},{nl:"¿Cómo estás?",en:"How are you?"},{nl:"Me llamo...",en:"My name is..."},{nl:"Soy de...",en:"I am from..."},{nl:"¡Hasta luego!",en:"See you later!"}]},
{type:"fb",s:"¿Cómo {1} usted?",a:"está",opts:["está","estás","estoy","están"],hint:"Formal 'you' requires the third person form."},
{type:"mc",q:"The shopkeeper says 'Que le vaya bien'. This is:",opts:["A greeting","An insult","A farewell wish","A question"],ans:"A farewell wish",hint:"The shopkeeper is wishing you well as you leave."},
{type:"drag_fill",s:"{1}, me {2} Ana. Soy {3} España.",blanks:{1:"Hola",2:"llamo",3:"de"},pool:["Hola","llamo","de","Adiós","llamas","en"],hint:"Complete self-introduction: greeting + name + origin."},
{type:"mc",q:"It is 8 PM. You greet someone with:",opts:["Buenos días","Buenas tardes","Buenas noches","Buenas mañanas"],ans:"Buenas noches",hint:"8 PM is after sunset in most places."},
{type:"fb",s:"Ella es {1}. De Londres.",a:"inglesa",opts:["inglesa","inglés","española","francesa"],hint:"A woman from the English capital."},
{type:"mc",q:"'¿Qué tal?' is best used with:",opts:["Your boss","A judge","A close friend","A police officer"],ans:"A close friend",hint:"This is the most casual way to greet someone."},
{type:"mc",q:"Correct order for a first meeting?",opts:["Name, goodbye, greeting","Greeting, name, farewell","Farewell, greeting, name","Name, greeting, name"],ans:"Greeting, name, farewell",hint:"You always start with a greeting before anything else."},
{type:"drag_fill",s:"¡{1} días, {2}! ¿Cómo {3}?",blanks:{1:"Buenos",2:"señora",3:"está"},pool:["Buenos","señora","está","Buenas","señor","estás"],hint:"Formal morning greeting to a woman."},
{type:"match",pairs:[{nl:"Yo soy",en:"I am"},{nl:"Tú eres",en:"You are"},{nl:"Él es",en:"He is"},{nl:"Ella es",en:"She is"}]},
{type:"mc",q:"'Soy médica' tells you she is:",opts:["A nurse","A female doctor","A male doctor","A student"],ans:"A female doctor",hint:"The -a ending on the profession indicates feminine."},
]}
]},
// ══════════════════════════════════════════════════════════════
// UNIT 2: Mi Familia — Family & Descriptions (A1.1)
// 8 lessons, 18+ steps each
// ══════════════════════════════════════════════════════════════
{n:2,lang:"es",track:"v1",title:"Mi Familia",sub:"Family & Descriptions",icon:"👨‍👩‍👧‍👦",level:"A1.1",color:"#7B5EE8",lessons:[

// ===== L1: Parents & Siblings =====
{id:"esp2l1",title:"Padres y Hermanos",icon:"👨‍👩‍👧",xp:15,board:true,steps:[
{type:"intro",title:"Padres y Hermanos",desc:"Learn the words for your closest family members: parents and siblings.",goals:["Learn padre, madre, hermano, hermana, hijo, hija","Use el/la articles with family nouns","Talk about your immediate family"]},
{type:"teach",kind:"word",nl:"el padre",en:"the father",phonetic:"el PAH-dreh",example:"A: ¿Quién es él?\nB: Es mi padre.",exampleEn:"A: Who is he?\nB: He is my father.",note:"Masculine noun. El padre = the father."},
{type:"teach",kind:"word",nl:"la madre",en:"the mother",phonetic:"la MAH-dreh",example:"A: ¿Quién es ella?\nB: Es mi madre.",exampleEn:"A: Who is she?\nB: She is my mother.",note:"Feminine noun. La madre = the mother."},
{type:"teach",kind:"word",nl:"el hermano",en:"the brother",phonetic:"el air-MAH-noh",example:"A: ¿Tienes hermanos?\nB: Sí, tengo un hermano.",exampleEn:"A: Do you have siblings?\nB: Yes, I have a brother.",note:"Masculine. Hermanos (plural) can mean siblings in general."},
{type:"teach",kind:"word",nl:"la hermana",en:"the sister",phonetic:"la air-MAH-nah",example:"A: ¿Tienes una hermana?\nB: Sí, se llama María.",exampleEn:"A: Do you have a sister?\nB: Yes, her name is María.",note:"Feminine form of hermano. Note the -a ending."},
{type:"tip",title:"El and La",text:"Spanish nouns have gender.\n\n- el = the (masculine)\n- la = the (feminine)\n\nFamily words often come in pairs:\nel padre / la madre\nel hermano / la hermana",icon:"📝"},
{type:"teach",kind:"word",nl:"el hijo",en:"the son",phonetic:"el EE-hoh",example:"A: ¿Cuántos hijos tienes?\nB: Tengo un hijo.",exampleEn:"A: How many children do you have?\nB: I have one son.",note:"The H is silent in Spanish. Hijos (plural) = children."},
{type:"teach",kind:"word",nl:"la hija",en:"the daughter",phonetic:"la EE-hah",example:"A: ¿Tienes hijas?\nB: Sí, tengo una hija.",exampleEn:"A: Do you have daughters?\nB: Yes, I have one daughter.",note:"Feminine of hijo. Silent H. The -a marks feminine."},
{type:"mc",q:"What does 'la madre' mean?",opts:["the mother","the father","the sister","the daughter"],ans:"the mother",hint:"Think of the feminine parent."},
{type:"mc",q:"Which article goes with 'hermano'?",opts:["el","la","un","los"],ans:"el",hint:"Hermano ends in -o, a masculine ending."},
{type:"fb",s:"Mi {1} se llama Carlos.",a:"padre",opts:["padre","madre","hija","hermana"],hint:"Carlos is male and a parent figure."},
{type:"match",pairs:[{nl:"el padre",en:"the father"},{nl:"la madre",en:"the mother"},{nl:"el hermano",en:"the brother"},{nl:"la hermana",en:"the sister"},{nl:"el hijo",en:"the son"},{nl:"la hija",en:"the daughter"}]},
{type:"mc",q:"How do you say 'the daughter' in Spanish?",opts:["la hija","el hijo","la hermana","la madre"],ans:"la hija",hint:"Feminine form of the word for son."},
{type:"fb",s:"Tengo una {1}. Se llama Ana.",a:"hermana",opts:["hermano","hermana","padre","hijo"],hint:"Ana is female, and she is a sibling."},
{type:"mc",q:"What is the feminine form of 'el hijo'?",opts:["la hija","la madre","la hermana","la prima"],ans:"la hija",hint:"Change the -o ending to -a for feminine."},
{type:"mc",q:"'El hermano' means...",opts:["the brother","the sister","the father","the cousin"],ans:"the brother",hint:"A male sibling, not a parent."},
{type:"fb",s:"Ella es mi {1}. Es muy simpática.",a:"madre",opts:["madre","padre","hijo","hermano"],hint:"A female parent who is very nice."},
{type:"mc",q:"Which word means 'the son'?",opts:["el hijo","el padre","el hermano","el abuelo"],ans:"el hijo",hint:"A male child of a parent."},
]},

// ===== L2: Extended Family =====
{id:"esp2l2",title:"La Familia Grande",icon:"👵",xp:15,board:true,steps:[
{type:"intro",title:"La Familia Grande",desc:"Meet the extended family: grandparents, aunts, uncles, and cousins.",goals:["Learn abuelo/a, tío/a, primo/a","Use el/la correctly","Describe your extended family"]},
{type:"teach",kind:"word",nl:"el abuelo",en:"the grandfather",phonetic:"el ah-BWEH-loh",example:"A: ¿Cómo se llama tu abuelo?\nB: Mi abuelo se llama Pedro.",exampleEn:"A: What is your grandfather's name?\nB: My grandfather's name is Pedro.",note:"Los abuelos (plural) = the grandparents."},
{type:"teach",kind:"word",nl:"la abuela",en:"the grandmother",phonetic:"la ah-BWEH-lah",example:"A: ¿Dónde vive tu abuela?\nB: Mi abuela vive en Madrid.",exampleEn:"A: Where does your grandmother live?\nB: My grandmother lives in Madrid.",note:"Feminine of abuelo. The -a ending signals feminine."},
{type:"teach",kind:"word",nl:"el tío",en:"the uncle",phonetic:"el TEE-oh",example:"A: ¿Tienes tíos?\nB: Sí, tengo un tío en Barcelona.",exampleEn:"A: Do you have uncles?\nB: Yes, I have an uncle in Barcelona.",note:"Note the accent on the i: tío. Without it, tio would be wrong."},
{type:"teach",kind:"word",nl:"la tía",en:"the aunt",phonetic:"la TEE-ah",example:"A: ¿Quién es ella?\nB: Es mi tía Carmen.",exampleEn:"A: Who is she?\nB: She is my aunt Carmen.",note:"Feminine of tío. Also has an accent: tía."},
{type:"teach",kind:"word",nl:"el primo",en:"the cousin (male)",phonetic:"el PREE-moh",example:"A: ¿Tienes primos?\nB: Sí, tengo tres primos.",exampleEn:"A: Do you have cousins?\nB: Yes, I have three cousins.",note:"Male cousin. Los primos = cousins (mixed or all male)."},
{type:"teach",kind:"word",nl:"la prima",en:"the cousin (female)",phonetic:"la PREE-mah",example:"A: ¿Quién es tu prima?\nB: Mi prima se llama Lucía.",exampleEn:"A: Who is your cousin?\nB: My cousin's name is Lucía.",note:"Female cousin. Change -o to -a for the feminine form."},
{type:"tip",title:"Gender Pairs in Family Words",text:"Most Spanish family words come in masculine/feminine pairs:\n\n- el abuelo / la abuela\n- el tío / la tía\n- el primo / la prima\n\nThe pattern: -o = masculine, -a = feminine.",icon:"💡"},
{type:"mc",q:"What does 'la abuela' mean?",opts:["the grandmother","the grandfather","the aunt","the mother"],ans:"the grandmother",hint:"The feminine form of the grandparent word."},
{type:"mc",q:"How do you say 'the uncle' in Spanish?",opts:["el tío","el primo","el abuelo","el padre"],ans:"el tío",hint:"A male sibling of your parent."},
{type:"fb",s:"Mi {1} se llama Carmen. Es la hermana de mi madre.",a:"tía",opts:["tía","prima","abuela","hermana"],hint:"Your parent's sister is your..."},
{type:"match",pairs:[{nl:"el abuelo",en:"the grandfather"},{nl:"la abuela",en:"the grandmother"},{nl:"el tío",en:"the uncle"},{nl:"la tía",en:"the aunt"},{nl:"el primo",en:"the cousin (male)"},{nl:"la prima",en:"the cousin (female)"}]},
{type:"mc",q:"Which is the feminine form of 'el primo'?",opts:["la prima","la tía","la abuela","la madre"],ans:"la prima",hint:"Change the -o ending to show feminine."},
{type:"fb",s:"Mi {1} Pedro es el padre de mi madre.",a:"abuelo",opts:["abuelo","tío","primo","padre"],hint:"Your mother's father is your..."},
{type:"mc",q:"'Los abuelos' means...",opts:["the grandparents","the uncles","the cousins","the parents"],ans:"the grandparents",hint:"The plural of abuelo/abuela together."},
{type:"mc",q:"What does 'el primo' mean?",opts:["the cousin (male)","the uncle","the brother","the nephew"],ans:"the cousin (male)",hint:"A child of your aunt or uncle."},
{type:"fb",s:"Tengo una {1} que vive en Sevilla. Es la hija de mi tío.",a:"prima",opts:["prima","tía","abuela","hermana"],hint:"Your uncle's daughter is your female..."},
{type:"mc",q:"How do you say 'the aunt' in Spanish?",opts:["la tía","la prima","la abuela","la madre"],ans:"la tía",hint:"The feminine form of tío, with accent."},
]},

// ===== L3: My Family (Possessives) =====
{id:"esp2l3",title:"Mi Familia",icon:"❤️",xp:15,board:true,steps:[
{type:"intro",title:"Mi Familia",desc:"Learn to say my, your, his/her to talk about your own family.",goals:["Learn possessives: mi, tu, su","Say 'Mi madre se llama...'","Ask about someone's family"]},
{type:"teach",kind:"grammar",nl:"mi",en:"my",phonetic:"mee",example:"A: ¿Cómo se llama tu madre?\nB: Mi madre se llama Elena.",exampleEn:"A: What is your mother's name?\nB: My mother's name is Elena.",note:"Mi = my. Does not change for gender: mi padre, mi madre."},
{type:"teach",kind:"grammar",nl:"tu",en:"your (informal)",phonetic:"too",example:"A: ¿Dónde vive tu hermano?\nB: Mi hermano vive en Valencia.",exampleEn:"A: Where does your brother live?\nB: My brother lives in Valencia.",note:"Tu = your (informal). No accent mark. Tú (with accent) = you."},
{type:"teach",kind:"grammar",nl:"su",en:"his/her/your (formal)",phonetic:"soo",example:"A: ¿Cómo se llama su padre?\nB: Su padre se llama Juan.",exampleEn:"A: What is his father's name?\nB: His father's name is Juan.",note:"Su = his, her, your (formal), or their. Context tells you which."},
{type:"tip",title:"Possessives: mi, tu, su",text:"These possessives go BEFORE the noun:\n\n- mi padre = my father\n- tu hermana = your sister\n- su hijo = his/her son\n\nThey do NOT change for masculine/feminine.\nFor plural nouns, add -s: mis padres, tus hermanos.",icon:"📝"},
{type:"teach",kind:"phrase",nl:"se llama",en:"is called / his/her name is",phonetic:"seh YAH-mah",example:"A: ¿Cómo se llama tu primo?\nB: Se llama Carlos.",exampleEn:"A: What is your cousin's name?\nB: His name is Carlos.",note:"Literally 'calls himself/herself'. Very common for names."},
{type:"teach",kind:"grammar",nl:"mis",en:"my (plural)",phonetic:"mees",example:"A: ¿Tienes hermanos?\nB: Sí, mis hermanos se llaman Pedro y Ana.",exampleEn:"A: Do you have siblings?\nB: Yes, my siblings are called Pedro and Ana.",note:"Mis = my (plural). Used with plural nouns: mis padres, mis primos."},
{type:"mc",q:"How do you say 'my mother' in Spanish?",opts:["mi madre","su madre","tu madre","mis madre"],ans:"mi madre",hint:"The possessive for first person singular."},
{type:"mc",q:"'Tu hermano' means...",opts:["your brother","my brother","his brother","our brother"],ans:"your brother",hint:"Tu (no accent) is the informal possessive."},
{type:"fb",s:"{1} padre se llama Roberto.",a:"Mi",opts:["Mi","Tu","Su","Mis"],hint:"I am talking about my own father."},
{type:"mc",q:"Which possessive means 'his' or 'her'?",opts:["su","mi","tu","mis"],ans:"su",hint:"The third-person possessive in Spanish."},
{type:"fb",s:"¿Cómo se llama {1} abuela?",a:"tu",opts:["tu","mi","su","mis"],hint:"I am asking YOU about YOUR grandmother."},
{type:"match",pairs:[{nl:"mi padre",en:"my father"},{nl:"tu madre",en:"your mother"},{nl:"su hermano",en:"his/her brother"},{nl:"mis primos",en:"my cousins"},{nl:"tu abuelo",en:"your grandfather"}]},
{type:"mc",q:"How do you say 'my siblings' (plural)?",opts:["mis hermanos","mi hermanos","mis hermano","su hermanos"],ans:"mis hermanos",hint:"Plural possessive plus plural noun."},
{type:"fb",s:"{1} hija se llama Sofía.",a:"Su",opts:["Su","Mi","Tu","Mis"],hint:"Talking about someone else's daughter."},
{type:"mc",q:"What does 'Mi abuela se llama Rosa' mean?",opts:["My grandmother's name is Rosa","Your grandmother's name is Rosa","His grandmother's name is Rosa","My grandfather's name is Rosa"],ans:"My grandmother's name is Rosa",hint:"Mi = my, abuela = grandmother, se llama = is called."},
{type:"fb",s:"¿Cómo {1} llama tu tía?",a:"se",opts:["se","mi","es","su"],hint:"Part of the name-asking phrase: se llama."},
{type:"mc",q:"'Mis padres' means...",opts:["my parents","my father","your parents","his parents"],ans:"my parents",hint:"Mis is the plural possessive for 'my'."},
{type:"fb",s:"{1} hermanas se llaman Ana y Lucía.",a:"Mis",opts:["Mis","Mi","Tu","Su"],hint:"I am talking about my own sisters, plural."},
]},

// ===== L4: Numbers 0-10 =====
{id:"esp2l4",title:"Los Números",icon:"🔢",xp:15,board:true,steps:[
{type:"intro",title:"Los Números: 0-10",desc:"Learn to count from zero to ten in Spanish and ask about quantities.",goals:["Count from 0 to 10","Ask ¿Cuántos hermanos tienes?","Answer with numbers"]},
{type:"teach",kind:"word",nl:"cero",en:"zero",phonetic:"SEH-roh",example:"A: ¿Cuántos gatos tienes?\nB: Cero. No tengo gatos.",exampleEn:"A: How many cats do you have?\nB: Zero. I don't have cats.",note:"Cero = 0. The c before e sounds like 'th' in Spain, 's' in Latin America."},
{type:"teach",kind:"word",nl:"uno",en:"one",phonetic:"OO-noh",example:"A: ¿Cuántos hermanos tienes?\nB: Tengo uno.",exampleEn:"A: How many siblings do you have?\nB: I have one.",note:"Uno = 1. Before masculine nouns: un hermano. Before feminine: una hermana."},
{type:"teach",kind:"word",nl:"dos",en:"two",phonetic:"dohs",example:"A: ¿Cuántas hijas tienes?\nB: Tengo dos hijas.",exampleEn:"A: How many daughters do you have?\nB: I have two daughters.",note:"Dos = 2. Does not change for gender."},
{type:"teach",kind:"word",nl:"tres",en:"three",phonetic:"trehs",example:"A: ¿Cuántos primos tienes?\nB: Tengo tres primos.",exampleEn:"A: How many cousins do you have?\nB: I have three cousins.",note:"Tres = 3. The r is a single tap, not a trill."},
{type:"teach",kind:"word",nl:"cuatro",en:"four",phonetic:"KWAH-troh",example:"A: ¿Cuántos tíos tienes?\nB: Tengo cuatro tíos.",exampleEn:"A: How many uncles do you have?\nB: I have four uncles.",note:"Cuatro = 4. The cu- sounds like 'kw'."},
{type:"teach",kind:"word",nl:"cinco",en:"five",phonetic:"SEEN-koh",example:"A: ¿Cuántas personas hay en tu familia?\nB: Cinco.",exampleEn:"A: How many people are in your family?\nB: Five.",note:"Cinco = 5. The c before i sounds like 's' (Latin America) or 'th' (Spain)."},
{type:"tip",title:"Numbers 6-10",text:"- seis = 6\n- siete = 7\n- ocho = 8\n- nueve = 9\n- diez = 10\n\nAll numbers except uno are the same for masculine and feminine.",icon:"🔢"},
{type:"teach",kind:"word",nl:"seis",en:"six",phonetic:"says",example:"A: ¿Cuántos hermanos tienes?\nB: Tengo seis hermanos.",exampleEn:"A: How many siblings do you have?\nB: I have six siblings.",note:"Seis = 6. Rhymes with English 'says'."},
{type:"teach",kind:"word",nl:"siete",en:"seven",phonetic:"see-EH-teh",example:"A: ¿Cuántos primos tienes?\nB: Siete.",exampleEn:"A: How many cousins do you have?\nB: Seven.",note:"Siete = 7. Two syllables."},
{type:"teach",kind:"word",nl:"ocho",en:"eight",phonetic:"OH-choh",example:"A: ¿Cuántas personas hay?\nB: Hay ocho personas.",exampleEn:"A: How many people are there?\nB: There are eight people.",note:"Ocho = 8. The ch sounds like English 'ch' in 'church'."},
{type:"teach",kind:"word",nl:"nueve",en:"nine",phonetic:"NWEH-beh",example:"A: ¿Cuántos años tiene tu primo?\nB: Tiene nueve años.",exampleEn:"A: How old is your cousin?\nB: He is nine years old.",note:"Nueve = 9. The v sounds like a soft b in Spanish."},
{type:"teach",kind:"word",nl:"diez",en:"ten",phonetic:"dee-EHS",example:"A: ¿Cuántos hijos tiene tu tía?\nB: Tiene diez hijos.",exampleEn:"A: How many children does your aunt have?\nB: She has ten children.",note:"Diez = 10. Two letters for one sound at the end: z."},
{type:"mc",q:"What number is 'cinco'?",opts:["5","3","7","9"],ans:"5",hint:"Count on your hand: all five fingers."},
{type:"mc",q:"How do you say '8' in Spanish?",opts:["ocho","seis","nueve","cuatro"],ans:"ocho",hint:"Starts with 'o' and has a 'ch' sound."},
{type:"fb",s:"Tengo {1} hermanos: Pedro, Ana y Luis.",a:"tres",opts:["tres","dos","cuatro","cinco"],hint:"Count the names listed after the number."},
{type:"match",pairs:[{nl:"uno",en:"1"},{nl:"cuatro",en:"4"},{nl:"siete",en:"7"},{nl:"diez",en:"10"},{nl:"cero",en:"0"}]},
{type:"mc",q:"What is 'nueve' in English?",opts:["nine","new","seven","five"],ans:"nine",hint:"One less than diez (ten)."},
{type:"fb",s:"Mi abuela tiene {1} hijos.",a:"seis",opts:["seis","tres","ocho","uno"],hint:"The number that comes after cinco."},
]},

// ===== L5: Descriptions with Ser =====
{id:"esp2l5",title:"¿Cómo Es?",icon:"📏",xp:15,board:true,steps:[
{type:"intro",title:"¿Cómo Es?",desc:"Describe people using ser (to be) with adjectives. Learn how adjectives change for masculine and feminine.",goals:["Use ser for descriptions","Learn alto, bajo, grande, joven, viejo","Understand adjective gender agreement"]},
{type:"teach",kind:"grammar",nl:"es",en:"is (he/she/it is)",phonetic:"ehs",example:"A: ¿Cómo es tu padre?\nB: Mi padre es alto.",exampleEn:"A: What is your father like?\nB: My father is tall.",note:"Es is from the verb ser (to be). Used for permanent traits."},
{type:"teach",kind:"word",nl:"alto",en:"tall (masculine)",phonetic:"AHL-toh",example:"A: ¿Tu hermano es alto?\nB: Sí, mi hermano es muy alto.",exampleEn:"A: Is your brother tall?\nB: Yes, my brother is very tall.",note:"Alto = tall (for males). Alta = tall (for females)."},
{type:"teach",kind:"word",nl:"alta",en:"tall (feminine)",phonetic:"AHL-tah",example:"A: ¿Tu madre es alta?\nB: Sí, mi madre es alta.",exampleEn:"A: Is your mother tall?\nB: Yes, my mother is tall.",note:"Alta = tall (feminine). The -a ending matches feminine nouns."},
{type:"teach",kind:"word",nl:"bajo",en:"short (masculine)",phonetic:"BAH-hoh",example:"A: ¿Tu primo es alto?\nB: No, es bajo.",exampleEn:"A: Is your cousin tall?\nB: No, he is short.",note:"Bajo = short in height (male). Baja = short (female)."},
{type:"teach",kind:"word",nl:"grande",en:"big / large",phonetic:"GRAHN-deh",example:"A: ¿Tu familia es grande?\nB: Sí, mi familia es muy grande.",exampleEn:"A: Is your family big?\nB: Yes, my family is very big.",note:"Grande does not change for gender. Same for masculine and feminine."},
{type:"teach",kind:"word",nl:"pequeño",en:"small (masculine)",phonetic:"peh-KEH-nyoh",example:"A: ¿Tu hijo es grande?\nB: No, es pequeño.",exampleEn:"A: Is your son big?\nB: No, he is small.",note:"Pequeño = small (male). Pequeña = small (female). The ñ sounds like 'ny'."},
{type:"tip",title:"Adjective Gender Agreement",text:"In Spanish, adjectives must match the noun's gender:\n\n- -o ending = masculine: alto, bajo, pequeño\n- -a ending = feminine: alta, baja, pequeña\n- -e ending = same for both: grande\n\nMi padre es alto. Mi madre es alta.",icon:"📝"},
{type:"teach",kind:"word",nl:"joven",en:"young",phonetic:"HOH-ben",example:"A: ¿Tu tía es joven?\nB: Sí, mi tía es muy joven.",exampleEn:"A: Is your aunt young?\nB: Yes, my aunt is very young.",note:"Joven = young. Same form for masculine and feminine."},
{type:"teach",kind:"word",nl:"viejo",en:"old (masculine)",phonetic:"bee-EH-hoh",example:"A: ¿Tu abuelo es viejo?\nB: Sí, mi abuelo es viejo.",exampleEn:"A: Is your grandfather old?\nB: Yes, my grandfather is old.",note:"Viejo = old (male). Vieja = old (female). The v sounds like a soft b."},
{type:"mc",q:"How do you say 'My mother is tall'?",opts:["Mi madre es alta","Mi madre es alto","Mi madre es grande","Mi madre es bajo"],ans:"Mi madre es alta",hint:"Madre is feminine, so the adjective needs -a."},
{type:"mc",q:"Which adjective does NOT change for gender?",opts:["grande","alto","bajo","pequeño"],ans:"grande",hint:"Adjectives ending in -e stay the same."},
{type:"fb",s:"Mi hermano es muy {1}.",a:"alto",opts:["alto","alta","grandes","baja"],hint:"Your brother is male, so use the -o form."},
{type:"match",pairs:[{nl:"alto",en:"tall (masc.)"},{nl:"baja",en:"short (fem.)"},{nl:"grande",en:"big"},{nl:"joven",en:"young"},{nl:"viejo",en:"old (masc.)"}]},
{type:"mc",q:"'Mi abuela es vieja' means...",opts:["My grandmother is old","My grandfather is old","My grandmother is young","My grandmother is tall"],ans:"My grandmother is old",hint:"Abuela = grandmother, vieja = old (feminine)."},
{type:"fb",s:"Mi tía es {1}. Tiene 25 años.",a:"joven",opts:["joven","vieja","alto","grande"],hint:"25 years old is not old, it is..."},
{type:"mc",q:"Which is correct: 'Mi padre es ___'?",opts:["bajo","baja","bajas","bajos"],ans:"bajo",hint:"Padre is masculine singular, so use the -o form."},
{type:"fb",s:"Mi familia es muy {1}. Tengo seis hermanos.",a:"grande",opts:["grande","pequeña","alto","joven"],hint:"Six siblings means a big family."},
]},

// ===== L6: Hair and Eyes =====
{id:"esp2l6",title:"Pelo y Ojos",icon:"👁️",xp:15,board:true,steps:[
{type:"intro",title:"Pelo y Ojos",desc:"Learn to describe hair and eye color. Build richer descriptions of people.",goals:["Learn moreno, rubio, pelo, ojos","Describe hair and eye color","Use tiene for physical descriptions"]},
{type:"teach",kind:"word",nl:"el pelo",en:"the hair",phonetic:"el PEH-loh",example:"A: ¿De qué color es tu pelo?\nB: Mi pelo es negro.",exampleEn:"A: What color is your hair?\nB: My hair is black.",note:"El pelo = the hair. Used with colors for descriptions."},
{type:"teach",kind:"word",nl:"los ojos",en:"the eyes",phonetic:"lohs OH-hohs",example:"A: ¿De qué color son tus ojos?\nB: Mis ojos son marrones.",exampleEn:"A: What color are your eyes?\nB: My eyes are brown.",note:"Los ojos = the eyes. Always plural. The j sounds like English 'h'."},
{type:"teach",kind:"word",nl:"moreno",en:"dark-haired / brunette (masc.)",phonetic:"moh-REH-noh",example:"A: ¿Tu hermano es rubio?\nB: No, es moreno.",exampleEn:"A: Is your brother blond?\nB: No, he is dark-haired.",note:"Moreno = dark hair (male). Morena = dark hair (female)."},
{type:"teach",kind:"word",nl:"rubio",en:"blond (masculine)",phonetic:"ROO-bee-oh",example:"A: ¿Cómo es tu primo?\nB: Mi primo es rubio.",exampleEn:"A: What does your cousin look like?\nB: My cousin is blond.",note:"Rubio = blond (male). Rubia = blond (female)."},
{type:"teach",kind:"word",nl:"negro",en:"black (color)",phonetic:"NEH-groh",example:"A: ¿De qué color es el pelo de tu madre?\nB: Tiene el pelo negro.",exampleEn:"A: What color is your mother's hair?\nB: She has black hair.",note:"Negro = black. Used for hair and eye color."},
{type:"teach",kind:"word",nl:"marrón",en:"brown (color)",phonetic:"mah-ROHN",example:"A: ¿De qué color son tus ojos?\nB: Son marrones.",exampleEn:"A: What color are your eyes?\nB: They are brown.",note:"Marrón = brown. Plural: marrones. Same for masculine and feminine."},
{type:"teach",kind:"phrase",nl:"tiene el pelo",en:"has (the) hair",phonetic:"tee-EH-neh el PEH-loh",example:"A: ¿Cómo es tu hermana?\nB: Tiene el pelo largo y rubio.",exampleEn:"A: What does your sister look like?\nB: She has long blond hair.",note:"Use tiene + el pelo + adjective to describe someone's hair."},
{type:"tip",title:"Describing Appearance with Tiene",text:"Use 'tiene' (has) for physical features:\n\n- Tiene el pelo negro. (has black hair)\n- Tiene los ojos marrones. (has brown eyes)\n\nUse 'es' (is) for general traits:\n- Es moreno. (He is dark-haired.)\n- Es alta. (She is tall.)",icon:"💡"},
{type:"mc",q:"How do you say 'She has brown eyes'?",opts:["Tiene los ojos marrones","Es los ojos marrones","Tiene el pelo marrón","Su ojos son marrones"],ans:"Tiene los ojos marrones",hint:"Use tiene + los ojos + the color word."},
{type:"mc",q:"What does 'morena' describe?",opts:["a dark-haired woman","a blond woman","brown eyes","black hair"],ans:"a dark-haired woman",hint:"The -a ending tells you it is feminine."},
{type:"fb",s:"Mi padre tiene el pelo {1}.",a:"negro",opts:["negro","ojos","moreno","tiene"],hint:"A very dark hair color, not brown."},
{type:"match",pairs:[{nl:"el pelo",en:"the hair"},{nl:"los ojos",en:"the eyes"},{nl:"rubio",en:"blond"},{nl:"moreno",en:"dark-haired"},{nl:"marrón",en:"brown"},{nl:"negro",en:"black"}]},
{type:"mc",q:"'Mi hermana es rubia' means...",opts:["My sister is blond","My sister is brunette","My brother is blond","My sister has brown eyes"],ans:"My sister is blond",hint:"Rubia is the feminine form of rubio."},
{type:"fb",s:"Mi madre tiene los {1} marrones.",a:"ojos",opts:["ojos","pelo","hermano","padre"],hint:"The body part on your face used for seeing."},
{type:"mc",q:"Which describes dark hair on a man?",opts:["moreno","morena","rubio","negro"],ans:"moreno",hint:"The masculine -o ending for dark-haired."},
{type:"fb",s:"Mi primo es {1}. Tiene el pelo amarillo.",a:"rubio",opts:["rubio","moreno","negro","alto"],hint:"Light or golden hair describes someone who is..."},
{type:"mc",q:"How do you ask 'What color are your eyes?'",opts:["¿De qué color son tus ojos?","¿Cómo son tus ojos?","¿Tienes ojos?","¿Cuántos ojos tienes?"],ans:"¿De qué color son tus ojos?",hint:"Literally: Of what color are your eyes?"},
]},

// ===== L7: Tener (to have) =====
{id:"esp2l7",title:"Tener",icon:"✋",xp:15,board:true,steps:[
{type:"intro",title:"Tener: To Have",desc:"Learn the verb tener (to have). Use it to talk about family, possessions, and age.",goals:["Conjugate tener: tengo, tienes, tiene","Use tener for family and age","Say 'Tengo X años' for age"]},
{type:"teach",kind:"grammar",nl:"tengo",en:"I have",phonetic:"TEHN-goh",example:"A: ¿Tienes hermanos?\nB: Sí, tengo dos hermanos.",exampleEn:"A: Do you have siblings?\nB: Yes, I have two siblings.",note:"Tengo = I have. Irregular yo form of tener."},
{type:"teach",kind:"grammar",nl:"tienes",en:"you have (informal)",phonetic:"tee-EH-nehs",example:"A: ¿Cuántos primos tienes?\nB: Tengo cinco primos.",exampleEn:"A: How many cousins do you have?\nB: I have five cousins.",note:"Tienes = you have (informal tú form)."},
{type:"teach",kind:"grammar",nl:"tiene",en:"he/she has, you have (formal)",phonetic:"tee-EH-neh",example:"A: ¿Cuántos hijos tiene tu tía?\nB: Tiene tres hijos.",exampleEn:"A: How many children does your aunt have?\nB: She has three children.",note:"Tiene = he/she has, or usted has (formal you)."},
{type:"tip",title:"Tener Conjugation (Singular)",text:"Tener is irregular:\n\n- yo tengo = I have\n- tú tienes = you have\n- él/ella tiene = he/she has\n\nTener is used for possession AND age:\n- Tengo un hermano. (I have a brother.)\n- Tengo diez años. (I am ten years old.)",icon:"📝"},
{type:"teach",kind:"phrase",nl:"tengo ... años",en:"I am ... years old",phonetic:"TEHN-goh ... AH-nyohs",example:"A: ¿Cuántos años tienes?\nB: Tengo ocho años.",exampleEn:"A: How old are you?\nB: I am eight years old.",note:"Spanish uses tener (to have) for age, not ser (to be). Literally: I have X years."},
{type:"teach",kind:"phrase",nl:"¿Cuántos años tienes?",en:"How old are you?",phonetic:"KWAHN-tohs AH-nyohs tee-EH-nehs",example:"A: ¿Cuántos años tienes?\nB: Tengo nueve años. ¿Y tú?",exampleEn:"A: How old are you?\nB: I am nine years old. And you?",note:"Literally: How many years do you have? ¿Cuántos = how many."},
{type:"mc",q:"How do you say 'I have' in Spanish?",opts:["tengo","tienes","tiene","tener"],ans:"tengo",hint:"The yo (I) form of tener is irregular."},
{type:"mc",q:"How do you say 'I am 10 years old'?",opts:["Tengo diez años","Soy diez años","Es diez años","Tiene diez años"],ans:"Tengo diez años",hint:"Spanish uses 'to have' for age, not 'to be'."},
{type:"fb",s:"Mi madre {1} cuatro hermanos.",a:"tiene",opts:["tiene","tengo","tienes","tener"],hint:"Third person singular: he/she has."},
{type:"mc",q:"'¿Cuántos años tienes?' asks about...",opts:["your age","your name","your family","your height"],ans:"your age",hint:"Años means years. The question asks how many."},
{type:"fb",s:"¿Cuántos hermanos {1}?",a:"tienes",opts:["tienes","tengo","tiene","tener"],hint:"Asking YOU (informal) how many siblings."},
{type:"match",pairs:[{nl:"tengo",en:"I have"},{nl:"tienes",en:"you have"},{nl:"tiene",en:"he/she has"},{nl:"tengo cinco años",en:"I am 5 years old"},{nl:"¿Cuántos años?",en:"How old?"}]},
{type:"mc",q:"Which is correct? 'Mi abuelo ___ ocho hijos.'",opts:["tiene","tengo","tienes","tener"],ans:"tiene",hint:"Mi abuelo is third person: he."},
{type:"fb",s:"{1} tres primos en Madrid.",a:"Tengo",opts:["Tengo","Tienes","Tiene","Tener"],hint:"I am saying what I have. First person."},
{type:"mc",q:"'Mi prima tiene siete años' means...",opts:["My cousin is 7 years old","My cousin has 7 brothers","My cousin is 7 feet tall","My cousin has 7 eyes"],ans:"My cousin is 7 years old",hint:"Tiene + años = expressing age in Spanish."},
{type:"fb",s:"¿Cuántos años {1} tu abuela?",a:"tiene",opts:["tiene","tengo","tienes","tener"],hint:"Asking about HER age, third person singular."},
{type:"mc",q:"How would you say 'You have two sisters'?",opts:["Tienes dos hermanas","Tengo dos hermanas","Tiene dos hermanas","Tener dos hermanas"],ans:"Tienes dos hermanas",hint:"Addressing someone informally: tú form."},
]},

// ===== L8: Describe Your Family (Review) =====
{id:"esp2l8",title:"¡Describe Tu Familia!",icon:"🏠",xp:20,board:true,steps:[
{type:"intro",title:"¡Describe Tu Familia!",desc:"Put it all together. Describe your family using everything from this unit.",goals:["Combine family vocabulary with possessives","Use ser and tener for descriptions","Practice numbers and adjective agreement"]},
{type:"tip",title:"Describing People: Full Toolkit",text:"You now have these tools:\n\n- Family words: padre, madre, hermano, abuelo, tío, primo...\n- Possessives: mi, tu, su, mis\n- Ser + adjective: es alto, es joven, es grande\n- Tener + feature: tiene el pelo negro, tiene los ojos marrones\n- Tener + age: tiene diez años\n- Numbers: cero to diez",icon:"🧰"},
{type:"mc",q:"How do you say 'My father is tall and dark-haired'?",opts:["Mi padre es alto y moreno","Mi padre tiene alto y moreno","Mi padre es alta y morena","Su padre es alto y morena"],ans:"Mi padre es alto y moreno",hint:"Use es for traits. Padre is masculine: -o endings."},
{type:"fb",s:"Mi hermana {1} el pelo rubio.",a:"tiene",opts:["tiene","es","tengo","tienes"],hint:"For physical features like hair, use the verb 'to have'."},
{type:"mc",q:"Which sentence is correct?",opts:["Mi abuela es vieja","Mi abuela es viejo","Mi abuela es viejas","Mi abuela tiene vieja"],ans:"Mi abuela es vieja",hint:"Abuela is feminine singular. Match the adjective."},
{type:"fb",s:"Mi tío es {1} y tiene los ojos marrones.",a:"alto",opts:["alto","alta","grande","tiene"],hint:"Tío is masculine. Choose the masculine adjective for height."},
{type:"match",pairs:[{nl:"Mi madre es alta",en:"My mother is tall"},{nl:"Tengo tres hermanos",en:"I have three siblings"},{nl:"Su padre tiene los ojos negros",en:"His father has black eyes"},{nl:"Mi prima es joven",en:"My cousin is young"},{nl:"Tiene cinco años",en:"He/she is 5 years old"}]},
{type:"mc",q:"'Mi primo tiene ocho años y es bajo' means...",opts:["My cousin is 8 years old and is short","My cousin has 8 brothers and is tall","My cousin is 8 years old and is blond","My cousin has 8 years and is big"],ans:"My cousin is 8 years old and is short",hint:"Tiene + años = age. Bajo = short in height."},
{type:"fb",s:"Tengo {1} hermanas: María y Sofía.",a:"dos",opts:["dos","tres","cuatro","uno"],hint:"Count the names: María and Sofía."},
{type:"mc",q:"How do you ask 'How old is your grandmother?'",opts:["¿Cuántos años tiene tu abuela?","¿Cómo es tu abuela?","¿Cuántos hermanos tiene tu abuela?","¿Tienes abuela?"],ans:"¿Cuántos años tiene tu abuela?",hint:"Use the age question pattern with 'tiene' for her."},
{type:"fb",s:"Mi {1} se llama Pedro. Es el padre de mi padre.",a:"abuelo",opts:["abuelo","tío","primo","hermano"],hint:"Your father's father is your grand..."},
{type:"mc",q:"Which is correct? 'Mi madre es ___.'",opts:["morena","moreno","morenos","morenas"],ans:"morena",hint:"Madre is feminine singular. Use the -a form."},
{type:"drag_fill",s:"Mi {1} es {2} y tiene los ojos {3}.",blanks:{1:"hermana",2:"alta",3:"marrones"},pool:["hermana","alta","marrones","hermano","bajo","negro"],hint:"Describe a tall female sibling with brown eyes."},
{type:"fb",s:"Mi familia es {1}. Tengo seis hermanos.",a:"grande",opts:["grande","pequeña","alto","joven"],hint:"Six siblings means a large, not small, family."},
{type:"mc",q:"How do you say 'His aunt is young'?",opts:["Su tía es joven","Mi tía es joven","Su tío es joven","Su tía tiene joven"],ans:"Su tía es joven",hint:"Su = his/her. Tía = aunt. Use es for traits."},
{type:"match",pairs:[{nl:"el padre",en:"the father"},{nl:"la abuela",en:"the grandmother"},{nl:"el primo",en:"the cousin (male)"},{nl:"la tía",en:"the aunt"},{nl:"el hijo",en:"the son"},{nl:"la hermana",en:"the sister"}]},
{type:"fb",s:"¿Cuántos {1} tiene tu tío?",a:"hijos",opts:["hijos","años","hermanos","ojos"],hint:"Asking how many children your uncle has."},
{type:"mc",q:"Complete: 'Mi abuelo tiene ___ años.'",opts:["diez","alto","rubio","grande"],ans:"diez",hint:"Age uses a number with años."},
]}

]},
// ══════════════════════════════════════════════════════════════
// UNIT 3: Números y Colores — Numbers, Days & Colors (A1.1)
// 8 lessons, 18+ steps each
// ══════════════════════════════════════════════════════════════
{n:3,lang:"es",track:"v1",title:"Números y Colores",sub:"Numbers, Days & Colors",icon:"🎨",level:"A1.1",color:"#7B5EE8",lessons:[
// ===== L1: Numbers 11-20 =====
{id:"esp3l1",title:"Once a Veinte",icon:"🔢",xp:15,board:true,steps:[
{type:"intro",title:"Once a Veinte",desc:"Expand your number range from 11 to 20.",goals:["Count from 11 to 20","Recognize number patterns","Use numbers in simple sentences"]},
{type:"teach",kind:"word",nl:"once",en:"eleven",phonetic:"ON-seh",example:"A: ¿Cuántos alumnos hay?\nB: Hay once alumnos.",exampleEn:"A: How many students are there?\nB: There are eleven students.",note:"Once = 11. Unique word, no pattern to follow."},
{type:"teach",kind:"word",nl:"doce",en:"twelve",phonetic:"DOH-seh",example:"A: ¿Cuántos meses tiene un año?\nB: Tiene doce meses.",exampleEn:"A: How many months does a year have?\nB: It has twelve months.",note:"Doce = 12. Also a unique word."},
{type:"teach",kind:"word",nl:"trece",en:"thirteen",phonetic:"TREH-seh",example:"A: ¿Cuántos años tienes?\nB: Tengo trece años.",exampleEn:"A: How old are you?\nB: I am thirteen years old.",note:"Trece = 13. Starts the 'ce' pattern: trece, catorce, quince."},
{type:"teach",kind:"word",nl:"catorce",en:"fourteen",phonetic:"ka-TOR-seh",example:"A: ¿Cuántos primos tienes?\nB: Tengo catorce primos.",exampleEn:"A: How many cousins do you have?\nB: I have fourteen cousins.",note:"Catorce = 14."},
{type:"teach",kind:"word",nl:"quince",en:"fifteen",phonetic:"KEEN-seh",example:"A: ¿A qué hora es la clase?\nB: A las quince. A las tres.",exampleEn:"A: What time is the class?\nB: At fifteen. At three.",note:"Quince = 15. In many countries, the quinceañera celebrates a girl turning 15."},
{type:"tip",title:"16-19 pattern: dieci + number",text:"From 16 to 19, numbers are compound words:\n16 = dieciséis (diez + y + seis)\n17 = diecisiete (diez + y + siete)\n18 = dieciocho (diez + y + ocho)\n19 = diecinueve (diez + y + nueve)\nAll one word!",icon:"💡"},
{type:"teach",kind:"word",nl:"dieciséis",en:"sixteen",phonetic:"dyeh-see-SAYS",example:"A: ¿Cuántos años tiene tu hermana?\nB: Tiene dieciséis años.",exampleEn:"A: How old is your sister?\nB: She is sixteen years old.",note:"Dieciséis = 16. Dieci + séis. Note the accent on the é."},
{type:"teach",kind:"word",nl:"veinte",en:"twenty",phonetic:"BAYN-teh",example:"A: ¿Cuántos estudiantes hay en la clase?\nB: Hay veinte.",exampleEn:"A: How many students are in the class?\nB: There are twenty.",note:"Veinte = 20. Important base number for 21-29."},
{type:"mc",q:"What number is 'quince'?",opts:["15","14","13","16"],ans:"15",hint:"This number has a famous birthday celebration named after it."},
{type:"mc",q:"How do you say 12 in Spanish?",opts:["doce","trece","once","diez"],ans:"doce",hint:"One more than once (11)."},
{type:"fb",s:"Mi primo tiene {1} años.",a:"catorce",opts:["catorce","cuatro","quince","doce"],hint:"The number between trece and quince."},
{type:"mc",q:"'Dieciséis' is formed from which two numbers?",opts:["Diez + seis","Diez + siete","Doce + seis","Dieci + seis"],ans:"Diez + seis",hint:"Ten plus six, written as one compound word."},
{type:"match",pairs:[{nl:"once",en:"11"},{nl:"trece",en:"13"},{nl:"quince",en:"15"},{nl:"dieciséis",en:"16"},{nl:"veinte",en:"20"}]},
{type:"fb",s:"Hay {1} estudiantes en la clase.",a:"veinte",opts:["veinte","doce","once","trece"],hint:"The round number that equals two times ten."},
{type:"mc",q:"What number comes after 'diecisiete'?",opts:["dieciséis","dieciocho","diecinueve","veinte"],ans:"dieciocho",hint:"17 + 1 in the dieci- compound pattern."},
{type:"mc",q:"'Once' means:",opts:["11","1","10","12"],ans:"11",hint:"The first number after diez that has its own unique name."},
{type:"fb",s:"Tengo {1} años. El año que viene cumplo trece.",a:"doce",opts:["doce","once","trece","diez"],hint:"One less than the number mentioned next year."},
]},
// ===== L2: Numbers 21-100 =====
{id:"esp3l2",title:"Veintiuno a Cien",icon:"💯",xp:15,board:true,steps:[
{type:"intro",title:"Veintiuno a Cien",desc:"Learn numbers up to 100. Master the tens and the 21-29 compound pattern.",goals:["Count by tens to 100","Use 21-29 compound numbers","Say any number up to 100"]},
{type:"teach",kind:"word",nl:"veintiuno",en:"twenty-one",phonetic:"bayn-tee-OO-no",example:"A: ¿Cuántos años tienes?\nB: Tengo veintiún años.",exampleEn:"A: How old are you?\nB: I am twenty-one years old.",note:"21-29 are compound words: veinti + number. Veintiún before masculine nouns."},
{type:"teach",kind:"word",nl:"treinta",en:"thirty",phonetic:"TRAYN-ta",example:"A: ¿Cuántos días tiene septiembre?\nB: Septiembre tiene treinta días.",exampleEn:"A: How many days does September have?\nB: September has thirty days.",note:"Treinta = 30. From 31 onward: treinta y uno, treinta y dos (separate words)."},
{type:"teach",kind:"word",nl:"cuarenta",en:"forty",phonetic:"kwa-REN-ta",example:"A: ¿Cuántos años tiene tu padre?\nB: Tiene cuarenta años.",exampleEn:"A: How old is your father?\nB: He is forty years old.",note:"Cuarenta = 40. All tens from 30+ follow the -enta/-inta pattern."},
{type:"teach",kind:"word",nl:"cincuenta",en:"fifty",phonetic:"seen-KWEN-ta",example:"A: ¿Cuántas personas hay?\nB: Hay cincuenta personas.",exampleEn:"A: How many people are there?\nB: There are fifty people.",note:"Cincuenta = 50."},
{type:"tip",title:"Tens: 30-100",text:"30 = treinta\n40 = cuarenta\n50 = cincuenta\n60 = sesenta\n70 = setenta\n80 = ochenta\n90 = noventa\n100 = cien\n\nFor in-between: treinta Y uno, cuarenta Y dos.\nThe 'y' (and) connects tens and ones from 31 onward.",icon:"🔢"},
{type:"teach",kind:"word",nl:"sesenta",en:"sixty",phonetic:"seh-SEN-ta",example:"A: ¿Cuántos minutos tiene una hora?\nB: Sesenta minutos.",exampleEn:"A: How many minutes are in an hour?\nB: Sixty minutes.",note:"Sesenta = 60."},
{type:"teach",kind:"word",nl:"cien",en:"one hundred",phonetic:"SYEN",example:"A: ¿Cuánto cuesta?\nB: Cien euros.",exampleEn:"A: How much does it cost?\nB: One hundred euros.",note:"Cien = 100 (exactly). Ciento is used before smaller numbers: ciento uno (101)."},
{type:"mc",q:"How do you say 35 in Spanish?",opts:["treinta y cinco","treintacinco","treinticinco","trece y cinco"],ans:"treinta y cinco",hint:"From 31 onward, tens and ones are connected with 'y'."},
{type:"mc",q:"What is 'cuarenta'?",opts:["40","14","4","44"],ans:"40",hint:"The tens number related to cuatro (4)."},
{type:"fb",s:"Mi abuelo tiene {1} años.",a:"sesenta",opts:["sesenta","seis","dieciséis","cien"],hint:"The tens version of the number six."},
{type:"mc",q:"21-29 are written as:",opts:["Two separate words with 'y'","One compound word (veinti-)","Three words","Just the ones digit"],ans:"One compound word (veinti-)",hint:"Unlike 31+, these are fused into a single word."},
{type:"match",pairs:[{nl:"treinta",en:"30"},{nl:"cincuenta",en:"50"},{nl:"setenta",en:"70"},{nl:"noventa",en:"90"},{nl:"cien",en:"100"}]},
{type:"fb",s:"¿Cuántos años tienes? Tengo {1} años.",a:"veintiuno",opts:["veintiuno","veinte y uno","veinti","uno"],hint:"The compound form for twenty-one."},
{type:"mc",q:"'Cien' is used for exactly 100. For 101 you say:",opts:["cien uno","ciento uno","cien y uno","un ciento"],ans:"ciento uno",hint:"Above exactly 100, a longer form of the word is used."},
{type:"mc",q:"How do you say 99?",opts:["noventa y nueve","noventanueve","noventa nueve","nueve y noventa"],ans:"noventa y nueve",hint:"Tens + y + ones for numbers 31 and above."},
{type:"fb",s:"Hay {1} personas en el autobús.",a:"cuarenta",opts:["cuarenta","cuatro","catorce","cincuenta"],hint:"The tens number derived from four."},
{type:"mc",q:"How do you say 73?",opts:["setenta y tres","setentaytres","siete y tres","sesenta y tres"],ans:"setenta y tres",hint:"Seventy + y + three, written as separate words."},
]},
// ===== L3: Days of the Week =====
{id:"esp3l3",title:"Los Días de la Semana",icon:"📅",xp:15,board:true,steps:[
{type:"intro",title:"Los Días de la Semana",desc:"Learn the seven days of the week and how to talk about weekly schedules.",goals:["Name all 7 days","Know days are NOT capitalized","Use 'el lunes' and 'los lunes'"]},
{type:"teach",kind:"word",nl:"el lunes",en:"Monday",phonetic:"el LOO-nes",example:"A: ¿Qué día es hoy?\nB: Hoy es lunes.",exampleEn:"A: What day is today?\nB: Today is Monday.",note:"Days of the week are NOT capitalized in Spanish. El lunes = on Monday."},
{type:"teach",kind:"word",nl:"el martes",en:"Tuesday",phonetic:"el MAR-tes",example:"A: ¿Cuándo es la clase de español?\nB: El martes a las diez.",exampleEn:"A: When is the Spanish class?\nB: On Tuesday at ten.",note:"Martes = Tuesday. Named after Mars (Marte)."},
{type:"teach",kind:"word",nl:"el miércoles",en:"Wednesday",phonetic:"el mee-ER-ko-les",example:"A: ¿Trabajas el miércoles?\nB: No, el miércoles no trabajo.",exampleEn:"A: Do you work on Wednesday?\nB: No, I don't work on Wednesday.",note:"Miércoles = Wednesday. Named after Mercury."},
{type:"teach",kind:"word",nl:"el jueves",en:"Thursday",phonetic:"el HWEH-ves",example:"A: ¿Qué haces el jueves?\nB: Estudio español el jueves.",exampleEn:"A: What do you do on Thursday?\nB: I study Spanish on Thursday.",note:"Jueves = Thursday. Named after Jupiter (Jove)."},
{type:"teach",kind:"word",nl:"el viernes",en:"Friday",phonetic:"el vee-ER-nes",example:"A: ¡Por fin es viernes!\nB: ¡Sí! ¿Planes para el fin de semana?",exampleEn:"A: Finally it's Friday!\nB: Yes! Plans for the weekend?",note:"Viernes = Friday. Named after Venus."},
{type:"teach",kind:"word",nl:"el sábado",en:"Saturday",phonetic:"el SA-ba-do",example:"A: ¿Qué haces el sábado?\nB: Voy al parque con mi familia.",exampleEn:"A: What do you do on Saturday?\nB: I go to the park with my family.",note:"Sábado = Saturday. Has an accent because stress is on the third-to-last syllable."},
{type:"teach",kind:"word",nl:"el domingo",en:"Sunday",phonetic:"el do-MEEN-go",example:"A: ¿Descansas el domingo?\nB: Sí, el domingo es para descansar.",exampleEn:"A: Do you rest on Sunday?\nB: Yes, Sunday is for resting.",note:"Domingo = Sunday. Named after the Lord's day (dominus)."},
{type:"tip",title:"Days are lowercase!",text:"In Spanish, days of the week are never capitalized:\nlunes, martes, miércoles, jueves, viernes, sábado, domingo.\n\nUse 'el' for one specific day: el lunes (on Monday).\nUse 'los' for every week: los lunes (on Mondays).",icon:"📝"},
{type:"mc",q:"Which day comes after jueves?",opts:["miércoles","viernes","sábado","martes"],ans:"viernes",hint:"The day named after Venus, the start of the weekend."},
{type:"mc",q:"Days of the week in Spanish are:",opts:["Always capitalized","Never capitalized","Capitalized on Mondays only","Sometimes capitalized"],ans:"Never capitalized",hint:"Unlike English, Spanish does not capitalize day names."},
{type:"fb",s:"Hoy es {1}. Mañana es martes.",a:"lunes",opts:["lunes","miércoles","domingo","sábado"],hint:"The day before Tuesday."},
{type:"match",pairs:[{nl:"lunes",en:"Monday"},{nl:"miércoles",en:"Wednesday"},{nl:"viernes",en:"Friday"},{nl:"sábado",en:"Saturday"},{nl:"domingo",en:"Sunday"}]},
{type:"mc",q:"'Los martes' means:",opts:["This Tuesday","On Tuesdays (every week)","Last Tuesday","Two Tuesdays"],ans:"On Tuesdays (every week)",hint:"The plural article 'los' indicates regular repetition."},
{type:"fb",s:"¿Qué día es hoy? Hoy es {1}.",a:"viernes",opts:["viernes","lunes","sábado","martes"],hint:"The last weekday before the weekend."},
{type:"mc",q:"Which TWO days form the weekend?",opts:["sábado y domingo","viernes y sábado","lunes y martes","jueves y viernes"],ans:"sábado y domingo",hint:"The traditional weekend days in Spanish-speaking countries."},
{type:"mc",q:"The Spanish week starts on:",opts:["Sunday","Monday","Saturday","It varies"],ans:"Monday",hint:"Calendars in Spanish-speaking countries begin with this day."},
{type:"fb",s:"El {1} no hay clase.",a:"domingo",opts:["domingo","lunes","martes","jueves"],hint:"The day of rest at the end of the week."},
]},
// ===== L4: Months & Seasons =====
{id:"esp3l4",title:"Los Meses y las Estaciones",icon:"🗓️",xp:15,board:true,steps:[
{type:"intro",title:"Los Meses y las Estaciones",desc:"Learn the twelve months, four seasons, and how to say dates.",goals:["Name all 12 months","Know the 4 seasons","Say dates in Spanish"]},
{type:"teach",kind:"word",nl:"enero",en:"January",phonetic:"eh-NEH-ro",example:"A: ¿Cuándo es tu cumpleaños?\nB: En enero. El tres de enero.",exampleEn:"A: When is your birthday?\nB: In January. January third.",note:"Enero = January. Months are NOT capitalized in Spanish!"},
{type:"teach",kind:"word",nl:"febrero",en:"February",phonetic:"feh-BREH-ro",example:"A: ¿Cuántos días tiene febrero?\nB: Tiene veintiocho días.",exampleEn:"A: How many days does February have?\nB: It has twenty-eight days.",note:"Febrero = February."},
{type:"tip",title:"All 12 months (lowercase!)",text:"enero, febrero, marzo, abril, mayo, junio,\njulio, agosto, septiembre, octubre, noviembre, diciembre.\n\nLike days, months are NEVER capitalized.\nUse 'en' for months: en enero = in January.",icon:"🗓️"},
{type:"teach",kind:"phrase",nl:"¿Cuándo es tu cumpleaños?",en:"When is your birthday?",phonetic:"KWAN-do es too koom-pleh-AH-nyos",example:"A: ¿Cuándo es tu cumpleaños?\nB: Mi cumpleaños es el quince de marzo.",exampleEn:"A: When is your birthday?\nB: My birthday is March fifteenth.",note:"Cumpleaños = birthday. Literally: fulfill years."},
{type:"teach",kind:"phrase",nl:"el tres de enero",en:"January third",phonetic:"el TRES deh eh-NEH-ro",example:"A: ¿Qué fecha es hoy?\nB: Hoy es el tres de enero.",exampleEn:"A: What is today's date?\nB: Today is January third.",note:"Dates: el + number + de + month. No ordinal numbers except for the first (el primero)."},
{type:"teach",kind:"word",nl:"la primavera",en:"spring",phonetic:"la pree-ma-VEH-ra",example:"A: ¿Cuál es tu estación favorita?\nB: La primavera. Me gustan las flores.",exampleEn:"A: What is your favorite season?\nB: Spring. I like flowers.",note:"La primavera = spring. Feminine noun."},
{type:"teach",kind:"word",nl:"el verano",en:"summer",phonetic:"el veh-RA-no",example:"A: ¿Qué haces en verano?\nB: Voy a la playa.",exampleEn:"A: What do you do in summer?\nB: I go to the beach.",note:"El verano = summer. Masculine noun."},
{type:"teach",kind:"word",nl:"el otoño",en:"autumn / fall",phonetic:"el o-TO-nyo",example:"A: ¿Te gusta el otoño?\nB: Sí, me gustan los colores.",exampleEn:"A: Do you like autumn?\nB: Yes, I like the colors.",note:"El otoño = autumn. Note the ñ."},
{type:"teach",kind:"word",nl:"el invierno",en:"winter",phonetic:"el een-vee-ER-no",example:"A: ¿Hace frío en invierno?\nB: Sí, hace mucho frío.",exampleEn:"A: Is it cold in winter?\nB: Yes, it is very cold.",note:"El invierno = winter. Masculine noun."},
{type:"mc",q:"Months in Spanish are:",opts:["Capitalized like English","Never capitalized","Capitalized only in titles","All uppercase"],ans:"Never capitalized",hint:"Same rule as days of the week."},
{type:"mc",q:"How do you say 'March 15th' in Spanish?",opts:["El quince de marzo","Marzo quince","El quince marzo","Quince de el marzo"],ans:"El quince de marzo",hint:"Pattern: el + number + de + month."},
{type:"fb",s:"Mi cumpleaños es en {1}.",a:"abril",opts:["abril","lunes","primavera","veinte"],hint:"The fourth month of the year."},
{type:"match",pairs:[{nl:"la primavera",en:"spring"},{nl:"el verano",en:"summer"},{nl:"el otoño",en:"autumn"},{nl:"el invierno",en:"winter"}]},
{type:"mc",q:"Which month has only 28 days (usually)?",opts:["enero","febrero","marzo","abril"],ans:"febrero",hint:"The shortest month of the year."},
{type:"fb",s:"Hoy es el {1} de septiembre.",a:"tres",opts:["tres","septiembre","lunes","otoño"],hint:"The number goes between 'el' and 'de' in dates."},
{type:"mc",q:"'En verano' means:",opts:["In summer","In winter","On vacation","In the morning"],ans:"In summer",hint:"Verano is the warm season between spring and autumn."},
{type:"mc",q:"Which is the correct date format?",opts:["El tres de enero","Enero tres","Three January","De enero el tres"],ans:"El tres de enero",hint:"Article + number + de + month."},
]},
// ===== L5: Colors =====
{id:"esp3l5",title:"Los Colores",icon:"🌈",xp:15,board:true,steps:[
{type:"intro",title:"Los Colores",desc:"Learn color words and how they agree with the noun they describe.",goals:["Name common colors","Apply gender agreement to colors","Describe objects with colors"]},
{type:"teach",kind:"word",nl:"rojo",en:"red (masculine)",phonetic:"RRO-ho",example:"A: ¿De qué color es el tomate?\nB: El tomate es rojo.",exampleEn:"A: What color is the tomato?\nB: The tomato is red.",note:"Rojo = red (masc). Roja = red (fem). Changes for gender."},
{type:"teach",kind:"word",nl:"azul",en:"blue",phonetic:"a-SOOL",example:"A: ¿De qué color es el cielo?\nB: El cielo es azul.",exampleEn:"A: What color is the sky?\nB: The sky is blue.",note:"Azul = blue. Does NOT change for gender. Same for m/f."},
{type:"teach",kind:"word",nl:"verde",en:"green",phonetic:"VER-deh",example:"A: ¿De qué color es la hierba?\nB: La hierba es verde.",exampleEn:"A: What color is the grass?\nB: The grass is green.",note:"Verde = green. Ends in -e, same for masculine and feminine."},
{type:"teach",kind:"word",nl:"amarillo",en:"yellow (masculine)",phonetic:"a-ma-REE-yo",example:"A: ¿De qué color es el sol?\nB: El sol es amarillo.",exampleEn:"A: What color is the sun?\nB: The sun is yellow.",note:"Amarillo = yellow (masc). Amarilla = yellow (fem)."},
{type:"teach",kind:"word",nl:"blanco",en:"white (masculine)",phonetic:"BLAN-ko",example:"A: ¿De qué color es la nieve?\nB: La nieve es blanca.",exampleEn:"A: What color is the snow?\nB: The snow is white.",note:"Blanco = white (masc). Blanca = white (fem)."},
{type:"teach",kind:"word",nl:"negro",en:"black (masculine)",phonetic:"NEH-gro",example:"A: ¿De qué color es tu gato?\nB: Mi gato es negro.",exampleEn:"A: What color is your cat?\nB: My cat is black.",note:"Negro = black (masc). Negra = black (fem)."},
{type:"tip",title:"Color Gender Rules",text:"Colors ending in -o change for gender:\nrojo/roja, blanco/blanca, negro/negra, amarillo/amarilla.\n\nColors ending in -e or consonant do NOT change:\nverde, azul, marrón, gris, naranja.\n\nAll colors add -s or -es for plural.",icon:"🎨"},
{type:"teach",kind:"word",nl:"gris",en:"gray",phonetic:"GREES",example:"A: ¿De qué color es el elefante?\nB: El elefante es gris.",exampleEn:"A: What color is the elephant?\nB: The elephant is gray.",note:"Gris = gray. Same for masculine and feminine."},
{type:"mc",q:"'La casa es blanca' uses 'blanca' because:",opts:["Casa is feminine","Casa is big","Blanco sounds wrong","It is always blanca"],ans:"Casa is feminine",hint:"The -a ending on the color matches the feminine noun."},
{type:"mc",q:"Which color does NOT change for gender?",opts:["rojo","azul","blanco","amarillo"],ans:"azul",hint:"Colors ending in a consonant stay the same."},
{type:"fb",s:"El cielo es {1}.",a:"azul",opts:["azul","rojo","verde","blanco"],hint:"The color you see when you look up on a clear day."},
{type:"mc",q:"How do you say 'the red car' if coche is masculine?",opts:["el coche roja","el coche rojo","la coche rojo","el coche rojos"],ans:"el coche rojo",hint:"Masculine noun needs masculine adjective: -o ending."},
{type:"match",pairs:[{nl:"rojo",en:"red"},{nl:"azul",en:"blue"},{nl:"verde",en:"green"},{nl:"amarillo",en:"yellow"},{nl:"blanco",en:"white"},{nl:"negro",en:"black"}]},
{type:"fb",s:"La mesa es {1}.",a:"blanca",opts:["blanca","blanco","blancos","blancas"],hint:"Mesa is feminine singular. Match the color ending."},
{type:"mc",q:"The plural of 'azul' is:",opts:["azules","azuls","azulo","azula"],ans:"azules",hint:"Colors ending in consonant add -es for plural."},
{type:"mc",q:"What color is 'amarilla'?",opts:["Yellow (feminine)","Orange (feminine)","Green (feminine)","Gold (feminine)"],ans:"Yellow (feminine)",hint:"The -a ending marks it as feminine of amarillo."},
{type:"fb",s:"Los gatos son {1}.",a:"negros",opts:["negros","negro","negras","negra"],hint:"Masculine plural cats need the masculine plural color."},
]},
// ===== L6: More Colors & Descriptions =====
{id:"esp3l6",title:"Más Colores",icon:"🖌️",xp:15,board:true,steps:[
{type:"intro",title:"Más Colores",desc:"Learn more colors and describe objects around you.",goals:["Learn naranja, rosa, morado, marrón","Describe everyday objects","Combine colors with nouns"]},
{type:"teach",kind:"word",nl:"naranja",en:"orange (color)",phonetic:"na-RAN-ha",example:"A: ¿De qué color es la naranja?\nB: La naranja es naranja.",exampleEn:"A: What color is the orange?\nB: The orange is orange.",note:"Naranja = orange (color). Does NOT change for gender."},
{type:"teach",kind:"word",nl:"rosa",en:"pink",phonetic:"RRO-sa",example:"A: ¿De qué color es la flor?\nB: La flor es rosa.",exampleEn:"A: What color is the flower?\nB: The flower is pink.",note:"Rosa = pink. Does NOT change for gender. Also means 'rose' (the flower)."},
{type:"teach",kind:"word",nl:"morado",en:"purple (masculine)",phonetic:"mo-RA-do",example:"A: ¿De qué color es la uva?\nB: La uva es morada.",exampleEn:"A: What color is the grape?\nB: The grape is purple.",note:"Morado = purple (masc). Morada = purple (fem)."},
{type:"teach",kind:"word",nl:"marrón",en:"brown",phonetic:"ma-RRON",example:"A: ¿De qué color es el chocolate?\nB: El chocolate es marrón.",exampleEn:"A: What color is the chocolate?\nB: The chocolate is brown.",note:"Marrón = brown. Same for masculine and feminine."},
{type:"teach",kind:"phrase",nl:"¿De qué color es?",en:"What color is it?",phonetic:"deh KEH ko-LOR ES",example:"A: ¿De qué color es tu coche?\nB: Mi coche es gris.",exampleEn:"A: What color is your car?\nB: My car is gray.",note:"Literally: Of what color is? Standard way to ask about color."},
{type:"teach",kind:"word",nl:"el libro",en:"the book",phonetic:"el LEE-bro",example:"A: ¿De qué color es el libro?\nB: El libro es azul.",exampleEn:"A: What color is the book?\nB: The book is blue.",note:"El libro = the book. Masculine noun."},
{type:"teach",kind:"word",nl:"la flor",en:"the flower",phonetic:"la FLOR",example:"A: ¿De qué color es la flor?\nB: La flor es roja.",exampleEn:"A: What color is the flower?\nB: The flower is red.",note:"La flor = the flower. Feminine noun."},
{type:"mc",q:"'Naranja' as a color is:",opts:["Same for masculine and feminine","Different: naranjo/naranja","Only for fruit","Only for feminine nouns"],ans:"Same for masculine and feminine",hint:"This color does not change its ending."},
{type:"mc",q:"The feminine of 'morado' is:",opts:["morada","morado","moradas","moroda"],ans:"morada",hint:"Colors ending in -o switch to -a for feminine."},
{type:"fb",s:"La uva es {1}.",a:"morada",opts:["morada","morado","rosa","naranja"],hint:"Grapes are typically this color, and uva is feminine."},
{type:"mc",q:"Which colors do NOT change for gender?",opts:["Rojo and blanco","Azul and verde","Amarillo and negro","Blanco and negro"],ans:"Azul and verde",hint:"Colors ending in -e or a consonant stay the same."},
{type:"match",pairs:[{nl:"naranja",en:"orange"},{nl:"rosa",en:"pink"},{nl:"morado/a",en:"purple"},{nl:"marrón",en:"brown"},{nl:"gris",en:"gray"}]},
{type:"fb",s:"¿De qué {1} es tu casa?",a:"color",opts:["color","día","nombre","año"],hint:"You are asking about the visual appearance."},
{type:"mc",q:"'El libro rojo' means:",opts:["The red book","The red flower","The big book","The open book"],ans:"The red book",hint:"Libro = book, and the color follows the noun."},
{type:"fb",s:"Las flores son {1}.",a:"rosas",opts:["rosas","rosa","rojas","rojo"],hint:"Pink flowers, feminine plural. This color adds -s for plural."},
{type:"mc",q:"How do you say 'the brown table'?",opts:["la mesa marrón","la mesa marrona","el mesa marrón","la mesa marrono"],ans:"la mesa marrón",hint:"Marrón does not change for gender."},
{type:"fb",s:"El cielo es {1}.",a:"azul",opts:["azul","verde","rojo","negro"],hint:"The sky shares its color with the sea on a clear day."},
]},
// ===== L7: Time Expressions =====
{id:"esp3l7",title:"¿Qué Hora Es?",icon:"🕐",xp:15,board:true,steps:[
{type:"intro",title:"¿Qué Hora Es?",desc:"Learn to tell time and use basic time expressions.",goals:["Ask and tell the time","Use es la / son las","Know morning, afternoon, night expressions"]},
{type:"teach",kind:"phrase",nl:"¿Qué hora es?",en:"What time is it?",phonetic:"keh OH-ra ES",example:"A: Perdón, ¿qué hora es?\nB: Son las tres.",exampleEn:"A: Excuse me, what time is it?\nB: It's three o'clock.",note:"Standard way to ask the time. Hora = hour."},
{type:"teach",kind:"phrase",nl:"Es la una",en:"It's one o'clock",phonetic:"es la OO-na",example:"A: ¿Qué hora es?\nB: Es la una.",exampleEn:"A: What time is it?\nB: It's one o'clock.",note:"ONLY 1:00 uses 'es la' (singular). All other hours use 'son las'."},
{type:"teach",kind:"phrase",nl:"Son las dos",en:"It's two o'clock",phonetic:"son las DOS",example:"A: ¿Qué hora es?\nB: Son las dos.",exampleEn:"A: What time is it?\nB: It's two o'clock.",note:"Son las + number for all hours except 1:00. Son las tres, son las cuatro..."},
{type:"teach",kind:"phrase",nl:"y media",en:"and a half (thirty)",phonetic:"ee MEH-dya",example:"A: ¿Qué hora es?\nB: Son las tres y media.",exampleEn:"A: What time is it?\nB: It's three thirty.",note:"Y media = :30. Son las cinco y media = 5:30."},
{type:"teach",kind:"phrase",nl:"y cuarto",en:"and a quarter (fifteen)",phonetic:"ee KWAR-to",example:"A: ¿Qué hora es?\nB: Son las dos y cuarto.",exampleEn:"A: What time is it?\nB: It's two fifteen.",note:"Y cuarto = :15. Son las siete y cuarto = 7:15."},
{type:"teach",kind:"phrase",nl:"de la mañana",en:"in the morning (AM)",phonetic:"deh la ma-NYAH-na",example:"A: ¿A qué hora es la clase?\nB: A las ocho de la mañana.",exampleEn:"A: What time is the class?\nB: At eight in the morning.",note:"De la mañana = AM. De la tarde = PM (afternoon). De la noche = PM (night)."},
{type:"tip",title:"Time Summary",text:"1:00: Es la una.\nAll others: Son las + number.\nAdd minutes: y cinco, y diez, y veinte.\n:15 = y cuarto. :30 = y media.\nAM = de la mañana.\nPM (day) = de la tarde.\nPM (night) = de la noche.",icon:"🕐"},
{type:"mc",q:"'Son las cinco' means:",opts:["It's five o'clock","It's one o'clock","I have five","There are five"],ans:"It's five o'clock",hint:"Son las + number tells the time."},
{type:"mc",q:"Why does 1:00 use 'es la una' instead of 'son las'?",opts:["Una is singular, so the verb is singular too","It is an exception","Una is special","Es sounds better"],ans:"Una is singular, so the verb is singular too",hint:"One hour = singular. Two+ hours = plural."},
{type:"fb",s:"{1} las tres y media.",a:"Son",opts:["Son","Es","Soy","Hay"],hint:"Plural verb for hours above one."},
{type:"mc",q:"3:15 in Spanish is:",opts:["Son las tres y cuarto","Son las tres y media","Es la tres y cuarto","Son las tres y quince"],ans:"Son las tres y cuarto",hint:"Quarter past uses the word for 'quarter'."},
{type:"fb",s:"Son las ocho de la {1}.",a:"mañana",opts:["mañana","tarde","noche","media"],hint:"8 o'clock in the morning, not evening."},
{type:"match",pairs:[{nl:"Es la una",en:"It's 1:00"},{nl:"Son las dos",en:"It's 2:00"},{nl:"y media",en:":30"},{nl:"y cuarto",en:":15"},{nl:"de la mañana",en:"AM"}]},
{type:"mc",q:"How do you say 9:30 PM?",opts:["Son las nueve y media de la noche","Es la nueve y media","Son las nueve y cuarto","Son las nueve de la mañana"],ans:"Son las nueve y media de la noche",hint:"9 PM uses the night time expression."},
{type:"fb",s:"¿A qué {1} es la clase?",a:"hora",opts:["hora","día","color","tiempo"],hint:"You are asking about the time of the class."},
{type:"mc",q:"6:00 PM would be said with:",opts:["de la mañana","de la tarde","de la noche","de la hora"],ans:"de la tarde",hint:"6 PM is still afternoon, before night falls."},
{type:"fb",s:"Son las tres y {1}.",a:"cuarto",opts:["cuarto","media","cinco","diez"],hint:"This word means 'quarter' and represents :15."},
]},
// ===== L8: Review & Practice =====
{id:"esp3l8",title:"¡Todo Junto!",icon:"🧩",xp:20,board:true,steps:[
{type:"intro",title:"¡Todo Junto!",desc:"Combine numbers, days, months, colors, and time in real conversations.",goals:["Use numbers in context","Talk about schedules with days and times","Describe objects with colors"]},
{type:"mc",q:"How do you say 47?",opts:["cuarenta y siete","cuarentasiete","cuatro y siete","cuarenta siete"],ans:"cuarenta y siete",hint:"Tens + y + ones for numbers 31 and above."},
{type:"fb",s:"Mi cumpleaños es el {1} de marzo.",a:"quince",opts:["quince","marzo","lunes","color"],hint:"A number for the date, between 'el' and 'de'."},
{type:"mc",q:"What day comes after miércoles?",opts:["martes","jueves","viernes","lunes"],ans:"jueves",hint:"The day named after Jupiter, in the middle of the work week."},
{type:"match",pairs:[{nl:"enero",en:"January"},{nl:"mayo",en:"May"},{nl:"agosto",en:"August"},{nl:"octubre",en:"October"},{nl:"diciembre",en:"December"}]},
{type:"fb",s:"La clase es los {1} a las diez.",a:"martes",opts:["martes","enero","rojo","diez"],hint:"A day of the week, plural because it repeats weekly."},
{type:"mc",q:"'Son las siete y cuarto de la mañana' means:",opts:["It's 7:15 AM","It's 7:30 AM","It's 7:45 AM","It's 7:00 AM"],ans:"It's 7:15 AM",hint:"Cuarto = quarter = 15 minutes."},
{type:"fb",s:"La flor es {1} y amarilla.",a:"roja",opts:["roja","rojo","rojos","rojas"],hint:"Flor is feminine singular. Match the color."},
{type:"mc",q:"'Hoy es el primero de enero' means:",opts:["Today is January first","Today is the first Monday","Today is in January","Today is the beginning"],ans:"Today is January first",hint:"Primero = first. Only the 1st of the month uses an ordinal."},
{type:"drag_fill",s:"La clase es el {1} a las {2} de la {3}.",blanks:{1:"lunes",2:"tres",3:"tarde"},pool:["lunes","tres","tarde","martes","dos","mañana"],hint:"Complete the schedule: day + time + time of day."},
{type:"mc",q:"How many days are in 'febrero'?",opts:["28 (usually)","30","31","29"],ans:"28 (usually)",hint:"The shortest month of the year."},
{type:"match",pairs:[{nl:"rojo",en:"red"},{nl:"azul",en:"blue"},{nl:"verde",en:"green"},{nl:"blanco",en:"white"},{nl:"morado",en:"purple"},{nl:"gris",en:"gray"}]},
{type:"fb",s:"Son las {1} y media de la noche.",a:"once",opts:["once","tres","ocho","una"],hint:"11:30 PM. A number between diez and doce."},
{type:"mc",q:"'El coche azul' uses 'azul' (not 'azulo') because:",opts:["Azul never changes for gender","Coche is neutral","Blue is special","It is informal"],ans:"Azul never changes for gender",hint:"Colors ending in consonant or -e are invariable."},
{type:"mc",q:"Complete: 'Mi padre tiene ___ años.'",opts:["cuarenta y cinco","cuarenta cinco","cuarentacinco","cuarenta con cinco"],ans:"cuarenta y cinco",hint:"From 31 onward, tens and ones connect with 'y'."},
{type:"drag_fill",s:"Hoy es {1}, el {2} de {3}.",blanks:{1:"jueves",2:"veinte",3:"septiembre"},pool:["jueves","veinte","septiembre","lunes","quince","marzo"],hint:"Complete: day of week + date + month."},
{type:"fb",s:"¿De qué {1} es tu coche?",a:"color",opts:["color","hora","día","nombre"],hint:"Asking about the visual appearance of the car."},
{type:"mc",q:"Which is correct for 1:30 PM?",opts:["Es la una y media de la tarde","Son las una y media","Es la una y cuarto","Son la una y media"],ans:"Es la una y media de la tarde",hint:"1:00 is singular: es la una. Plus y media for :30."},
]}
]},
// ══════════════════════════════════════════════════════════════
// UNIT 4: ¡A Comer! — Food & Drink (A1.2)
// 8 lessons, 18+ steps each
// ══════════════════════════════════════════════════════════════
{n:4,lang:"es",track:"v1",title:"¡A Comer!",sub:"Food & Drink",icon:"🍽️",level:"A1.2",color:"#7B5EE8",lessons:[
// ===== L1: Basic Foods =====
{id:"esp4l1",title:"Comida Básica",icon:"🍞",xp:15,board:true,steps:[
{type:"intro",title:"Comida Básica",desc:"Learn the essential food words you will need every day in Spanish.",goals:["Name basic foods in Spanish","Use el/la correctly with food nouns","Understand the special case of el agua"]},
{type:"teach",kind:"word",nl:"la manzana",en:"the apple",phonetic:"man-SAH-nah",example:"A: ¿Te gustan las manzanas?\nB: Sí, me gustan mucho.",exampleEn:"A: Do you like apples?\nB: Yes, I like them a lot.",note:"Feminine noun. Plural: las manzanas."},
{type:"teach",kind:"word",nl:"el plátano",en:"the banana",phonetic:"PLAH-tah-noh",example:"A: ¿Quieres un plátano?\nB: Sí, por favor.",exampleEn:"A: Do you want a banana?\nB: Yes, please.",note:"Masculine noun. Also called 'la banana' in some countries."},
{type:"teach",kind:"word",nl:"la naranja",en:"the orange",phonetic:"nah-RAHN-hah",example:"A: ¿De qué color es la naranja?\nB: La naranja es naranja.",exampleEn:"A: What color is the orange?\nB: The orange is orange.",note:"Feminine. The fruit and the color share the same word."},
{type:"teach",kind:"word",nl:"la fresa",en:"the strawberry",phonetic:"FREH-sah",example:"A: ¿Qué fruta te gusta más?\nB: Me gustan las fresas.",exampleEn:"A: What fruit do you like most?\nB: I like strawberries.",note:"Feminine. Plural: las fresas."},
{type:"teach",kind:"word",nl:"la uva",en:"the grape",phonetic:"OO-bah",example:"A: ¿Quieres uvas?\nB: No, gracias. No me gustan las uvas.",exampleEn:"A: Do you want grapes?\nB: No, thanks. I don't like grapes.",note:"Feminine. Almost always used in plural: las uvas."},
{type:"teach",kind:"word",nl:"el limón",en:"the lemon / lime",phonetic:"lee-MOHN",example:"A: ¿Tienes limones?\nB: Sí, tengo tres limones.",exampleEn:"A: Do you have lemons?\nB: Yes, I have three lemons.",note:"Masculine. In most of Latin America, limón refers to lime."},
{type:"tip",title:"Me gusta vs Me gustan",text:"Me gusta + singular noun:\nMe gusta la manzana.\n\nMe gustan + plural noun:\nMe gustan las fresas.\n\nThe verb agrees with what you LIKE, not with you.",icon:"💡"},
{type:"mc",q:"How do you say 'I like strawberries'?",opts:["Me gustan las fresas","Me gusta las fresas","Yo gusto las fresas","Me gusta la fresa"],ans:"Me gustan las fresas",hint:"Fresas is plural, so the verb must match."},
{type:"fb",s:"¿Te {1} las naranjas?",a:"gustan",opts:["gustan","gusta","gusto","gustas"],hint:"Naranjas is plural. The verb agrees with what is liked."},
{type:"mc",q:"What is 'el plátano'?",opts:["the banana","the apple","the orange","the grape"],ans:"the banana",hint:"This yellow fruit is popular in tropical countries."},
{type:"match",pairs:[{nl:"la manzana",en:"apple"},{nl:"el plátano",en:"banana"},{nl:"la naranja",en:"orange"},{nl:"la fresa",en:"strawberry"},{nl:"la uva",en:"grape"}]},
{type:"fb",s:"No me {1} el limón.",a:"gusta",opts:["gusta","gustan","gusto","gustas"],hint:"Limón is singular. The verb agrees with the thing liked."},
{type:"mc",q:"Which fruit is feminine?",opts:["la fresa","el plátano","el limón","el durazno"],ans:"la fresa",hint:"Look for the article 'la' before the noun."},
{type:"drag_fill",s:"A mí me {1} las {2} pero no me {3} el {4}.",blanks:{1:"gustan",2:"uvas",3:"gusta",4:"limón"},pool:["gustan","uvas","gusta","limón","manzana","gustas"],hint:"Plural fruit uses gustan. Singular fruit uses gusta."},
{type:"mc",q:"'La naranja es naranja' means:",opts:["The orange is orange","The orange is red","I like oranges","The orange is sweet"],ans:"The orange is orange",hint:"The same word names both the fruit and its color."},
{type:"fb",s:"Me {1} mucho la manzana.",a:"gusta",opts:["gusta","gustan","gusto","gustas"],hint:"Manzana is singular, so the verb takes singular form."},
{type:"mc",q:"How do you say 'I don't like grapes'?",opts:["No me gustan las uvas","No me gusta las uvas","Me no gustan las uvas","No gusto las uvas"],ans:"No me gustan las uvas",hint:"Put 'no' before 'me gustan'. Uvas is plural."},
]},
{id:"esp4l2",title:"Las Verduras",icon:"🥦",xp:15,board:true,steps:[
{type:"intro",title:"Las Verduras",desc:"Learn vegetables and practice talking about food preferences.",goals:["Name 6 common vegetables","Use querer (to want)","Express food preferences"]},
{type:"teach",kind:"word",nl:"la verdura",en:"the vegetable",phonetic:"ber-DOO-rah",example:"A: ¿Te gustan las verduras?\nB: Sí, como verduras todos los días.",exampleEn:"A: Do you like vegetables?\nB: Yes, I eat vegetables every day.",note:"Feminine. General term for all vegetables."},
{type:"teach",kind:"word",nl:"el tomate",en:"the tomato",phonetic:"toh-MAH-teh",example:"A: ¿Quieres tomate en la ensalada?\nB: Sí, me gusta el tomate.",exampleEn:"A: Do you want tomato in the salad?\nB: Yes, I like tomato.",note:"Masculine. Key ingredient in Spanish cooking."},
{type:"teach",kind:"word",nl:"la lechuga",en:"the lettuce",phonetic:"leh-CHOO-gah",example:"A: ¿Qué necesitamos para la ensalada?\nB: Necesitamos lechuga y tomate.",exampleEn:"A: What do we need for the salad?\nB: We need lettuce and tomato.",note:"Feminine. Base of most salads."},
{type:"teach",kind:"word",nl:"la cebolla",en:"the onion",phonetic:"seh-BOH-yah",example:"A: ¿Te gusta la cebolla?\nB: No mucho. Me hace llorar.",exampleEn:"A: Do you like onion?\nB: Not much. It makes me cry.",note:"Feminine. The 'll' sounds like 'y' in most dialects."},
{type:"teach",kind:"word",nl:"el ajo",en:"the garlic",phonetic:"AH-hoh",example:"A: ¿Cuánto ajo pongo?\nB: Pon mucho ajo, por favor.",exampleEn:"A: How much garlic should I put?\nB: Put a lot of garlic, please.",note:"Masculine. Essential in Spanish and Latin American cooking."},
{type:"teach",kind:"word",nl:"la patata",en:"the potato",phonetic:"pah-TAH-tah",example:"A: ¿Quieres patatas fritas?\nB: ¡Sí! Me encantan las patatas fritas.",exampleEn:"A: Do you want french fries?\nB: Yes! I love french fries.",note:"Feminine. In Latin America: la papa."},
{type:"teach",kind:"phrase",nl:"quiero",en:"I want",phonetic:"kee-EH-roh",example:"A: ¿Qué quieres comer?\nB: Quiero una ensalada, por favor.",exampleEn:"A: What do you want to eat?\nB: I want a salad, please.",note:"From querer. Stem changes: quiero, quieres, quiere, queremos, quieren."},
{type:"tip",title:"Querer: A Stem-Changing Verb",text:"Querer (to want) changes e to ie in most forms:\nyo quiero\ntú quieres\nél/ella quiere\nnosotros queremos (no change!)\nellos quieren\n\nThis e→ie pattern is very common in Spanish.",icon:"📝"},
{type:"mc",q:"What is 'la cebolla'?",opts:["the onion","the garlic","the potato","the tomato"],ans:"the onion",hint:"This vegetable can make you cry when you cut it."},
{type:"fb",s:"Yo {1} una ensalada de tomate.",a:"quiero",opts:["quiero","quieres","quiere","queremos"],hint:"The subject is 'yo'. Find the matching form of querer."},
{type:"match",pairs:[{nl:"el tomate",en:"tomato"},{nl:"la lechuga",en:"lettuce"},{nl:"la cebolla",en:"onion"},{nl:"el ajo",en:"garlic"},{nl:"la patata",en:"potato"}]},
{type:"mc",q:"Which form completes: 'Ella ___ patatas fritas.'?",opts:["quiere","quiero","quieres","queremos"],ans:"quiere",hint:"Ella is third person singular. The stem changes e to ie."},
{type:"fb",s:"¿Te {1} las verduras?",a:"gustan",opts:["gustan","gusta","gusto","gustas"],hint:"Verduras is plural. The verb agrees with what is liked."},
{type:"mc",q:"In Latin America, 'la patata' is called:",opts:["la papa","la batata","el patato","la papata"],ans:"la papa",hint:"A shorter word used across Latin America for potato."},
{type:"drag_fill",s:"{1} una ensalada con {2} y {3}.",blanks:{1:"Quiero",2:"lechuga",3:"tomate"},pool:["Quiero","lechuga","tomate","quieres","cebolla","patata"],hint:"'I want' + salad ingredients from the lesson."},
{type:"fb",s:"El {1} es muy importante en la cocina española.",a:"ajo",opts:["ajo","uva","fresa","limón"],hint:"This small but strong ingredient is essential in Spanish cooking."},
{type:"mc",q:"'Nosotros queremos' means:",opts:["we want","they want","you want","I want"],ans:"we want",hint:"Nosotros is 'we'. Note: no stem change in this form."},
]},
{id:"esp4l3",title:"Las Bebidas",icon:"🥤",xp:15,board:true,steps:[
{type:"intro",title:"Las Bebidas",desc:"Learn drinks and how to order at a café.",goals:["Name 6 common drinks","Order a drink politely","Use 'un/una' with drinks"]},
{type:"teach",kind:"word",nl:"el agua",en:"the water",phonetic:"AH-gwah",example:"A: ¿Qué quieres beber?\nB: Quiero un vaso de agua, por favor.",exampleEn:"A: What do you want to drink?\nB: I want a glass of water, please.",note:"Feminine meaning but uses 'el' (el agua) to avoid 'la a-' clash. Plural: las aguas."},
{type:"teach",kind:"word",nl:"el café",en:"the coffee",phonetic:"kah-FEH",example:"A: ¿Tomas café por la mañana?\nB: Sí, siempre tomo café con leche.",exampleEn:"A: Do you have coffee in the morning?\nB: Yes, I always have coffee with milk.",note:"Masculine. Café con leche = coffee with milk. Very common in Spain."},
{type:"teach",kind:"word",nl:"el té",en:"the tea",phonetic:"TEH",example:"A: ¿Quieres té o café?\nB: Prefiero té, gracias.",exampleEn:"A: Do you want tea or coffee?\nB: I prefer tea, thanks.",note:"Masculine. Written with accent: té (without accent, 'te' means 'you')."},
{type:"teach",kind:"word",nl:"la leche",en:"the milk",phonetic:"LEH-cheh",example:"A: ¿Hay leche en la nevera?\nB: No, necesitamos comprar leche.",exampleEn:"A: Is there milk in the fridge?\nB: No, we need to buy milk.",note:"Feminine. Very common in café con leche and desserts."},
{type:"teach",kind:"word",nl:"el zumo",en:"the juice",phonetic:"THOO-moh",example:"A: ¿Quieres un zumo de naranja?\nB: Sí, me encanta el zumo de naranja.",exampleEn:"A: Do you want an orange juice?\nB: Yes, I love orange juice.",note:"Masculine. In Latin America: el jugo."},
{type:"teach",kind:"word",nl:"la cerveza",en:"the beer",phonetic:"ser-BEH-sah",example:"A: ¿Tomamos una cerveza?\nB: ¡Buena idea! Una cerveza, por favor.",exampleEn:"A: Shall we have a beer?\nB: Good idea! A beer, please.",note:"Feminine. C before e = 's' sound in Latin America, 'th' in Spain."},
{type:"tip",title:"Ordering Drinks",text:"To order:\nUn café, por favor. (masc)\nUna cerveza, por favor. (fem)\n\nUn/una = a/an.\nUn before masculine nouns.\nUna before feminine nouns.\n\n¿Me pone...? = Could you give me...? (polite, Spain)",icon:"☕"},
{type:"mc",q:"Why do we say 'el agua' instead of 'la agua'?",opts:["To avoid two 'a' sounds together","Because agua is masculine","Because all drinks use el","It's a grammar exception with no rule"],ans:"To avoid two 'a' sounds together",hint:"Spanish avoids la + a- at the start of a word."},
{type:"fb",s:"Quiero {1} café con leche.",a:"un",opts:["un","una","el","la"],hint:"Café is masculine. Use the masculine indefinite article."},
{type:"match",pairs:[{nl:"el agua",en:"water"},{nl:"el café",en:"coffee"},{nl:"el té",en:"tea"},{nl:"la leche",en:"milk"},{nl:"la cerveza",en:"beer"}]},
{type:"mc",q:"How do you order a beer politely?",opts:["Una cerveza, por favor","Un cerveza, por favor","La cerveza, por favor","Cerveza me da"],ans:"Una cerveza, por favor",hint:"Cerveza is feminine. Use 'una' and add 'por favor'."},
{type:"fb",s:"¿Quieres {1} de naranja?",a:"zumo",opts:["zumo","agua","leche","cerveza"],hint:"The orange version of this drink is a breakfast staple."},
{type:"mc",q:"In Latin America, 'el zumo' is called:",opts:["el jugo","el sumo","la zuma","el zugo"],ans:"el jugo",hint:"A different word for juice used across Latin America."},
{type:"drag_fill",s:"Para mí, {1} café con {2}, por {3}.",blanks:{1:"un",2:"leche",3:"favor"},pool:["un","leche","favor","una","agua","gracias"],hint:"Order coffee (masc) with milk, politely."},
{type:"fb",s:"¿Hay {1} en la nevera?",a:"leche",opts:["leche","café","zumo","té"],hint:"This white drink is kept cold in the fridge."},
{type:"mc",q:"Which drink is feminine?",opts:["la cerveza","el café","el té","el zumo"],ans:"la cerveza",hint:"Look for the article 'la' before the noun."},
{type:"mc",q:"How do you say 'I want tea, please'?",opts:["Quiero té, por favor","Quiero el té, por favor","Yo quiere té","Me gusta té, por favor"],ans:"Quiero té, por favor",hint:"Use quiero + the drink name. No article needed when ordering."},
]},
{id:"esp4l4",title:"La Comida",icon:"🍲",xp:15,board:true,steps:[
{type:"intro",title:"La Comida",desc:"Learn basic meal foods and express hunger and thirst.",goals:["Name common meal foods","Use tener hambre / tener sed","Talk about meals of the day"]},
{type:"teach",kind:"word",nl:"el pan",en:"the bread",phonetic:"PAHN",example:"A: ¿Quieres pan con mantequilla?\nB: Sí, me gusta el pan fresco.",exampleEn:"A: Do you want bread with butter?\nB: Yes, I like fresh bread.",note:"Masculine. A staple at every Spanish meal."},
{type:"teach",kind:"word",nl:"el arroz",en:"the rice",phonetic:"ah-RROHS",example:"A: ¿Qué comes con el pollo?\nB: Como arroz con pollo.",exampleEn:"A: What do you eat with chicken?\nB: I eat rice with chicken.",note:"Masculine. Base of paella and many Latin American dishes."},
{type:"teach",kind:"word",nl:"el pollo",en:"the chicken",phonetic:"POH-yoh",example:"A: ¿Te gusta el pollo?\nB: Sí, como pollo casi todos los días.",exampleEn:"A: Do you like chicken?\nB: Yes, I eat chicken almost every day.",note:"Masculine. The 'll' sounds like 'y'."},
{type:"teach",kind:"word",nl:"el pescado",en:"the fish (food)",phonetic:"pes-KAH-doh",example:"A: ¿Prefieres carne o pescado?\nB: Prefiero el pescado.",exampleEn:"A: Do you prefer meat or fish?\nB: I prefer fish.",note:"Masculine. El pez = live fish. El pescado = fish as food."},
{type:"teach",kind:"word",nl:"la carne",en:"the meat",phonetic:"KAR-neh",example:"A: ¿Comes carne?\nB: No, soy vegetariano.",exampleEn:"A: Do you eat meat?\nB: No, I'm vegetarian.",note:"Feminine. General term for all meat."},
{type:"teach",kind:"phrase",nl:"tener hambre",en:"to be hungry",phonetic:"teh-NER AHM-breh",example:"A: ¿Tienes hambre?\nB: Sí, tengo mucha hambre.",exampleEn:"A: Are you hungry?\nB: Yes, I'm very hungry.",note:"Literally 'to have hunger'. Spanish uses tener, not ser/estar."},
{type:"teach",kind:"phrase",nl:"tener sed",en:"to be thirsty",phonetic:"teh-NER SED",example:"A: Tengo sed. ¿Hay agua?\nB: Sí, hay agua en la nevera.",exampleEn:"A: I'm thirsty. Is there water?\nB: Yes, there's water in the fridge.",note:"Literally 'to have thirst'. Use mucha sed for 'very thirsty'."},
{type:"tip",title:"Tener Expressions",text:"Spanish uses 'tener' (to have) where English uses 'to be':\ntener hambre = to be hungry\ntener sed = to be thirsty\ntener frío = to be cold\ntener calor = to be hot\ntener sueño = to be sleepy\n\nUse mucho/mucha for 'very':\nTengo mucha hambre. (hambre is feminine)",icon:"💡"},
{type:"mc",q:"How do you say 'I'm hungry' in Spanish?",opts:["Tengo hambre","Soy hambre","Estoy hambre","Tengo hambrito"],ans:"Tengo hambre",hint:"Spanish uses 'to have hunger', not 'to be hungry'."},
{type:"fb",s:"¿{1} sed? Hay agua en la nevera.",a:"Tienes",opts:["Tienes","Tengo","Tiene","Tenemos"],hint:"Asking 'you' (informal) if they have thirst."},
{type:"match",pairs:[{nl:"el pan",en:"bread"},{nl:"el arroz",en:"rice"},{nl:"el pollo",en:"chicken"},{nl:"la carne",en:"meat"},{nl:"el pescado",en:"fish"}]},
{type:"mc",q:"What is the difference between 'el pez' and 'el pescado'?",opts:["Pez is alive, pescado is food","Pez is big, pescado is small","Pez is sea fish, pescado is river fish","They are the same"],ans:"Pez is alive, pescado is food",hint:"One swims, the other is on your plate."},
{type:"fb",s:"Tengo mucha {1}. Quiero comer.",a:"hambre",opts:["hambre","sed","sueño","calor"],hint:"You want to eat, so you're feeling this."},
{type:"mc",q:"Which is correct: 'Tengo mucho hambre' or 'Tengo mucha hambre'?",opts:["Tengo mucha hambre","Tengo mucho hambre","Tengo muy hambre","Tengo hambre mucho"],ans:"Tengo mucha hambre",hint:"Hambre is a feminine noun, so use mucha."},
{type:"drag_fill",s:"Tengo {1}. Quiero {2} con {3}.",blanks:{1:"hambre",2:"arroz",3:"pollo"},pool:["hambre","arroz","pollo","sed","pan","carne"],hint:"Express hunger and name a classic rice dish."},
{type:"fb",s:"Como {1} casi todos los días.",a:"pollo",opts:["pollo","agua","leche","zumo"],hint:"This common protein sounds like POH-yoh."},
{type:"mc",q:"Translate: '¿Quieres pan con mantequilla?'",opts:["Do you want bread with butter?","Do you like bread and butter?","Is there bread with butter?","I want bread with butter"],ans:"Do you want bread with butter?",hint:"¿Quieres...? is asking if you want something."},
]},
{id:"esp4l5",title:"El Desayuno",icon:"🥐",xp:15,board:true,steps:[
{type:"intro",title:"El Desayuno",desc:"Learn breakfast foods and describe what you eat in the morning.",goals:["Name breakfast items","Use tomar/desayunar","Describe your breakfast"]},
{type:"teach",kind:"word",nl:"el desayuno",en:"the breakfast",phonetic:"deh-sah-YOO-noh",example:"A: ¿Qué tomas para el desayuno?\nB: Tomo café con tostadas.",exampleEn:"A: What do you have for breakfast?\nB: I have coffee with toast.",note:"Masculine. From des- (un-) + ayuno (fasting). Breaking the fast!"},
{type:"teach",kind:"word",nl:"la tostada",en:"the toast",phonetic:"tohs-TAH-dah",example:"A: ¿Quieres tostadas con tomate?\nB: Sí, con tomate y aceite de oliva.",exampleEn:"A: Do you want toast with tomato?\nB: Yes, with tomato and olive oil.",note:"Feminine. Tostadas con tomate is a classic Spanish breakfast."},
{type:"teach",kind:"word",nl:"el huevo",en:"the egg",phonetic:"WEH-boh",example:"A: ¿Cómo quieres los huevos?\nB: Quiero huevos revueltos, por favor.",exampleEn:"A: How do you want the eggs?\nB: I want scrambled eggs, please.",note:"Masculine. The H is silent. Plural: los huevos."},
{type:"teach",kind:"word",nl:"el cereal",en:"the cereal",phonetic:"seh-reh-AHL",example:"A: ¿Desayunas cereal?\nB: Sí, cereal con leche.",exampleEn:"A: Do you have cereal for breakfast?\nB: Yes, cereal with milk.",note:"Masculine. A cognate! Same meaning as in English."},
{type:"teach",kind:"word",nl:"la mermelada",en:"the jam / marmalade",phonetic:"mer-meh-LAH-dah",example:"A: ¿Hay mermelada de fresa?\nB: Sí, está en la mesa.",exampleEn:"A: Is there strawberry jam?\nB: Yes, it's on the table.",note:"Feminine. Cognate of English 'marmalade'."},
{type:"teach",kind:"phrase",nl:"desayunar",en:"to have breakfast",phonetic:"deh-sah-yoo-NAR",example:"A: ¿A qué hora desayunas?\nB: Desayuno a las ocho.",exampleEn:"A: What time do you have breakfast?\nB: I have breakfast at eight.",note:"Regular -ar verb: desayuno, desayunas, desayuna, desayunamos."},
{type:"tip",title:"Spanish Breakfast Culture",text:"Spanish breakfast is typically light:\nCafé con leche + tostadas (toast)\nOften with aceite de oliva y tomate.\n\nBigger breakfasts:\nChurros con chocolate (a treat!)\nBocadillo (sandwich on baguette)\n\nBreakfast is the smallest meal.\nLunch (la comida) is the main meal, eaten around 2-3 PM.",icon:"🇪🇸"},
{type:"mc",q:"What does 'desayuno' literally mean?",opts:["Breaking the fast","Morning food","First meal","Light eating"],ans:"Breaking the fast",hint:"Des- means 'un-' and ayuno means 'fasting'."},
{type:"fb",s:"¿Qué {1} para el desayuno?",a:"tomas",opts:["tomas","comes","quieres","bebes"],hint:"Asking what someone has/takes for breakfast."},
{type:"match",pairs:[{nl:"el desayuno",en:"breakfast"},{nl:"la tostada",en:"toast"},{nl:"el huevo",en:"egg"},{nl:"la mermelada",en:"jam"},{nl:"el cereal",en:"cereal"}]},
{type:"mc",q:"A typical Spanish breakfast includes:",opts:["Café con leche and tostadas","Eggs and bacon","Pancakes and syrup","Rice and beans"],ans:"Café con leche and tostadas",hint:"Spanish breakfast is light. Think coffee and bread."},
{type:"fb",s:"Desayuno a las {1}.",a:"ocho",opts:["ocho","pan","café","leche"],hint:"Fill in a time. Most people eat breakfast around this hour."},
{type:"mc",q:"Which is the main meal in Spain?",opts:["La comida (lunch)","El desayuno (breakfast)","La cena (dinner)","La merienda (snack)"],ans:"La comida (lunch)",hint:"Eaten around 2-3 PM, this is the biggest meal of the day."},
{type:"drag_fill",s:"Para el {1}, tomo {2} con {3} y tostadas con {4}.",blanks:{1:"desayuno",2:"café",3:"leche",4:"mermelada"},pool:["desayuno","café","leche","mermelada","cena","agua"],hint:"Describe a typical Spanish morning meal."},
{type:"fb",s:"¿Cómo quieres los {1}?",a:"huevos",opts:["huevos","café","pan","tostadas"],hint:"Asking how someone wants these oval breakfast items prepared."},
{type:"mc",q:"Translate: 'Quiero tostadas con tomate y aceite de oliva.'",opts:["I want toast with tomato and olive oil","I want toasted tomatoes with oil","I like toast with tomato sauce","I need bread with butter"],ans:"I want toast with tomato and olive oil",hint:"A classic Spanish breakfast. Tostada = toast."},
{type:"fb",s:"Yo {1} a las siete y media.",a:"desayuno",opts:["desayuno","desayunas","desayuna","desayunamos"],hint:"First person singular of desayunar."},
]},
{id:"esp4l6",title:"En el Restaurante",icon:"🍽️",xp:15,board:true,steps:[
{type:"intro",title:"En el Restaurante",desc:"Learn to order food, ask for the bill, and be polite at a restaurant.",goals:["Order food at a restaurant","Ask for the menu and the bill","Use me pone / me trae"]},
{type:"teach",kind:"phrase",nl:"la carta",en:"the menu",phonetic:"KAR-tah",example:"A: ¿Nos trae la carta, por favor?\nB: Sí, aquí tienen.",exampleEn:"A: Could you bring us the menu, please?\nB: Yes, here you go.",note:"Feminine. Also called 'el menú'. La carta is more common in Spain."},
{type:"teach",kind:"phrase",nl:"pedir",en:"to order / to ask for",phonetic:"peh-DEER",example:"A: ¿Estáis listos para pedir?\nB: Sí, yo quiero la paella.",exampleEn:"A: Are you ready to order?\nB: Yes, I want the paella.",note:"Stem-changing: pido, pides, pide, pedimos, piden (e→i)."},
{type:"teach",kind:"phrase",nl:"la cuenta",en:"the bill / check",phonetic:"KWEN-tah",example:"A: ¿Nos trae la cuenta, por favor?\nB: Ahora mismo.",exampleEn:"A: Could you bring us the bill, please?\nB: Right away.",note:"Feminine. In Spain, you must ask for the bill. They won't bring it automatically."},
{type:"teach",kind:"word",nl:"la ensalada",en:"the salad",phonetic:"en-sah-LAH-dah",example:"A: ¿Qué van a pedir?\nB: Una ensalada mixta para empezar.",exampleEn:"A: What are you going to order?\nB: A mixed salad to start.",note:"Feminine. Ensalada mixta is a common starter in Spain."},
{type:"teach",kind:"word",nl:"la sopa",en:"the soup",phonetic:"SOH-pah",example:"A: ¿Hay sopa del día?\nB: Sí, hoy tenemos sopa de verduras.",exampleEn:"A: Is there a soup of the day?\nB: Yes, today we have vegetable soup.",note:"Feminine. Gazpacho is a famous cold soup from Andalusia."},
{type:"teach",kind:"phrase",nl:"de primero / de segundo",en:"for the first course / second course",phonetic:"deh pree-MEH-roh / seh-GOON-doh",example:"A: ¿Qué quiere de primero?\nB: De primero, la sopa. De segundo, el pescado.",exampleEn:"A: What would you like for the first course?\nB: For the first course, soup. For second, fish.",note:"Spanish meals have courses: de primero (starter), de segundo (main), de postre (dessert)."},
{type:"tip",title:"Restaurant Phrases",text:"Useful phrases:\n¿Nos trae la carta? = Can you bring the menu?\n¿Me pone un...? = Can I have a...? (Spain)\nPara mí, el/la... = For me, the...\nDe primero / de segundo / de postre\n¿Nos trae la cuenta? = Can we have the bill?\n\nTipping in Spain: not expected but 5-10% is appreciated.",icon:"🍽️"},
{type:"mc",q:"How do you ask for the menu in Spain?",opts:["¿Nos trae la carta, por favor?","¿Dónde está el menú?","Quiero la carta","Dame la carta"],ans:"¿Nos trae la carta, por favor?",hint:"Use the polite form with 'nos trae' (could you bring us)."},
{type:"fb",s:"De {1}, quiero la sopa.",a:"primero",opts:["primero","segundo","postre","carta"],hint:"This word indicates the first course of a meal."},
{type:"match",pairs:[{nl:"la carta",en:"menu"},{nl:"la cuenta",en:"bill"},{nl:"la ensalada",en:"salad"},{nl:"la sopa",en:"soup"},{nl:"pedir",en:"to order"}]},
{type:"mc",q:"In Spain, what happens with the bill?",opts:["You must ask for it","It comes automatically","You pay at the counter","There is no tipping"],ans:"You must ask for it",hint:"Spanish restaurants wait until you request la cuenta."},
{type:"fb",s:"¿{1} listos para pedir?",a:"Estáis",opts:["Estáis","Somos","Tenemos","Queremos"],hint:"Asking 'are you (plural) ready?' uses estar, not ser."},
{type:"mc",q:"What is 'de segundo'?",opts:["the main course","the dessert","the starter","the drink"],ans:"the main course",hint:"Segundo means second. It's the second course after the starter."},
{type:"drag_fill",s:"De {1}, la {2}. De {3}, el {4}.",blanks:{1:"primero",2:"ensalada",3:"segundo",4:"pescado"},pool:["primero","ensalada","segundo","pescado","postre","sopa"],hint:"Order a starter salad and a fish main course."},
{type:"fb",s:"¿Nos trae la {1}, por favor?",a:"cuenta",opts:["cuenta","carta","sopa","ensalada"],hint:"You've finished eating and want to pay."},
{type:"mc",q:"Translate: 'Para mí, una ensalada mixta.'",opts:["For me, a mixed salad","I want a mixed salad","A salad for everyone","The mixed salad is good"],ans:"For me, a mixed salad",hint:"'Para mí' means 'for me'. A polite way to order."},
{type:"fb",s:"¿Hay sopa del {1}?",a:"día",opts:["día","menú","primero","noche"],hint:"Asking if there is a soup of the ___. A daily special."},
]},
{id:"esp4l7",title:"Los Sabores",icon:"😋",xp:15,board:true,steps:[
{type:"intro",title:"Los Sabores",desc:"Learn to describe food tastes and give opinions about meals.",goals:["Describe food flavors","Use está + adjective for food","Give opinions on dishes"]},
{type:"teach",kind:"word",nl:"dulce",en:"sweet",phonetic:"DOOL-seh",example:"A: ¿Cómo es el pastel?\nB: Está muy dulce. Me gusta.",exampleEn:"A: How is the cake?\nB: It's very sweet. I like it.",note:"Same form for masculine and feminine. El chocolate es dulce."},
{type:"teach",kind:"word",nl:"salado",en:"salty",phonetic:"sah-LAH-doh",example:"A: ¿Qué tal la sopa?\nB: Está un poco salada.",exampleEn:"A: How's the soup?\nB: It's a little salty.",note:"Masculine: salado. Feminine: salada. Agrees with the noun."},
{type:"teach",kind:"word",nl:"picante",en:"spicy / hot",phonetic:"pee-KAHN-teh",example:"A: ¿Te gusta la comida picante?\nB: No mucho. Prefiero la comida suave.",exampleEn:"A: Do you like spicy food?\nB: Not much. I prefer mild food.",note:"Same form for both genders. Very common in Mexican cuisine."},
{type:"teach",kind:"word",nl:"rico / delicioso",en:"delicious",phonetic:"RREE-koh / deh-lee-see-OH-soh",example:"A: ¿Qué tal la paella?\nB: ¡Está riquísima! Muy rica.",exampleEn:"A: How's the paella?\nB: It's delicious! Very tasty.",note:"Rico/rica is informal. Delicioso/a is more formal. Both mean delicious."},
{type:"teach",kind:"phrase",nl:"está bueno / malo",en:"it tastes good / bad",phonetic:"ehs-TAH BWEH-noh / MAH-loh",example:"A: ¿Está bueno el pescado?\nB: Sí, está muy bueno.",exampleEn:"A: Is the fish good?\nB: Yes, it's very good.",note:"Use ESTAR (not ser) for how food tastes right now. Está bueno = it tastes good."},
{type:"tip",title:"Ser vs Estar with Food",text:"SER = what it IS (permanent quality):\nLa paella es un plato español.\n(Paella is a Spanish dish.)\n\nESTAR = how it IS right now (condition/taste):\nLa paella está deliciosa.\n(The paella tastes delicious.)\n\nFor food opinions, almost always use ESTAR:\n¿Está bueno? ¿Está rico? ¿Está caliente?",icon:"📝"},
{type:"teach",kind:"word",nl:"caliente",en:"hot (temperature)",phonetic:"kah-lee-EN-teh",example:"A: ¡Cuidado! La sopa está muy caliente.\nB: Gracias. Espero un momento.",exampleEn:"A: Careful! The soup is very hot.\nB: Thanks. I'll wait a moment.",note:"Same for both genders. For spicy hot, use 'picante'."},
{type:"mc",q:"Which verb do you use to describe how food tastes?",opts:["estar","ser","tener","haber"],ans:"estar",hint:"Food taste is a current condition, not a permanent trait."},
{type:"fb",s:"La sopa {1} un poco salada.",a:"está",opts:["está","es","tiene","hay"],hint:"Describing how the soup tastes right now."},
{type:"match",pairs:[{nl:"dulce",en:"sweet"},{nl:"salado",en:"salty"},{nl:"picante",en:"spicy"},{nl:"caliente",en:"hot"},{nl:"rico",en:"delicious"}]},
{type:"mc",q:"'¡Está riquísima!' means:",opts:["It's absolutely delicious!","It's very expensive!","She is very rich!","It's extremely spicy!"],ans:"It's absolutely delicious!",hint:"Rico with food means delicious. The suffix -ísima means 'extremely'."},
{type:"fb",s:"¿Te gusta la comida {1}?",a:"picante",opts:["picante","caliente","dulce","salada"],hint:"Asking about spicy food, common in Mexican cuisine."},
{type:"mc",q:"Which sentence is correct?",opts:["La paella está deliciosa","La paella es deliciosa","La paella tiene deliciosa","La paella hay deliciosa"],ans:"La paella está deliciosa",hint:"How it tastes right now = estar. Ser also works for general quality, but estar is preferred."},
{type:"drag_fill",s:"La sopa {1} muy {2} pero el postre {3} demasiado {4}.",blanks:{1:"está",2:"rica",3:"está",4:"dulce"},pool:["está","rica","está","dulce","es","salada"],hint:"Both describe current taste. Use estar for both."},
{type:"fb",s:"¡Cuidado! El café {1} muy caliente.",a:"está",opts:["está","es","tiene","hay"],hint:"The coffee IS hot right now. Current state = estar."},
{type:"mc",q:"What is the difference between 'caliente' and 'picante'?",opts:["Caliente = temperature, picante = spicy flavor","Caliente = spicy, picante = temperature","They mean the same thing","Caliente = warm, picante = burning hot"],ans:"Caliente = temperature, picante = spicy flavor",hint:"One is about heat you feel, the other about heat you taste."},
{type:"fb",s:"El helado {1} muy dulce.",a:"está",opts:["está","es","tiene","hay"],hint:"Describing how the ice cream tastes right now."},
]},
{id:"esp4l8",title:"¿Qué Comemos?",icon:"🛒",xp:15,board:true,steps:[
{type:"intro",title:"¿Qué Comemos?",desc:"Put it all together: order meals, describe food, and express preferences.",goals:["Order a complete meal","Combine food vocabulary with opinions","Use gustar, querer, estar naturally"]},
{type:"mc",q:"How do you say 'I'm thirsty'?",opts:["Tengo sed","Estoy sed","Soy sed","Tengo sedo"],ans:"Tengo sed",hint:"Spanish uses 'to have thirst', not 'to be thirsty'."},
{type:"drag_fill",s:"Me {1} las fresas pero no me {2} el limón.",blanks:{1:"gustan",2:"gusta"},pool:["gustan","gusta","gusto","gustas"],hint:"Fresas is plural (gustan). Limón is singular (gusta)."},
{type:"match",pairs:[{nl:"el desayuno",en:"breakfast"},{nl:"la carne",en:"meat"},{nl:"el pescado",en:"fish"},{nl:"la cuenta",en:"bill"},{nl:"la ensalada",en:"salad"}]},
{type:"mc",q:"You want to order the fish. What do you say?",opts:["Para mí, el pescado, por favor","Yo quiere el pescado","Me pongo el pescado","El pescado me gusta pedir"],ans:"Para mí, el pescado, por favor",hint:"'Para mí' + the item is the polite way to order."},
{type:"drag_fill",s:"De {1}, la sopa. De {2}, el pollo con arroz.",blanks:{1:"primero",2:"segundo"},pool:["primero","segundo","postre","carta"],hint:"Name the first course and the second course."},
{type:"drag_fill",s:"¿Nos {1} la {2}, por {3}?",blanks:{1:"trae",2:"cuenta",3:"favor"},pool:["trae","cuenta","favor","pone","carta","gracias"],hint:"Ask the waiter to bring the bill politely."},
{type:"mc",q:"Which is correct?",opts:["El café está caliente","El café es caliente","El café tiene caliente","El café está picante"],ans:"El café está caliente",hint:"Temperature of a drink right now = estar + caliente."},
{type:"fb",s:"La paella {1} muy rica.",a:"está",opts:["está","es","tiene","hay"],hint:"Describing how the paella tastes. Current condition."},
{type:"mc",q:"Translate: 'Quiero un zumo de naranja y tostadas con mermelada.'",opts:["I want an orange juice and toast with jam","I want a tomato juice and toast with butter","I like orange juice with bread","I need a naranja juice and toast"],ans:"I want an orange juice and toast with jam",hint:"Zumo de naranja = orange juice. Mermelada = jam."},
{type:"drag_fill",s:"Tengo mucha {1}. {2} comer {3} con {4}.",blanks:{1:"hambre",2:"Quiero",3:"arroz",4:"pollo"},pool:["hambre","Quiero","arroz","pollo","sed","Tengo"],hint:"Express hunger and order a classic rice dish."},
{type:"mc",q:"What is NOT a first course (de primero)?",opts:["el pollo con arroz","la sopa","la ensalada","la sopa del día"],ans:"el pollo con arroz",hint:"Chicken with rice is a main dish (de segundo), not a starter."},
{type:"fb",s:"¿Me {1} un café con leche?",a:"pone",opts:["pone","trae","da","tiene"],hint:"A polite way to order in Spain. Literally: 'Do you put me...?'"},
{type:"match",pairs:[{nl:"dulce",en:"sweet"},{nl:"salado",en:"salty"},{nl:"picante",en:"spicy"},{nl:"caliente",en:"hot"},{nl:"la carta",en:"menu"}]},
{type:"mc",q:"Which expression uses 'tener' in Spanish but 'to be' in English?",opts:["Tengo hambre (I'm hungry)","Tengo un libro (I have a book)","Tengo que estudiar (I have to study)","Tengo pan (I have bread)"],ans:"Tengo hambre (I'm hungry)",hint:"In Spanish you 'have hunger', in English you 'are hungry'."},
{type:"drag_fill",s:"De {1}, una {2} mixta. De {3}, {4} con patatas.",blanks:{1:"primero",2:"ensalada",3:"segundo",4:"carne"},pool:["primero","ensalada","segundo","carne","postre","sopa"],hint:"Order a two-course meal: salad starter, meat main."},
{type:"mc",q:"A friend says '¡Está riquísima!' about the paella. This means:",opts:["It's absolutely delicious","It's extremely expensive","She's very rich","It's very spicy"],ans:"It's absolutely delicious",hint:"Rico/a with food = delicious. The -ísima suffix = extremely."},
{type:"fb",s:"¿Me {1} un café, por favor?",a:"pone",opts:["pone","trae","quiero","gusta"],hint:"A polite way to order in Spain, meaning 'can you give me'."},
]}
]},
// ===== UNIT 5: Mi Día (Daily Routine & Reflexive Verbs) =====
{n:5,lang:"es",track:"v1",title:"Mi Día",sub:"Daily Routine & Reflexive Verbs",icon:"🌅",level:"A1.2",color:"#7B5EE8",lessons:[
// L1: Morning Routine — 18 steps (1 intro + 5 teach + 1 tip + 5 mc + 3 fb + 1 match + 1 drag_fill + 1 mc = 18)
{id:"esp5l1",title:"Por la Mañana",icon:"🌤️",xp:15,board:true,steps:[
{type:"intro",title:"Por la Mañana",desc:"Learn morning routine vocabulary and reflexive verbs.",goals:["Name 6 morning activities","Understand reflexive verbs","Use me/te/se pronouns"]},
{type:"teach",kind:"word",nl:"despertarse",en:"to wake up",phonetic:"des-per-TAR-seh",example:"A: ¿A qué hora te despiertas?\nB: Me despierto a las siete.",exampleEn:"A: What time do you wake up?\nB: I wake up at seven.",note:"Reflexive + stem-changing (e to ie): me despierto, te despiertas, se despierta."},
{type:"teach",kind:"word",nl:"levantarse",en:"to get up",phonetic:"leh-ban-TAR-seh",example:"A: ¿Te levantas temprano?\nB: Sí, me levanto a las seis y media.",exampleEn:"A: Do you get up early?\nB: Yes, I get up at six thirty.",note:"Reflexive -ar verb: me levanto, te levantas, se levanta, nos levantamos."},
{type:"teach",kind:"word",nl:"ducharse",en:"to shower",phonetic:"doo-CHAR-seh",example:"A: ¿Te duchas por la mañana o por la noche?\nB: Me ducho por la mañana.",exampleEn:"A: Do you shower in the morning or at night?\nB: I shower in the morning.",note:"Reflexive -ar verb: me ducho, te duchas, se ducha."},
{type:"teach",kind:"word",nl:"vestirse",en:"to get dressed",phonetic:"bes-TEER-seh",example:"A: ¿Ya te has vestido?\nB: No, todavía estoy en pijama.",exampleEn:"A: Have you gotten dressed yet?\nB: No, I'm still in my pajamas.",note:"Reflexive + stem-changing (e to i): me visto, te vistes, se viste."},
{type:"teach",kind:"word",nl:"desayunar",en:"to have breakfast",phonetic:"deh-sah-yoo-NAR",example:"A: ¿Qué desayunas?\nB: Desayuno café con tostadas.",exampleEn:"A: What do you have for breakfast?\nB: I have coffee with toast.",note:"Regular -ar verb (NOT reflexive): desayuno, desayunas, desayuna."},
{type:"tip",title:"Reflexive Verbs",text:"Reflexive verbs show the action on YOURSELF:\nMe despierto = I wake (myself) up\nTe duchas = You shower (yourself)\nSe viste = He/she dresses (himself/herself)\n\nPronouns: me, te, se, nos, se\nThe pronoun goes BEFORE the conjugated verb.\n\nNot reflexive: desayunar (you don't breakfast yourself!).",icon:"💡"},
{type:"mc",q:"Which is the correct 'yo' form of despertarse?",opts:["Me despierto","Me desperto","Yo despierto","Me despierta"],ans:"Me despierto",hint:"Reflexive pronoun me + stem change e to ie in the root."},
{type:"fb",s:"Ella {1} ducha por la mañana.",a:"se",opts:["se","me","te","nos"],hint:"Third person reflexive pronoun for 'she showers herself'."},
{type:"match",pairs:[{nl:"me despierto",en:"I wake up"},{nl:"te levantas",en:"you get up"},{nl:"se ducha",en:"he/she showers"},{nl:"me visto",en:"I get dressed"},{nl:"desayuno",en:"I have breakfast"}]},
{type:"mc",q:"Which verb is NOT reflexive?",opts:["desayunar","ducharse","vestirse","levantarse"],ans:"desayunar",hint:"You don't do breakfast TO yourself. It has no reflexive pronoun."},
{type:"fb",s:"¿A qué hora te {1}?",a:"levantas",opts:["levantas","levanto","levanta","levantamos"],hint:"Asking 'you' (tú) what time you get up."},
{type:"mc",q:"Translate: 'I get dressed at eight.'",opts:["Me visto a las ocho","Me vesto a las ocho","Visto me a las ocho","Me viste a las ocho"],ans:"Me visto a las ocho",hint:"Reflexive pronoun before the verb. Stem changes e to i."},
{type:"drag_fill",s:"Primero {1} {2}, luego {3} {4} y después desayuno.",blanks:{1:"me",2:"despierto",3:"me",4:"ducho"},pool:["me","despierto","me","ducho","se","levanto"],hint:"First I wake up, then I shower, then I eat breakfast."},
{type:"fb",s:"Nosotros {1} levantamos a las siete.",a:"nos",opts:["nos","me","se","te"],hint:"The reflexive pronoun for 'we' (nosotros)."},
{type:"mc",q:"'Se viste rápido' means:",opts:["He/she gets dressed quickly","I get dressed quickly","You get dressed quickly","We get dressed quickly"],ans:"He/she gets dressed quickly",hint:"'Se' is the third person reflexive pronoun."},
{type:"fb",s:"Me {1} a las siete todos los días.",a:"despierto",opts:["despierto","levanto","ducho","visto"],hint:"The first thing you do when the alarm rings."},
{type:"mc",q:"What pronoun goes with 'nosotros' in reflexive verbs?",opts:["nos","me","se","te"],ans:"nos",hint:"We + ourselves uses this reflexive pronoun."},
]},
// L2: -ar Verbs Present — 18 steps
{id:"esp5l2",title:"Verbos -ar",icon:"📝",xp:15,board:true,steps:[
{type:"intro",title:"Verbos -ar",desc:"Master the present tense of regular -ar verbs.",goals:["Conjugate 6 regular -ar verbs","Use all person forms","Build sentences with -ar verbs"]},
{type:"teach",kind:"word",nl:"hablar",en:"to speak / to talk",phonetic:"ah-BLAR",example:"A: ¿Hablas español?\nB: Sí, hablo un poco de español.",exampleEn:"A: Do you speak Spanish?\nB: Yes, I speak a little Spanish.",note:"-ar verb: hablo, hablas, habla, hablamos, hablan. The H is silent!"},
{type:"teach",kind:"word",nl:"estudiar",en:"to study",phonetic:"ehs-too-dee-AR",example:"A: ¿Dónde estudias?\nB: Estudio en la universidad.",exampleEn:"A: Where do you study?\nB: I study at the university.",note:"-ar verb: estudio, estudias, estudia, estudiamos, estudian."},
{type:"teach",kind:"word",nl:"trabajar",en:"to work",phonetic:"trah-bah-HAR",example:"A: ¿Dónde trabajas?\nB: Trabajo en una oficina.",exampleEn:"A: Where do you work?\nB: I work in an office.",note:"-ar verb: trabajo, trabajas, trabaja, trabajamos, trabajan."},
{type:"teach",kind:"word",nl:"comprar",en:"to buy",phonetic:"kohm-PRAR",example:"A: ¿Qué compras en el supermercado?\nB: Compro fruta y leche.",exampleEn:"A: What do you buy at the supermarket?\nB: I buy fruit and milk.",note:"-ar verb: compro, compras, compra, compramos, compran."},
{type:"teach",kind:"word",nl:"escuchar",en:"to listen",phonetic:"ehs-koo-CHAR",example:"A: ¿Escuchas música?\nB: Sí, escucho música todos los días.",exampleEn:"A: Do you listen to music?\nB: Yes, I listen to music every day.",note:"-ar verb: escucho, escuchas, escucha, escuchamos, escuchan."},
{type:"tip",title:"-ar Verb Endings",text:"Remove -ar, add these endings:\nyo: -o (hablo)\ntú: -as (hablas)\nél/ella: -a (habla)\nnosotros: -amos (hablamos)\nellos/ellas: -an (hablan)\n\n-ar verbs are the LARGEST group in Spanish.\nAbout 80% of all Spanish verbs are -ar!",icon:"📝"},
{type:"mc",q:"What is the 'nosotros' form of hablar?",opts:["hablamos","hablais","hablan","hablo"],ans:"hablamos",hint:"Nosotros always gets the -amos ending for -ar verbs."},
{type:"fb",s:"Ella {1} en un hospital.",a:"trabaja",opts:["trabaja","trabajo","trabajas","trabajamos"],hint:"She works. Third person singular of an -ar verb."},
{type:"match",pairs:[{nl:"hablo",en:"I speak"},{nl:"estudias",en:"you study"},{nl:"trabaja",en:"he/she works"},{nl:"compramos",en:"we buy"},{nl:"escuchan",en:"they listen"}]},
{type:"mc",q:"About what percentage of Spanish verbs are -ar?",opts:["About 80%","About 50%","About 30%","About 95%"],ans:"About 80%",hint:"The vast majority of Spanish verbs belong to this group."},
{type:"fb",s:"¿{1} español?",a:"Hablas",opts:["Hablas","Hablo","Habla","Hablamos"],hint:"Asking 'you' (tú) if you speak Spanish."},
{type:"mc",q:"Complete: 'Nosotros ___ fruta en el mercado.'",opts:["compramos","compran","compro","compras"],ans:"compramos",hint:"We buy. Nosotros + -ar verb = -amos ending."},
{type:"drag_fill",s:"Yo {1} español y mi hermana {2} música.",blanks:{1:"estudio",2:"escucha"},pool:["estudio","escucha","estudia","escucho","estudiamos","escuchamos"],hint:"I study (yo) and she listens (ella)."},
{type:"fb",s:"Ellos {1} en el supermercado los sábados.",a:"compran",opts:["compran","compra","compro","compramos"],hint:"They buy. Third person plural of comprar."},
{type:"mc",q:"Translate: 'We work in the morning and study at night.'",opts:["Trabajamos por la mañana y estudiamos por la noche","Trabajan por la mañana y estudian por la noche","Trabajo por la mañana y estudio por la noche","Trabajas por la mañana y estudias por la noche"],ans:"Trabajamos por la mañana y estudiamos por la noche",hint:"We = nosotros. Both verbs need -amos ending."},
{type:"fb",s:"Mi madre {1} en el supermercado.",a:"compra",opts:["compra","compro","compras","compran"],hint:"She buys. Third person singular of comprar."},
{type:"mc",q:"What ending does 'yo' get with -ar verbs?",opts:["-o","-as","-a","-amos"],ans:"-o",hint:"The first person singular always ends in this letter."},
]},
// L3: Daily Activities — 18 steps
{id:"esp5l3",title:"Actividades Diarias",icon:"📋",xp:15,board:true,steps:[
{type:"intro",title:"Actividades Diarias",desc:"Learn more daily activities with -er/-ir verbs and irregulars.",goals:["Use leer, escribir, dormir","Understand stem changes (o to ue)","Use ir (to go)"]},
{type:"teach",kind:"word",nl:"leer",en:"to read",phonetic:"leh-ER",example:"A: ¿Qué lees?\nB: Leo un libro muy interesante.",exampleEn:"A: What are you reading?\nB: I'm reading a very interesting book.",note:"-er verb: leo, lees, lee, leemos, leen."},
{type:"teach",kind:"word",nl:"escribir",en:"to write",phonetic:"ehs-kree-BEER",example:"A: ¿Escribes un diario?\nB: Sí, escribo un poco cada noche.",exampleEn:"A: Do you write a diary?\nB: Yes, I write a little each night.",note:"-ir verb: escribo, escribes, escribe, escribimos, escriben."},
{type:"teach",kind:"word",nl:"dormir",en:"to sleep",phonetic:"dor-MEER",example:"A: ¿Cuántas horas duermes?\nB: Duermo ocho horas.",exampleEn:"A: How many hours do you sleep?\nB: I sleep eight hours.",note:"Stem-changing (o to ue): duermo, duermes, duerme, dormimos, duermen."},
{type:"teach",kind:"word",nl:"ver",en:"to see / to watch",phonetic:"BER",example:"A: ¿Qué ves en la tele?\nB: Veo una película española.",exampleEn:"A: What do you watch on TV?\nB: I watch a Spanish movie.",note:"Irregular yo: veo. Rest regular: ves, ve, vemos, ven."},
{type:"teach",kind:"word",nl:"ir",en:"to go",phonetic:"EER",example:"A: ¿Adónde vas?\nB: Voy al supermercado.",exampleEn:"A: Where are you going?\nB: I'm going to the supermarket.",note:"Very irregular: voy, vas, va, vamos, van. One of the most used verbs!"},
{type:"tip",title:"Stem-Changing Verbs: o to ue",text:"Some verbs change o to ue in stressed forms:\ndormir: duermo, duermes, duerme, dormimos, duermen\n\nNote: nosotros does NOT change!\nThe stress falls on the ending, not the stem.\n\nOther o to ue verbs: poder (puedo), volver (vuelvo).",icon:"📝"},
{type:"mc",q:"What is the 'yo' form of dormir?",opts:["duermo","dormo","durmo","dormio"],ans:"duermo",hint:"The o in the stem changes to ue when stressed."},
{type:"fb",s:"Ella {1} al trabajo en autobús.",a:"va",opts:["va","voy","vas","vamos"],hint:"She goes. Third person singular of ir."},
{type:"match",pairs:[{nl:"leo",en:"I read"},{nl:"escribes",en:"you write"},{nl:"duerme",en:"he/she sleeps"},{nl:"vemos",en:"we see"},{nl:"van",en:"they go"}]},
{type:"mc",q:"Why doesn't 'dormimos' change the stem?",opts:["The stress is on the ending, not the stem","Nosotros forms never change","It's an exception to the rule","Both dormimos and duermimos work"],ans:"The stress is on the ending, not the stem",hint:"Stem changes only happen in stressed syllables."},
{type:"fb",s:"¿Adónde {1}?",a:"vas",opts:["vas","voy","va","vamos"],hint:"Asking 'where are you going?' to one person (tú)."},
{type:"mc",q:"Translate: 'I watch TV at night.'",opts:["Veo la tele por la noche","Voy la tele por la noche","Leo la tele por la noche","Ver la tele por la noche"],ans:"Veo la tele por la noche",hint:"Veo = I watch/see. Irregular yo form of ver."},
{type:"drag_fill",s:"Por la noche {1} un libro y después {2} ocho horas.",blanks:{1:"leo",2:"duermo"},pool:["leo","duermo","lees","duermes","veo","voy"],hint:"At night I read and then I sleep."},
{type:"fb",s:"Nosotros {1} al parque los domingos.",a:"vamos",opts:["vamos","van","voy","vas"],hint:"We go. Nosotros form of ir."},
{type:"mc",q:"Which verb is stem-changing (o to ue)?",opts:["dormir","escribir","leer","ir"],ans:"dormir",hint:"This verb changes its root vowel in stressed forms."},
{type:"fb",s:"¿Qué {1} en la tele?",a:"ves",opts:["ves","veo","ve","ver"],hint:"Asking what YOU (tú) watch on TV."},
{type:"mc",q:"Complete: 'Nosotros ___ al cine los viernes.'",opts:["vamos","van","voy","ir"],ans:"vamos",hint:"We go. Nosotros form of ir."},
]},
// L4: Reflexive Verbs — 18 steps
{id:"esp5l4",title:"Verbos Reflexivos",icon:"🪞",xp:15,board:true,steps:[
{type:"intro",title:"Verbos Reflexivos",desc:"Practice more reflexive verbs for daily routines.",goals:["Use 4 new reflexive verbs","Place pronouns correctly","Use articles with body parts"]},
{type:"teach",kind:"word",nl:"lavarse",en:"to wash (oneself)",phonetic:"lah-BAR-seh",example:"A: ¿Te lavas las manos antes de comer?\nB: Sí, siempre me lavo las manos.",exampleEn:"A: Do you wash your hands before eating?\nB: Yes, I always wash my hands.",note:"Me lavo, te lavas, se lava, nos lavamos, se lavan."},
{type:"teach",kind:"word",nl:"peinarse",en:"to comb one's hair",phonetic:"pay-NAR-seh",example:"A: ¿Te peinas después de ducharte?\nB: Sí, me peino y me visto.",exampleEn:"A: Do you brush your hair after showering?\nB: Yes, I brush my hair and get dressed.",note:"Me peino, te peinas, se peina. Regular -ar reflexive."},
{type:"teach",kind:"word",nl:"acostarse",en:"to go to bed",phonetic:"ah-kohs-TAR-seh",example:"A: ¿A qué hora te acuestas?\nB: Me acuesto a las once.",exampleEn:"A: What time do you go to bed?\nB: I go to bed at eleven.",note:"Stem-changing (o to ue): me acuesto, te acuestas, se acuesta."},
{type:"teach",kind:"word",nl:"sentarse",en:"to sit down",phonetic:"sen-TAR-seh",example:"A: ¿Dónde te sientas en clase?\nB: Me siento al lado de la ventana.",exampleEn:"A: Where do you sit in class?\nB: I sit next to the window.",note:"Stem-changing (e to ie): me siento, te sientas, se sienta."},
{type:"teach",kind:"phrase",nl:"cepillarse los dientes",en:"to brush one's teeth",phonetic:"seh-pee-YAR-seh lohs dee-EN-tehs",example:"A: ¿Cuántas veces te cepillas los dientes?\nB: Me cepillo los dientes tres veces al día.",exampleEn:"A: How many times do you brush your teeth?\nB: I brush my teeth three times a day.",note:"Me cepillo, te cepillas, se cepilla. Use LOS dientes, not MIS."},
{type:"tip",title:"Reflexive + Body Parts",text:"With reflexive verbs, use THE article (not possessive) for body parts:\nMe lavo LAS manos. (not mis manos)\nMe cepillo LOS dientes. (not mis dientes)\nSe peina EL pelo. (not su pelo)\n\nThe reflexive pronoun already shows whose body it is.",icon:"💡"},
{type:"mc",q:"How do you say 'I go to bed at ten'?",opts:["Me acuesto a las diez","Me acosto a las diez","Acuesto me a las diez","Me acuesta a las diez"],ans:"Me acuesto a las diez",hint:"Stem change o to ue: acostarse becomes me acuesto."},
{type:"fb",s:"Ella {1} sienta en el sofá.",a:"se",opts:["se","me","te","nos"],hint:"Third person reflexive pronoun."},
{type:"match",pairs:[{nl:"me lavo",en:"I wash"},{nl:"te peinas",en:"you comb"},{nl:"se acuesta",en:"he/she goes to bed"},{nl:"nos sentamos",en:"we sit down"},{nl:"se cepillan",en:"they brush"}]},
{type:"mc",q:"'Me cepillo LOS dientes' (not MIS dientes) because:",opts:["The reflexive pronoun already shows ownership","It's a grammar exception with no logic","Both forms are correct in all cases","Los sounds better than mis here"],ans:"The reflexive pronoun already shows ownership",hint:"The me already tells us whose teeth they are."},
{type:"fb",s:"¿A qué hora te {1}?",a:"acuestas",opts:["acuestas","acuesto","acuesta","acostamos"],hint:"Asking what time YOU (tú) go to bed."},
{type:"mc",q:"Which verb has the stem change e to ie?",opts:["sentarse","lavarse","peinarse","cepillarse"],ans:"sentarse",hint:"Me siento, te sientas. The e in sent- changes."},
{type:"drag_fill",s:"Yo {1} {2} las manos y después {3} {4} los dientes.",blanks:{1:"me",2:"lavo",3:"me",4:"cepillo"},pool:["me","lavo","me","cepillo","se","peino"],hint:"I wash my hands and then brush my teeth."},
{type:"fb",s:"Nosotros nos {1} en el sofá para ver la tele.",a:"sentamos",opts:["sentamos","sentimos","siento","sientan"],hint:"We sit down. Nosotros form has no stem change."},
{type:"mc",q:"Translate: 'She combs her hair every morning.'",opts:["Se peina todas las mañanas","Me peino todas las mañanas","Se peina todos las mañanas","Peina se todas las mañanas"],ans:"Se peina todas las mañanas",hint:"Se = she (reflexive). Todas las mañanas = every morning."},
{type:"fb",s:"Me {1} los dientes tres veces al día.",a:"cepillo",opts:["cepillo","cepillas","lavo","peino"],hint:"First person of the verb for teeth brushing."},
{type:"mc",q:"'Me acuesto a las once' means:",opts:["I go to bed at eleven","I wake up at eleven","I get dressed at eleven","I shower at eleven"],ans:"I go to bed at eleven",hint:"Acostarse = to go to bed. The last action of the day."},
]},
// L5: Sequence Words — 18 steps
{id:"esp5l5",title:"El Orden del Día",icon:"📅",xp:15,board:true,steps:[
{type:"intro",title:"El Orden del Día",desc:"Use sequence words to describe your daily routine in order.",goals:["Use primero, luego, después, finalmente","Combine time with activities","Describe a full day"]},
{type:"teach",kind:"word",nl:"primero",en:"first",phonetic:"pree-MEH-roh",example:"A: ¿Qué haces por la mañana?\nB: Primero me despierto a las siete.",exampleEn:"A: What do you do in the morning?\nB: First I wake up at seven.",note:"Sequence word. Placed at the start of the sentence."},
{type:"teach",kind:"word",nl:"luego / después",en:"then / after",phonetic:"LWEH-goh / des-PWEHS",example:"A: ¿Y después?\nB: Luego me ducho y después desayuno.",exampleEn:"A: And then?\nB: Then I shower and after that I have breakfast.",note:"Luego and después are interchangeable. Both mean 'then/after'."},
{type:"teach",kind:"word",nl:"antes de",en:"before",phonetic:"AHN-tes deh",example:"A: ¿Te duchas antes de desayunar?\nB: Sí, siempre antes de desayunar.",exampleEn:"A: Do you shower before having breakfast?\nB: Yes, always before having breakfast.",note:"Antes de + infinitive: before doing something."},
{type:"teach",kind:"word",nl:"después de",en:"after (doing)",phonetic:"des-PWEHS deh",example:"A: ¿Qué haces después de trabajar?\nB: Después de trabajar voy al gimnasio.",exampleEn:"A: What do you do after work?\nB: After working I go to the gym.",note:"Después de + infinitive: after doing something."},
{type:"teach",kind:"word",nl:"finalmente",en:"finally",phonetic:"fee-nahl-MEN-teh",example:"A: ¿Y al final del día?\nB: Finalmente me acuesto a las once.",exampleEn:"A: And at the end of the day?\nB: Finally I go to bed at eleven.",note:"Used to mark the last action in a sequence."},
{type:"tip",title:"Building a Routine Description",text:"Use this pattern:\nPrimero + activity + time.\nLuego/Después + activity.\nDespués de + infinitive + next activity.\nFinalmente + last activity.\n\nExample:\nPrimero me levanto a las siete.\nLuego me ducho.\nDespués de desayunar, voy al trabajo.\nFinalmente me acuesto a las once.",icon:"📝"},
{type:"mc",q:"Which word means 'before'?",opts:["antes de","después de","luego","finalmente"],ans:"antes de",hint:"The opposite of después de. Something that happens first."},
{type:"fb",s:"{1} me despierto y luego me levanto.",a:"Primero",opts:["Primero","Después","Finalmente","Luego"],hint:"The first action in a sequence gets this word."},
{type:"match",pairs:[{nl:"primero",en:"first"},{nl:"luego",en:"then"},{nl:"después de",en:"after"},{nl:"antes de",en:"before"},{nl:"finalmente",en:"finally"}]},
{type:"mc",q:"'Después de comer, leo un libro' means:",opts:["After eating, I read a book","Before eating, I read a book","While eating, I read a book","Instead of eating, I read a book"],ans:"After eating, I read a book",hint:"Después de + infinitive = after doing something."},
{type:"fb",s:"Me ducho {1} de desayunar.",a:"antes",opts:["antes","después","primero","luego"],hint:"You shower BEFORE eating breakfast, not after."},
{type:"mc",q:"Which sentence is in the correct order?",opts:["Primero me levanto, luego me ducho, finalmente desayuno","Finalmente me levanto, primero me ducho, luego desayuno","Luego me levanto, finalmente me ducho, primero desayuno","Después me levanto, antes me ducho, primero desayuno"],ans:"Primero me levanto, luego me ducho, finalmente desayuno",hint:"First = primero, then = luego, last = finalmente."},
{type:"drag_fill",s:"{1} me despierto. {2} me ducho. {3} de vestirme, desayuno.",blanks:{1:"Primero",2:"Luego",3:"Después"},pool:["Primero","Luego","Después","Antes","Finalmente","Por"],hint:"Order: first, then, after getting dressed."},
{type:"fb",s:"{1} de comer, leo un libro.",a:"Después",opts:["Después","Antes","Primero","Luego"],hint:"You read AFTER eating, not before."},
{type:"mc",q:"Translate: 'Finally I go to bed at eleven.'",opts:["Finalmente me acuesto a las once","Primero me acuesto a las once","Después me acuesto a las once","Antes me acuesto a las once"],ans:"Finalmente me acuesto a las once",hint:"The last action of the day uses this sequence word."},
{type:"fb",s:"Estudio por la {1} y trabajo por la tarde.",a:"mañana",opts:["mañana","noche","tarde","hora"],hint:"The first part of the day, before afternoon."},
{type:"mc",q:"What comes after 'antes de' or 'después de'?",opts:["An infinitive verb","A conjugated verb","A noun only","An adjective"],ans:"An infinitive verb",hint:"Before/after DOING something uses the base form."},
]},
// L6: ¿A Qué Hora? — 18 steps
{id:"esp5l6",title:"¿A Qué Hora?",icon:"⏰",xp:15,board:true,steps:[
{type:"intro",title:"¿A Qué Hora?",desc:"Combine time expressions with daily activities.",goals:["Ask and answer 'at what time?'","Use frequency words","Schedule activities throughout the day"]},
{type:"teach",kind:"phrase",nl:"¿a qué hora?",en:"at what time?",phonetic:"ah keh OH-rah",example:"A: ¿A qué hora te levantas?\nB: Me levanto a las siete y media.",exampleEn:"A: At what time do you get up?\nB: I get up at seven thirty.",note:"Always 'a las' + hour (except 1:00 = a la una)."},
{type:"teach",kind:"phrase",nl:"a las + hora",en:"at + time",phonetic:"ah lahs",example:"A: ¿Cuándo comes?\nB: Como a las dos de la tarde.",exampleEn:"A: When do you eat?\nB: I eat at two in the afternoon.",note:"A la una (1:00), a las dos, a las tres... Always a las for 2+."},
{type:"teach",kind:"word",nl:"temprano",en:"early",phonetic:"tem-PRAH-noh",example:"A: ¿Te levantas temprano?\nB: Sí, me levanto muy temprano, a las cinco.",exampleEn:"A: Do you get up early?\nB: Yes, I get up very early, at five.",note:"Opposite: tarde (late). Muy temprano = very early."},
{type:"teach",kind:"word",nl:"tarde",en:"late",phonetic:"TAR-deh",example:"A: ¿Por qué llegas tarde?\nB: Porque me levanto tarde.",exampleEn:"A: Why are you arriving late?\nB: Because I get up late.",note:"Tarde = late (adverb) or afternoon (noun). Context matters!"},
{type:"teach",kind:"word",nl:"siempre / nunca",en:"always / never",phonetic:"see-EM-preh / NOON-kah",example:"A: ¿Siempre desayunas?\nB: No, nunca desayuno. No tengo hambre.",exampleEn:"A: Do you always have breakfast?\nB: No, I never have breakfast. I'm not hungry.",note:"Siempre = always. Nunca = never. Go before the verb."},
{type:"tip",title:"Frequency Words",text:"Common frequency words:\nsiempre = always\ncasi siempre = almost always\na veces = sometimes\ncasi nunca = almost never\nnunca = never\n\nPlacement: usually BEFORE the verb.\nSiempre me levanto temprano.\nNunca como pescado.",icon:"📝"},
{type:"mc",q:"How do you say 'at two o'clock'?",opts:["a las dos","a la dos","en las dos","por las dos"],ans:"a las dos",hint:"For hours 2+, use 'a las'. Only 1:00 uses 'a la'."},
{type:"fb",s:"¿A qué {1} te acuestas?",a:"hora",opts:["hora","tiempo","día","vez"],hint:"Asking 'at what ___?' when asking about the time of an action."},
{type:"match",pairs:[{nl:"siempre",en:"always"},{nl:"a veces",en:"sometimes"},{nl:"nunca",en:"never"},{nl:"temprano",en:"early"},{nl:"tarde",en:"late"}]},
{type:"mc",q:"'Nunca como pescado' means:",opts:["I never eat fish","I always eat fish","I sometimes eat fish","I eat fish late"],ans:"I never eat fish",hint:"Nunca = never. It goes before the verb."},
{type:"fb",s:"Me levanto {1} a las cinco de la mañana.",a:"siempre",opts:["siempre","nunca","tarde","hora"],hint:"I get up at 5 AM every single day without exception."},
{type:"mc",q:"What time expression means 'at 1:00'?",opts:["a la una","a las una","a la uno","a el una"],ans:"a la una",hint:"One o'clock is the exception. Use singular 'la' instead of 'las'."},
{type:"drag_fill",s:"{1} me levanto {2} pero hoy me levanto {3} a las {4}.",blanks:{1:"Siempre",2:"temprano",3:"tarde",4:"diez"},pool:["Siempre","temprano","tarde","diez","Nunca","ocho"],hint:"I always get up early but today I'm getting up late."},
{type:"fb",s:"A {1} como en un restaurante.",a:"veces",opts:["veces","siempre","nunca","vamos"],hint:"Not always, not never, but occasionally."},
{type:"mc",q:"Translate: 'I always shower in the morning.'",opts:["Siempre me ducho por la mañana","Nunca me ducho por la mañana","Me ducho siempre la mañana","Siempre ducho me por la mañana"],ans:"Siempre me ducho por la mañana",hint:"Siempre before the reflexive pronoun + verb."},
{type:"fb",s:"Me levanto {1} los lunes.",a:"temprano",opts:["temprano","tarde","nunca","siempre"],hint:"Getting up early on Monday mornings."},
{type:"mc",q:"What does 'casi nunca' mean?",opts:["almost never","almost always","sometimes","never ever"],ans:"almost never",hint:"Casi = almost. Nunca = never. Combined together."},
]},
// L7: Weekend Activities — 18 steps
{id:"esp5l7",title:"El Fin de Semana",icon:"🎉",xp:15,board:true,steps:[
{type:"intro",title:"El Fin de Semana",desc:"Talk about weekend activities and free time.",goals:["Describe weekend plans","Use ir + a + place","Combine activities with locations"]},
{type:"teach",kind:"phrase",nl:"el fin de semana",en:"the weekend",phonetic:"el feen deh seh-MAH-nah",example:"A: ¿Qué haces los fines de semana?\nB: Los fines de semana descanso.",exampleEn:"A: What do you do on weekends?\nB: On weekends I rest.",note:"Masculine. Plural: los fines de semana."},
{type:"teach",kind:"word",nl:"descansar",en:"to rest",phonetic:"des-kahn-SAR",example:"A: ¿Descansas los domingos?\nB: Sí, los domingos descanso en casa.",exampleEn:"A: Do you rest on Sundays?\nB: Yes, on Sundays I rest at home.",note:"Regular -ar verb: descanso, descansas, descansa."},
{type:"teach",kind:"word",nl:"jugar",en:"to play",phonetic:"hoo-GAR",example:"A: ¿Juegas al fútbol?\nB: Sí, juego al fútbol los sábados.",exampleEn:"A: Do you play football?\nB: Yes, I play football on Saturdays.",note:"Stem-changing (u to ue): juego, juegas, juega, jugamos, juegan. Uses a + el = al."},
{type:"teach",kind:"phrase",nl:"ir al parque",en:"to go to the park",phonetic:"eer al PAR-keh",example:"A: ¿Adónde vais este domingo?\nB: Vamos al parque con los niños.",exampleEn:"A: Where are you going this Sunday?\nB: We're going to the park with the kids.",note:"Ir + al (a + el) + place. Ir + a la + feminine place."},
{type:"teach",kind:"word",nl:"pasear",en:"to go for a walk",phonetic:"pah-seh-AR",example:"A: ¿Te gusta pasear?\nB: Sí, paseo por el centro los domingos.",exampleEn:"A: Do you like to walk?\nB: Yes, I walk around the center on Sundays.",note:"Regular -ar verb: paseo, paseas, pasea. Pasear al perro = walk the dog."},
{type:"tip",title:"Ir + a + Place",text:"Use ir to talk about going places:\nVoy al parque. (a + el = al)\nVoy a la playa. (a + la stays)\nVoy a casa. (no article with casa)\n\nir: voy, vas, va, vamos, van\n\nVamos = let's go! (very common)",icon:"📝"},
{type:"mc",q:"What is the stem change in jugar?",opts:["u to ue","o to ue","e to ie","e to i"],ans:"u to ue",hint:"Juego, juegas, juega. The u in jug- changes."},
{type:"fb",s:"Los sábados {1} al fútbol.",a:"juego",opts:["juego","jugo","juegas","jugamos"],hint:"I play. First person singular with stem change."},
{type:"match",pairs:[{nl:"descansar",en:"to rest"},{nl:"jugar",en:"to play"},{nl:"pasear",en:"to walk"},{nl:"ver la tele",en:"to watch TV"},{nl:"ir al parque",en:"to go to the park"}]},
{type:"mc",q:"How do you say 'Let's go!'?",opts:["¡Vamos!","¡Voy!","¡Van!","¡Vas!"],ans:"¡Vamos!",hint:"The nosotros form of ir doubles as 'let's go'."},
{type:"fb",s:"¿{1} al cine este sábado?",a:"Vamos",opts:["Vamos","Voy","Van","Vas"],hint:"Suggesting we go to the cinema. Let's go!"},
{type:"mc",q:"Complete: 'Mi padre ___ por el parque todas las tardes.'",opts:["pasea","paseo","paseas","paseamos"],ans:"pasea",hint:"My father (él) walks. Third person singular."},
{type:"drag_fill",s:"Los fines de semana {1} al {2} y después {3} la {4}.",blanks:{1:"voy",2:"parque",3:"veo",4:"tele"},pool:["voy","parque","veo","tele","juego","fútbol"],hint:"On weekends I go to the park and then watch TV."},
{type:"fb",s:"Los domingos {1} en casa.",a:"descanso",opts:["descanso","descansas","descansa","descansamos"],hint:"I rest on Sundays. First person singular."},
{type:"mc",q:"Translate: 'We play football on Saturdays.'",opts:["Jugamos al fútbol los sábados","Juegan al fútbol los sábados","Juego al fútbol los sábados","Juegas al fútbol los sábados"],ans:"Jugamos al fútbol los sábados",hint:"We = nosotros. No stem change in nosotros form: jugamos."},
{type:"fb",s:"Los fines de semana me gusta {1}.",a:"pasear",opts:["pasear","paseamos","paseas","pasea"],hint:"After me gusta, use the infinitive form."},
{type:"mc",q:"'Voy a la playa' uses 'a la' because:",opts:["Playa is feminine","Playa is masculine","We always use a la","It's a contraction"],ans:"Playa is feminine",hint:"A + la stays as two words. Only a + el becomes al."},
]},
// L8: Un Día Típico review — 18 steps
{id:"esp5l8",title:"Un Día Típico",icon:"📖",xp:15,board:true,steps:[
{type:"intro",title:"Un Día Típico",desc:"Describe a complete typical day from morning to night.",goals:["Combine all unit vocabulary","Use sequence words naturally","Describe routines fluently"]},
{type:"mc",q:"How do you say 'I wake up at seven'?",opts:["Me despierto a las siete","Me desperto a las siete","Despierto me a las siete","Me despierta a las siete"],ans:"Me despierto a las siete",hint:"Reflexive pronoun + stem change e to ie."},
{type:"fb",s:"{1} me levanto y luego me ducho.",a:"Primero",opts:["Primero","Después","Finalmente","Nunca"],hint:"The sequence word for the first action."},
{type:"match",pairs:[{nl:"me despierto",en:"I wake up"},{nl:"me ducho",en:"I shower"},{nl:"me visto",en:"I get dressed"},{nl:"desayuno",en:"I have breakfast"},{nl:"me acuesto",en:"I go to bed"}]},
{type:"mc",q:"Which is correct for 'She always gets up early'?",opts:["Siempre se levanta temprano","Siempre me levanta temprano","Se siempre levanta temprano","Levanta se siempre temprano"],ans:"Siempre se levanta temprano",hint:"Siempre first, then reflexive pronoun + verb."},
{type:"fb",s:"Después de {1}, voy al trabajo.",a:"desayunar",opts:["desayunar","desayuno","desayunas","desayuna"],hint:"After + infinitive (base form of the verb)."},
{type:"drag_fill",s:"Por la mañana {1} español y por la {2} {3} en una oficina.",blanks:{1:"estudio",2:"tarde",3:"trabajo"},pool:["estudio","tarde","trabajo","estudio","noche","descanso"],hint:"In the morning I study, in the afternoon I work."},
{type:"mc",q:"'Me cepillo los dientes' uses 'los' instead of 'mis' because:",opts:["The reflexive pronoun already shows ownership","Los sounds more natural in this phrase","Both forms are equally correct always","Mis is only for clothing items"],ans:"The reflexive pronoun already shows ownership",hint:"The me already indicates whose teeth they are."},
{type:"fb",s:"Los sábados {1} al fútbol con mis amigos.",a:"juego",opts:["juego","jugar","juega","jugamos"],hint:"I play. First person with stem change u to ue."},
{type:"mc",q:"Translate: 'I never eat fish.'",opts:["Nunca como pescado","Siempre como pescado","No como nunca pescado","Nunca pescado como"],ans:"Nunca como pescado",hint:"Nunca goes before the verb."},
{type:"drag_fill",s:"{1} de trabajar, {2} al {3} y luego {4} la tele.",blanks:{1:"Después",2:"voy",3:"parque",4:"veo"},pool:["Después","voy","parque","veo","Antes","como"],hint:"After work, I go to the park and then watch TV."},
{type:"fb",s:"A {1} como en un restaurante los viernes.",a:"veces",opts:["veces","siempre","nunca","cada"],hint:"Not always, not never. Occasionally."},
{type:"mc",q:"Which uses 'a la una' (not 'a las')?",opts:["Como a la una de la tarde","Me levanto a la siete","Me acuesto a la once","Estudio a la tres"],ans:"Como a la una de la tarde",hint:"Only 1:00 uses singular 'a la'. All other hours use 'a las'."},
{type:"match",pairs:[{nl:"siempre",en:"always"},{nl:"a veces",en:"sometimes"},{nl:"nunca",en:"never"},{nl:"temprano",en:"early"},{nl:"tarde",en:"late"}]},
{type:"fb",s:"Finalmente me {1} a las once de la noche.",a:"acuesto",opts:["acuesto","levanto","despierto","ducho"],hint:"The last action of the day is going to bed."},
{type:"mc",q:"Which pair means 'before' and 'after'?",opts:["antes de / después de","primero / luego","temprano / tarde","siempre / nunca"],ans:"antes de / después de",hint:"These two prepositions are opposites and both use 'de'."},
{type:"fb",s:"Ella {1} va al trabajo en autobús.",a:"siempre",opts:["siempre","nunca","veces","antes"],hint:"She does this every single day without exception."},
{type:"mc",q:"Translate: 'First I shower, then I have breakfast.'",opts:["Primero me ducho, luego desayuno","Luego me ducho, primero desayuno","Finalmente me ducho, luego desayuno","Antes me ducho, después desayuno"],ans:"Primero me ducho, luego desayuno",hint:"First = primero, then = luego."},
]}
]},
// ===== UNIT 6: La Casa (Home, Rooms & Prepositions) =====
{n:6,lang:"es",track:"v1",title:"La Casa",sub:"Home, Rooms & Prepositions",icon:"🏠",level:"A1.2",color:"#7B5EE8",lessons:[
// L1: Las Habitaciones — 18 steps
{id:"esp6l1",title:"Las Habitaciones",icon:"🚪",xp:15,board:true,steps:[
{type:"intro",title:"Las Habitaciones",desc:"Learn the rooms of a house and describe where things are.",goals:["Name 6 rooms in a house","Use hay (there is/are)","Say what is in each room"]},
{type:"teach",kind:"word",nl:"la casa",en:"the house",phonetic:"KAH-sah",example:"A: ¿Dónde vives?\nB: Vivo en una casa grande.",exampleEn:"A: Where do you live?\nB: I live in a big house.",note:"Feminine. Also used in phrases: en casa = at home."},
{type:"teach",kind:"word",nl:"la cocina",en:"the kitchen",phonetic:"koh-SEE-nah",example:"A: ¿Dónde está tu madre?\nB: Está en la cocina.",exampleEn:"A: Where is your mother?\nB: She's in the kitchen.",note:"Feminine. Also means 'cooking' or 'cuisine'."},
{type:"teach",kind:"word",nl:"el salón",en:"the living room",phonetic:"sah-LOHN",example:"A: ¿Vemos la tele?\nB: Sí, vamos al salón.",exampleEn:"A: Shall we watch TV?\nB: Yes, let's go to the living room.",note:"Masculine. Also called 'la sala' in Latin America."},
{type:"teach",kind:"word",nl:"el dormitorio",en:"the bedroom",phonetic:"dor-mee-TOH-ree-oh",example:"A: ¿Cuántos dormitorios tiene tu casa?\nB: Tiene tres dormitorios.",exampleEn:"A: How many bedrooms does your house have?\nB: It has three bedrooms.",note:"Masculine. From dormir (to sleep). Also: la habitación."},
{type:"teach",kind:"word",nl:"el baño",en:"the bathroom",phonetic:"BAH-nyoh",example:"A: ¿Dónde está el baño?\nB: Está al final del pasillo.",exampleEn:"A: Where is the bathroom?\nB: It's at the end of the hallway.",note:"Masculine. The ñ makes a 'ny' sound."},
{type:"teach",kind:"word",nl:"el jardín",en:"the garden",phonetic:"har-DEEN",example:"A: ¿Tienes jardín?\nB: Sí, tenemos un jardín pequeño.",exampleEn:"A: Do you have a garden?\nB: Yes, we have a small garden.",note:"Masculine. The J sounds like a strong English 'h'."},
{type:"tip",title:"Hay = There Is / There Are",text:"Hay is used for both singular and plural:\nHay un baño. = There is a bathroom.\nHay tres dormitorios. = There are 3 bedrooms.\n\nHay NEVER changes form.\nUse it to describe what exists somewhere.\n\n¿Hay...? = Is there...? / Are there...?",icon:"💡"},
{type:"mc",q:"How do you say 'There are two bathrooms'?",opts:["Hay dos baños","Están dos baños","Son dos baños","Tienen dos baños"],ans:"Hay dos baños",hint:"Use the unchanging form that means 'there is/are'."},
{type:"fb",s:"¿Dónde está tu madre? Está en la {1}.",a:"cocina",opts:["cocina","jardín","baño","casa"],hint:"The room where people cook and prepare food."},
{type:"match",pairs:[{nl:"la cocina",en:"kitchen"},{nl:"el salón",en:"living room"},{nl:"el dormitorio",en:"bedroom"},{nl:"el baño",en:"bathroom"},{nl:"el jardín",en:"garden"}]},
{type:"mc",q:"'El dormitorio' comes from which verb?",opts:["dormir (to sleep)","dar (to give)","decir (to say)","doler (to hurt)"],ans:"dormir (to sleep)",hint:"The bedroom is where you do this activity."},
{type:"fb",s:"{1} un jardín muy grande en la casa.",a:"Hay",opts:["Hay","Está","Es","Tiene"],hint:"To say something exists in a place, use this word."},
{type:"mc",q:"In Latin America, 'el salón' is often called:",opts:["la sala","el cuarto","la pieza","el comedor"],ans:"la sala",hint:"A shorter word for living room, common across Latin America."},
{type:"drag_fill",s:"Mi casa tiene tres {1}, una {2} y un {3} pequeño.",blanks:{1:"dormitorios",2:"cocina",3:"jardín"},pool:["dormitorios","cocina","jardín","baños","sala","salón"],hint:"Describe a house with bedrooms, kitchen, and garden."},
{type:"fb",s:"¿Cuántos {1} tiene tu casa?",a:"baños",opts:["baños","jardín","cocina","salón"],hint:"Asking about the number of rooms for washing."},
{type:"mc",q:"Translate: '¿Dónde está el baño?'",opts:["Where is the bathroom?","Where is the kitchen?","Is there a bathroom?","Do you have a bathroom?"],ans:"Where is the bathroom?",hint:"Dónde = where, está = is. A very useful question!"},
{type:"fb",s:"La {1} es donde preparamos la comida.",a:"cocina",opts:["cocina","sala","baño","jardín"],hint:"The room for cooking and preparing food."},
]},
// L2: Los Muebles — 18 steps
{id:"esp6l2",title:"Los Muebles",icon:"🛋️",xp:15,board:true,steps:[
{type:"intro",title:"Los Muebles",desc:"Learn furniture words and describe what is in each room.",goals:["Name common furniture","Use hay with furniture","Say where things are"]},
{type:"teach",kind:"word",nl:"la mesa",en:"the table",phonetic:"MEH-sah",example:"A: ¿Dónde comemos?\nB: En la mesa del salón.",exampleEn:"A: Where do we eat?\nB: At the table in the living room.",note:"Feminine. Mesa de cocina = kitchen table."},
{type:"teach",kind:"word",nl:"la silla",en:"the chair",phonetic:"SEE-yah",example:"A: ¿Hay sillas en el jardín?\nB: Sí, hay cuatro sillas.",exampleEn:"A: Are there chairs in the garden?\nB: Yes, there are four chairs.",note:"Feminine. The 'll' sounds like 'y'."},
{type:"teach",kind:"word",nl:"la cama",en:"the bed",phonetic:"KAH-mah",example:"A: ¿Es grande tu cama?\nB: Sí, tengo una cama doble.",exampleEn:"A: Is your bed big?\nB: Yes, I have a double bed.",note:"Feminine. Cama doble = double. Cama individual = single."},
{type:"teach",kind:"word",nl:"el sofá",en:"the sofa / couch",phonetic:"soh-FAH",example:"A: ¿Dónde está el sofá?\nB: El sofá está en el salón.",exampleEn:"A: Where is the sofa?\nB: The sofa is in the living room.",note:"Masculine. Accent on the last syllable."},
{type:"teach",kind:"word",nl:"la nevera",en:"the fridge",phonetic:"neh-BEH-rah",example:"A: ¿Hay leche en la nevera?\nB: No, la nevera está vacía.",exampleEn:"A: Is there milk in the fridge?\nB: No, the fridge is empty.",note:"Feminine. Also: el frigorífico (more formal, Spain)."},
{type:"teach",kind:"word",nl:"el armario",en:"the wardrobe / closet",phonetic:"ar-MAH-ree-oh",example:"A: ¿Dónde está tu ropa?\nB: En el armario del dormitorio.",exampleEn:"A: Where are your clothes?\nB: In the wardrobe in the bedroom.",note:"Masculine. Can also mean kitchen cabinet."},
{type:"tip",title:"Estar for Location",text:"Use ESTAR to say where things ARE:\nLa mesa está en la cocina.\nEl sofá está en el salón.\n\nUse HAY to say things EXIST:\nHay una mesa en la cocina.\n\nEstar = specific location (known item).\nHay = existence (unknown/new item).",icon:"📝"},
{type:"mc",q:"Which verb says WHERE a specific thing is?",opts:["estar","hay","ser","tener"],ans:"estar",hint:"To describe the location of something known, use this verb."},
{type:"fb",s:"El sofá {1} en el salón.",a:"está",opts:["está","hay","es","tiene"],hint:"The sofa is in a specific location. Use the location verb."},
{type:"match",pairs:[{nl:"la mesa",en:"table"},{nl:"la silla",en:"chair"},{nl:"la cama",en:"bed"},{nl:"el sofá",en:"sofa"},{nl:"la nevera",en:"fridge"}]},
{type:"mc",q:"Where would you normally find 'la nevera'?",opts:["en la cocina","en el dormitorio","en el jardín","en el baño"],ans:"en la cocina",hint:"This appliance keeps food cold. It belongs in the food room."},
{type:"fb",s:"¿{1} sillas en el jardín?",a:"Hay",opts:["Hay","Están","Son","Tienen"],hint:"Asking if chairs exist in the garden."},
{type:"mc",q:"'La cama está en el dormitorio' uses estar because:",opts:["It describes a location","It describes a quality","It describes an emotion","It describes an action"],ans:"It describes a location",hint:"Estar is used for WHERE things are physically placed."},
{type:"drag_fill",s:"En la cocina {1} una {2} y una {3}.",blanks:{1:"hay",2:"mesa",3:"nevera"},pool:["hay","mesa","nevera","está","cama","silla"],hint:"Say what exists in the kitchen."},
{type:"fb",s:"Mi ropa {1} en el armario.",a:"está",opts:["está","hay","es","tiene"],hint:"Your clothes are IN a specific place. Location verb."},
{type:"mc",q:"How do you say 'There is a sofa in the living room'?",opts:["Hay un sofá en el salón","Está un sofá en el salón","Es un sofá en el salón","Tiene un sofá"],ans:"Hay un sofá en el salón",hint:"Something EXISTS somewhere = hay."},
{type:"fb",s:"La {1} es grande y cómoda.",a:"cama",opts:["cama","mesa","silla","nevera"],hint:"You sleep on this piece of furniture."},
]},
// L3: -er/-ir Verbs — 18 steps
{id:"esp6l3",title:"Verbos -er / -ir",icon:"📖",xp:15,board:true,steps:[
{type:"intro",title:"Verbos -er / -ir",desc:"Learn the present tense of -er and -ir verbs.",goals:["Conjugate regular -er verbs","Conjugate regular -ir verbs","Spot the nosotros difference"]},
{type:"teach",kind:"word",nl:"comer",en:"to eat",phonetic:"koh-MER",example:"A: ¿Dónde comes hoy?\nB: Como en casa con mi familia.",exampleEn:"A: Where are you eating today?\nB: I'm eating at home with my family.",note:"-er verb: como, comes, come, comemos, comen."},
{type:"teach",kind:"word",nl:"beber",en:"to drink",phonetic:"beh-BER",example:"A: ¿Qué bebes por la mañana?\nB: Bebo café con leche.",exampleEn:"A: What do you drink in the morning?\nB: I drink coffee with milk.",note:"-er verb: bebo, bebes, bebe, bebemos, beben."},
{type:"teach",kind:"word",nl:"vivir",en:"to live",phonetic:"bee-BEER",example:"A: ¿Dónde vives?\nB: Vivo en Madrid.",exampleEn:"A: Where do you live?\nB: I live in Madrid.",note:"-ir verb: vivo, vives, vive, vivimos, viven."},
{type:"teach",kind:"word",nl:"escribir",en:"to write",phonetic:"ehs-kree-BEER",example:"A: ¿Escribes muchos mensajes?\nB: Sí, escribo mensajes todos los días.",exampleEn:"A: Do you write many messages?\nB: Yes, I write messages every day.",note:"-ir verb: escribo, escribes, escribe, escribimos, escriben."},
{type:"teach",kind:"word",nl:"leer",en:"to read",phonetic:"leh-ER",example:"A: ¿Qué lees?\nB: Leo un libro muy interesante.",exampleEn:"A: What are you reading?\nB: I'm reading a very interesting book.",note:"-er verb: leo, lees, lee, leemos, leen."},
{type:"tip",title:"-er and -ir Verb Endings",text:"-ER verbs (comer):\nyo como, tú comes, él come\nnosotros comemos, ellos comen\n\n-IR verbs (vivir):\nyo vivo, tú vives, él vive\nnosotros vivimos, ellos viven\n\nAlmost identical! Only nosotros differs:\n-emos vs -imos.",icon:"📝"},
{type:"mc",q:"What is the 'yo' form of 'comer'?",opts:["como","come","comes","comemos"],ans:"como",hint:"First person singular of -er verbs ends in -o."},
{type:"fb",s:"Ella {1} en Barcelona.",a:"vive",opts:["vive","vivo","vives","vivimos"],hint:"Third person singular of vivir."},
{type:"match",pairs:[{nl:"como",en:"I eat"},{nl:"bebes",en:"you drink"},{nl:"vive",en:"he/she lives"},{nl:"escribimos",en:"we write"},{nl:"leen",en:"they read"}]},
{type:"mc",q:"How do -er and -ir verbs differ in nosotros?",opts:["-emos vs -imos","-amos vs -imos","They are identical","-enos vs -inos"],ans:"-emos vs -imos",hint:"The only form where these two groups have different endings."},
{type:"fb",s:"Nosotros {1} en un restaurante.",a:"comemos",opts:["comemos","comimos","comen","como"],hint:"We eat. Nosotros + comer in present tense."},
{type:"mc",q:"Complete: 'Ellos ___ agua.'",opts:["beben","bebe","bebo","bebes"],ans:"beben",hint:"They (ellos) is third person plural. -er verb ending."},
{type:"drag_fill",s:"Yo {1} en Madrid y {2} en un restaurante.",blanks:{1:"vivo",2:"como"},pool:["vivo","como","vive","come","vivimos","comemos"],hint:"I live in Madrid and I eat at a restaurant."},
{type:"fb",s:"¿Qué {1} tú?",a:"lees",opts:["lees","lee","leo","leemos"],hint:"What do YOU read? Second person singular of leer."},
{type:"mc",q:"Translate: 'We write messages every day.'",opts:["Escribimos mensajes todos los días","Escriben mensajes todos los días","Escribo mensajes todos los días","Escribes mensajes todos los días"],ans:"Escribimos mensajes todos los días",hint:"We write = escribimos. The -imos ending for nosotros."},
{type:"fb",s:"Mi hermano {1} mucho café.",a:"bebe",opts:["bebe","bebo","bebes","beben"],hint:"He drinks. Third person singular."},
{type:"mc",q:"What does 'Nosotros vivimos en España' mean?",opts:["We live in Spain","They live in Spain","You live in Spain","I live in Spain"],ans:"We live in Spain",hint:"Nosotros = we, vivimos = we live."},
]},
// L4: Hay y Estar — 18 steps
{id:"esp6l4",title:"Hay y Estar",icon:"📍",xp:15,board:true,steps:[
{type:"intro",title:"Hay y Estar",desc:"Master the difference between hay (existence) and estar (location).",goals:["Use hay for existence","Use estar for location","Combine both in descriptions"]},
{type:"teach",kind:"phrase",nl:"hay",en:"there is / there are",phonetic:"AH-ee",example:"A: ¿Hay un supermercado cerca?\nB: Sí, hay uno en la calle Mayor.",exampleEn:"A: Is there a supermarket nearby?\nB: Yes, there's one on Main Street.",note:"Hay never changes form. Works for singular and plural."},
{type:"teach",kind:"phrase",nl:"está / están",en:"is (located) / are (located)",phonetic:"ehs-TAH / ehs-TAHN",example:"A: ¿Dónde está el supermercado?\nB: Está en la calle Mayor.",exampleEn:"A: Where is the supermarket?\nB: It's on Main Street.",note:"Estar for location: está (singular), están (plural)."},
{type:"teach",kind:"word",nl:"cerca",en:"near / nearby",phonetic:"SER-kah",example:"A: ¿Está cerca el colegio?\nB: Sí, está muy cerca.",exampleEn:"A: Is the school nearby?\nB: Yes, it's very near.",note:"Cerca de = near to. Mi casa está cerca del parque."},
{type:"teach",kind:"word",nl:"lejos",en:"far",phonetic:"LEH-hohs",example:"A: ¿Está lejos la playa?\nB: No, no está lejos.",exampleEn:"A: Is the beach far?\nB: No, it's not far.",note:"Lejos de = far from. El aeropuerto está lejos del centro."},
{type:"tip",title:"Hay vs Estar: The Key Rule",text:"HAY = something EXISTS (unknown/indefinite):\n¿Hay un banco? Hay dos sillas.\n\nESTAR = WHERE something IS (known/definite):\n¿Dónde está el banco?\nLas sillas están en el jardín.\n\nHay + un/una/number (indefinite)\nEstar + el/la/name (definite)",icon:"💡"},
{type:"mc",q:"'¿Hay un restaurante cerca?' uses hay because:",opts:["We ask if one EXISTS","We know which restaurant","We know where it is","The restaurant is definite"],ans:"We ask if one EXISTS",hint:"Hay asks about the existence of something unknown."},
{type:"fb",s:"¿Dónde {1} la biblioteca?",a:"está",opts:["está","hay","es","tiene"],hint:"Asking WHERE a specific known place is located."},
{type:"mc",q:"Which is correct?",opts:["Hay tres sillas en la cocina","Están tres sillas en la cocina","Son tres sillas en la cocina","Tienen tres sillas"],ans:"Hay tres sillas en la cocina",hint:"Stating that chairs EXIST somewhere uses hay."},
{type:"fb",s:"{1} un parque cerca de mi casa.",a:"Hay",opts:["Hay","Está","Es","Tiene"],hint:"A park exists near your house. Use the existence word."},
{type:"match",pairs:[{nl:"Hay un banco",en:"There is a bank"},{nl:"El banco está aquí",en:"The bank is here"},{nl:"Hay dos gatos",en:"There are two cats"},{nl:"Los gatos están fuera",en:"The cats are outside"}]},
{type:"mc",q:"'Las sillas están en el jardín' uses estar because:",opts:["It tells WHERE specific chairs are","It says chairs exist","It describes the chairs","It counts the chairs"],ans:"It tells WHERE specific chairs are",hint:"Known chairs in a specific location = estar."},
{type:"drag_fill",s:"{1} una farmacia {2}, pero {3} un poco {4}.",blanks:{1:"Hay",2:"cerca",3:"está",4:"lejos"},pool:["Hay","cerca","está","lejos","Es","dentro"],hint:"A pharmacy exists nearby, but it is located somewhat far."},
{type:"fb",s:"¿{1} lejos el aeropuerto?",a:"Está",opts:["Está","Hay","Es","Tiene"],hint:"Asking if a known place is far. Location question."},
{type:"mc",q:"Translate: 'There are many restaurants nearby.'",opts:["Hay muchos restaurantes cerca","Están muchos restaurantes cerca","Son muchos restaurantes","Los restaurantes están cerca"],ans:"Hay muchos restaurantes cerca",hint:"Restaurants exist (hay). Not asking about specific ones."},
{type:"fb",s:"El supermercado {1} en la calle Mayor.",a:"está",opts:["está","hay","es","tiene"],hint:"A specific store at a specific location."},
{type:"mc",q:"How do you say 'Is there a pharmacy nearby?'",opts:["¿Hay una farmacia cerca?","¿Está una farmacia cerca?","¿Es una farmacia cerca?","¿Tiene farmacia?"],ans:"¿Hay una farmacia cerca?",hint:"Asking if something EXISTS uses hay."},
{type:"fb",s:"Los niños {1} en el parque.",a:"están",opts:["están","hay","son","tienen"],hint:"Known people at a known location. Plural of estar."},
]},
// L5: Las Preposiciones — 18 steps
{id:"esp6l5",title:"Las Preposiciones",icon:"📦",xp:15,board:true,steps:[
{type:"intro",title:"Las Preposiciones",desc:"Learn prepositions of place to describe where things are.",goals:["Use en, sobre, debajo de, al lado de","Describe object locations","Learn del and al contractions"]},
{type:"teach",kind:"word",nl:"en",en:"in / on / at",phonetic:"EN",example:"A: ¿Dónde está el libro?\nB: Está en la mesa.",exampleEn:"A: Where is the book?\nB: It's on the table.",note:"Very versatile: en la mesa (on), en la cocina (in), en casa (at)."},
{type:"teach",kind:"phrase",nl:"sobre / encima de",en:"on top of",phonetic:"SOH-breh / en-SEE-mah deh",example:"A: ¿Dónde están las llaves?\nB: Están sobre la mesa.",exampleEn:"A: Where are the keys?\nB: They're on top of the table.",note:"Sobre and encima de both mean 'on top of'."},
{type:"teach",kind:"phrase",nl:"debajo de",en:"under / below",phonetic:"deh-BAH-hoh deh",example:"A: ¿Dónde está el gato?\nB: Está debajo de la cama.",exampleEn:"A: Where is the cat?\nB: It's under the bed.",note:"Always followed by 'de': debajo de la mesa."},
{type:"teach",kind:"phrase",nl:"al lado de",en:"next to / beside",phonetic:"al LAH-doh deh",example:"A: ¿Dónde está el banco?\nB: Está al lado del supermercado.",exampleEn:"A: Where is the bank?\nB: It's next to the supermarket.",note:"Al lado de = next to. Del = de + el (contraction)."},
{type:"teach",kind:"phrase",nl:"entre",en:"between",phonetic:"EN-treh",example:"A: ¿Dónde está la farmacia?\nB: Está entre el banco y el restaurante.",exampleEn:"A: Where is the pharmacy?\nB: It's between the bank and the restaurant.",note:"Entre + noun + y + noun. Always connects two things."},
{type:"tip",title:"Contractions: del and al",text:"de + el = del (mandatory contraction)\nEl gato está debajo del sofá.\n\na + el = al (mandatory contraction)\nVoy al supermercado.\n\nNO contraction with la/los/las:\ndebajo de la mesa (correct)\nal lado de la tienda (correct)",icon:"📝"},
{type:"mc",q:"'El gato está ___ la cama.'",opts:["debajo de","debajo","bajo de","en debajo"],ans:"debajo de",hint:"Under the bed requires debajo + de before the noun."},
{type:"fb",s:"Las llaves están {1} la mesa.",a:"sobre",opts:["sobre","debajo","entre","detrás"],hint:"The keys are ON TOP of the table."},
{type:"match",pairs:[{nl:"sobre",en:"on top of"},{nl:"debajo de",en:"under"},{nl:"al lado de",en:"next to"},{nl:"entre",en:"between"},{nl:"en",en:"in/on/at"}]},
{type:"mc",q:"'de + el' becomes:",opts:["del","de el","dal","d'el"],ans:"del",hint:"This is a mandatory contraction in Spanish."},
{type:"fb",s:"La farmacia está {1} el banco y el restaurante.",a:"entre",opts:["entre","al lado","debajo","sobre"],hint:"The pharmacy is in the middle of two places."},
{type:"mc",q:"Translate: 'The car is in front of the house.'",opts:["El coche está delante de la casa","El coche está detrás de la casa","El coche está al lado de la casa","El coche hay delante"],ans:"El coche está delante de la casa",hint:"Delante de = in front of. Use estar for location."},
{type:"drag_fill",s:"El gato está {1} {2} sofá y la silla está {3} {4} la mesa.",blanks:{1:"debajo",2:"del",3:"al lado",4:"de"},pool:["debajo","del","al lado","de","sobre","entre"],hint:"Cat under the sofa (de + el = del), chair next to the table."},
{type:"fb",s:"El coche está {1} de la casa.",a:"detrás",opts:["detrás","delante","encima","dentro"],hint:"The car is BEHIND the house, not in front."},
{type:"mc",q:"Which uses the contraction 'al'?",opts:["Voy al supermercado","Voy a la tienda","Voy a los parques","Voy a las casas"],ans:"Voy al supermercado",hint:"a + el = al. Only with masculine singular el."},
{type:"mc",q:"'El libro está entre la lámpara y la ventana' means:",opts:["The book is between the lamp and the window","The book is on the lamp and the window","The book is under the lamp","The book is next to the window"],ans:"The book is between the lamp and the window",hint:"Entre connects two objects with 'y' (and)."},
{type:"fb",s:"El gato está {1} de la puerta.",a:"delante",opts:["delante","debajo","sobre","entre"],hint:"The cat is in front of the door, facing you."},
]},
// L6: Mi Dormitorio — 18 steps
{id:"esp6l6",title:"Mi Dormitorio",icon:"🛏️",xp:15,board:true,steps:[
{type:"intro",title:"Mi Dormitorio",desc:"Describe your bedroom using furniture and prepositions.",goals:["Describe a bedroom","Combine furniture + preposition + estar","Use ser vs estar for rooms"]},
{type:"teach",kind:"word",nl:"la ventana",en:"the window",phonetic:"ben-TAH-nah",example:"A: ¿Hay una ventana en tu dormitorio?\nB: Sí, hay una ventana grande.",exampleEn:"A: Is there a window in your bedroom?\nB: Yes, there's a big window.",note:"Feminine. V in Spanish sounds like soft B."},
{type:"teach",kind:"word",nl:"la puerta",en:"the door",phonetic:"PWER-tah",example:"A: ¿Está abierta la puerta?\nB: No, la puerta está cerrada.",exampleEn:"A: Is the door open?\nB: No, the door is closed.",note:"Feminine. Abierta = open, cerrada = closed."},
{type:"teach",kind:"word",nl:"la lámpara",en:"the lamp",phonetic:"LAHM-pah-rah",example:"A: ¿Dónde está la lámpara?\nB: La lámpara está sobre la mesa.",exampleEn:"A: Where is the lamp?\nB: The lamp is on the table.",note:"Feminine. Accent on the first syllable."},
{type:"teach",kind:"word",nl:"la alfombra",en:"the rug / carpet",phonetic:"al-FOHM-brah",example:"A: ¿De qué color es la alfombra?\nB: La alfombra es azul.",exampleEn:"A: What color is the rug?\nB: The rug is blue.",note:"Feminine. From Arabic (many al- words in Spanish come from Arabic)."},
{type:"teach",kind:"word",nl:"el escritorio",en:"the desk",phonetic:"ehs-kree-TOH-ree-oh",example:"A: ¿Dónde estudias?\nB: Estudio en mi escritorio.",exampleEn:"A: Where do you study?\nB: I study at my desk.",note:"Masculine. From escribir (to write)."},
{type:"tip",title:"Ser vs Estar for Rooms",text:"SER = permanent qualities:\nMi dormitorio es grande.\nLa cocina es pequeña.\n\nESTAR = location or current state:\nLa cama está al lado de la ventana.\nLa puerta está cerrada.\n\nSer = what it IS.\nEstar = where it IS or how it IS right now.",icon:"📝"},
{type:"mc",q:"'La alfombra' comes from which language?",opts:["Arabic","Latin","French","Greek"],ans:"Arabic",hint:"Many Spanish words starting with 'al-' have this origin."},
{type:"fb",s:"La lámpara {1} sobre el escritorio.",a:"está",opts:["está","es","hay","tiene"],hint:"The lamp is at a specific location. Use estar."},
{type:"match",pairs:[{nl:"la ventana",en:"window"},{nl:"la puerta",en:"door"},{nl:"la lámpara",en:"lamp"},{nl:"la alfombra",en:"rug"},{nl:"el escritorio",en:"desk"}]},
{type:"mc",q:"How do you say 'My bedroom is small'?",opts:["Mi dormitorio es pequeño","Mi dormitorio está pequeño","Mi dormitorio tiene pequeño","Hay pequeño dormitorio"],ans:"Mi dormitorio es pequeño",hint:"A permanent quality of the room = ser, not estar."},
{type:"fb",s:"La cama está al lado de la {1}.",a:"ventana",opts:["ventana","puerta","alfombra","lámpara"],hint:"The bed is next to the opening that lets light in."},
{type:"mc",q:"Which is correct for a big kitchen?",opts:["La cocina es grande","La cocina está grande","La cocina tiene grande","Hay grande cocina"],ans:"La cocina es grande",hint:"Size is a quality. Qualities use ser."},
{type:"drag_fill",s:"Mi dormitorio {1} {2}. La cama {3} al lado {4} la ventana.",blanks:{1:"es",2:"pequeño",3:"está",4:"de"},pool:["es","pequeño","está","de","hay","grande"],hint:"Quality = ser. Location = estar."},
{type:"fb",s:"¿Está {1} la puerta?",a:"abierta",opts:["abierta","cerrada","grande","pequeña"],hint:"Asking if the door is in the open state."},
{type:"mc",q:"Translate: 'There is a blue rug under the desk.'",opts:["Hay una alfombra azul debajo del escritorio","Está una alfombra azul debajo del escritorio","Hay una alfombra azul sobre el escritorio","Una alfombra está debajo"],ans:"Hay una alfombra azul debajo del escritorio",hint:"Something exists (hay) under (debajo de + el = del) the desk."},
{type:"fb",s:"El dormitorio {1} pequeño pero cómodo.",a:"es",opts:["es","está","hay","tiene"],hint:"A permanent quality of the room. Use ser."},
{type:"mc",q:"'La ventana está abierta' means:",opts:["The window is open","The window is closed","The window is big","The window is new"],ans:"The window is open",hint:"Abierta describes a temporary state of the window."},
]},
// L7: Las Tareas del Hogar — 18 steps
{id:"esp6l7",title:"Las Tareas del Hogar",icon:"🧹",xp:15,board:true,steps:[
{type:"intro",title:"Las Tareas del Hogar",desc:"Learn household chores and talk about obligations.",goals:["Name 6 household chores","Use tener que + infinitive","Talk about who does what"]},
{type:"teach",kind:"phrase",nl:"limpiar",en:"to clean",phonetic:"leem-pee-AR",example:"A: ¿Quién limpia la casa?\nB: Yo limpio los sábados.",exampleEn:"A: Who cleans the house?\nB: I clean on Saturdays.",note:"Regular -ar: limpio, limpias, limpia, limpiamos, limpian."},
{type:"teach",kind:"phrase",nl:"cocinar",en:"to cook",phonetic:"koh-see-NAR",example:"A: ¿Sabes cocinar?\nB: Sí, cocino todos los días.",exampleEn:"A: Do you know how to cook?\nB: Yes, I cook every day.",note:"Regular -ar verb. Related to la cocina (kitchen)."},
{type:"teach",kind:"phrase",nl:"lavar los platos",en:"to wash the dishes",phonetic:"lah-BAR lohs PLAH-tohs",example:"A: ¿Quién lava los platos?\nB: Yo lavo los platos después de comer.",exampleEn:"A: Who does the dishes?\nB: I do the dishes after eating.",note:"Lavar = to wash. Also: lavar la ropa = to do laundry."},
{type:"teach",kind:"phrase",nl:"hacer la cama",en:"to make the bed",phonetic:"ah-SER lah KAH-mah",example:"A: ¿Haces la cama por la mañana?\nB: Sí, siempre hago la cama.",exampleEn:"A: Do you make the bed in the morning?\nB: Yes, I always make the bed.",note:"Hacer = to do/make. Irregular: hago, haces, hace, hacemos, hacen."},
{type:"teach",kind:"phrase",nl:"tener que + infinitivo",en:"to have to + verb",phonetic:"teh-NER keh",example:"A: ¿Qué tienes que hacer hoy?\nB: Tengo que limpiar la cocina.",exampleEn:"A: What do you have to do today?\nB: I have to clean the kitchen.",note:"Tener que = have to/must. Tengo que, tienes que, tiene que..."},
{type:"tip",title:"Tener que + Infinitive",text:"Tener que + infinitive = have to/must:\nTengo que limpiar. = I have to clean.\nTienes que cocinar. = You have to cook.\nTenemos que lavar. = We have to wash.\n\nThe main verb (tener) conjugates.\nThe second verb stays in infinitive.",icon:"📝"},
{type:"mc",q:"How do you say 'I have to cook'?",opts:["Tengo que cocinar","Tengo cocinar","Tengo de cocinar","Cocino que tengo"],ans:"Tengo que cocinar",hint:"Tener + que + infinitive. The formula never changes."},
{type:"fb",s:"Ella {1} que lavar los platos.",a:"tiene",opts:["tiene","tengo","tienes","tenemos"],hint:"She has to. Third person singular of tener."},
{type:"match",pairs:[{nl:"limpiar",en:"to clean"},{nl:"cocinar",en:"to cook"},{nl:"lavar los platos",en:"to do the dishes"},{nl:"hacer la cama",en:"to make the bed"},{nl:"tener que",en:"to have to"}]},
{type:"mc",q:"'Hago la cama' uses 'hago' because:",opts:["Hacer is irregular in the yo form","Hacer follows regular -er rules","It's a spelling change","Both haco and hago work"],ans:"Hacer is irregular in the yo form",hint:"Hacer has an irregular first person: yo hago."},
{type:"fb",s:"¿Quién {1} la casa los sábados?",a:"limpia",opts:["limpia","limpio","limpias","limpiamos"],hint:"Asking who (third person) cleans on Saturdays."},
{type:"mc",q:"Translate: 'We have to vacuum today.'",opts:["Tenemos que pasar la aspiradora hoy","Tenemos pasar la aspiradora hoy","Pasamos que tener la aspiradora","Hay pasar aspiradora"],ans:"Tenemos que pasar la aspiradora hoy",hint:"We have to = tenemos que + infinitive."},
{type:"drag_fill",s:"Yo {1} que {2} la cocina y mi hermano {3} que lavar los {4}.",blanks:{1:"tengo",2:"limpiar",3:"tiene",4:"platos"},pool:["tengo","limpiar","tiene","platos","tienes","cocinar"],hint:"I have to clean, he has to wash dishes."},
{type:"fb",s:"Siempre {1} la cama por la mañana.",a:"hago",opts:["hago","haces","hace","hacemos"],hint:"I always make the bed. First person of hacer."},
{type:"mc",q:"Which chore involves 'la ropa'?",opts:["Lavar la ropa","Pasar la aspiradora","Hacer la cama","Limpiar la cocina"],ans:"Lavar la ropa",hint:"Ropa = clothes. This chore involves washing them."},
{type:"fb",s:"Tenemos que {1} la ropa los domingos.",a:"lavar",opts:["lavar","lavamos","lava","lavas"],hint:"After tener que, use the infinitive form."},
{type:"mc",q:"What does 'Mi madre cocina todos los días' mean?",opts:["My mother cooks every day","My mother cleans every day","My mother washes every day","My mother works every day"],ans:"My mother cooks every day",hint:"Cocina comes from cocinar, related to la cocina (kitchen)."},
{type:"fb",s:"Yo {1} los platos y mi hermana limpia la cocina.",a:"lavo",opts:["lavo","lavas","lava","lavamos"],hint:"I wash. First person singular of lavar."},
]},
// L8: Mi Casa Ideal review — 18 steps
{id:"esp6l8",title:"Mi Casa Ideal",icon:"🏡",xp:15,board:true,steps:[
{type:"intro",title:"Mi Casa Ideal",desc:"Describe your ideal house combining all vocabulary from this unit.",goals:["Describe rooms and furniture","Use hay, estar, ser correctly","Talk about chores and locations"]},
{type:"mc",q:"Which verb describes WHERE something is?",opts:["estar","hay","ser","tener"],ans:"estar",hint:"For the specific location of known things."},
{type:"fb",s:"{1} tres dormitorios en mi casa.",a:"Hay",opts:["Hay","Están","Son","Tienen"],hint:"Stating that bedrooms EXIST in the house."},
{type:"match",pairs:[{nl:"la cocina",en:"kitchen"},{nl:"el jardín",en:"garden"},{nl:"el baño",en:"bathroom"},{nl:"el escritorio",en:"desk"},{nl:"la alfombra",en:"rug"}]},
{type:"mc",q:"'Mi dormitorio es grande' uses ser because:",opts:["Size is a permanent quality","Size is a location","Size is temporary","Size uses estar"],ans:"Size is a permanent quality",hint:"Characteristics always use ser."},
{type:"fb",s:"La mesa {1} en la cocina.",a:"está",opts:["está","hay","es","tiene"],hint:"A specific table at a specific place. Location = estar."},
{type:"drag_fill",s:"En el salón {1} un {2} grande y la tele {3} {4} la mesa.",blanks:{1:"hay",2:"sofá",3:"está",4:"sobre"},pool:["hay","sofá","está","sobre","es","debajo"],hint:"A sofa exists in the room, TV is on the table."},
{type:"mc",q:"How do you say 'I have to clean the bathroom'?",opts:["Tengo que limpiar el baño","Tengo limpiar el baño","Limpio que tengo el baño","Hay limpiar baño"],ans:"Tengo que limpiar el baño",hint:"Tener que + infinitive."},
{type:"fb",s:"El gato está {1} de la cama.",a:"debajo",opts:["debajo","sobre","entre","delante"],hint:"The cat is UNDER the bed, hiding."},
{type:"mc",q:"Translate: 'There is a lamp on the desk.'",opts:["Hay una lámpara sobre el escritorio","Está una lámpara sobre el escritorio","La lámpara hay sobre el escritorio","Hay lámpara debajo"],ans:"Hay una lámpara sobre el escritorio",hint:"Something exists (hay) on top of (sobre) the desk."},
{type:"drag_fill",s:"Mi hermana {1} que {2} la cama y yo {3} que {4} los platos.",blanks:{1:"tiene",2:"hacer",3:"tengo",4:"lavar"},pool:["tiene","hacer","tengo","lavar","tienes","limpiar"],hint:"She makes the bed, I do the dishes."},
{type:"fb",s:"El armario está al {1} de la cama.",a:"lado",opts:["lado","fondo","frente","centro"],hint:"The wardrobe is NEXT to the bed. Al ___ de."},
{type:"mc",q:"Which correctly uses both hay and estar?",opts:["Hay un parque cerca. El parque está al lado del colegio.","Hay un parque cerca. El parque hay al lado del colegio.","Está un parque cerca. Hay al lado del colegio.","El parque hay cerca."],ans:"Hay un parque cerca. El parque está al lado del colegio.",hint:"Hay introduces. Estar locates."},
{type:"match",pairs:[{nl:"limpiar",en:"to clean"},{nl:"sobre",en:"on top of"},{nl:"debajo de",en:"under"},{nl:"al lado de",en:"next to"},{nl:"tener que",en:"to have to"}]},
{type:"fb",s:"Mi casa {1} pequeña pero muy bonita.",a:"es",opts:["es","está","hay","tiene"],hint:"Permanent quality of the house. Use ser."},
{type:"mc",q:"Complete: 'La puerta ___ cerrada.'",opts:["está","es","hay","tiene"],ans:"está",hint:"Current state (closed). Conditions use estar."},
{type:"mc",q:"Which uses estar (not ser)?",opts:["La puerta está cerrada","Mi casa es grande","El jardín es bonito","La cocina es pequeña"],ans:"La puerta está cerrada",hint:"Current state/condition = estar. Quality = ser."},
{type:"fb",s:"¿{1} un banco cerca de aquí?",a:"Hay",opts:["Hay","Está","Es","Tiene"],hint:"Asking if a bank EXISTS nearby."},
]}
]},
// ══════════════════════════════════════════════════════════════
// UNIT 7: ¿Dónde Está? — Directions & Transport (A1.4)
// 8 lessons, 18+ steps each
// ══════════════════════════════════════════════════════════════
{n:7,lang:"es",track:"v1",title:"¿Dónde Está?",sub:"Directions & Transport",icon:"🗺️",level:"A1.4",color:"#7B5EE8",lessons:[
  {id:"esp7l1",title:"Lugares de la Ciudad",icon:"🏙️",xp:15,board:true,steps:[
    {type:"intro",title:"Lugares de la Ciudad",desc:"Learn the names of important places you will find in any Spanish-speaking city.",goals:["Name 8 common city places","Use estar to locate places","Ask where places are"]},
    {type:"teach",kind:"word",nl:"el banco",en:"the bank",phonetic:"el BAN-koh",example:"A: ¿Dónde está el banco?\nB: El banco está en la calle Mayor.\nA: Gracias, señor.",exampleEn:"A: Where is the bank?\nB: The bank is on Main Street.\nA: Thank you, sir.",note:"Where you go for money. Not a bench (that is el banquete)."},
    {type:"teach",kind:"word",nl:"la farmacia",en:"the pharmacy",phonetic:"la far-MA-see-ah",example:"A: Necesito una farmacia.\nB: Hay una farmacia cerca de aquí.\nA: ¿Dónde exactamente?",exampleEn:"A: I need a pharmacy.\nB: There is a pharmacy near here.\nA: Where exactly?",note:"Look for the green cross sign in Spanish cities.",cognate:"pharmacy"},
    {type:"teach",kind:"word",nl:"el hospital",en:"the hospital",phonetic:"el os-pee-TAL",example:"A: ¿El hospital está lejos?\nB: No, está muy cerca.\nA: ¡Qué bien!",exampleEn:"A: Is the hospital far?\nB: No, it is very close.\nA: That's great!",note:"Stress falls on the last syllable: hospiTAL.",cognate:"hospital"},
    {type:"teach",kind:"word",nl:"la estación",en:"the station",phonetic:"la es-tah-see-ON",example:"A: ¿Dónde está la estación?\nB: La estación está al final de esta calle.\nA: Muchas gracias.",exampleEn:"A: Where is the station?\nB: The station is at the end of this street.\nA: Thank you very much.",note:"Can be la estación de tren (train) or de autobús (bus)."},
    {type:"teach",kind:"word",nl:"el supermercado",en:"the supermarket",phonetic:"el soo-per-mer-KA-doh",example:"A: ¿Hay un supermercado aquí?\nB: Sí, hay uno al lado del banco.\nA: Perfecto.",exampleEn:"A: Is there a supermarket here?\nB: Yes, there is one next to the bank.\nA: Perfect.",note:"A large grocery store. A smaller one is la tienda.",cognate:"supermarket"},
    {type:"teach",kind:"word",nl:"la iglesia",en:"the church",phonetic:"la ee-GLEH-see-ah",example:"A: ¿Ves la iglesia?\nB: Sí, es muy bonita.\nA: Es muy antigua.",exampleEn:"A: Do you see the church?\nB: Yes, it is very beautiful.\nA: It is very old.",note:"Every Spanish town has one in the plaza central."},
    {type:"teach",kind:"word",nl:"el parque",en:"the park",phonetic:"el PAR-keh",example:"A: ¿Vamos al parque?\nB: Sí, el parque está cerca.\nA: ¡Vamos!",exampleEn:"A: Shall we go to the park?\nB: Yes, the park is close.\nA: Let's go!",note:"A green space in the city. El Retiro is famous in Madrid."},
    {type:"teach",kind:"word",nl:"el museo",en:"the museum",phonetic:"el moo-SEH-oh",example:"A: ¿Te gusta el museo?\nB: Sí, me gusta mucho el museo de arte.\nA: A mí también.",exampleEn:"A: Do you like the museum?\nB: Yes, I like the art museum a lot.\nA: Me too.",note:"El Prado in Madrid is one of the world's great museums.",cognate:"museum"},
    {type:"tip",title:"Estar for Location",text:"Use estar (not ser) to say where something IS located:\n\nEl banco está aquí. (The bank is here.)\nLa farmacia está lejos. (The pharmacy is far.)\n\nRemember: estar = location and condition.\nser = identity and characteristics."},
    {type:"mc",q:"¿Dónde compras comida?",opts:["En el supermercado","En el hospital","En la iglesia","En el museo"],ans:"En el supermercado",hint:"Think about which place sells food and groceries."},
    {type:"mc",q:"You need medicine. Where do you go?",opts:["La farmacia","El banco","El parque","La estación"],ans:"La farmacia",hint:"This place has a green cross sign outside."},
    {type:"fb",s:"El hospital {1} cerca de aquí.",a:"está",opts:["está","es","hay","son"],hint:"You are describing where something is located."},
    {type:"fb",s:"¿Dónde {1} la estación de tren?",a:"está",opts:["está","es","hay","son"],hint:"Asking about the location of a specific place."},
    {type:"match",pairs:[{nl:"el banco",en:"the bank"},{nl:"la farmacia",en:"the pharmacy"},{nl:"el hospital",en:"the hospital"},{nl:"la estación",en:"the station"},{nl:"el supermercado",en:"the supermarket"}]},
    {type:"mc",q:"La iglesia está en la plaza central. What is the iglesia?",opts:["The church","The school","The library","The theater"],ans:"The church",hint:"This building is often found in the main square of Spanish towns."},
    {type:"fb",s:"¿Hay un {1} cerca de aquí?",a:"parque",opts:["parque","está","banco está","iglesia está"],hint:"You want to find a green space to relax outdoors."},
    {type:"mc",q:"Which place would you visit to see paintings and sculptures?",opts:["El museo","El banco","La estación","El supermercado"],ans:"El museo",hint:"This is where art and historical objects are displayed."},
    {type:"mc",q:"El parque está al lado del museo. What does 'al lado del' mean?",opts:["Next to","Far from","Behind","In front of"],ans:"Next to",hint:"You learned this preposition when describing your home."}
  ]},
  {id:"esp7l2",title:"¿Dónde Está...?",icon:"❓",xp:15,board:true,steps:[
    {type:"intro",title:"¿Dónde Está...?",desc:"Learn how to ask for directions politely in Spanish.",goals:["Ask where places are","Use polite expressions","Understand simple location answers"]},
    {type:"teach",kind:"phrase",nl:"¿Dónde está...?",en:"Where is...?",phonetic:"DON-deh es-TA",example:"A: Perdone, ¿dónde está el banco?\nB: Está en la calle Sol.\nA: Gracias.",exampleEn:"A: Excuse me, where is the bank?\nB: It is on Sol Street.\nA: Thank you.",note:"The most common way to ask for a location."},
    {type:"teach",kind:"phrase",nl:"¿Cómo llego a...?",en:"How do I get to...?",phonetic:"KO-moh YEH-goh ah",example:"A: ¿Cómo llego al hospital?\nB: Sigue todo recto.\nA: ¿Está lejos?",exampleEn:"A: How do I get to the hospital?\nB: Go straight ahead.\nA: Is it far?",note:"Llegar means to arrive. Llego is the yo form."},
    {type:"teach",kind:"word",nl:"perdone",en:"excuse me (formal)",phonetic:"per-DOH-neh",example:"A: Perdone, ¿hay una farmacia por aquí?\nB: Sí, hay una en la esquina.\nA: Muchas gracias.",exampleEn:"A: Excuse me, is there a pharmacy around here?\nB: Yes, there is one on the corner.\nA: Thank you very much.",note:"Formal form of perdonar. Use with strangers."},
    {type:"teach",kind:"word",nl:"disculpe",en:"excuse me, pardon me (formal)",phonetic:"dis-KOOL-peh",example:"A: Disculpe, ¿dónde está el metro?\nB: El metro está detrás de la iglesia.\nA: Perfecto, gracias.",exampleEn:"A: Excuse me, where is the metro?\nB: The metro is behind the church.\nA: Perfect, thank you.",note:"Slightly more formal than perdone. Both work with strangers."},
    {type:"teach",kind:"phrase",nl:"por aquí",en:"around here",phonetic:"por ah-KEE",example:"A: ¿Hay un banco por aquí?\nB: Sí, hay uno muy cerca.\nA: ¿Dónde exactamente?",exampleEn:"A: Is there a bank around here?\nB: Yes, there is one very close.\nA: Where exactly?",note:"Use when you want to find something nearby."},
    {type:"teach",kind:"word",nl:"la calle",en:"the street",phonetic:"la KA-yeh",example:"A: ¿En qué calle está el museo?\nB: Está en la calle Alcalá.\nA: Gracias, disculpe.",exampleEn:"A: On which street is the museum?\nB: It is on Alcalá Street.\nA: Thank you, excuse me.",note:"The main road through a city. La avenida is a wider road."},
    {type:"tip",title:"Asking for Directions",text:"Two common patterns:\n\n1. ¿Dónde está + place?\n   ¿Dónde está el banco?\n\n2. ¿Cómo llego a + place?\n   ¿Cómo llego al museo?\n\nNote: a + el = al.\nStart with perdone or disculpe to be polite."},
    {type:"mc",q:"You want to find the station. What do you ask?",opts:["¿Dónde está la estación?","¿Cómo es la estación?","¿Cuándo está la estación?","¿Quién está la estación?"],ans:"¿Dónde está la estación?",hint:"You need the question word for location, not time or identity."},
    {type:"mc",q:"What does '¿Cómo llego al parque?' mean?",opts:["How do I get to the park?","Where is the park?","Do you like the park?","Is the park open?"],ans:"How do I get to the park?",hint:"Llegar means to arrive. Cómo asks about the manner or way."},
    {type:"fb",s:"Perdone, ¿{1} está la farmacia?",a:"dónde",opts:["dónde","cómo","cuándo","quién"],hint:"You need the question word that asks about a place."},
    {type:"fb",s:"¿Cómo {1} al hospital?",a:"llego",opts:["llego","está","hay","es"],hint:"You need the yo form of the verb meaning to arrive."},
    {type:"match",pairs:[{nl:"¿Dónde está?",en:"Where is it?"},{nl:"perdone",en:"excuse me"},{nl:"disculpe",en:"pardon me"},{nl:"por aquí",en:"around here"},{nl:"la calle",en:"the street"},{nl:"¿Cómo llego?",en:"How do I get there?"}]},
    {type:"mc",q:"Perdone, ¿hay un supermercado por aquí? What does 'por aquí' mean?",opts:["Around here","Over there","Very far","Next door"],ans:"Around here",hint:"This phrase refers to the general nearby area."},
    {type:"fb",s:"Disculpe, ¿hay una {1} por aquí?",a:"farmacia",opts:["farmacia","cómo","dónde","está"],hint:"You need medicine. Which place sells it?"},
    {type:"mc",q:"Which expression is used to politely get a stranger's attention?",opts:["Perdone","Hola","Adiós","Gracias"],ans:"Perdone",hint:"This word comes from the verb perdonar."},
    {type:"fb",s:"¿Dónde está {1} museo?",a:"el",opts:["el","la","un","los"],hint:"Museo is a masculine noun. Which article fits?"},
    {type:"mc",q:"El banco está en la calle Mayor. Where is the bank?",opts:["On Mayor Street","In the park","Behind the church","Next to the station"],ans:"On Mayor Street",hint:"La calle means the street. Mayor is the name of the street."}
  ]},
  {id:"esp7l3",title:"Gira a la Derecha",icon:"➡️",xp:15,board:true,steps:[
    {type:"intro",title:"Gira a la Derecha",desc:"Learn how to give and understand basic directions in Spanish.",goals:["Give simple directions","Understand left, right, straight","Use direction phrases with confidence"]},
    {type:"teach",kind:"phrase",nl:"todo recto",en:"straight ahead",phonetic:"TOH-doh REK-toh",example:"A: ¿Cómo llego al banco?\nB: Sigue todo recto.\nA: ¿Y luego?",exampleEn:"A: How do I get to the bank?\nB: Go straight ahead.\nA: And then?",note:"The most common direction. Recto means straight."},
    {type:"teach",kind:"phrase",nl:"a la derecha",en:"to the right",phonetic:"ah la deh-REH-chah",example:"A: ¿Dónde está la farmacia?\nB: Gira a la derecha.\nA: Gracias.",exampleEn:"A: Where is the pharmacy?\nB: Turn to the right.\nA: Thank you.",note:"La derecha is the right side. Use with girar (to turn)."},
    {type:"teach",kind:"phrase",nl:"a la izquierda",en:"to the left",phonetic:"ah la eez-kee-EHR-dah",example:"A: ¿Cómo llego a la estación?\nB: Gira a la izquierda en la esquina.\nA: ¿En la primera esquina?",exampleEn:"A: How do I get to the station?\nB: Turn left at the corner.\nA: At the first corner?",note:"La izquierda is the left side. Careful with the spelling."},
    {type:"teach",kind:"phrase",nl:"en la esquina",en:"on the corner",phonetic:"en la es-KEE-nah",example:"A: ¿Dónde está el banco?\nB: Está en la esquina.\nA: ¿En esta esquina?",exampleEn:"A: Where is the bank?\nB: It is on the corner.\nA: On this corner?",note:"La esquina is where two streets meet."},
    {type:"teach",kind:"phrase",nl:"al final de",en:"at the end of",phonetic:"al fee-NAL deh",example:"A: ¿Dónde está el parque?\nB: Está al final de esta calle.\nA: No está lejos entonces.",exampleEn:"A: Where is the park?\nB: It is at the end of this street.\nA: It is not far then.",note:"El final means the end. Al final de = at the end of."},
    {type:"teach",kind:"phrase",nl:"la primera calle",en:"the first street",phonetic:"la pree-MEH-rah KA-yeh",example:"A: ¿Cómo llego al museo?\nB: Toma la primera calle a la derecha.\nA: ¡Entendido!",exampleEn:"A: How do I get to the museum?\nB: Take the first street on the right.\nA: Got it!",note:"Primera = first, segunda = second, tercera = third."},
    {type:"tip",title:"Giving Directions",text:"Common direction patterns:\n\nSigue todo recto. (Go straight.)\nGira a la derecha. (Turn right.)\nGira a la izquierda. (Turn left.)\nEstá en la esquina. (It is on the corner.)\nEstá al final de la calle. (It is at the end of the street.)\nToma la primera calle. (Take the first street.)"},
    {type:"mc",q:"Someone says: 'Gira a la izquierda.' What should you do?",opts:["Turn left","Turn right","Go straight","Go back"],ans:"Turn left",hint:"Izquierda is the opposite of derecha."},
    {type:"mc",q:"The museum is where two streets meet. Where is it?",opts:["En la esquina","Al final de la calle","Todo recto","A la derecha"],ans:"En la esquina",hint:"The point where two streets cross has a specific name."},
    {type:"fb",s:"Sigue todo {1} y luego gira a la derecha.",a:"recto",opts:["recto","derecha","izquierda","esquina"],hint:"This word means straight, describing the direction ahead of you."},
    {type:"fb",s:"El hospital está al {1} de esta calle.",a:"final",opts:["final","lado","esquina","recto"],hint:"The hospital is at the very end, where the street stops."},
    {type:"match",pairs:[{nl:"todo recto",en:"straight ahead"},{nl:"a la derecha",en:"to the right"},{nl:"a la izquierda",en:"to the left"},{nl:"en la esquina",en:"on the corner"},{nl:"al final de",en:"at the end of"}]},
    {type:"mc",q:"¿Cómo llego al supermercado? 'Toma la primera calle a la derecha.' What does this mean?",opts:["Take the first street on the right","Take the first street on the left","Go straight to the supermarket","The supermarket is on the corner"],ans:"Take the first street on the right",hint:"Primera means first, and derecha is one of the two sides."},
    {type:"fb",s:"Gira a la {1} en la esquina.",a:"derecha",opts:["derecha","recto","final","calle"],hint:"You need to make a turn, not go straight. Pick the right side."},
    {type:"mc",q:"Which phrase means 'at the end of this street'?",opts:["Al final de esta calle","En la esquina de esta calle","Todo recto por esta calle","A la derecha de esta calle"],ans:"Al final de esta calle",hint:"You are looking for the phrase with the word for end."},
    {type:"fb",s:"Toma la {1} calle a la izquierda.",a:"primera",opts:["primera","segunda","derecha","recto"],hint:"You need the ordinal number for number one."},
    {type:"mc",q:"Perdone, ¿cómo llego a la iglesia? 'Sigue todo recto y está a la izquierda.' Where is the church?",opts:["Straight ahead, then on the left","Straight ahead, then on the right","On the corner to the right","At the end of the first street"],ans:"Straight ahead, then on the left",hint:"Recto means straight, and izquierda is the opposite of derecha."}
  ]},
  {id:"esp7l4",title:"El Transporte",icon:"🚌",xp:15,board:true,steps:[
    {type:"intro",title:"El Transporte",desc:"Learn vocabulary for different types of transport used to get around the city and beyond.",goals:["Name 7 types of transport","Talk about how you travel","Use transport vocabulary in sentences"]},
    {type:"teach",kind:"word",nl:"el autobús",en:"the bus",phonetic:"el ow-toh-BOOS",example:"A: ¿Tomas el autobús?\nB: Sí, tomo el autobús todos los días.\nA: ¿A qué hora llega?",exampleEn:"A: Do you take the bus?\nB: Yes, I take the bus every day.\nA: What time does it arrive?",note:"Stress on the last syllable. Plural: los autobuses."},
    {type:"teach",kind:"word",nl:"el tren",en:"the train",phonetic:"el tren",example:"A: ¿Vamos en tren?\nB: Sí, el tren es rápido.\nA: ¿Dónde está la estación?",exampleEn:"A: Shall we go by train?\nB: Yes, the train is fast.\nA: Where is the station?",note:"Short and easy to remember. El AVE is Spain's high speed train."},
    {type:"teach",kind:"word",nl:"el metro",en:"the metro, subway",phonetic:"el MEH-troh",example:"A: ¿Hay metro en esta ciudad?\nB: Sí, la estación de metro está cerca.\nA: Perfecto.",exampleEn:"A: Is there a metro in this city?\nB: Yes, the metro station is nearby.\nA: Perfect.",note:"Madrid, Barcelona, and México City have large metro systems.",cognate:"metro"},
    {type:"teach",kind:"word",nl:"el taxi",en:"the taxi",phonetic:"el TAK-see",example:"A: Necesito un taxi.\nB: Hay una parada de taxi en la esquina.\nA: Gracias.",exampleEn:"A: I need a taxi.\nB: There is a taxi stand on the corner.\nA: Thank you.",note:"Taxis are usually white in Spain, yellow or green in Latin America.",cognate:"taxi"},
    {type:"teach",kind:"word",nl:"el avión",en:"the airplane",phonetic:"el ah-bee-ON",example:"A: ¿Viajas en avión?\nB: Sí, voy a Madrid en avión.\nA: ¡Qué emocionante!",exampleEn:"A: Do you travel by plane?\nB: Yes, I go to Madrid by plane.\nA: How exciting!",note:"El aeropuerto is the airport.",cognate:"aviation"},
    {type:"teach",kind:"word",nl:"el barco",en:"the boat, ship",phonetic:"el BAR-koh",example:"A: ¿Te gusta viajar en barco?\nB: Sí, me gusta mucho.\nA: El mar es muy bonito.",exampleEn:"A: Do you like traveling by boat?\nB: Yes, I like it a lot.\nA: The sea is very beautiful.",note:"Can mean a small boat or a large ship."},
    {type:"teach",kind:"word",nl:"la bicicleta",en:"the bicycle",phonetic:"la bee-see-KLEH-tah",example:"A: ¿Tienes bicicleta?\nB: Sí, voy al parque en bicicleta.\nA: ¡Qué bien!",exampleEn:"A: Do you have a bicycle?\nB: Yes, I go to the park by bicycle.\nA: How nice!",note:"Often shortened to la bici in spoken Spanish.",cognate:"bicycle"},
    {type:"tip",title:"En + Transport",text:"To say how you travel, use en + transport:\n\nen autobús (by bus)\nen tren (by train)\nen metro (by metro)\nen taxi (by taxi)\nen avión (by plane)\nen barco (by boat)\nen bicicleta (by bicycle)\n\nException: a pie means on foot (not en pie)."},
    {type:"mc",q:"How do you say 'by train' in Spanish?",opts:["En tren","A tren","Con tren","Por tren"],ans:"En tren",hint:"The preposition for transport is a two-letter word meaning in."},
    {type:"mc",q:"You want to travel across the ocean. Which transport do you use?",opts:["El barco","El autobús","La bicicleta","El metro"],ans:"El barco",hint:"You need something that floats on water."},
    {type:"fb",s:"Voy al trabajo en {1} todos los días.",a:"autobús",opts:["autobús","avión","barco","pie"],hint:"This is the most common public transport for daily commuting."},
    {type:"fb",s:"La estación de {1} está debajo de la calle.",a:"metro",opts:["metro","taxi","barco","avión"],hint:"This underground transport system runs beneath the city streets."},
    {type:"match",pairs:[{nl:"el autobús",en:"the bus"},{nl:"el tren",en:"the train"},{nl:"el metro",en:"the metro"},{nl:"el avión",en:"the airplane"},{nl:"el barco",en:"the boat"},{nl:"la bicicleta",en:"the bicycle"}]},
    {type:"mc",q:"Voy al parque en bicicleta. How does the speaker get to the park?",opts:["By bicycle","By bus","On foot","By taxi"],ans:"By bicycle",hint:"La bicicleta has two wheels and you pedal it."},
    {type:"mc",q:"Which is the exception to the 'en + transport' rule?",opts:["A pie","En coche","En taxi","En tren"],ans:"A pie",hint:"Walking uses a different preposition than vehicles."},
    {type:"fb",s:"¿Viajas en {1} a Madrid?",a:"avión",opts:["avión","pie","bicicleta","esquina"],hint:"Madrid is far away. You need the fastest transport."},
    {type:"mc",q:"Necesito un taxi. Hay una parada de taxi en la esquina. What is a 'parada de taxi'?",opts:["A taxi stand","A taxi driver","A taxi ride","A taxi price"],ans:"A taxi stand",hint:"La parada is the place where you wait for transport to stop."}
  ]},
  {id:"esp7l5",title:"Ir + a",icon:"🚶",xp:15,board:true,steps:[
    {type:"intro",title:"Ir + a",desc:"Learn to use the verb ir (to go) with destinations and future actions.",goals:["Conjugate ir in the present","Use ir + a + place","Use ir + a + infinitive for near future"]},
    {type:"teach",kind:"phrase",nl:"voy a",en:"I go to, I am going to",phonetic:"boy ah",example:"A: ¿Adónde vas?\nB: Voy a la estación.\nA: ¿En autobús?",exampleEn:"A: Where are you going?\nB: I am going to the station.\nA: By bus?",note:"Yo voy. Ir is very irregular. Voy a + place = going to a place."},
    {type:"teach",kind:"phrase",nl:"vas a",en:"you go to (informal)",phonetic:"bas ah",example:"A: ¿Vas al supermercado?\nB: Sí, voy a comprar fruta.\nA: ¿Me compras manzanas?",exampleEn:"A: Are you going to the supermarket?\nB: Yes, I am going to buy fruit.\nA: Can you buy me apples?",note:"Tú vas. Used with friends and family."},
    {type:"teach",kind:"phrase",nl:"va a",en:"he/she/you(formal) goes to",phonetic:"ba ah",example:"A: ¿Adónde va María?\nB: Va al hospital.\nA: ¿Está enferma?",exampleEn:"A: Where is María going?\nB: She is going to the hospital.\nA: Is she sick?",note:"Él/ella/usted va. One form for all three."},
    {type:"teach",kind:"phrase",nl:"vamos a",en:"we go to, we are going to",phonetic:"BA-mohs ah",example:"A: ¿Vamos al parque?\nB: ¡Sí, vamos!\nA: ¡Vamos en bicicleta!",exampleEn:"A: Shall we go to the park?\nB: Yes, let's go!\nA: Let's go by bicycle!",note:"Nosotros vamos. Also used as Let's go!"},
    {type:"teach",kind:"phrase",nl:"van a",en:"they/you(plural) go to",phonetic:"ban ah",example:"A: ¿Adónde van tus padres?\nB: Van al museo.\nA: ¡Qué interesante!",exampleEn:"A: Where are your parents going?\nB: They are going to the museum.\nA: How interesting!",note:"Ellos/ellas/ustedes van."},
    {type:"tip",title:"Ir + a: Two Uses",text:"Ir + a has two important uses:\n\n1. Going to a PLACE:\n   Voy al banco. (I go to the bank.)\n   Va a la farmacia. (She goes to the pharmacy.)\n\n2. Going to DO something (near future):\n   Voy a comer. (I am going to eat.)\n   Vamos a estudiar. (We are going to study.)\n\nRemember: a + el = al."},
    {type:"mc",q:"How do you say 'I am going to the museum'?",opts:["Voy al museo","Vas al museo","Va al museo","Vamos al museo"],ans:"Voy al museo",hint:"You need the yo form of ir, which is very irregular."},
    {type:"mc",q:"Vamos a estudiar español. What does this mean?",opts:["We are going to study Spanish","We study Spanish","We studied Spanish","We want to study Spanish"],ans:"We are going to study Spanish",hint:"Ir + a + infinitive expresses a near future action."},
    {type:"fb",s:"María {1} a la farmacia.",a:"va",opts:["va","voy","vas","vamos"],hint:"María is third person singular. Which form of ir matches?"},
    {type:"fb",s:"¿Adónde {1} tus hermanos?",a:"van",opts:["van","va","vamos","vas"],hint:"Tus hermanos is third person plural. Which form fits?"},
    {type:"mc",q:"¿Vas a comprar pan? What is being asked?",opts:["Are you going to buy bread?","Did you buy bread?","Do you like bread?","Where is the bread?"],ans:"Are you going to buy bread?",hint:"Ir + a + infinitive talks about something that will happen soon."},
    {type:"match",pairs:[{nl:"voy",en:"I go"},{nl:"vas",en:"you go"},{nl:"va",en:"he/she goes"},{nl:"vamos",en:"we go"},{nl:"van",en:"they go"}]},
    {type:"fb",s:"Nosotros {1} al parque en bicicleta.",a:"vamos",opts:["vamos","van","voy","vas"],hint:"Nosotros needs the we form of this irregular verb."},
    {type:"mc",q:"Voy al banco. What does 'al' replace?",opts:["a + el","a + la","a + los","a + un"],ans:"a + el",hint:"This contraction only happens with the masculine singular article."},
    {type:"fb",s:"¿{1} a la estación en metro?",a:"Vas",opts:["Vas","Voy","Va","Van"],hint:"The question is directed at you (tú). Which form of ir fits?"},
    {type:"mc",q:"Mis padres van a viajar en avión. What are the parents going to do?",opts:["Travel by plane","Buy a plane","Go to the airport","Work at the airport"],ans:"Travel by plane",hint:"Van a + infinitive describes what they will do soon."},
    {type:"drag_fill",s:"Yo {1} al supermercado y María {2} a la farmacia.",blanks:{1:"voy",2:"va"},pool:["voy","va","vas","vamos"],hint:"Match each subject to the correct form of ir."}
  ]},
  {id:"esp7l6",title:"Venir de",icon:"🔙",xp:15,board:true,steps:[
    {type:"intro",title:"Venir de",desc:"Learn to say where you are coming from and contrast ir (to go) with venir (to come).",goals:["Conjugate venir in the present","Use venir de + place","Contrast ir and venir"]},
    {type:"teach",kind:"word",nl:"venir",en:"to come",phonetic:"beh-NEER",example:"A: ¿De dónde vienes?\nB: Vengo de la estación.\nA: ¿Vienes en metro?",exampleEn:"A: Where are you coming from?\nB: I come from the station.\nA: Are you coming by metro?",note:"Venir is irregular. The stem changes from e to ie in most forms."},
    {type:"teach",kind:"phrase",nl:"vengo de",en:"I come from",phonetic:"BEN-goh deh",example:"A: ¿De dónde vienes?\nB: Vengo del supermercado.\nA: ¿Compraste fruta?",exampleEn:"A: Where are you coming from?\nB: I come from the supermarket.\nA: Did you buy fruit?",note:"Yo vengo. Note the g in the yo form, like tengo."},
    {type:"teach",kind:"phrase",nl:"vienes de",en:"you come from (informal)",phonetic:"bee-EH-nehs deh",example:"A: ¿Vienes del parque?\nB: Sí, vengo del parque.\nA: ¿Está bonito hoy?",exampleEn:"A: Are you coming from the park?\nB: Yes, I come from the park.\nA: Is it nice today?",note:"Tú vienes. The stem changes: ven- becomes vien-."},
    {type:"teach",kind:"phrase",nl:"viene de",en:"he/she comes from",phonetic:"bee-EH-neh deh",example:"A: ¿De dónde viene Pedro?\nB: Viene del hospital.\nA: ¿Está bien?",exampleEn:"A: Where is Pedro coming from?\nB: He comes from the hospital.\nA: Is he okay?",note:"Él/ella/usted viene."},
    {type:"teach",kind:"phrase",nl:"venimos de",en:"we come from",phonetic:"beh-NEE-mohs deh",example:"A: ¿De dónde venís?\nB: Venimos del museo.\nA: ¿Os gustó?",exampleEn:"A: Where are you coming from?\nB: We come from the museum.\nA: Did you like it?",note:"Nosotros venimos. No stem change in this form."},
    {type:"tip",title:"Ir vs Venir",text:"Ir = movement AWAY from the speaker.\n  Voy al banco. (I am going to the bank.)\n\nVenir = movement TOWARD the speaker.\n  Vengo del banco. (I am coming from the bank.)\n\nKey difference:\n  ir + a (going TO a place)\n  venir + de (coming FROM a place)\n\nNote: de + el = del."},
    {type:"mc",q:"How do you say 'I come from the park'?",opts:["Vengo del parque","Voy al parque","Viene del parque","Vamos al parque"],ans:"Vengo del parque",hint:"You need the yo form of venir, plus from."},
    {type:"mc",q:"What does 'del' replace?",opts:["de + el","de + la","de + los","de + un"],ans:"de + el",hint:"This contraction works like al (a + el), but with a different preposition."},
    {type:"fb",s:"¿De dónde {1} María?",a:"viene",opts:["viene","vengo","vienes","vienen"],hint:"María is third person singular. Which form of venir fits?"},
    {type:"fb",s:"Nosotros {1} de la estación.",a:"venimos",opts:["venimos","vienen","vengo","viene"],hint:"Nosotros needs the we form of venir."},
    {type:"mc",q:"Ir is to go TO a place. Venir is to come FROM a place. Which sentence uses venir correctly?",opts:["Vengo de la farmacia","Vengo a la farmacia","Voy de la farmacia","Vengo la farmacia"],ans:"Vengo de la farmacia",hint:"Venir always pairs with de, meaning from."},
    {type:"match",pairs:[{nl:"vengo",en:"I come"},{nl:"vienes",en:"you come"},{nl:"viene",en:"he/she comes"},{nl:"venimos",en:"we come"},{nl:"vienen",en:"they come"}]},
    {type:"mc",q:"Pedro viene del hospital. Where was Pedro?",opts:["At the hospital","Going to the hospital","Near the hospital","Looking for the hospital"],ans:"At the hospital",hint:"Venir de means coming FROM. He was there before."},
    {type:"fb",s:"Vengo {1} supermercado.",a:"del",opts:["del","al","de la","a la"],hint:"Supermercado is masculine. De + el contracts to one word."},
    {type:"drag_fill",s:"Yo {1} al banco y luego {2} del banco.",blanks:{1:"voy",2:"vengo"},pool:["voy","vengo","va","viene"],hint:"First you go there, then you come back from there."},
    {type:"mc",q:"¿Vienes de la iglesia? What is being asked?",opts:["Are you coming from the church?","Are you going to the church?","Do you like the church?","Where is the church?"],ans:"Are you coming from the church?",hint:"Vienes de asks about your origin, not your destination."},
    {type:"fb",s:"Mis padres {1} del museo.",a:"vienen",opts:["vienen","viene","venimos","vengo"],hint:"Mis padres is third person plural. Which form matches?"},
    {type:"mc",q:"Which pair shows the correct contrast?",opts:["Voy a / vengo de","Voy de / vengo a","Voy al / vengo al","Voy del / vengo del"],ans:"Voy a / vengo de",hint:"Going pairs with to, and coming pairs with from."}
  ]},
  {id:"esp7l7",title:"¡Gira! ¡Sigue!",icon:"🔄",xp:15,board:true,steps:[
    {type:"intro",title:"¡Gira! ¡Sigue!",desc:"Learn to give commands using the tú imperative, the form used with friends and people you know.",goals:["Form tú imperatives for regular verbs","Learn key irregular tú imperatives","Give clear directions using commands"]},
    {type:"teach",kind:"phrase",nl:"gira",en:"turn (command)",phonetic:"HEE-rah",example:"A: ¿Cómo llego a la farmacia?\nB: Gira a la derecha en la esquina.\nA: ¿En la primera esquina?",exampleEn:"A: How do I get to the pharmacy?\nB: Turn right at the corner.\nA: At the first corner?",note:"From girar. Tú imperative of -ar verbs: drop -ar, add -a."},
    {type:"teach",kind:"phrase",nl:"sigue",en:"continue, keep going (command)",phonetic:"SEE-geh",example:"A: ¿Sigo todo recto?\nB: Sí, sigue todo recto dos calles.\nA: ¿Y luego?",exampleEn:"A: Do I go straight?\nB: Yes, keep going straight two blocks.\nA: And then?",note:"From seguir (e to i stem change). Sigue todo recto = keep going straight."},
    {type:"teach",kind:"phrase",nl:"cruza",en:"cross (command)",phonetic:"KROO-sah",example:"A: ¿Cruzo la calle?\nB: Sí, cruza la calle y gira a la izquierda.\nA: Entendido.",exampleEn:"A: Do I cross the street?\nB: Yes, cross the street and turn left.\nA: Understood.",note:"From cruzar. Cruza la calle = cross the street."},
    {type:"teach",kind:"phrase",nl:"toma",en:"take (command)",phonetic:"TOH-mah",example:"A: ¿Qué autobús tomo?\nB: Toma el autobús número 5.\nA: Gracias.",exampleEn:"A: Which bus do I take?\nB: Take bus number 5.\nA: Thank you.",note:"From tomar. Toma la primera calle = take the first street."},
    {type:"teach",kind:"phrase",nl:"para",en:"stop (command)",phonetic:"PA-rah",example:"A: ¿Paro aquí?\nB: Sí, para aquí. El banco está enfrente.\nA: Ah, ya lo veo.",exampleEn:"A: Do I stop here?\nB: Yes, stop here. The bank is in front.\nA: Ah, I see it now.",note:"From parar. Para aquí = stop here."},
    {type:"teach",kind:"phrase",nl:"ven",en:"come (command, irregular)",phonetic:"ben",example:"A: ¡Ven aquí!\nB: ¿Qué pasa?\nA: Ven, te enseño algo.",exampleEn:"A: Come here!\nB: What is it?\nA: Come, I will show you something.",note:"Irregular. The tú imperative of venir is just ven, not viene."},
    {type:"tip",title:"Tú Imperative: Regular Verbs",text:"To form the tú command for regular verbs:\n\n-ar verbs: drop -ar, add -a\n  girar: gira (turn)\n  cruzar: cruza (cross)\n  tomar: toma (take)\n  parar: para (stop)\n\n-er/-ir verbs: drop -er/-ir, add -e\n  comer: come (eat)\n  seguir: sigue (continue)\n\nIrregulars to memorize:\n  venir: ven (come)\n  ir: ve (go)\n  salir: sal (leave/go out)"},
    {type:"mc",q:"How do you tell a friend to turn left?",opts:["Gira a la izquierda","Giras a la izquierda","Girar a la izquierda","Giramos a la izquierda"],ans:"Gira a la izquierda",hint:"The tú imperative of -ar verbs ends in -a, without the -s."},
    {type:"mc",q:"What does 'Cruza la calle' mean?",opts:["Cross the street","The street crosses","I cross the street","Crossing the street"],ans:"Cross the street",hint:"This is a command form, telling someone to do something."},
    {type:"fb",s:"{1} todo recto y luego gira a la derecha.",a:"Sigue",opts:["Sigue","Sigues","Seguir","Sigo"],hint:"You need the tú command form, telling someone to continue."},
    {type:"fb",s:"{1} el autobús número 3.",a:"Toma",opts:["Toma","Tomas","Tomar","Tomo"],hint:"You are telling a friend which bus to catch. Use the command form."},
    {type:"match",pairs:[{nl:"gira",en:"turn"},{nl:"sigue",en:"continue"},{nl:"cruza",en:"cross"},{nl:"toma",en:"take"},{nl:"para",en:"stop"},{nl:"ven",en:"come"}]},
    {type:"mc",q:"The tú imperative of venir is:",opts:["ven","viene","vienes","vengo"],ans:"ven",hint:"This verb has an irregular command form that is very short."},
    {type:"drag_fill",s:"{1} la calle y {2} a la derecha.",blanks:{1:"Cruza",2:"gira"},pool:["Cruza","gira","sigue","para"],hint:"First you go across the road, then you change direction."},
    {type:"fb",s:"¡{1} aquí! Quiero enseñarte algo.",a:"Ven",opts:["Ven","Viene","Vienes","Vengo"],hint:"You are calling someone to come to where you are. Irregular command."},
    {type:"mc",q:"Which is the correct set of directions? 'Sigue todo recto, gira a la izquierda, y el banco está en la esquina.'",opts:["Go straight, turn left, the bank is on the corner","Turn right, go straight, the bank is far","Cross the street, stop, the bank is behind you","Take the first street, turn right, the bank is on the left"],ans:"Go straight, turn left, the bank is on the corner",hint:"Translate each command in order: sigue, gira, esquina."},
    {type:"mc",q:"What is the tú imperative of 'salir'?",opts:["sal","sale","sales","salir"],ans:"sal",hint:"Like ven from venir, this is an irregular short form."}
  ]},
  {id:"esp7l8",title:"¿Cómo Llego?",icon:"🧭",xp:15,board:true,steps:[
    {type:"intro",title:"¿Cómo Llego?",desc:"Combine everything from this unit: places, directions, transport, ir, venir, and commands in real-world scenarios.",goals:["Navigate a city using Spanish","Combine directions with transport","Handle real direction conversations"]},
    {type:"teach",kind:"phrase",nl:"¿Está lejos?",en:"Is it far?",phonetic:"es-TA LEH-hos",example:"A: ¿Cómo llego al museo?\nB: Sigue todo recto cinco minutos.\nA: ¿Está lejos?",exampleEn:"A: How do I get to the museum?\nB: Go straight for five minutes.\nA: Is it far?",note:"A useful follow-up when someone gives you directions."},
    {type:"teach",kind:"phrase",nl:"a pie",en:"on foot, walking",phonetic:"ah pee-EH",example:"A: ¿Vamos a pie o en autobús?\nB: Vamos a pie. No está lejos.\nA: ¡Vale, vamos!",exampleEn:"A: Shall we walk or take the bus?\nB: Let's walk. It is not far.\nA: Okay, let's go!",note:"The only transport that does not use en. A pie = on foot."},
    {type:"teach",kind:"phrase",nl:"la parada",en:"the stop (bus/metro)",phonetic:"la pa-RA-dah",example:"A: ¿Dónde está la parada de autobús?\nB: Está en la esquina de la calle.\nA: Gracias, voy para allá.",exampleEn:"A: Where is the bus stop?\nB: It is on the corner of the street.\nA: Thank you, I will head there.",note:"La parada de autobús = bus stop. La parada de metro = metro stop."},
    {type:"teach",kind:"word",nl:"el semáforo",en:"the traffic light",phonetic:"el seh-MA-foh-roh",example:"A: ¿Dónde giro?\nB: Gira a la derecha en el semáforo.\nA: ¿En el primer semáforo?",exampleEn:"A: Where do I turn?\nB: Turn right at the traffic light.\nA: At the first traffic light?",note:"A useful landmark when giving directions."},
    {type:"teach",kind:"phrase",nl:"está muy cerca",en:"it is very close",phonetic:"es-TA mooy SEHR-kah",example:"A: ¿Está lejos la farmacia?\nB: No, está muy cerca. A cinco minutos a pie.\nA: Perfecto.",exampleEn:"A: Is the pharmacy far?\nB: No, it is very close. Five minutes on foot.\nA: Perfect.",note:"Cerca = close, lejos = far. You already know these."},
    {type:"tip",title:"Complete Direction Dialogue",text:"A typical direction exchange:\n\n1. Get attention: Perdone / Disculpe\n2. Ask: ¿Dónde está...? / ¿Cómo llego a...?\n3. Receive directions: Sigue, gira, cruza, toma...\n4. Clarify: ¿Está lejos? / ¿Puedo ir a pie?\n5. Thank: Muchas gracias."},
    {type:"mc",q:"How do you say 'on foot' in Spanish?",opts:["A pie","En pie","Con pie","De pie"],ans:"A pie",hint:"This is the exception to the en + transport pattern."},
    {type:"mc",q:"¿Dónde está la parada de autobús? What is a 'parada'?",opts:["A stop","A street","A corner","A bridge"],ans:"A stop",hint:"This is the place where the bus picks up passengers."},
    {type:"fb",s:"Gira a la izquierda en el {1}.",a:"semáforo",opts:["semáforo","esquina","calle","parque"],hint:"You turn at the object with red, yellow, and green lights."},
    {type:"fb",s:"No, no está lejos. Está muy {1}.",a:"cerca",opts:["cerca","lejos","grande","recto"],hint:"The opposite of lejos, meaning the place is nearby."},
    {type:"mc",q:"Perdone, ¿cómo llego a la estación? 'Sigue todo recto, cruza la calle en el semáforo, y la estación está a la izquierda.' Which direction is NOT mentioned?",opts:["Turn right","Go straight","Cross the street","It is on the left"],ans:"Turn right",hint:"Read each instruction: recto, cruza, izquierda. What is missing?"},
    {type:"drag_fill",s:"Perdone, ¿{1} está el banco? Sigue todo recto y {2} a la derecha.",blanks:{1:"dónde",2:"gira"},pool:["dónde","gira","viene","del"],hint:"First ask for location, then give the turning command."},
    {type:"match",pairs:[{nl:"a pie",en:"on foot"},{nl:"la parada",en:"the stop"},{nl:"el semáforo",en:"the traffic light"},{nl:"está lejos",en:"it is far"},{nl:"está cerca",en:"it is close"}]},
    {type:"mc",q:"Vengo de la estación y voy al museo. Which verbs describe the speaker's journey?",opts:["Coming from + going to","Going from + coming to","Staying at + going to","Coming to + going from"],ans:"Coming from + going to",hint:"Venir de means coming from, and ir a means going to."},
    {type:"fb",s:"¿Puedo ir {1} pie? No está lejos.",a:"a",opts:["a","en","de","por"],hint:"Walking uses a special preposition, not the usual en."},
    {type:"drag_fill",s:"Voy {1} banco en metro y vengo {2} banco en taxi.",blanks:{1:"al",2:"del"},pool:["al","del","a la","de la"],hint:"Banco is masculine. Going TO uses a+el, coming FROM uses de+el."},
    {type:"mc",q:"A tourist asks you: '¿Dónde está el hospital?' You reply: 'Sigue todo recto, toma la segunda calle a la izquierda, y el hospital está al final de la calle.' How many direction steps did you give?",opts:["Three","Two","Four","One"],ans:"Three",hint:"Count each separate instruction: sigue, toma, está al final."}
  ]}
]},
// ══════════════════════════════════════════════════════════════
// UNIT 8: De Compras — Shopping & Clothing (A1.4)
// 8 lessons, 18+ steps each
// ══════════════════════════════════════════════════════════════
{n:8,lang:"es",track:"v1",title:"De Compras",sub:"Shopping & Clothing",icon:"🛍️",level:"A1.4",color:"#7B5EE8",lessons:[
{id:"esp8l1",title:"La Ropa I",icon:"👔",xp:15,board:true,steps:[
{type:"intro",title:"La Ropa I",desc:"Learn your first clothing words in Spanish. Every noun comes with its article: el (masculine) or la (feminine).",goals:["Learn 8 clothing items with articles","Practice gender agreement","Use clothing words in simple sentences"]},
{type:"teach",kind:"word",nl:"la camisa",en:"shirt",phonetic:"ka-MEE-sa",example:"A: ¿Te gusta esta camisa?\nB: Sí, es muy bonita.",exampleEn:"A: Do you like this shirt?\nB: Yes, it's very pretty.",note:"Feminine noun. La camisa can be formal or casual."},
{type:"teach",kind:"word",nl:"el pantalón",en:"pants, trousers",phonetic:"pan-ta-LON",example:"A: ¿De qué color es tu pantalón?\nB: Mi pantalón es negro.",exampleEn:"A: What color are your pants?\nB: My pants are black.",note:"Masculine singular. Plural: los pantalones."},
{type:"teach",kind:"word",nl:"el vestido",en:"dress",phonetic:"ves-TEE-do",example:"A: ¿Llevas un vestido hoy?\nB: Sí, llevo un vestido azul.",exampleEn:"A: Are you wearing a dress today?\nB: Yes, I'm wearing a blue dress.",note:"Masculine noun. Llevar means to wear or to carry."},
{type:"teach",kind:"word",nl:"la falda",en:"skirt",phonetic:"FAL-da",example:"A: ¿Te gusta la falda roja?\nB: Prefiero la falda verde.",exampleEn:"A: Do you like the red skirt?\nB: I prefer the green skirt.",note:"Feminine noun. Preferir means to prefer."},
{type:"teach",kind:"word",nl:"los zapatos",en:"shoes",phonetic:"sa-PA-tos",example:"A: ¿Dónde están mis zapatos?\nB: Están debajo de la cama.",exampleEn:"A: Where are my shoes?\nB: They're under the bed.",note:"Masculine plural. One shoe: el zapato."},
{type:"teach",kind:"word",nl:"la chaqueta",en:"jacket",phonetic:"cha-KE-ta",example:"A: Hace frío hoy.\nB: Sí, necesito mi chaqueta.",exampleEn:"A: It's cold today.\nB: Yes, I need my jacket.",note:"Feminine noun. For cold weather or fashion."},
{type:"teach",kind:"word",nl:"el abrigo",en:"coat, overcoat",phonetic:"a-BREE-go",example:"A: ¿Llevas abrigo?\nB: Sí, porque hace mucho frío.",exampleEn:"A: Are you wearing a coat?\nB: Yes, because it's very cold.",note:"Masculine noun. Heavier than una chaqueta."},
{type:"teach",kind:"word",nl:"el sombrero",en:"hat",phonetic:"som-BRE-ro",example:"A: ¡Qué bonito sombrero!\nB: Gracias, es nuevo.",exampleEn:"A: What a nice hat!\nB: Thanks, it's new.",note:"Masculine noun. You may recognize this word from English."},
{type:"tip",title:"Llevar: To Wear",text:"In Spanish, llevar means both 'to wear' and 'to carry'.\nLlevo una camisa. = I wear/am wearing a shirt.\nLlevo una bolsa. = I carry/am carrying a bag.\nContext tells you which meaning applies."},
{type:"mc",q:"¿Cómo se dice 'dress' en español?",opts:["el vestido","la falda","la camisa","el pantalón"],ans:"el vestido",hint:"Think of the word that sounds like 'vest' in English."},
{type:"mc",q:"¿Cuál es femenina: camisa, pantalón, vestido, abrigo?",opts:["la camisa","el pantalón","el vestido","el abrigo"],ans:"la camisa",hint:"Most words ending in -a are feminine in Spanish."},
{type:"fb",s:"Necesito {1} nuevos para caminar.",a:"zapatos",opts:["zapatos","camisa","vestido","sombrero"],hint:"Which clothing item do you need for walking?"},
{type:"fb",s:"Hace frío. Llevo mi {1}.",a:"abrigo",opts:["abrigo","falda","camisa","sombrero"],hint:"What heavy garment protects you from cold weather?"},
{type:"match",pairs:[{nl:"la camisa",en:"shirt"},{nl:"el pantalón",en:"pants"},{nl:"el vestido",en:"dress"},{nl:"la falda",en:"skirt"},{nl:"los zapatos",en:"shoes"}]},
{type:"mc",q:"Mi hermana lleva una ___ roja muy bonita.",opts:["falda","pantalón","zapatos","sombrero"],ans:"falda",hint:"Which feminine clothing item matches 'una' and 'roja'?"},
{type:"fb",s:"¿Te gusta mi {1} nuevo? Es de color negro.",a:"sombrero",opts:["sombrero","falda","camisa","zapatos"],hint:"Which masculine item do you wear on your head?"},
{type:"mc",q:"'Llevo una chaqueta' means:",opts:["I'm wearing a jacket","I'm buying a jacket","I want a jacket","I like a jacket"],ans:"I'm wearing a jacket",hint:"Remember the verb llevar and its clothing meaning."},
{type:"match",pairs:[{nl:"la chaqueta",en:"jacket"},{nl:"el abrigo",en:"coat"},{nl:"el sombrero",en:"hat"},{nl:"los zapatos",en:"shoes"},{nl:"el vestido",en:"dress"}]}
]},
{id:"esp8l2",title:"La Ropa II",icon:"👕",xp:15,board:true,steps:[
{type:"intro",title:"La Ropa II",desc:"Expand your wardrobe vocabulary with more everyday clothing items.",goals:["Learn 8 more clothing items","Practice singular and plural forms","Describe what people are wearing"]},
{type:"teach",kind:"word",nl:"la camiseta",en:"t-shirt",phonetic:"ka-mee-SE-ta",example:"A: ¿Qué llevas hoy?\nB: Llevo una camiseta blanca y vaqueros.",exampleEn:"A: What are you wearing today?\nB: I'm wearing a white t-shirt and jeans.",note:"Feminine. Camiseta is a small camisa (shirt)."},
{type:"teach",kind:"word",nl:"los vaqueros",en:"jeans",phonetic:"va-KE-ros",example:"A: ¿Tienes vaqueros azules?\nB: Sí, tengo dos pares de vaqueros.",exampleEn:"A: Do you have blue jeans?\nB: Yes, I have two pairs of jeans.",note:"Masculine plural. Also called los jeans in Latin America."},
{type:"teach",kind:"word",nl:"las zapatillas",en:"sneakers, trainers",phonetic:"sa-pa-TEE-yas",example:"A: ¿Llevas zapatillas para correr?\nB: Sí, son muy cómodas.",exampleEn:"A: Are you wearing sneakers to run?\nB: Yes, they're very comfortable.",note:"Feminine plural. Cómodo/cómoda means comfortable."},
{type:"teach",kind:"word",nl:"la bufanda",en:"scarf",phonetic:"bu-FAN-da",example:"A: Hace mucho frío afuera.\nB: Llevo mi bufanda y mi abrigo.",exampleEn:"A: It's very cold outside.\nB: I'm wearing my scarf and my coat.",note:"Feminine noun. Essential in winter."},
{type:"teach",kind:"word",nl:"los calcetines",en:"socks",phonetic:"kal-se-TEE-nes",example:"A: ¿De qué color son tus calcetines?\nB: Son blancos.",exampleEn:"A: What color are your socks?\nB: They're white.",note:"Masculine plural. One sock: el calcetín."},
{type:"teach",kind:"word",nl:"la ropa interior",en:"underwear",phonetic:"RO-pa in-te-RYOR",example:"A: ¿Qué necesitas comprar?\nB: Necesito ropa interior nueva.",exampleEn:"A: What do you need to buy?\nB: I need new underwear.",note:"Feminine. Literally 'interior clothing'."},
{type:"teach",kind:"word",nl:"el traje",en:"suit",phonetic:"TRA-he",example:"A: ¿Llevas traje al trabajo?\nB: Sí, llevo traje todos los días.",exampleEn:"A: Do you wear a suit to work?\nB: Yes, I wear a suit every day.",note:"Masculine noun. For formal occasions and work."},
{type:"teach",kind:"word",nl:"el cinturón",en:"belt",phonetic:"sin-tu-RON",example:"A: ¿Necesitas un cinturón?\nB: Sí, este pantalón es grande.",exampleEn:"A: Do you need a belt?\nB: Yes, these pants are big.",note:"Masculine noun. Accent on the last syllable."},
{type:"tip",title:"Singular and Plural Clothing",text:"Some clothing items are usually plural:\nlos zapatos (shoes), los calcetines (socks)\nlos vaqueros (jeans), las zapatillas (sneakers)\nOthers are usually singular:\nel vestido (dress), la camisa (shirt)\nel cinturón (belt), el sombrero (hat)"},
{type:"mc",q:"¿Cómo se dice 'sneakers' en español?",opts:["las zapatillas","los zapatos","los calcetines","los vaqueros"],ans:"las zapatillas",hint:"This word comes from zapato but with a diminutive ending."},
{type:"fb",s:"Para el trabajo formal, mi padre lleva un {1}.",a:"traje",opts:["traje","camiseta","bufanda","calcetines"],hint:"Think about formal business attire for men."},
{type:"mc",q:"¿Cuál llevas en los pies dentro de los zapatos?",opts:["los calcetines","la bufanda","el cinturón","la camiseta"],ans:"los calcetines",hint:"This item goes between your feet and your shoes."},
{type:"match",pairs:[{nl:"la camiseta",en:"t-shirt"},{nl:"los vaqueros",en:"jeans"},{nl:"la bufanda",en:"scarf"},{nl:"el cinturón",en:"belt"},{nl:"el traje",en:"suit"}]},
{type:"fb",s:"Hace frío. Necesito mi {1} para el cuello.",a:"bufanda",opts:["bufanda","camiseta","cinturón","traje"],hint:"Which item wraps around your neck for warmth?"},
{type:"mc",q:"'Llevo una camiseta y vaqueros' describes:",opts:["casual clothing","formal clothing","winter clothing","swimwear"],ans:"casual clothing",hint:"Think about when you would wear these items together."},
{type:"fb",s:"Las {1} son cómodas para correr.",a:"zapatillas",opts:["zapatillas","bufandas","camisetas","faldas"],hint:"Which comfortable shoes are good for exercise?"},
{type:"match",pairs:[{nl:"las zapatillas",en:"sneakers"},{nl:"los calcetines",en:"socks"},{nl:"la ropa interior",en:"underwear"},{nl:"la camiseta",en:"t-shirt"},{nl:"la bufanda",en:"scarf"}]},
{type:"mc",q:"Mi pantalón es grande. Necesito un ___.",opts:["cinturón","sombrero","calcetín","traje"],ans:"cinturón",hint:"What accessory holds your pants up when they are loose?"}
]},
{id:"esp8l3",title:"En la Tienda",icon:"🏪",xp:15,board:true,steps:[
{type:"intro",title:"En la Tienda",desc:"Learn essential phrases for shopping in a Spanish-speaking store.",goals:["Ask prices and sizes","Try on clothing","Express opinions about fit and style"]},
{type:"teach",kind:"phrase",nl:"¿Cuánto cuesta?",en:"How much does it cost?",phonetic:"KWAN-to KWES-ta",example:"A: ¿Cuánto cuesta esta camisa?\nB: Cuesta veinte euros.",exampleEn:"A: How much does this shirt cost?\nB: It costs twenty euros.",note:"Cuesta for one item. Cuestan for multiple items."},
{type:"teach",kind:"phrase",nl:"¿Tiene...?",en:"Do you have...?",phonetic:"TYE-ne",example:"A: ¿Tiene esta falda en azul?\nB: Sí, un momento, por favor.",exampleEn:"A: Do you have this skirt in blue?\nB: Yes, one moment, please.",note:"Formal question for store clerks. Use usted form."},
{type:"teach",kind:"phrase",nl:"Me lo llevo",en:"I'll take it",phonetic:"me lo YE-vo",example:"A: ¿Le gusta el vestido?\nB: Sí, me lo llevo.",exampleEn:"A: Do you like the dress?\nB: Yes, I'll take it.",note:"Me la llevo for feminine items. Me los/las llevo for plural."},
{type:"teach",kind:"word",nl:"probarse",en:"to try on",phonetic:"pro-BAR-se",example:"A: ¿Puedo probarme este vestido?\nB: Sí, el probador está allí.",exampleEn:"A: Can I try on this dress?\nB: Yes, the fitting room is over there.",note:"Reflexive verb. Me pruebo, te pruebas, se prueba."},
{type:"teach",kind:"phrase",nl:"Me queda bien",en:"It fits me well",phonetic:"me KE-da BYEN",example:"A: ¿Cómo te queda la chaqueta?\nB: Me queda bien, gracias.",exampleEn:"A: How does the jacket fit you?\nB: It fits me well, thanks.",note:"Me queda mal = it fits me badly. Me queda grande/pequeño = too big/small."},
{type:"teach",kind:"word",nl:"la talla",en:"size (clothing)",phonetic:"TA-ya",example:"A: ¿Qué talla usas?\nB: Uso la talla mediana.",exampleEn:"A: What size do you wear?\nB: I wear size medium.",note:"Feminine noun. Common sizes: pequeña (S), mediana (M), grande (L)."},
{type:"teach",kind:"word",nl:"barato",en:"cheap, inexpensive",phonetic:"ba-RA-to",example:"A: ¿Es cara esta camiseta?\nB: No, es muy barata.",exampleEn:"A: Is this t-shirt expensive?\nB: No, it's very cheap.",note:"Adjective. Barato/barata matches noun gender."},
{type:"teach",kind:"word",nl:"caro",en:"expensive",phonetic:"KA-ro",example:"A: ¿Cuánto cuesta el traje?\nB: Es muy caro. Cuesta quinientos euros.",exampleEn:"A: How much does the suit cost?\nB: It's very expensive. It costs five hundred euros.",note:"Adjective. Caro/cara matches noun gender."},
{type:"tip",title:"Shopping Vocabulary",text:"Key shopping phrases:\n¿Cuánto cuesta? = How much does it cost?\n¿Tiene...? = Do you have...?\n¿Puedo probarme...? = Can I try on...?\nMe queda bien/mal = It fits me well/badly\nMe lo llevo = I'll take it\nEs muy caro/barato = It's very expensive/cheap"},
{type:"mc",q:"You want to ask the price. You say:",opts:["¿Cuánto cuesta?","¿Tiene?","Me lo llevo","¿Qué talla?"],ans:"¿Cuánto cuesta?",hint:"Which phrase asks specifically about the cost of something?"},
{type:"fb",s:"¿Puedo {1} esta chaqueta?",a:"probarme",opts:["probarme","comprar","llevar","queda"],hint:"Which reflexive verb means to try something on?"},
{type:"mc",q:"La camisa es perfecta. ___.",opts:["Me la llevo","Me lo llevo","Me queda mal","Es cara"],ans:"Me la llevo",hint:"Camisa is feminine, so which pronoun matches?"},
{type:"fb",s:"El vestido me queda {1}. Necesito una talla más grande.",a:"pequeño",opts:["pequeño","bien","grande","mal"],hint:"If you need a bigger size, the current one is too what?"},
{type:"mc",q:"Este abrigo cuesta 500 euros. Es muy ___.",opts:["caro","barato","grande","bonito"],ans:"caro",hint:"Five hundred euros is a lot. What adjective describes the price?"},
{type:"match",pairs:[{nl:"¿Cuánto cuesta?",en:"How much?"},{nl:"Me lo llevo",en:"I'll take it"},{nl:"la talla",en:"the size"},{nl:"probarse",en:"to try on"},{nl:"barato",en:"cheap"}]},
{type:"fb",s:"¿{1} esta falda en rojo?",a:"Tiene",opts:["Tiene","Cuesta","Queda","Lleva"],hint:"Which word asks if the store has something available?"},
{type:"mc",q:"¿Qué talla usas? Uso la talla ___.",opts:["mediana","barata","bonita","roja"],ans:"mediana",hint:"Think about clothing size labels: small, medium, large."},
{type:"mc",q:"'Me queda bien' means:",opts:["It fits me well","I'll take it","It's cheap","I like it"],ans:"It fits me well",hint:"The verb quedar here refers to how clothing sits on you."}
]},
{id:"esp8l4",title:"Los Números Grandes",icon:"💰",xp:15,board:true,steps:[
{type:"intro",title:"Los Números Grandes",desc:"Learn numbers from 100 to 1000 so you can understand prices while shopping.",goals:["Count from 100 to 1000","Understand and say prices","Use numbers in shopping contexts"]},
{type:"teach",kind:"word",nl:"cien",en:"100",phonetic:"SYEN",example:"A: ¿Cuánto cuesta la chaqueta?\nB: Cuesta cien euros.",exampleEn:"A: How much does the jacket cost?\nB: It costs one hundred euros.",note:"Cien when exactly 100. Ciento before other numbers: ciento uno (101)."},
{type:"teach",kind:"word",nl:"doscientos",en:"200",phonetic:"dos-SYEN-tos",example:"A: ¿Cuánto cuestan los zapatos?\nB: Cuestan doscientos euros.",exampleEn:"A: How much do the shoes cost?\nB: They cost two hundred euros.",note:"Changes with gender: doscientos (m), doscientas (f)."},
{type:"teach",kind:"word",nl:"trescientos",en:"300",phonetic:"tres-SYEN-tos",example:"A: El traje cuesta trescientos euros.\nB: ¡Es muy caro!",exampleEn:"A: The suit costs three hundred euros.\nB: That's very expensive!",note:"Trescientos (m), trescientas (f). Same gender pattern."},
{type:"teach",kind:"word",nl:"quinientos",en:"500",phonetic:"kee-NYEN-tos",example:"A: ¿Cuánto cuesta el abrigo?\nB: Quinientos euros. Es de muy buena calidad.",exampleEn:"A: How much does the coat cost?\nB: Five hundred euros. It's very good quality.",note:"Irregular: not cincocientos. Quinientos/quinientas."},
{type:"teach",kind:"word",nl:"mil",en:"1000",phonetic:"MEEL",example:"A: Este vestido cuesta mil euros.\nB: ¡Mil euros! No, gracias.",exampleEn:"A: This dress costs a thousand euros.\nB: A thousand euros! No, thanks.",note:"Mil never changes form. Never say 'un mil'."},
{type:"tip",title:"Hundreds in Spanish",text:"100 = cien (alone) / ciento (+ more numbers)\n200 = doscientos/as\n300 = trescientos/as\n400 = cuatrocientos/as\n500 = quinientos/as (irregular)\n600 = seiscientos/as\n700 = setecientos/as\n800 = ochocientos/as\n900 = novecientos/as\n1000 = mil\nHundreds agree in gender with the noun:\ndoscientos euros, doscientas personas"},
{type:"mc",q:"¿Cómo se dice 500 en español?",opts:["quinientos","cincocientos","quientos","cincuentos"],ans:"quinientos",hint:"This is an irregular form that does not follow the pattern."},
{type:"fb",s:"El abrigo cuesta {1} euros. (300)",a:"trescientos",opts:["trescientos","trecientos","trescien","tresientos"],hint:"Three hundred follows the regular pattern: tres + cientos."},
{type:"mc",q:"How do you say exactly 100?",opts:["cien","ciento","un cien","una ciento"],ans:"cien",hint:"When the number stands alone at exactly 100, use the short form."},
{type:"mc",q:"Doscientas personas means:",opts:["200 people","200 men","2000 people","20 people"],ans:"200 people",hint:"The -as ending matches a feminine plural noun."},
{type:"fb",s:"Este traje cuesta {1} euros. (1000)",a:"mil",opts:["mil","miel","un mil","miles"],hint:"The word for one thousand never takes an article before it."},
{type:"match",pairs:[{nl:"cien",en:"100"},{nl:"doscientos",en:"200"},{nl:"quinientos",en:"500"},{nl:"setecientos",en:"700"},{nl:"mil",en:"1000"}]},
{type:"mc",q:"Ciento uno means:",opts:["101","110","100","111"],ans:"101",hint:"Ciento is used before additional numbers after one hundred."},
{type:"fb",s:"Los zapatos cuestan {1} euros. (400)",a:"cuatrocientos",opts:["cuatrocientos","quatrocientos","cuatroscientos","cuatrientos"],hint:"Four hundred: cuatro + cientos in their combined form."},
{type:"mc",q:"¿Cuánto cuestan las zapatillas? Cuestan ___ euros. (800)",opts:["ochocientos","ochoscientos","ocho cientos","ochicientos"],ans:"ochocientos",hint:"Eight hundred: ocho combined with cientos in one word."},
{type:"mc",q:"The jacket costs 150 euros. In Spanish:",opts:["ciento cincuenta euros","cien cincuenta euros","cincuenta cien euros","quince cero euros"],ans:"ciento cincuenta euros",hint:"When 100 is followed by more numbers, use the longer form."},
{type:"fb",s:"Las zapatillas cuestan {1} euros. (600)",a:"seiscientos",opts:["seiscientos","seicientos","seis cientos","seisciento"],hint:"Six hundred: seis combined with cientos in one word."}
]},
{id:"esp8l5",title:"Los Demostrativos",icon:"👉",xp:15,board:true,steps:[
{type:"intro",title:"Los Demostrativos",desc:"Learn to say 'this', 'that', and 'that over there' in Spanish. Spanish has three levels of distance.",goals:["Use este/esta for items nearby","Use ese/esa for items at medium distance","Use aquel/aquella for items far away"]},
{type:"teach",kind:"word",nl:"este / esta",en:"this (m/f)",phonetic:"ES-te / ES-ta",example:"A: ¿Te gusta esta camisa?\nB: Sí, esta camisa es muy bonita.",exampleEn:"A: Do you like this shirt?\nB: Yes, this shirt is very pretty.",note:"Near you. Este (m), esta (f), estos (m pl), estas (f pl)."},
{type:"teach",kind:"word",nl:"ese / esa",en:"that (m/f)",phonetic:"E-se / E-sa",example:"A: ¿Cuánto cuesta ese pantalón?\nB: Ese pantalón cuesta cincuenta euros.",exampleEn:"A: How much does that pair of pants cost?\nB: That pair of pants costs fifty euros.",note:"Near the listener. Ese (m), esa (f), esos (m pl), esas (f pl)."},
{type:"teach",kind:"word",nl:"aquel / aquella",en:"that over there (m/f)",phonetic:"a-KEL / a-KE-ya",example:"A: ¿Ves aquel sombrero?\nB: ¿Cuál? ¿Aquel sombrero negro?",exampleEn:"A: Do you see that hat over there?\nB: Which one? That black hat over there?",note:"Far from both speakers. Aquel (m), aquella (f), aquellos (m pl), aquellas (f pl)."},
{type:"tip",title:"Three Levels of Distance",text:"Spanish has THREE demonstratives, not just two:\n1. Este/esta (this): near the speaker\n2. Ese/esa (that): near the listener\n3. Aquel/aquella (that over there): far from both\n\nAll must match gender AND number of the noun:\neste zapato, esta falda\nesos zapatos, esas faldas\naquellos zapatos, aquellas faldas"},
{type:"teach",kind:"word",nl:"estos / estas",en:"these (m/f)",phonetic:"ES-tos / ES-tas",example:"A: ¿Son nuevos estos zapatos?\nB: Sí, estos zapatos son nuevos.",exampleEn:"A: Are these shoes new?\nB: Yes, these shoes are new.",note:"Plural of este/esta. Estos (m pl), estas (f pl)."},
{type:"teach",kind:"word",nl:"esos / esas",en:"those (m/f)",phonetic:"E-sos / E-sas",example:"A: ¿Te gustan esas zapatillas?\nB: No, prefiero esos vaqueros.",exampleEn:"A: Do you like those sneakers?\nB: No, I prefer those jeans.",note:"Plural of ese/esa. Esos (m pl), esas (f pl)."},
{type:"mc",q:"You point to a shirt right next to you. You say:",opts:["esta camisa","esa camisa","aquella camisa","el camisa"],ans:"esta camisa",hint:"Which demonstrative is used for things close to the speaker?"},
{type:"mc",q:"Your friend holds a hat. You say 'I like that hat'. Which word?",opts:["ese sombrero","este sombrero","aquel sombrero","el sombrero"],ans:"ese sombrero",hint:"The hat is near the listener, not near you or far away."},
{type:"fb",s:"¿Ves {1} vestido en la ventana? Está muy lejos.",a:"aquel",opts:["aquel","este","ese","el"],hint:"The dress is far from both of you. Which demonstrative fits?"},
{type:"mc",q:"___ zapatos son muy bonitos. (near me)",opts:["Estos","Esos","Aquellos","Los"],ans:"Estos",hint:"The shoes are near the speaker. Use the plural near form."},
{type:"fb",s:"¿Cuánto cuestan {1} calcetines? (near the listener)",a:"esos",opts:["esos","estos","aquellos","los"],hint:"The socks are near the other person. Use medium distance plural."},
{type:"match",pairs:[{nl:"este",en:"this (m)"},{nl:"esa",en:"that (f)"},{nl:"aquellos",en:"those over there (m)"},{nl:"estas",en:"these (f)"},{nl:"ese",en:"that (m)"}]},
{type:"mc",q:"'Aquellas faldas son baratas' means:",opts:["Those skirts over there are cheap","These skirts are cheap","Those skirts are expensive","That skirt over there is cheap"],ans:"Those skirts over there are cheap",hint:"Aquellas is the far feminine plural demonstrative."},
{type:"fb",s:"Me gusta {1} camiseta. (pointing to one right here)",a:"esta",opts:["esta","esa","aquella","la"],hint:"The t-shirt is right next to you. Camiseta is feminine."},
{type:"mc",q:"You see a coat in a faraway shop window. You say:",opts:["Mira aquel abrigo","Mira este abrigo","Mira ese abrigo","Mira el abrigo"],ans:"Mira aquel abrigo",hint:"The coat is far from both you and your companion."},
{type:"mc",q:"___ bufandas son muy caras. (those, medium distance)",opts:["Esas","Estas","Aquellas","Las"],ans:"Esas",hint:"Bufandas is feminine plural. The items are at medium distance."},
{type:"fb",s:"Quiero {1} zapatillas, las que están allí lejos.",a:"aquellas",opts:["aquellas","estas","esas","las"],hint:"The sneakers are far away from both speakers. Feminine plural."}
]},
{id:"esp8l6",title:"Colores y Ropa",icon:"🎨",xp:15,board:true,steps:[
{type:"intro",title:"Colores y Ropa",desc:"Combine colors with clothing and practice adjective agreement. Colors change to match the noun's gender and number.",goals:["Describe clothing with colors","Practice gender agreement with adjectives","Build longer descriptive sentences"]},
{type:"tip",title:"Color Agreement with Clothing",text:"Colors are adjectives that follow the noun:\nla camisa roja (the red shirt)\nel pantalón negro (the black pants)\n\nMost colors change for gender and number:\nrojo/roja/rojos/rojas\nnegro/negra/negros/negras\nblanco/blanca/blancos/blancas\n\nSome colors do NOT change:\nnaranja, rosa, marrón (pl: marrones)\nla camisa rosa, el pantalón rosa"},
{type:"teach",kind:"phrase",nl:"la camisa blanca",en:"the white shirt",phonetic:"ka-MEE-sa BLAN-ka",example:"A: ¿De qué color es tu camisa?\nB: Llevo una camisa blanca.",exampleEn:"A: What color is your shirt?\nB: I'm wearing a white shirt.",note:"Blanca matches the feminine noun camisa."},
{type:"teach",kind:"phrase",nl:"el pantalón negro",en:"the black pants",phonetic:"pan-ta-LON NE-gro",example:"A: ¿Qué llevas hoy?\nB: Llevo el pantalón negro y una camisa azul.",exampleEn:"A: What are you wearing today?\nB: I'm wearing the black pants and a blue shirt.",note:"Negro matches the masculine noun pantalón."},
{type:"teach",kind:"phrase",nl:"los zapatos marrones",en:"the brown shoes",phonetic:"sa-PA-tos ma-RO-nes",example:"A: ¿Te gustan estos zapatos?\nB: Sí, los zapatos marrones son bonitos.",exampleEn:"A: Do you like these shoes?\nB: Yes, the brown shoes are nice.",note:"Marrón adds -es for plural: marrones. No gender change."},
{type:"teach",kind:"phrase",nl:"la falda roja",en:"the red skirt",phonetic:"FAL-da RO-ha",example:"A: ¿Cuál prefieres?\nB: Prefiero la falda roja.",exampleEn:"A: Which do you prefer?\nB: I prefer the red skirt.",note:"Roja matches the feminine noun falda."},
{type:"teach",kind:"word",nl:"claro",en:"light (color)",phonetic:"KLA-ro",example:"A: ¿Te gusta el azul claro?\nB: Sí, prefiero el azul claro al azul oscuro.",exampleEn:"A: Do you like light blue?\nB: Yes, I prefer light blue to dark blue.",note:"Claro follows the color: verde claro, rosa claro."},
{type:"teach",kind:"word",nl:"oscuro",en:"dark (color)",phonetic:"os-KU-ro",example:"A: ¿Tienes esta camisa en verde oscuro?\nB: Sí, un momento.",exampleEn:"A: Do you have this shirt in dark green?\nB: Yes, one moment.",note:"Oscuro follows the color: rojo oscuro, azul oscuro."},
{type:"mc",q:"La camisa ___. (white, feminine)",opts:["blanca","blanco","blancos","blancas"],ans:"blanca",hint:"Camisa is feminine singular. What ending matches?"},
{type:"fb",s:"Llevo el pantalón {1} y la camisa azul.",a:"negro",opts:["negro","negra","negros","negras"],hint:"Pantalón is masculine singular. Match the adjective ending."},
{type:"mc",q:"Los zapatos ___. (brown, plural)",opts:["marrones","marrón","marrónes","marrons"],ans:"marrones",hint:"Marrón takes -es in the plural. No accent change needed."},
{type:"fb",s:"Me gusta la falda {1}. (red)",a:"roja",opts:["roja","rojo","rojas","rojos"],hint:"Falda is feminine singular. Match the color's ending."},
{type:"mc",q:"'Una camiseta rosa' is correct because:",opts:["Rosa doesn't change for gender","Rosa is always feminine","Camiseta is masculine","Rosa means pink only for girls"],ans:"Rosa doesn't change for gender",hint:"Some Spanish color words stay the same for all nouns."},
{type:"match",pairs:[{nl:"la chaqueta negra",en:"the black jacket"},{nl:"el vestido rojo",en:"the red dress"},{nl:"los calcetines blancos",en:"the white socks"},{nl:"las zapatillas azules",en:"the blue sneakers"},{nl:"la bufanda verde",en:"the green scarf"}]},
{type:"fb",s:"¿Tiene esta camisa en azul {1}?",a:"oscuro",opts:["oscuro","oscura","claro","clara"],hint:"When modifying a color, this word means the darker shade."},
{type:"mc",q:"El sombrero ___ es bonito. (light green)",opts:["verde claro","claro verde","verde clara","verdo claro"],ans:"verde claro",hint:"The shade word follows the color. Verde does not change for gender."},
{type:"drag_fill",s:"Llevo {1} zapatos {2} y {3} camisa {4}.",blanks:{1:"los",2:"negros",3:"una",4:"blanca"},pool:["los","negros","una","blanca","el","negro","la","blanco"],hint:"Match articles and colors to each noun's gender and number."},
{type:"mc",q:"Mi hermana lleva unas faldas ___. (red, plural)",opts:["rojas","roja","rojos","rojo"],ans:"rojas",hint:"Faldas is feminine plural. Match the color ending to it."}
]},
{id:"esp8l7",title:"En la Tienda de Ropa",icon:"🛒",xp:15,board:true,steps:[
{type:"intro",title:"En la Tienda de Ropa",desc:"Practice complete shopping dialogues. Combine clothing, colors, numbers, and shopping phrases in real conversations.",goals:["Have a full shopping conversation","Ask about sizes, colors, and prices","Make purchasing decisions"]},
{type:"teach",kind:"word",nl:"el probador",en:"fitting room",phonetic:"pro-ba-DOR",example:"A: ¿Puedo probarme este vestido?\nB: Sí, claro. El probador está al fondo.",exampleEn:"A: Can I try on this dress?\nB: Yes, of course. The fitting room is at the back.",note:"Masculine noun. Al fondo means at the back/far end."},
{type:"teach",kind:"word",nl:"la talla",en:"size",phonetic:"TA-ya",example:"A: ¿Qué talla necesita?\nB: Necesito la talla grande, por favor.",exampleEn:"A: What size do you need?\nB: I need size large, please.",note:"Sizes: pequeña (S), mediana (M), grande (L), extra grande (XL)."},
{type:"teach",kind:"phrase",nl:"¿Tiene otra talla?",en:"Do you have another size?",phonetic:"TYE-ne O-tra TA-ya",example:"A: Esta camisa me queda pequeña.\nB: ¿Tiene otra talla?\nA: Sí, aquí tiene la mediana.",exampleEn:"A: This shirt is too small on me.\nB: Do you have another size?\nA: Yes, here's the medium.",note:"Otra/otro means another or other."},
{type:"teach",kind:"phrase",nl:"pagar en efectivo",en:"to pay in cash",phonetic:"pa-GAR en e-fek-TEE-vo",example:"A: ¿Cómo quiere pagar?\nB: En efectivo, por favor.",exampleEn:"A: How would you like to pay?\nB: In cash, please.",note:"Efectivo means cash. Also: pagar con tarjeta (pay by card)."},
{type:"teach",kind:"phrase",nl:"pagar con tarjeta",en:"to pay by card",phonetic:"pa-GAR kon tar-HE-ta",example:"A: ¿Puedo pagar con tarjeta?\nB: Sí, por supuesto.",exampleEn:"A: Can I pay by card?\nB: Yes, of course.",note:"Tarjeta means card. Por supuesto means of course."},
{type:"tip",title:"A Complete Shopping Conversation",text:"In a clothing store, you might:\n1. ¿Tiene...? (ask if they have something)\n2. ¿Puedo probarme...? (ask to try it on)\n3. Me queda bien/mal/grande/pequeño (comment on fit)\n4. ¿Tiene otra talla/color? (ask for alternatives)\n5. ¿Cuánto cuesta? (ask the price)\n6. Me lo/la llevo (decide to buy)\n7. ¿Puedo pagar con tarjeta? (ask about payment)"},
{type:"mc",q:"You want to try on a jacket. You say:",opts:["¿Puedo probarme esta chaqueta?","¿Cuánto cuesta esta chaqueta?","Me llevo esta chaqueta.","¿Tiene otra chaqueta?"],ans:"¿Puedo probarme esta chaqueta?",hint:"Which phrase asks for permission to try clothing on?"},
{type:"fb",s:"Esta falda me queda {1}. Necesito otra talla.",a:"grande",opts:["grande","bien","bonita","cara"],hint:"You need a different size because this one does not fit properly."},
{type:"mc",q:"¿Cómo quiere pagar? ___.",opts:["Con tarjeta, por favor","Me lo llevo","Me queda bien","¿Cuánto cuesta?"],ans:"Con tarjeta, por favor",hint:"The clerk is asking about your payment method."},
{type:"fb",s:"¿Dónde está el {1}? Quiero probarme esta camisa.",a:"probador",opts:["probador","zapato","cinturón","vestido"],hint:"Which room in a store is used to try on clothing?"},
{type:"mc",q:"The pants fit perfectly. You say:",opts:["Me quedan bien","Me queda bien","Me queda mal","Me quedan mal"],ans:"Me quedan bien",hint:"Pantalones is plural, so the verb must match that form."},
{type:"drag_fill",s:"¿{1} esta camisa en {2} talla?",blanks:{1:"Tiene",2:"otra"},pool:["Tiene","otra","Cuesta","esta","Cuánto","esa"],hint:"Ask the clerk if they have an alternative size available."},
{type:"match",pairs:[{nl:"el probador",en:"fitting room"},{nl:"pagar con tarjeta",en:"pay by card"},{nl:"en efectivo",en:"in cash"},{nl:"¿Tiene otra talla?",en:"Do you have another size?"},{nl:"Me lo llevo",en:"I'll take it"}]},
{type:"mc",q:"Los zapatos cuestan doscientos euros. Son muy ___.",opts:["caros","baratos","grandes","bonitos"],ans:"caros",hint:"Two hundred euros for shoes is a high price."},
{type:"fb",s:"Me gusta el vestido azul. Me {1} llevo.",a:"lo",opts:["lo","la","los","las"],hint:"Vestido is masculine singular. Which pronoun matches?"},
{type:"mc",q:"¿Puedo pagar ___? No tengo tarjeta.",opts:["en efectivo","con tarjeta","con zapatos","en probador"],ans:"en efectivo",hint:"If you don't have a card, what is the other way to pay?"},
{type:"fb",s:"Estos pantalones me {1} muy bien. Me los llevo.",a:"quedan",opts:["quedan","queda","quedo","quedas"],hint:"The verb must agree with pantalones, which is plural."}
]},
{id:"esp8l8",title:"¡Vamos de Compras!",icon:"🎁",xp:15,board:true,steps:[
{type:"intro",title:"¡Vamos de Compras!",desc:"Put everything together: clothing, colors, demonstratives, numbers, and shopping phrases in complete conversations.",goals:["Combine all Unit 8 vocabulary in context","Practice full shopping scenarios","Review demonstratives with clothing descriptions"]},
{type:"tip",title:"Review: Shopping Toolkit",text:"Your complete shopping toolkit:\n1. Clothing: camisa, pantalón, vestido, falda, zapatos, chaqueta...\n2. Colors: rojo/a, azul, verde, negro/a, blanco/a, marrón...\n3. Demonstratives: este/ese/aquel (+ gender/number)\n4. Numbers: cien, doscientos, quinientos, mil\n5. Phrases: ¿Cuánto cuesta?, Me lo llevo, Me queda bien..."},
{type:"mc",q:"¿Cuánto cuestan estos zapatos negros?",opts:["How much do these black shoes cost?","How much does this black shoe cost?","Do you have these black shoes?","I want these black shoes."],ans:"How much do these black shoes cost?",hint:"Cuestan is plural. Estos is the near plural demonstrative."},
{type:"fb",s:"Me gusta {1} vestido rojo. ¿Cuánto cuesta?",a:"este",opts:["este","esta","ese","aquel"],hint:"Vestido is masculine. The item is close to the speaker."},
{type:"drag_fill",s:"{1} falda {2} cuesta {3} euros.",blanks:{1:"Esta",2:"blanca",3:"trescientos"},pool:["Esta","blanca","trescientos","Este","blanco","tres cientos"],hint:"Match the demonstrative and color to the feminine noun falda."},
{type:"mc",q:"You see a nice coat far away. You say: 'Mira ___ abrigo'.",opts:["aquel","este","ese","eso"],ans:"aquel",hint:"The coat is far from both you and your companion."},
{type:"fb",s:"Estos calcetines son muy {1}. Solo cuestan dos euros.",a:"baratos",opts:["baratos","caros","grandes","bonitos"],hint:"They only cost two euros. What does that make them?"},
{type:"mc",q:"La camiseta me queda pequeña. Necesito ___.",opts:["otra talla","otro color","el probador","pagar"],ans:"otra talla",hint:"The shirt is too small, so you need a different what?"},
{type:"drag_fill",s:"¿{1} probarme {2} chaqueta {3}?",blanks:{1:"Puedo",2:"esa",3:"verde"},pool:["Puedo","esa","verde","Puede","esta","verda"],hint:"Ask if you can try on a green jacket near the listener."},
{type:"match",pairs:[{nl:"este sombrero",en:"this hat"},{nl:"esa bufanda",en:"that scarf"},{nl:"aquellos zapatos",en:"those shoes over there"},{nl:"estas camisetas",en:"these t-shirts"},{nl:"esos vaqueros",en:"those jeans"}]},
{type:"fb",s:"El traje cuesta {1} euros. (500)",a:"quinientos",opts:["quinientos","cincocientos","quincientos","quinento"],hint:"Remember, this number has an irregular form that starts with 'quin'."},
{type:"mc",q:"You want to buy the skirt. It's feminine. You say:",opts:["Me la llevo","Me lo llevo","Me los llevo","Me las llevo"],ans:"Me la llevo",hint:"Falda is feminine singular. Match the pronoun accordingly."},
{type:"mc",q:"¿Cómo quiere pagar? No tengo efectivo. ___.",opts:["Con tarjeta, por favor","En efectivo, por favor","Me lo llevo","¿Cuánto cuesta?"],ans:"Con tarjeta, por favor",hint:"You don't have cash, so what is the alternative payment method?"},
{type:"fb",s:"Esas zapatillas {1} son muy cómodas.",a:"blancas",opts:["blancas","blancos","blanca","blanco"],hint:"Zapatillas is feminine plural. Match the color ending."},
{type:"drag_fill",s:"Llevo {1} camisa {2} y {3} pantalón {4}.",blanks:{1:"una",2:"azul",3:"un",4:"negro"},pool:["una","azul","un","negro","una","roja","el","negra"],hint:"Pair each article and color with the correct noun gender."},
{type:"mc",q:"'Aquellas faldas rojas cuestan ochocientos euros' means:",opts:["Those red skirts over there cost 800 euros","These red skirts cost 800 euros","That red skirt costs 800 euros","Those red skirts over there cost 80 euros"],ans:"Those red skirts over there cost 800 euros",hint:"Aquellas is far plural feminine. Ochocientos is 800."},
{type:"match",pairs:[{nl:"¿Cuánto cuesta?",en:"How much does it cost?"},{nl:"Me queda grande",en:"It's too big on me"},{nl:"pagar en efectivo",en:"pay in cash"},{nl:"la talla mediana",en:"size medium"},{nl:"¿Tiene otra talla?",en:"Do you have another size?"}]},
{type:"mc",q:"You see a beautiful dress in the store window. Complete: ¡Mira ___ vestido! ¡Es precioso!",opts:["ese","este","aquel","estos"],ans:"ese",hint:"The dress is at medium distance, in the window near where your friend is."}
]}
]}
,
// ══════════════════════════════════════════════════════════════
// UNIT 9: ¿Qué Pasó? — Pretérito Indefinido Regular (A2.1)
// 8 lessons, 18+ steps each
// ══════════════════════════════════════════════════════════════
{n:9,lang:"es",track:"v1",title:"¿Qué Pasó?",sub:"Past Tense: Regular Verbs",icon:"⏪",level:"A2.1",color:"#7B5EE8",lessons:[

// ===== LESSON 1: Introduction to the Past =====
{id:"esp9l1",title:"Ayer y Antes",icon:"📅",xp:15,board:true,steps:[
{type:"intro",title:"Ayer y Antes",desc:"Learn to talk about the past. You already know the present tense. Now we add the past: el pretérito indefinido.",goals:["Learn time expressions for the past","Understand when to use the past tense","Recognize past tense markers"]},
{type:"teach",kind:"word",nl:"ayer",en:"yesterday",phonetic:"ah-YEHR",example:"A: ¿Qué hiciste ayer?\nB: Ayer estudié español.\nA: ¡Qué bien!\nB: Sí, estudié dos horas.",exampleEn:"A: What did you do yesterday?\nB: Yesterday I studied Spanish.\nA: How nice!\nB: Yes, I studied for two hours.",note:"The most common past time word. Always placed at the start or end of a sentence."},
{type:"teach",kind:"word",nl:"anoche",en:"last night",phonetic:"ah-NOH-cheh",example:"A: ¿Qué comiste anoche?\nB: Anoche cené pasta.\nA: ¿Cocinaste tú?\nB: No, compré comida preparada.",exampleEn:"A: What did you eat last night?\nB: Last night I had pasta for dinner.\nA: Did you cook?\nB: No, I bought prepared food.",note:"Combines a (at) + noche (night). One single word, not two."},
{type:"teach",kind:"phrase",nl:"la semana pasada",en:"last week",phonetic:"la seh-MAH-nah pah-SAH-dah",example:"A: ¿Trabajaste la semana pasada?\nB: Sí, trabajé cinco días.\nA: ¿Y el fin de semana?\nB: Descansé en casa.",exampleEn:"A: Did you work last week?\nB: Yes, I worked five days.\nA: And the weekend?\nB: I rested at home.",note:"Pasado/pasada means 'last' or 'past' when placed AFTER the noun."},
{type:"teach",kind:"word",nl:"el mes pasado",en:"last month",phonetic:"el mehs pah-SAH-doh",example:"A: ¿Viajaste el mes pasado?\nB: Sí, visité Barcelona.\nA: ¿Te gustó?\nB: ¡Me encantó!",exampleEn:"A: Did you travel last month?\nB: Yes, I visited Barcelona.\nA: Did you like it?\nB: I loved it!",note:"El mes = the month. Pasado (masculine) matches mes (masculine)."},
{type:"teach",kind:"phrase",nl:"el año pasado",en:"last year",phonetic:"el AH-nyoh pah-SAH-doh",example:"A: ¿Dónde viviste el año pasado?\nB: El año pasado viví en Madrid.\nA: ¿Y ahora?\nB: Ahora vivo en Sevilla.",exampleEn:"A: Where did you live last year?\nB: Last year I lived in Madrid.\nA: And now?\nB: Now I live in Seville.",note:"El año = the year. Use for events further in the past."},
{type:"teach",kind:"word",nl:"antes",en:"before / earlier",phonetic:"AHN-tehs",example:"A: ¿Dónde trabajaste antes?\nB: Antes trabajé en un banco.\nA: ¿Y ahora?\nB: Ahora trabajo en una tienda.",exampleEn:"A: Where did you work before?\nB: Before I worked in a bank.\nA: And now?\nB: Now I work in a shop.",note:"Used to contrast past and present. You already know antes de (before doing something)."},
{type:"tip",title:"Talking About the Past",text:"In Spanish, the pretérito indefinido is used for completed actions in the past.\n\nKey time words:\n- ayer (yesterday)\n- anoche (last night)\n- la semana pasada (last week)\n- el mes pasado (last month)\n- el año pasado (last year)\n- antes (before)\n\nNotice: pasado/pasada goes AFTER the noun and matches its gender.\n- el mes pasado (masculine)\n- la semana pasada (feminine)"},
{type:"mc",q:"How do you say 'last week' in Spanish?",opts:["la semana pasada","el semana pasado","la semana antes","la pasada semana"],ans:"la semana pasada",hint:"Semana is feminine, so the adjective must match."},
{type:"mc",q:"Which word means 'yesterday'?",opts:["ayer","anoche","antes","pasado"],ans:"ayer",hint:"This is a single word, not a phrase with pasado."},
{type:"fb",s:"________ comí pizza con mi familia.",a:"Anoche",opts:["Anoche","Ayer mañana","El noche","La noche pasado"],hint:"Which time word means 'last night' as one word?"},
{type:"fb",s:"Viajé a México el ________ pasado.",a:"año",opts:["año","semana","noche","ayer"],hint:"Think about which noun is masculine and fits with 'el ... pasado'."},
{type:"mc",q:"'Pasada' is feminine because it matches which word?",opts:["semana","mes","año","día"],ans:"semana",hint:"Which of these time nouns is feminine?"},
{type:"match",pairs:[{nl:"ayer",en:"yesterday"},{nl:"anoche",en:"last night"},{nl:"la semana pasada",en:"last week"},{nl:"el mes pasado",en:"last month"},{nl:"el año pasado",en:"last year"}]},
{type:"fb",s:"________ trabajé mucho en la oficina.",a:"Ayer",opts:["Ayer","Mañana","Ahora","Siempre"],hint:"Which word refers to the day before today?"},
{type:"mc",q:"Which phrase means 'last month'?",opts:["el mes pasado","la mes pasada","el pasado mes","el mes antes"],ans:"el mes pasado",hint:"Mes is masculine, so the adjective ending should match."},
{type:"drag_fill",s:"{1} estudié español y {2} descansé.",blanks:{"1":"Ayer","2":"anoche"},pool:["Ayer","anoche","mañana","ahora"],hint:"One is 'yesterday' and the other is 'last night'."},
{type:"mc",q:"A: ¿Cuándo visitaste el museo?\nB: ________",opts:["La semana pasada.","La semana próxima.","Mañana por la tarde.","Ahora mismo."],ans:"La semana pasada.",hint:"The question asks about the past, so the answer must be a past time expression."},
{type:"fb",s:"________ de estudiar español, estudié francés.",a:"Antes",opts:["Antes","Después","Ayer","Anoche"],hint:"Which word means 'before' when comparing two past experiences?"}
]},

// ===== LESSON 2: -AR Verbs in Pretérito =====
{id:"esp9l2",title:"Yo Hablé",icon:"🗣️",xp:15,board:true,steps:[
{type:"intro",title:"Yo Hablé",desc:"Learn to conjugate -AR verbs in the past tense. You already know hablar, trabajar, comprar, cocinar, and estudiar in the present. Now let's use them in the past.",goals:["Conjugate -AR verbs in pretérito indefinido","Use all person forms (yo, tú, él/ella, nosotros, ellos)","Practice with familiar -AR verbs"]},
{type:"tip",title:"-AR Verb Endings in the Past",text:"To form the past tense of -AR verbs, remove -ar and add:\n\nyo: -é\ntú: -aste\nél/ella/usted: -ó\nnosotros: -amos\nellos/ellas/ustedes: -aron\n\nExample with hablar (to speak):\nhablé, hablaste, habló, hablamos, hablaron\n\nNotice: the yo form has an accent (é) and the él/ella form has an accent (ó). These accents are important!"},
{type:"verb_table",title:"Hablar (to speak)",label:"Pretérito Indefinido",groups:[{label:"",rows:[["yo","hablé"],["tú","hablaste"],["él/ella/Ud.","habló"],["nosotros","hablamos"],["ellos/Uds.","hablaron"]]}],note:"Notice: nosotros is the same as the present tense! Context tells you which one."},
{type:"teach",kind:"phrase",nl:"hablé",en:"I spoke / I talked",phonetic:"ah-BLEH",example:"A: ¿Hablaste con María?\nB: Sí, hablé con ella ayer.\nA: ¿Qué te dijo?\nB: Hablamos de las vacaciones.",exampleEn:"A: Did you talk to María?\nB: Yes, I talked to her yesterday.\nA: What did she say?\nB: We talked about the holidays.",note:"Yo hablé. The accent on the é is essential to mark past tense."},
{type:"teach",kind:"phrase",nl:"trabajé",en:"I worked",phonetic:"trah-bah-HEH",example:"A: ¿Trabajaste ayer?\nB: Sí, trabajé ocho horas.\nA: ¿No descansaste?\nB: Descanso hoy.",exampleEn:"A: Did you work yesterday?\nB: Yes, I worked eight hours.\nA: Didn't you rest?\nB: I rest today.",note:"From trabajar. Same pattern: remove -ar, add -é."},
{type:"teach",kind:"phrase",nl:"compró",en:"he/she bought",phonetic:"kohm-PROH",example:"A: ¿Qué compró tu madre?\nB: Compró fruta en el mercado.\nA: ¿Compró naranjas?\nB: Sí, y también manzanas.",exampleEn:"A: What did your mother buy?\nB: She bought fruit at the market.\nA: Did she buy oranges?\nB: Yes, and also apples.",note:"Él/ella/usted form. The accent on the ó marks past tense."},
{type:"teach",kind:"phrase",nl:"cocinaron",en:"they cooked",phonetic:"koh-see-NAH-rohn",example:"A: ¿Quién cocinó anoche?\nB: Mis padres cocinaron juntos.\nA: ¿Qué cocinaron?\nB: Cocinaron paella.",exampleEn:"A: Who cooked last night?\nB: My parents cooked together.\nA: What did they cook?\nB: They cooked paella.",note:"Ellos/ustedes form. The ending -aron is always the they/you-all form."},
{type:"teach",kind:"phrase",nl:"estudiaste",en:"you studied",phonetic:"ehs-too-dee-AHS-teh",example:"A: ¿Estudiaste para el examen?\nB: Sí, estudié tres horas.\nA: ¿Estudiaste sola?\nB: No, estudiamos juntas María y yo.",exampleEn:"A: Did you study for the exam?\nB: Yes, I studied three hours.\nA: Did you study alone?\nB: No, María and I studied together.",note:"Tú form. The ending -aste is always the you (informal) form."},
{type:"mc",q:"What is the yo form of 'comprar' in the past?",opts:["compré","compró","compraste","compraron"],ans:"compré",hint:"The yo ending for -AR verbs in the past has an accent on the last vowel."},
{type:"mc",q:"Complete: Ellos ________ en un restaurante anoche.",opts:["cenaron","cené","cenaste","cenó"],ans:"cenaron",hint:"Ellos requires the they form. What ending goes with -AR verbs for ellos?"},
{type:"fb",s:"Ayer yo ________ con mi amigo por teléfono.",a:"hablé",opts:["hablé","habló","hablaste","hablaron"],hint:"Yo form of hablar in the past. Remember the accent."},
{type:"fb",s:"Mi hermana ________ un vestido nuevo la semana pasada.",a:"compró",opts:["compró","compré","compraste","compraron"],hint:"Mi hermana is ella. Which ending matches él/ella?"},
{type:"match",pairs:[{nl:"hablé",en:"I spoke"},{nl:"hablaste",en:"you spoke"},{nl:"habló",en:"he/she spoke"},{nl:"hablamos",en:"we spoke"},{nl:"hablaron",en:"they spoke"}]},
{type:"mc",q:"Which form is the SAME in present and past for -AR verbs?",opts:["nosotros (hablamos)","yo (hablo/hablé)","tú (hablas/hablaste)","ellos (hablan/hablaron)"],ans:"nosotros (hablamos)",hint:"One person form looks identical in both tenses. Context distinguishes them."},
{type:"fb",s:"¿________ español en la escuela el año pasado?",a:"Estudiaste",opts:["Estudiaste","Estudié","Estudiaron","Estudió"],hint:"The question is directed at tú. What is the tú past ending for -AR?"},
{type:"drag_fill",s:"Ayer yo {1} y mi madre {2} la cena.",blanks:{"1":"trabajé","2":"cocinó"},pool:["trabajé","cocinó","trabajaron","cociné"],hint:"Yo gets the -é ending, and mi madre (ella) gets the -ó ending."},
{type:"mc",q:"A: ¿Quién compró el pan?\nB: Yo lo ________.",opts:["compré","compró","compraste","compraron"],ans:"compré",hint:"B is answering 'I bought it.' Which form is first person past?"},
{type:"fb",s:"Nosotros ________ juntos en la cocina anoche.",a:"cocinamos",opts:["cocinamos","cocinaron","cociné","cocinó"],hint:"Nosotros form of cocinar. This form looks the same as the present."}
]},

// ===== LESSON 3: -ER Verbs in Pretérito =====
{id:"esp9l3",title:"Yo Comí",icon:"🍽️",xp:15,board:true,steps:[
{type:"intro",title:"Yo Comí",desc:"Now let's learn the past tense for -ER verbs. The endings are different from -AR verbs, but just as regular.",goals:["Conjugate -ER verbs in pretérito indefinido","Compare -AR and -ER past tense endings","Practice with comer, beber, leer, aprender, vender"]},
{type:"tip",title:"-ER Verb Endings in the Past",text:"To form the past tense of -ER verbs, remove -er and add:\n\nyo: -í\ntú: -iste\nél/ella/usted: -ió\nnosotros: -imos\nellos/ellas/ustedes: -ieron\n\nExample with comer (to eat):\ncomí, comiste, comió, comimos, comieron\n\nKey difference from -AR: yo ends in -í (not -é), él/ella ends in -ió (not -ó)."},
{type:"verb_table",title:"Comer (to eat)",label:"Pretérito Indefinido",groups:[{label:"",rows:[["yo","comí"],["tú","comiste"],["él/ella/Ud.","comió"],["nosotros","comimos"],["ellos/Uds.","comieron"]]}],note:"The -ER and -IR verbs share the SAME past tense endings. Learn these once, use them twice!"},
{type:"teach",kind:"phrase",nl:"comí",en:"I ate",phonetic:"koh-MEE",example:"A: ¿Qué comiste ayer?\nB: Comí arroz con pollo.\nA: ¿Dónde comiste?\nB: Comí en un restaurante nuevo.",exampleEn:"A: What did you eat yesterday?\nB: I ate rice with chicken.\nA: Where did you eat?\nB: I ate at a new restaurant.",note:"Yo comí. The accent on -í marks the past tense for -ER verbs."},
{type:"teach",kind:"phrase",nl:"bebió",en:"he/she drank",phonetic:"beh-bee-OH",example:"A: ¿Qué bebió Juan anoche?\nB: Bebió una cerveza.\nA: ¿Solo una?\nB: Bueno, bebió dos.",exampleEn:"A: What did Juan drink last night?\nB: He drank a beer.\nA: Just one?\nB: Well, he drank two.",note:"From beber. Él/ella form: -ió (with accent)."},
{type:"teach",kind:"phrase",nl:"leí",en:"I read (past)",phonetic:"leh-EE",example:"A: ¿Leíste el libro?\nB: Sí, lo leí la semana pasada.\nA: ¿Te gustó?\nB: ¡Me encantó!",exampleEn:"A: Did you read the book?\nB: Yes, I read it last week.\nA: Did you like it?\nB: I loved it!",note:"From leer. Note: leí has an accent. Leer keeps the double e in some forms."},
{type:"teach",kind:"phrase",nl:"aprendimos",en:"we learned",phonetic:"ah-prehn-DEE-mohs",example:"A: ¿Qué aprendieron en clase?\nB: Aprendimos el pretérito.\nA: ¿Fue difícil?\nB: No, aprendimos rápido.",exampleEn:"A: What did you learn in class?\nB: We learned the past tense.\nA: Was it difficult?\nB: No, we learned quickly.",note:"Nosotros form of aprender. The -imos ending is always nosotros for -ER/-IR verbs."},
{type:"teach",kind:"phrase",nl:"vendieron",en:"they sold",phonetic:"behn-dee-EH-rohn",example:"A: ¿Vendieron la casa?\nB: Sí, la vendieron el mes pasado.\nA: ¿Por cuánto?\nB: No sé, pero vendieron rápido.",exampleEn:"A: Did they sell the house?\nB: Yes, they sold it last month.\nA: For how much?\nB: I don't know, but they sold quickly.",note:"From vender. Ellos form: -ieron."},
{type:"mc",q:"What is the yo form of 'comer' in the past?",opts:["comí","comé","comió","comiste"],ans:"comí",hint:"For -ER verbs, the yo past ending is different from -AR verbs. Think: -í not -é."},
{type:"mc",q:"Complete: Tú ________ un café esta mañana.",opts:["bebiste","bebí","bebió","bebieron"],ans:"bebiste",hint:"Tú form of beber in the past. The tú ending for -ER verbs is -iste."},
{type:"fb",s:"Nosotros ________ muchas palabras nuevas ayer.",a:"aprendimos",opts:["aprendimos","aprendieron","aprendí","aprendió"],hint:"Nosotros form of aprender in the past tense."},
{type:"fb",s:"Mi padre ________ el periódico anoche.",a:"leyó",opts:["leyó","leí","leíste","leyeron"],hint:"Él form of leer. Note the spelling change: le- plus -yó."},
{type:"match",pairs:[{nl:"comí",en:"I ate"},{nl:"bebiste",en:"you drank"},{nl:"aprendió",en:"he/she learned"},{nl:"vendimos",en:"we sold"},{nl:"leyeron",en:"they read"}]},
{type:"mc",q:"-ER and -IR verbs share the same past tense endings. Which ending is for 'ellos'?",opts:["-ieron","-aron","-eron","-iron"],ans:"-ieron",hint:"Think of comieron, vendieron. What letters follow the verb stem?"},
{type:"drag_fill",s:"Ayer yo {1} paella y mi amigo {2} agua.",blanks:{"1":"comí","2":"bebió"},pool:["comí","bebió","comiste","bebieron"],hint:"Yo gets -í, and mi amigo (él) gets -ió."},
{type:"fb",s:"¿________ el libro que te di la semana pasada?",a:"Leíste",opts:["Leíste","Leí","Leyó","Leyeron"],hint:"The question is asking tú. What is the tú past form of leer?"},
{type:"mc",q:"A: ¿Qué comieron ustedes?\nB: ________ pescado.",opts:["Comimos","Comieron","Comí","Comió"],ans:"Comimos",hint:"Ustedes asked, so B answers as 'we'. What is the nosotros form?"},
{type:"fb",s:"Los estudiantes ________ muchos libros el semestre pasado.",a:"leyeron",opts:["leyeron","leí","leíste","leyó"],hint:"Los estudiantes = ellos. What is the ellos form of leer in the past?"}
]},

// ===== LESSON 4: -IR Verbs in Pretérito =====
{id:"esp9l4",title:"Yo Viví",icon:"🏠",xp:15,board:true,steps:[
{type:"intro",title:"Yo Viví",desc:"The -IR verbs use the SAME past tense endings as -ER verbs. If you learned comí, comiste, comió, you already know how to conjugate -IR verbs!",goals:["Conjugate -IR verbs in pretérito indefinido","Confirm that -ER and -IR share identical endings","Practice with vivir, escribir, recibir, decidir, salir"]},
{type:"verb_table",title:"Vivir (to live)",label:"Pretérito Indefinido",groups:[{label:"",rows:[["yo","viví"],["tú","viviste"],["él/ella/Ud.","vivió"],["nosotros","vivimos"],["ellos/Uds.","vivieron"]]}],note:"Identical to -ER endings! The only difference between -ER and -IR in the past is the nosotros present (comemos vs vivimos), but in the past both use -imos."},
{type:"teach",kind:"phrase",nl:"viví",en:"I lived",phonetic:"bee-BEE",example:"A: ¿Dónde viviste antes?\nB: Viví en Barcelona tres años.\nA: ¿Te gustó?\nB: Sí, viví muy bien allí.",exampleEn:"A: Where did you live before?\nB: I lived in Barcelona for three years.\nA: Did you like it?\nB: Yes, I lived very well there.",note:"Yo viví. Same -í ending as -ER verbs (comí)."},
{type:"teach",kind:"phrase",nl:"escribió",en:"he/she wrote",phonetic:"ehs-kree-bee-OH",example:"A: ¿Quién escribió esta carta?\nB: La escribió mi hermana.\nA: ¿Cuándo la escribió?\nB: La escribió la semana pasada.",exampleEn:"A: Who wrote this letter?\nB: My sister wrote it.\nA: When did she write it?\nB: She wrote it last week.",note:"From escribir. Él/ella form: -ió (same as comió, bebió)."},
{type:"teach",kind:"phrase",nl:"recibí",en:"I received",phonetic:"reh-see-BEE",example:"A: ¿Recibiste mi mensaje?\nB: Sí, lo recibí ayer.\nA: ¿Por qué no contestaste?\nB: Recibí el mensaje muy tarde.",exampleEn:"A: Did you receive my message?\nB: Yes, I received it yesterday.\nA: Why didn't you reply?\nB: I received the message very late.",note:"From recibir. Regular -IR pattern."},
{type:"teach",kind:"phrase",nl:"decidimos",en:"we decided",phonetic:"deh-see-DEE-mohs",example:"A: ¿Qué decidieron?\nB: Decidimos viajar a España.\nA: ¡Qué emocionante!\nB: Sí, lo decidimos anoche.",exampleEn:"A: What did you decide?\nB: We decided to travel to Spain.\nA: How exciting!\nB: Yes, we decided last night.",note:"From decidir. Nosotros form: -imos."},
{type:"teach",kind:"phrase",nl:"salieron",en:"they went out / they left",phonetic:"sah-lee-EH-rohn",example:"A: ¿Salieron tus amigos anoche?\nB: Sí, salieron a cenar.\nA: ¿A qué hora salieron?\nB: Salieron a las ocho.",exampleEn:"A: Did your friends go out last night?\nB: Yes, they went out for dinner.\nA: What time did they leave?\nB: They left at eight.",note:"From salir. Ellos form: -ieron. Salir is regular in the past tense!"},
{type:"tip",title:"Three Groups, Two Patterns",text:"-AR verbs have their own set of endings:\n-é, -aste, -ó, -amos, -aron\n\n-ER and -IR verbs share ONE set of endings:\n-í, -iste, -ió, -imos, -ieron\n\nSo really, you only need to remember two patterns, not three!\n\nQuick comparison:\nyo: hablé vs comí/viví\ntú: hablaste vs comiste/viviste\nél: habló vs comió/vivió"},
{type:"mc",q:"What is the tú form of 'escribir' in the past?",opts:["escribiste","escribí","escribió","escribieron"],ans:"escribiste",hint:"Tú form for -IR verbs uses the same ending as -ER: think comiste, viviste..."},
{type:"mc",q:"Complete: Ellos ________ salir temprano.",opts:["decidieron","decidimos","decidí","decidió"],ans:"decidieron",hint:"Ellos requires the they form. What is the -ieron ending applied to decid-?"},
{type:"fb",s:"Yo ________ una carta a mi abuela el mes pasado.",a:"escribí",opts:["escribí","escribió","escribiste","escribieron"],hint:"Yo form of escribir. Same ending as comí and viví."},
{type:"fb",s:"Mi familia ________ en México antes de venir aquí.",a:"vivió",opts:["vivió","viví","vivimos","vivieron"],hint:"Mi familia is singular (ella). Which form matches él/ella?"},
{type:"match",pairs:[{nl:"viví",en:"I lived"},{nl:"escribiste",en:"you wrote"},{nl:"recibió",en:"he/she received"},{nl:"decidimos",en:"we decided"},{nl:"salieron",en:"they left"}]},
{type:"drag_fill",s:"Yo {1} una carta y ella la {2} ayer.",blanks:{"1":"escribí","2":"recibió"},pool:["escribí","recibió","escribieron","recibí"],hint:"Yo wrote (escribir -í) and ella received (recibir -ió)."},
{type:"mc",q:"Which statement about -ER and -IR verbs in the past is correct?",opts:["They share the same endings","They have completely different endings","-IR adds an extra letter","-ER has accents but -IR doesn't"],ans:"They share the same endings",hint:"Think about comí vs viví, comió vs vivió. Do you see a difference in the endings?"},
{type:"fb",s:"Nosotros ________ a las diez de la noche.",a:"salimos",opts:["salimos","salieron","salí","salió"],hint:"Nosotros form of salir. Remember the -imos ending."},
{type:"mc",q:"A: ¿Recibieron el paquete?\nB: Sí, lo ________ el lunes.",opts:["recibimos","recibieron","recibí","recibió"],ans:"recibimos",hint:"The question asks ustedes, so B answers as 'we'. Nosotros form of recibir."},
{type:"fb",s:"El mes pasado yo ________ en un apartamento nuevo.",a:"viví",opts:["viví","vivió","viviste","vivieron"],hint:"Yo form of vivir in the past. Same ending as comí."}
]},

// ===== LESSON 5: Telling Stories =====
{id:"esp9l5",title:"Primero, Luego, Después",icon:"📖",xp:15,board:true,steps:[
{type:"intro",title:"Primero, Luego, Después",desc:"Now combine all three verb types to tell stories about the past. Use sequencing words to connect your ideas.",goals:["Mix -AR, -ER, and -IR verbs in past tense","Use primero, luego, después, finalmente to sequence events","Tell a simple story about past events"]},
{type:"teach",kind:"word",nl:"primero",en:"first",phonetic:"pree-MEH-roh",example:"A: ¿Qué hiciste esta mañana?\nB: Primero desayuné.\nA: ¿Y después?\nB: Luego salí de casa.",exampleEn:"A: What did you do this morning?\nB: First I had breakfast.\nA: And then?\nB: Then I left the house.",note:"You know this from A1. Now use it to order past events."},
{type:"teach",kind:"word",nl:"luego",en:"then / next",phonetic:"LWEH-goh",example:"A: ¿Qué pasó luego?\nB: Luego caminé al trabajo.\nA: ¿Llegaste tarde?\nB: No, llegué a tiempo.",exampleEn:"A: What happened next?\nB: Then I walked to work.\nA: Did you arrive late?\nB: No, I arrived on time.",note:"Luego and después both mean 'then', but luego is slightly more immediate."},
{type:"teach",kind:"word",nl:"después",en:"after / afterwards",phonetic:"dehs-PWEHS",example:"A: Trabajé todo el día.\nB: ¿Y después?\nA: Después comí con amigos.\nB: ¡Qué bien!",exampleEn:"A: I worked all day.\nB: And afterwards?\nA: Afterwards I ate with friends.\nB: How nice!",note:"Después can also mean 'after' in después de + noun/infinitive."},
{type:"teach",kind:"word",nl:"finalmente",en:"finally",phonetic:"fee-nahl-MEHN-teh",example:"A: ¿Cómo terminó tu día?\nB: Finalmente llegué a casa.\nA: ¿A qué hora?\nB: Llegué a las diez.",exampleEn:"A: How did your day end?\nB: Finally I got home.\nA: At what time?\nB: I arrived at ten.",note:"Use finalmente to close a sequence of events."},
{type:"teach",kind:"phrase",nl:"llegué",en:"I arrived",phonetic:"yeh-GEH",example:"A: ¿A qué hora llegaste?\nB: Llegué a las nueve.\nA: ¿Llegaste en autobús?\nB: No, caminé.",exampleEn:"A: What time did you arrive?\nB: I arrived at nine.\nA: Did you arrive by bus?\nB: No, I walked.",note:"From llegar. Regular -AR past tense. Note: llegar keeps the double L."},
{type:"teach",kind:"phrase",nl:"caminé",en:"I walked",phonetic:"kah-mee-NEH",example:"A: ¿Cómo fuiste al parque?\nB: Caminé veinte minutos.\nA: ¿No tomaste el autobús?\nB: No, preferí caminar.",exampleEn:"A: How did you go to the park?\nB: I walked twenty minutes.\nA: Didn't you take the bus?\nB: No, I preferred to walk.",note:"From caminar. Regular -AR verb in the past."},
{type:"tip",title:"Telling a Story in Order",text:"Use these words to sequence past events:\n\nPrimero... (First...)\nLuego... (Then...)\nDespués... (After that...)\nFinalmente... (Finally...)\n\nExample story:\nPrimero desayuné en casa.\nLuego caminé al trabajo.\nDespués trabajé ocho horas.\nFinalmente cené con mi familia."},
{type:"mc",q:"Put in order: ________, luego, después, finalmente.",opts:["primero","antes","ayer","anoche"],ans:"primero",hint:"Which word means 'first' and starts a sequence?"},
{type:"fb",s:"________ comí en casa. Luego salí con amigos.",a:"Primero",opts:["Primero","Finalmente","Después","Antes"],hint:"This word starts a sequence of events: 'First I ate at home...'"},
{type:"mc",q:"Complete the story: Primero estudié. Luego comí. Después descansé. ________ salí con amigos.",opts:["Finalmente","Primero","Antes","Ayer"],ans:"Finalmente",hint:"Which word closes a sequence of events?"},
{type:"drag_fill",s:"{1} desayuné, {2} trabajé y {3} cené con mi familia.",blanks:{"1":"Primero","2":"luego","3":"finalmente"},pool:["Primero","luego","finalmente","ayer"],hint:"Put the sequence words in order: first, then, finally."},
{type:"fb",s:"________ de cenar, leí un libro.",a:"Después",opts:["Después","Primero","Luego","Finalmente"],hint:"Which word means 'after' and can be followed by 'de'?"},
{type:"match",pairs:[{nl:"primero",en:"first"},{nl:"luego",en:"then"},{nl:"después",en:"afterwards"},{nl:"finalmente",en:"finally"},{nl:"llegué",en:"I arrived"},{nl:"caminé",en:"I walked"}]},
{type:"mc",q:"A: ¿Qué hiciste el sábado?\nB: Primero ________ al mercado.",opts:["caminé","caminaste","caminó","caminaron"],ans:"caminé",hint:"B is talking about their own actions. Which person is that?"},
{type:"drag_fill",s:"El sábado {1} estudié, {2} comí pizza y {3} vi una película.",blanks:{"1":"primero","2":"después","3":"finalmente"},pool:["primero","después","finalmente","ayer"],hint:"Arrange the three sequence words in chronological order."},
{type:"fb",s:"Ayer mi hermano primero trabajó, luego ________ y finalmente descansó.",a:"comió",opts:["comió","comí","comiste","comieron"],hint:"Mi hermano is él. What is the él form of comer in the past?"},
{type:"mc",q:"Which mini-story is in the correct order?",opts:["Primero llegué, luego trabajé, finalmente salí.","Finalmente llegué, primero trabajé, después salí.","Después llegué, finalmente trabajé, primero salí.","Luego llegué, después trabajé, primero salí."],ans:"Primero llegué, luego trabajé, finalmente salí.",hint:"The correct chronological sequence starts with 'first' and ends with 'finally'."}
]},

// ===== LESSON 6: Asking About the Past =====
{id:"esp9l6",title:"¿Qué Hiciste?",icon:"❓",xp:15,board:true,steps:[
{type:"intro",title:"¿Qué Hiciste?",desc:"Learn to ask and answer questions about the past. Master the key question patterns Spanish speakers use every day.",goals:["Ask questions about past events","Use question words with past tense verbs","Give natural answers to past tense questions"]},
{type:"teach",kind:"phrase",nl:"¿Qué hiciste?",en:"What did you do?",phonetic:"keh ee-SEES-teh",example:"A: ¡Hola! ¿Qué hiciste ayer?\nB: Estudié y trabajé.\nA: ¿Nada más?\nB: También salí con amigos.",exampleEn:"A: Hi! What did you do yesterday?\nB: I studied and worked.\nA: Nothing else?\nB: I also went out with friends.",note:"Hiciste comes from hacer (irregular). For now, just learn this question as a fixed phrase."},
{type:"teach",kind:"phrase",nl:"¿Qué pasó?",en:"What happened?",phonetic:"keh pah-SOH",example:"A: ¿Qué pasó en la reunión?\nB: El jefe habló con todos.\nA: ¿Pasó algo importante?\nB: Sí, decidimos cambiar el horario.",exampleEn:"A: What happened at the meeting?\nB: The boss spoke with everyone.\nA: Did anything important happen?\nB: Yes, we decided to change the schedule.",note:"Pasó comes from pasar (to happen). Regular -AR past tense."},
{type:"teach",kind:"phrase",nl:"¿Cuándo?",en:"When?",phonetic:"KWAHN-doh",example:"A: Compré un coche nuevo.\nB: ¿Cuándo lo compraste?\nA: Lo compré el mes pasado.\nB: ¡Qué bien!",exampleEn:"A: I bought a new car.\nB: When did you buy it?\nA: I bought it last month.\nB: How nice!",note:"You know cuándo from A1. Now use it to ask about past events."},
{type:"teach",kind:"phrase",nl:"¿Dónde comiste?",en:"Where did you eat?",phonetic:"DOHN-deh koh-MEES-teh",example:"A: ¿Dónde comiste ayer?\nB: Comí en casa.\nA: ¿Cocinaste tú?\nB: No, cocinó mi madre.",exampleEn:"A: Where did you eat yesterday?\nB: I ate at home.\nA: Did you cook?\nB: No, my mother cooked.",note:"Dónde + past tense verb. The question word comes first, then the verb."},
{type:"teach",kind:"phrase",nl:"¿Con quién?",en:"With whom?",phonetic:"kohn kee-EHN",example:"A: Anoche salí a cenar.\nB: ¿Con quién cenaste?\nA: Cené con mi familia.\nB: ¡Qué bonito!",exampleEn:"A: Last night I went out for dinner.\nB: Who did you have dinner with?\nA: I had dinner with my family.\nB: How lovely!",note:"Con quién = with whom. Very common when asking about social activities."},
{type:"teach",kind:"phrase",nl:"¿Cómo fue?",en:"How was it?",phonetic:"KOH-moh fweh",example:"A: Visité el museo ayer.\nB: ¿Cómo fue?\nA: ¡Fue increíble!\nB: ¿Qué viste?",exampleEn:"A: I visited the museum yesterday.\nB: How was it?\nA: It was incredible!\nB: What did you see?",note:"Fue comes from ser (irregular). Learn this as a fixed expression for now."},
{type:"tip",title:"Forming Past Tense Questions",text:"In Spanish, questions in the past follow the same pattern as present:\n\n¿ + question word + verb (past) + rest?\n\n¿Qué comiste? (What did you eat?)\n¿Dónde trabajaste? (Where did you work?)\n¿Cuándo llegaron? (When did they arrive?)\n¿Con quién hablaste? (Who did you talk to?)\n\nYes/no questions: just add ¿...? marks.\n¿Estudiaste ayer? (Did you study yesterday?)"},
{type:"mc",q:"How do you ask 'What did you do yesterday?'",opts:["¿Qué hiciste ayer?","¿Qué haces ayer?","¿Qué haciste ayer?","¿Qué hicimos ayer?"],ans:"¿Qué hiciste ayer?",hint:"The fixed phrase for 'what did you (tú) do' uses hiciste."},
{type:"fb",s:"¿________ comiste anoche?",a:"Dónde",opts:["Dónde","Cuándo","Qué","Quién"],hint:"The answer would be a place (en casa, en un restaurante). Which question word asks about location?"},
{type:"mc",q:"A: Ayer viajé a Sevilla.\nB: ¿________ fue?",opts:["Cómo","Dónde","Cuándo","Qué"],ans:"Cómo",hint:"B is asking about the quality of the experience. Which word means 'how'?"},
{type:"fb",s:"¿________ hablaste por teléfono?",a:"Con quién",opts:["Con quién","Qué","Dónde","Cuándo"],hint:"The answer would be a person. Which phrase asks about a companion?"},
{type:"match",pairs:[{nl:"¿Qué hiciste?",en:"What did you do?"},{nl:"¿Qué pasó?",en:"What happened?"},{nl:"¿Dónde comiste?",en:"Where did you eat?"},{nl:"¿Cómo fue?",en:"How was it?"},{nl:"¿Con quién?",en:"With whom?"}]},
{type:"mc",q:"How do you ask 'Did you study yesterday?' in Spanish?",opts:["¿Estudiaste ayer?","¿Estudias ayer?","¿Estudiaron ayer?","¿Estudiar ayer?"],ans:"¿Estudiaste ayer?",hint:"Yes/no questions just need the past tense verb with question marks. Tú form of estudiar."},
{type:"drag_fill",s:"A: ¿{1} compraste el regalo?\nB: Lo compré {2}.",blanks:{"1":"Cuándo","2":"ayer"},pool:["Cuándo","ayer","Dónde","hoy"],hint:"A asks about timing, B gives a past time word."},
{type:"fb",s:"A: Cené con unos amigos.\nB: ¿________ cenaron?",a:"Dónde",opts:["Dónde","Cuándo","Qué","Cómo"],hint:"A natural follow-up question about eating out would ask about the place."},
{type:"mc",q:"A: Viajamos a la playa el verano pasado.\nB: ¡Qué bien! ¿Cómo ________?",opts:["fue","fuiste","fui","fueron"],ans:"fue",hint:"Asking 'how was it?' uses the él/ella form of ser in the past. It is a fixed expression."},
{type:"fb",s:"A: Compré un regalo para mamá.\nB: ¿________ lo compraste?",a:"Cuándo",opts:["Cuándo","Dónde","Qué","Con quién"],hint:"B wants to know the timing. Which question word asks about when?"}
]},

// ===== LESSON 7: Weekend & Holiday Stories =====
{id:"esp9l7",title:"El Fin de Semana",icon:"🏖️",xp:15,board:true,steps:[
{type:"intro",title:"El Fin de Semana",desc:"Talk about what you did on the weekend and during holidays. This is one of the most common conversation topics in Spanish!",goals:["Talk about weekend activities in the past","Use past tense in context with holiday vocabulary","Combine time expressions, sequence words, and past tense verbs"]},
{type:"teach",kind:"phrase",nl:"el fin de semana pasado",en:"last weekend",phonetic:"el feen deh seh-MAH-nah pah-SAH-doh",example:"A: ¿Qué hiciste el fin de semana pasado?\nB: Salí con mis amigos.\nA: ¿Adónde fueron?\nB: Caminamos por el parque.",exampleEn:"A: What did you do last weekend?\nB: I went out with my friends.\nA: Where did they go?\nB: We walked through the park.",note:"El fin de semana is masculine, so pasado (not pasada)."},
{type:"teach",kind:"phrase",nl:"las vacaciones",en:"the holidays / vacation",phonetic:"lahs bah-kah-see-OH-nehs",example:"A: ¿Dónde pasaste las vacaciones?\nB: Viajé a la playa.\nA: ¿Cuánto tiempo?\nB: Dos semanas.",exampleEn:"A: Where did you spend the holidays?\nB: I traveled to the beach.\nA: How long?\nB: Two weeks.",note:"Always plural in Spanish: las vacaciones (never la vacación for holidays)."},
{type:"teach",kind:"phrase",nl:"la playa",en:"the beach",phonetic:"la PLAH-yah",example:"A: ¿Visitaste la playa?\nB: Sí, caminé por la playa.\nA: ¿Nadaste?\nB: ¡Claro! Nadé toda la tarde.",exampleEn:"A: Did you visit the beach?\nB: Yes, I walked along the beach.\nA: Did you swim?\nB: Of course! I swam all afternoon.",note:"La playa is feminine. A very common vacation destination."},
{type:"teach",kind:"phrase",nl:"nadé",en:"I swam",phonetic:"nah-DEH",example:"A: ¿Qué hiciste en la playa?\nB: Nadé en el mar.\nA: ¿El agua estaba fría?\nB: No, estaba perfecta.",exampleEn:"A: What did you do at the beach?\nB: I swam in the sea.\nA: Was the water cold?\nB: No, it was perfect.",note:"From nadar. Regular -AR verb: nadé, nadaste, nadó, nadamos, nadaron."},
{type:"teach",kind:"phrase",nl:"visité",en:"I visited",phonetic:"bee-see-TEH",example:"A: ¿Adónde viajaste?\nB: Visité Madrid.\nA: ¿Qué visitaste allí?\nB: Visité el museo del Prado.",exampleEn:"A: Where did you travel?\nB: I visited Madrid.\nA: What did you visit there?\nB: I visited the Prado Museum.",note:"From visitar. Regular -AR verb. Very useful for travel stories."},
{type:"teach",kind:"phrase",nl:"pasé",en:"I spent (time)",phonetic:"pah-SEH",example:"A: ¿Cómo pasaste las vacaciones?\nB: Pasé dos semanas en la costa.\nA: ¿Con quién?\nB: Pasé las vacaciones con mi familia.",exampleEn:"A: How did you spend the holidays?\nB: I spent two weeks on the coast.\nA: With whom?\nB: I spent the holidays with my family.",note:"Pasar can mean 'to happen' or 'to spend time'. Context makes it clear."},
{type:"tip",title:"Talking About Weekends and Holidays",text:"Common weekend/holiday story patterns:\n\nEl fin de semana pasado + past verb\nDurante las vacaciones + past verb\nEn verano/invierno + past verb\n\nUseful combinations:\nVisité + place (I visited...)\nViajé a + place (I traveled to...)\nPasé + time + en + place (I spent... in...)\nNadé en + body of water (I swam in...)\nCaminé por + place (I walked through...)"},
{type:"mc",q:"How do you say 'last weekend' in Spanish?",opts:["el fin de semana pasado","la fin de semana pasada","el fin de semana antes","los fines de semana pasados"],ans:"el fin de semana pasado",hint:"Fin is masculine. What form does pasado take to match?"},
{type:"fb",s:"________ las vacaciones en Barcelona el año pasado.",a:"Pasé",opts:["Pasé","Pasó","Pasaron","Pasaste"],hint:"Yo form of pasar. Who is telling their own story?"},
{type:"mc",q:"A: ¿Qué hiciste el fin de semana pasado?\nB: ________ a la playa y nadé.",opts:["Viajé","Viajó","Viajaron","Viajaste"],ans:"Viajé",hint:"B is talking about themselves. Which person form is that?"},
{type:"fb",s:"Mis padres ________ un museo en Madrid.",a:"visitaron",opts:["visitaron","visité","visitaste","visitó"],hint:"Mis padres = ellos. Which past tense ending matches ellos for -AR verbs?"},
{type:"drag_fill",s:"El fin de semana pasado {1} a la playa, {2} en el mar y {3} por la arena.",blanks:{"1":"viajé","2":"nadé","3":"caminé"},pool:["viajé","nadé","caminé","comí"],hint:"Three -AR verbs in the yo form: travel, swim, walk."},
{type:"match",pairs:[{nl:"el fin de semana pasado",en:"last weekend"},{nl:"las vacaciones",en:"the holidays"},{nl:"la playa",en:"the beach"},{nl:"nadé",en:"I swam"},{nl:"visité",en:"I visited"},{nl:"pasé",en:"I spent (time)"}]},
{type:"mc",q:"Complete: ¿Cómo ________ las vacaciones?",opts:["pasaste","pasé","pasó","pasaron"],ans:"pasaste",hint:"The question is asking tú. Which form matches?"},
{type:"fb",s:"Durante las vacaciones, mi familia ________ por toda España.",a:"viajó",opts:["viajó","viajé","viajamos","viajaron"],hint:"Mi familia is singular (it/she). Which form matches él/ella?"},
{type:"mc",q:"A: Pasé las vacaciones en la playa.\nB: ¡Qué bien! ¿________?",opts:["Nadaste en el mar?","Nadé en el mar?","Nadaron en el mar?","Nadar en el mar?"],ans:"Nadaste en el mar?",hint:"B is asking A (tú) a follow-up question. Which form is tú?"},
{type:"drag_fill",s:"A: ¿Dónde {1} las vacaciones?\nB: {2} dos semanas en Barcelona.",blanks:{"1":"pasaste","2":"Pasé"},pool:["pasaste","Pasé","pasó","pasaron"],hint:"A asks tú, B answers yo."}
]},

// ===== LESSON 8: Review & Practice =====
{id:"esp9l8",title:"Repaso: ¿Qué Pasó?",icon:"🔄",xp:15,board:true,steps:[
{type:"intro",title:"Repaso: ¿Qué Pasó?",desc:"Review everything from this unit. Mix -AR, -ER, and -IR verbs in the past tense with time expressions and sequence words.",goals:["Conjugate all three verb types in the past","Use time expressions and sequence words fluently","Tell complete stories about past events"]},
{type:"mc",q:"What are the yo past tense endings for -AR vs -ER/-IR?",opts:["-é vs -í","-í vs -é","-ó vs -ió","Both use -é"],ans:"-é vs -í",hint:"Think: hablé (AR) vs comí (ER/IR). The vowel changes."},
{type:"fb",s:"Ayer mi madre ________ una torta de chocolate.",a:"cocinó",opts:["cocinó","cociné","cocinaste","cocinaron"],hint:"Mi madre = ella. Which -AR past ending matches ella?"},
{type:"mc",q:"Complete: Nosotros ________ mucho en la clase de español.",opts:["aprendimos","aprendieron","aprendí","aprendió"],ans:"aprendimos",hint:"Nosotros form of aprender. What is the -ER/-IR ending for nosotros?"},
{type:"fb",s:"¿A qué hora ________ tú del trabajo ayer?",a:"saliste",opts:["saliste","salí","salió","salieron"],hint:"Tú form of salir. The -IR past ending for tú is -iste."},
{type:"match",pairs:[{nl:"hablé",en:"I spoke"},{nl:"comiste",en:"you ate"},{nl:"vivió",en:"he/she lived"},{nl:"compramos",en:"we bought"},{nl:"escribieron",en:"they wrote"},{nl:"bebí",en:"I drank"}]},
{type:"drag_fill",s:"Ayer yo {1} español y después {2} un libro.",blanks:{"1":"estudié","2":"leí"},pool:["estudié","leí","estudió","leyó"],hint:"Both are yo forms: estudiar (-AR: -é) and leer (-ER: -í)."},
{type:"mc",q:"Which sentence correctly uses the past tense?",opts:["Ayer comí en un restaurante.","Ayer como en un restaurante.","Ayer comeré en un restaurante.","Ayer comer en un restaurante."],ans:"Ayer comí en un restaurante.",hint:"Ayer requires a past tense verb. Which option shows the correct yo past form of comer?"},
{type:"fb",s:"El año pasado mis amigos ________ a México.",a:"viajaron",opts:["viajaron","viajé","viajaste","viajó"],hint:"Mis amigos = ellos. Which -AR past ending matches ellos?"},
{type:"mc",q:"A: ¿Qué hiciste el fin de semana?\nB: Primero ________, luego comí y finalmente descansé.",opts:["trabajé","trabajó","trabajaste","trabajaron"],ans:"trabajé",hint:"B is telling their own story (yo). Which form is first person -AR past?"},
{type:"drag_fill",s:"{1} desayuné, {2} caminé al trabajo y {3} cené con mi familia.",blanks:{"1":"Primero","2":"luego","3":"finalmente"},pool:["Primero","luego","finalmente","ayer"],hint:"Sequence words in order: first, then, finally."},
{type:"fb",s:"Mi hermana ________ una carta a nuestra abuela la semana pasada.",a:"escribió",opts:["escribió","escribí","escribiste","escribieron"],hint:"Mi hermana = ella. Which -IR past form matches ella?"},
{type:"mc",q:"How do you ask 'What happened?' in Spanish?",opts:["¿Qué pasó?","¿Qué pasa?","¿Qué pasaste?","¿Qué pasaron?"],ans:"¿Qué pasó?",hint:"Pasar in the past for 'it happened' uses the él/ella form."},
{type:"drag_fill",s:"A: ¿{1} hiciste ayer?\nB: {2} a la playa y {3} en el mar.",blanks:{"1":"Qué","2":"Viajé","3":"nadé"},pool:["Qué","Viajé","nadé","Cómo"],hint:"A asks 'what did you do?' B answers with two yo-form past verbs."},
{type:"match",pairs:[{nl:"ayer",en:"yesterday"},{nl:"anoche",en:"last night"},{nl:"la semana pasada",en:"last week"},{nl:"el mes pasado",en:"last month"},{nl:"el fin de semana pasado",en:"last weekend"}]},
{type:"fb",s:"¿________ las vacaciones el verano pasado?",a:"Dónde pasaste",opts:["Dónde pasaste","Qué pasó","Cuándo pasaron","Cómo pasé"],hint:"Asking tú about where they spent their holidays."},
{type:"mc",q:"Complete the story: El sábado visité el museo. ________ compré recuerdos. Finalmente cené en un restaurante.",opts:["Después","Primero","Ayer","Anoche"],ans:"Después",hint:"This word fits between 'first' and 'finally' in a sequence."},
{type:"mc",q:"Which verb group has DIFFERENT past tense endings from the other two?",opts:["-AR verbs","-ER verbs","-IR verbs","All three are different"],ans:"-AR verbs",hint:"Remember: two of the three groups share identical past tense endings. Which one stands alone?"},
{type:"fb",s:"Anoche nosotros ________ una película en casa.",a:"vimos",opts:["vimos","vieron","vi","vio"],hint:"Nosotros form of ver. Regular -ER pattern in the past: -imos."}
]}

]},
// ══════════════════════════════════════════════════════════════
// UNIT 10: Historias — Pretérito Indefinido Irregular (A2.1)
// 8 lessons, 18+ steps each
// ══════════════════════════════════════════════════════════════
{n:10,lang:"es",track:"v1",title:"Historias",sub:"Past Tense: Irregular Verbs",icon:"📖",level:"A2.1",color:"#7B5EE8",lessons:[

// ===== LESSON 1: Ser/Ir in the Past =====
{id:"esp10l1",title:"Fui al parque",icon:"🔀",xp:15,board:true,steps:[
{type:"intro",title:"Fui al parque",desc:"Ser and ir share the same irregular past tense forms. Context tells you which verb is meant.",goals:["Learn fui/fuiste/fue/fuimos/fueron","Distinguish ser vs ir in past context","Narrate past movements and identities"]},
{type:"teach",kind:"verb",nl:"fui",en:"I was / I went",phonetic:"FWEE",example:"A: ¿Adónde fuiste ayer?\nB: Fui al parque con mi perro.\nA: ¡Qué bien! Yo fui al cine.",exampleEn:"A: Where did you go yesterday?\nB: I went to the park with my dog.\nA: How nice! I went to the cinema.",note:"Ser and ir share the same past forms. Context decides the meaning."},
{type:"teach",kind:"verb",nl:"fuiste",en:"you were / you went",phonetic:"FWEES-teh",example:"A: ¿Fuiste tú el ganador?\nB: Sí, fui yo.\nA: ¡Felicidades! ¿Fuiste a celebrar?",exampleEn:"A: Were you the winner?\nB: Yes, it was me.\nA: Congratulations! Did you go celebrate?",note:"Informal singular 'you' form. Same for ser and ir."},
{type:"teach",kind:"verb",nl:"fue",en:"he/she was, he/she went",phonetic:"FWEH",example:"A: ¿Quién fue tu profesor?\nB: Fue el señor García.\nA: Él fue muy buen profesor.\nB: Sí, fue excelente.",exampleEn:"A: Who was your teacher?\nB: It was Mr. García.\nA: He was a very good teacher.\nB: Yes, he was excellent.",note:"Third person singular. Also used for usted."},
{type:"teach",kind:"verb",nl:"fuimos",en:"we were / we went",phonetic:"FWEE-mos",example:"A: ¿Adónde fuimos el domingo?\nB: Fuimos a la playa.\nA: ¡Cierto! Fuimos con los niños.",exampleEn:"A: Where did we go on Sunday?\nB: We went to the beach.\nA: Right! We went with the kids.",note:"First person plural. Same for ser and ir."},
{type:"teach",kind:"verb",nl:"fueron",en:"they were / they went",phonetic:"FWEH-ron",example:"A: ¿Fueron tus padres a la fiesta?\nB: Sí, fueron los primeros en llegar.\nA: ¡Fueron muy puntuales!",exampleEn:"A: Did your parents go to the party?\nB: Yes, they were the first to arrive.\nA: They were very punctual!",note:"Third person plural. Also used for ustedes."},
{type:"tip",title:"Ser and ir: same past, different meaning",text:"Ser (to be) and ir (to go) share identical past tense forms:\n\nyo fui, tú fuiste, él/ella fue, nosotros fuimos, ellos fueron\n\nHow to tell them apart:\n- Ir uses 'a' + place: Fui al cine (I went to the cinema)\n- Ser describes identity: Fue un buen día (It was a good day)\n\nContext always makes the meaning clear."},
{type:"mc",q:"Ayer yo ___ al supermercado. (ir)",opts:["fui","fue","fuiste","fueron"],ans:"fui",hint:"First person singular, the speaker went somewhere"},
{type:"mc",q:"La fiesta ___ muy divertida. (ser)",opts:["fue","fui","fuimos","fueron"],ans:"fue",hint:"Third person singular describing the party"},
{type:"fb",s:"Nosotros {1} a la playa el sábado.",a:"fuimos",opts:["fuimos","fueron","fui","fue"],hint:"First person plural, we went to the beach"},
{type:"fb",s:"¿Tú {1} al concierto anoche?",a:"fuiste",opts:["fuiste","fue","fui","fueron"],hint:"Asking 'you' informally about going somewhere"},
{type:"mc",q:"Mis abuelos ___ profesores. (ser, past)",opts:["fueron","fuimos","fue","fui"],ans:"fueron",hint:"Third person plural describing what they were"},
{type:"fb",s:"Ella {1} la mejor estudiante de la clase.",a:"fue",opts:["fue","fui","fueron","fuimos"],hint:"Third person singular describing an identity"},
{type:"match",pairs:[{nl:"Fui al cine",en:"I went to the cinema"},{nl:"Fue un buen día",en:"It was a good day"},{nl:"Fuimos a casa",en:"We went home"},{nl:"Fueron mis amigos",en:"They were my friends"},{nl:"¿Fuiste tú?",en:"Was it you?"}]},
{type:"mc",q:"Which sentence uses 'ir' (to go), not 'ser' (to be)?",opts:["Fui al mercado","Fue increíble","Fueron buenos estudiantes","Fue mi cumpleaños"],ans:"Fui al mercado",hint:"Look for movement toward a place with 'a'"},
{type:"fb",s:"El viaje {1} fantástico.",a:"fue",opts:["fue","fui","fuiste","fueron"],hint:"Third person, describing what the trip was like"},
{type:"drag_fill",s:"Ayer {1} al parque y {2} un día perfecto.",blanks:{"1":"fui","2":"fue"},pool:["fui","fue","fuimos","fueron"],hint:"First 'I went', then 'it was' describing the day"},
{type:"mc",q:"Ellos ___ a México el año pasado.",opts:["fueron","fuimos","fue","fui"],ans:"fueron",hint:"Third person plural, they traveled somewhere"},
{type:"fb",s:"¿Quién {1} tu primer amigo en la escuela?",a:"fue",opts:["fue","fui","fueron","fuiste"],hint:"Asking about identity, third person singular"}
]},

// ===== LESSON 2: Tener & Hacer =====
{id:"esp10l2",title:"Tuve suerte",icon:"🍀",xp:15,board:true,steps:[
{type:"intro",title:"Tuve suerte",desc:"Tener and hacer are two essential irregular verbs in the past. Both change their stems completely.",goals:["Conjugate tener in pretérito (tuve, tuviste, tuvo...)","Conjugate hacer in pretérito (hice, hiciste, hizo...)","Use both verbs to narrate past events"]},
{type:"teach",kind:"verb",nl:"tuve",en:"I had",phonetic:"TOO-veh",example:"A: ¿Tuviste un buen fin de semana?\nB: Sí, tuve mucha suerte.\nA: ¿Qué pasó?\nB: Tuve un día perfecto.",exampleEn:"A: Did you have a good weekend?\nB: Yes, I had a lot of luck.\nA: What happened?\nB: I had a perfect day.",note:"Tener changes to 'tuv-' stem in all past forms."},
{type:"teach",kind:"verb",nl:"tuviste",en:"you had",phonetic:"too-VEES-teh",example:"A: ¿Tuviste tiempo para estudiar?\nB: No, no tuve tiempo.\nA: ¿Tuviste mucho trabajo?\nB: Sí, tuve tres reuniones.",exampleEn:"A: Did you have time to study?\nB: No, I didn't have time.\nA: Did you have a lot of work?\nB: Yes, I had three meetings.",note:"Informal 'you' form. Stem: tuv- + -iste."},
{type:"teach",kind:"verb",nl:"tuvo",en:"he/she had",phonetic:"TOO-vo",example:"A: Mi hermana tuvo un bebé.\nB: ¡Felicidades! ¿Tuvo niño o niña?\nA: Tuvo una niña.\nB: ¡Qué bonito!",exampleEn:"A: My sister had a baby.\nB: Congratulations! Did she have a boy or girl?\nA: She had a girl.\nB: How lovely!",note:"Third person singular. Stem: tuv- + -o (no accent)."},
{type:"verb_table",title:"Tener: pretérito indefinido",label:"Irregular stem: tuv-",groups:[{label:"",rows:[["yo","tuve"],["tú","tuviste"],["él/ella/usted","tuvo"],["nosotros","tuvimos"],["ellos/ustedes","tuvieron"]]}],note:"Notice: no accent marks on tuve/tuvo, unlike regular verbs."},
{type:"teach",kind:"verb",nl:"hice",en:"I did / I made",phonetic:"EE-seh",example:"A: ¿Qué hiciste ayer?\nB: Hice la cena para mi familia.\nA: ¡Qué bien! Yo hice un pastel.\nB: ¡Delicioso!",exampleEn:"A: What did you do yesterday?\nB: I made dinner for my family.\nA: How nice! I made a cake.\nB: Delicious!",note:"Hacer changes to 'hic-' stem. Yo form: hice."},
{type:"teach",kind:"verb",nl:"hizo",en:"he/she did / made",phonetic:"EE-so",example:"A: ¿Quién hizo esta paella?\nB: La hizo mi madre.\nA: ¡Hizo un trabajo increíble!\nB: Sí, siempre hace buena comida.",exampleEn:"A: Who made this paella?\nB: My mother made it.\nA: She did an incredible job!\nB: Yes, she always makes good food.",note:"Note: hizo (not hico). The c changes to z before o."},
{type:"verb_table",title:"Hacer: pretérito indefinido",label:"Irregular stem: hic- (hiz- for él/ella)",groups:[{label:"",rows:[["yo","hice"],["tú","hiciste"],["él/ella/usted","hizo"],["nosotros","hicimos"],["ellos/ustedes","hicieron"]]}],note:"The z in 'hizo' keeps the /s/ sound (c before o would be /k/)."},
{type:"mc",q:"Ayer yo ___ mucho trabajo. (tener)",opts:["tuve","tuvo","tuviste","tuvieron"],ans:"tuve",hint:"First person singular past of tener"},
{type:"fb",s:"Ella {1} una fiesta el viernes.",a:"hizo",opts:["hizo","hice","hiciste","hicieron"],hint:"Third person singular past of hacer"},
{type:"mc",q:"¿Qué ___ tú el fin de semana? (hacer)",opts:["hiciste","hicieron","hice","hizo"],ans:"hiciste",hint:"Asking 'you' informally what you did"},
{type:"fb",s:"Nosotros {1} que esperar dos horas.",a:"tuvimos",opts:["tuvimos","tuvieron","tuvo","tuve"],hint:"First person plural, we had to wait"},
{type:"match",pairs:[{nl:"Tuve suerte",en:"I had luck"},{nl:"Hizo calor",en:"It was hot (lit: it made heat)"},{nl:"Tuvimos tiempo",en:"We had time"},{nl:"¿Qué hiciste?",en:"What did you do?"},{nl:"Tuvo un problema",en:"He/she had a problem"}]},
{type:"mc",q:"Los niños ___ un dibujo para su madre. (hacer)",opts:["hicieron","hicimos","hizo","hice"],ans:"hicieron",hint:"Third person plural, the children made something"},
{type:"fb",s:"Mi abuelo {1} una vida muy interesante.",a:"tuvo",opts:["tuvo","tuve","tuvimos","tuvieron"],hint:"Third person singular, describing grandfather's life"},
{type:"drag_fill",s:"Ayer {1} mucho frío y no {2} nada especial.",blanks:{"1":"hizo","2":"hice"},pool:["hizo","hice","tuve","tuvo"],hint:"First blank: weather (hacer), second: what I did"},
{type:"mc",q:"Mis padres ___ tres hijos. (tener, past)",opts:["tuvieron","tuvimos","tuvo","tuve"],ans:"tuvieron",hint:"Third person plural, they had children"},
{type:"fb",s:"¿Qué {1} tú para la cena anoche? (hacer)",a:"hiciste",opts:["hiciste","hizo","hice","hicieron"],hint:"Second person singular, asking what you prepared"}
]},

// ===== LESSON 3: Estar & Poder =====
{id:"esp10l3",title:"Estuve en casa",icon:"🏠",xp:15,board:true,steps:[
{type:"intro",title:"Estuve en casa",desc:"Estar and poder follow the same 'u-stem' pattern as tener. Once you learn the pattern, these verbs become easier.",goals:["Conjugate estar in pretérito (estuve, estuviste, estuvo...)","Conjugate poder in pretérito (pude, pudiste, pudo...)","Recognize the u-stem irregular pattern"]},
{type:"teach",kind:"verb",nl:"estuve",en:"I was (location/state)",phonetic:"es-TOO-veh",example:"A: ¿Dónde estuviste ayer?\nB: Estuve en casa todo el día.\nA: ¿Estuviste enfermo?\nB: Sí, estuve con fiebre.",exampleEn:"A: Where were you yesterday?\nB: I was at home all day.\nA: Were you sick?\nB: Yes, I had a fever.",note:"Estar changes to 'estuv-' stem. Same endings as tener (tuve/estuve)."},
{type:"teach",kind:"verb",nl:"estuvo",en:"he/she was (location/state)",phonetic:"es-TOO-vo",example:"A: ¿Dónde estuvo María anoche?\nB: Estuvo en el hospital.\nA: ¿Estuvo mucho tiempo?\nB: Estuvo tres horas.",exampleEn:"A: Where was María last night?\nB: She was at the hospital.\nA: Was she there a long time?\nB: She was there three hours.",note:"Third person singular. No accent on estuvo."},
{type:"teach",kind:"verb",nl:"estuvimos",en:"we were (location/state)",phonetic:"es-too-VEE-mos",example:"A: ¿Estuvimos en este restaurante antes?\nB: Sí, estuvimos aquí en enero.\nA: ¡Claro! Estuvimos con tus padres.",exampleEn:"A: Were we at this restaurant before?\nB: Yes, we were here in January.\nA: Of course! We were with your parents.",note:"First person plural. Stem: estuv- + -imos."},
{type:"tip",title:"The u-stem family",text:"Three important verbs share the same 'u-stem' pattern:\n\ntener: tuv- (tuve, tuviste, tuvo, tuvimos, tuvieron)\nestar: estuv- (estuve, estuviste, estuvo, estuvimos, estuvieron)\npoder: pud- (pude, pudiste, pudo, pudimos, pudieron)\n\nAll use the SAME endings with NO accent marks:\n-e, -iste, -o, -imos, -ieron\n\nLearn one, know three!"},
{type:"teach",kind:"verb",nl:"pude",en:"I could / I managed to",phonetic:"POO-deh",example:"A: ¿Pudiste terminar el proyecto?\nB: Sí, pude terminarlo anoche.\nA: ¡Qué bien! Yo no pude dormir.\nB: ¿Por qué no pudiste?",exampleEn:"A: Were you able to finish the project?\nB: Yes, I managed to finish it last night.\nA: Great! I couldn't sleep.\nB: Why couldn't you?",note:"Poder changes to 'pud-' stem. In past tense means 'managed to' or 'failed to'."},
{type:"teach",kind:"verb",nl:"pudo",en:"he/she could / managed to",phonetic:"POO-do",example:"A: ¿Tu hijo pudo aprobar el examen?\nB: Sí, pudo aprobar con buena nota.\nA: ¡Fantástico!\nB: No pudo creerlo.",exampleEn:"A: Was your son able to pass the exam?\nB: Yes, he managed to pass with a good grade.\nA: Fantastic!\nB: He couldn't believe it.",note:"Third person singular. No accent on pudo."},
{type:"verb_table",title:"Poder: pretérito indefinido",label:"Irregular stem: pud-",groups:[{label:"",rows:[["yo","pude"],["tú","pudiste"],["él/ella/usted","pudo"],["nosotros","pudimos"],["ellos/ustedes","pudieron"]]}],note:"Same endings as tener and estar. No accents."},
{type:"mc",q:"Ayer yo ___ en la oficina hasta las nueve. (estar)",opts:["estuve","estuvo","estuvimos","estuvieron"],ans:"estuve",hint:"First person singular, describing where you were"},
{type:"fb",s:"Ella no {1} venir a la fiesta. (poder)",a:"pudo",opts:["pudo","pude","pudimos","pudieron"],hint:"Third person singular, she was unable to come"},
{type:"mc",q:"Nosotros ___ en Madrid la semana pasada. (estar)",opts:["estuvimos","estuvieron","estuvo","estuve"],ans:"estuvimos",hint:"First person plural, where we were located"},
{type:"fb",s:"¿Tú {1} encontrar las llaves? (poder)",a:"pudiste",opts:["pudiste","pudo","pude","pudieron"],hint:"Asking 'you' informally if you managed to do something"},
{type:"match",pairs:[{nl:"Estuve enfermo",en:"I was sick"},{nl:"No pudo dormir",en:"He couldn't sleep"},{nl:"Estuvimos juntos",en:"We were together"},{nl:"¿Pudiste llamar?",en:"Were you able to call?"},{nl:"Estuvieron aquí",en:"They were here"}]},
{type:"mc",q:"Los estudiantes no ___ terminar el examen. (poder)",opts:["pudieron","pudimos","pudo","pude"],ans:"pudieron",hint:"Third person plural, the students couldn't finish"},
{type:"drag_fill",s:"Ayer {1} en casa porque no {2} salir.",blanks:{"1":"estuve","2":"pude"},pool:["estuve","estuvo","pude","pudo"],hint:"First: where I was (estar), second: what I couldn't do (poder)"},
{type:"fb",s:"Mi jefe {1} muy contento con el resultado.",a:"estuvo",opts:["estuvo","estuve","estuvimos","estuvieron"],hint:"Third person singular, describing the boss's state"},
{type:"mc",q:"¿Tú ___ hablar con el director? (poder)",opts:["pudiste","pudo","pude","pudieron"],ans:"pudiste",hint:"Second person singular, asking if you managed something"},
{type:"fb",s:"Los turistas {1} en el hotel toda la tarde. (estar)",a:"estuvieron",opts:["estuvieron","estuvimos","estuvo","estuve"],hint:"Third person plural, the tourists were at a location"}
]},

// ===== LESSON 4: Poner & Saber =====
{id:"esp10l4",title:"Puse la mesa",icon:"🍽️",xp:15,board:true,steps:[
{type:"intro",title:"Puse la mesa",desc:"Two more u-stem irregulars: poner (to put) and saber (to know/find out). In the past, saber means 'found out'.",goals:["Conjugate poner in pretérito (puse, pusiste, puso...)","Conjugate saber in pretérito (supe, supiste, supo...)","Understand saber's meaning shift in the past tense"]},
{type:"teach",kind:"verb",nl:"puse",en:"I put / I placed",phonetic:"POO-seh",example:"A: ¿Dónde pusiste mis llaves?\nB: Las puse en la mesa.\nA: No están ahí. ¿Las puse yo en el bolso?\nB: ¡Sí! Las pusiste en el bolso.",exampleEn:"A: Where did you put my keys?\nB: I put them on the table.\nA: They're not there. Did I put them in the bag?\nB: Yes! You put them in the bag.",note:"Poner changes to 'pus-' stem. Same u-stem pattern as tener, estar, poder."},
{type:"teach",kind:"verb",nl:"puso",en:"he/she put",phonetic:"POO-so",example:"A: ¿Quién puso la música?\nB: La puso mi hermano.\nA: ¡Puso una canción muy buena!\nB: Sí, él puso toda la lista.",exampleEn:"A: Who put the music on?\nB: My brother put it on.\nA: He put on a really good song!\nB: Yes, he put on the whole playlist.",note:"Third person singular. No accent on puso."},
{type:"verb_table",title:"Poner: pretérito indefinido",label:"Irregular stem: pus-",groups:[{label:"",rows:[["yo","puse"],["tú","pusiste"],["él/ella/usted","puso"],["nosotros","pusimos"],["ellos/ustedes","pusieron"]]}],note:"Same u-stem pattern. Compare: tuve, estuve, pude, puse."},
{type:"teach",kind:"verb",nl:"supe",en:"I found out / I learned",phonetic:"SOO-peh",example:"A: ¿Cuándo supiste la noticia?\nB: Lo supe ayer por la noche.\nA: Yo lo supe esta mañana.\nB: ¡Fue una gran sorpresa!",exampleEn:"A: When did you find out the news?\nB: I found out last night.\nA: I found out this morning.\nB: It was a big surprise!",note:"Saber in past tense means 'found out', not just 'knew'. Stem: sup-."},
{type:"teach",kind:"verb",nl:"supo",en:"he/she found out",phonetic:"SOO-po",example:"A: ¿Tu madre supo la verdad?\nB: Sí, lo supo todo.\nA: ¿Cómo lo supo?\nB: Mi hermana se lo dijo.",exampleEn:"A: Did your mother find out the truth?\nB: Yes, she found out everything.\nA: How did she find out?\nB: My sister told her.",note:"Third person singular. Saber in past = discovery of information."},
{type:"tip",title:"Meaning shifts in the past",text:"Some verbs change meaning in the pretérito:\n\nsaber: normally 'to know' but in past = 'found out, discovered'\n- Supe la respuesta = I found out the answer\n\npoder: normally 'to be able' but in past = 'managed to' or 'failed to'\n- Pude hacerlo = I managed to do it\n- No pude hacerlo = I failed to do it\n\nThese shifts happen because the pretérito marks completed actions."},
{type:"mc",q:"¿Dónde ___ tú el libro? (poner)",opts:["pusiste","pusieron","puse","puso"],ans:"pusiste",hint:"Second person singular, asking where you placed it"},
{type:"fb",s:"Yo {1} la noticia esta mañana. (saber)",a:"supe",opts:["supe","supo","supimos","supieron"],hint:"First person singular, I discovered the news"},
{type:"mc",q:"Ella ___ las flores en un vaso. (poner)",opts:["puso","puse","pusieron","pusimos"],ans:"puso",hint:"Third person singular, she placed something"},
{type:"fb",s:"Nosotros no {1} nada hasta ayer. (saber)",a:"supimos",opts:["supimos","supieron","supo","supe"],hint:"First person plural, we didn't find out until yesterday"},
{type:"match",pairs:[{nl:"Puse la mesa",en:"I set the table"},{nl:"Supo la verdad",en:"He found out the truth"},{nl:"Pusimos todo",en:"We put everything"},{nl:"¿Supiste?",en:"Did you find out?"},{nl:"Pusieron música",en:"They put on music"}]},
{type:"mc",q:"Los vecinos ___ la música muy alta. (poner)",opts:["pusieron","pusimos","puso","puse"],ans:"pusieron",hint:"Third person plural, the neighbors did something with music"},
{type:"fb",s:"¿Cuándo {1} tú que ibas a ser padre?",a:"supiste",opts:["supiste","supo","supe","supieron"],hint:"Asking someone when they discovered something personal"},
{type:"drag_fill",s:"Ella {1} los platos en la mesa y él {2} la noticia.",blanks:{"1":"puso","2":"supo"},pool:["puso","supo","puse","supe"],hint:"First: she placed (poner), second: he discovered (saber)"},
{type:"mc",q:"Yo ___ mi abrigo en la silla. (poner)",opts:["puse","puso","pusiste","pusieron"],ans:"puse",hint:"First person singular, I placed my coat somewhere"},
{type:"fb",s:"Todos {1} la verdad al final. (saber)",a:"supieron",opts:["supieron","supimos","supo","supe"],hint:"Third person plural, everyone eventually found out"},
{type:"mc",q:"Ella ___ las fotos en el álbum. (poner)",opts:["puso","puse","pusimos","pusieron"],ans:"puso",hint:"Third person singular, she placed photos somewhere"}
]},

// ===== LESSON 5: Decir & Querer =====
{id:"esp10l5",title:"¿Qué dijiste?",icon:"💬",xp:15,board:true,steps:[
{type:"intro",title:"¿Qué dijiste?",desc:"Decir and querer use 'i-stem' patterns. Decir also has a special third person: dijeron (not dijieron).",goals:["Conjugate decir in pretérito (dije, dijiste, dijo...)","Conjugate querer in pretérito (quise, quisiste, quiso...)","Recognize the i-stem pattern"]},
{type:"teach",kind:"verb",nl:"dije",en:"I said / I told",phonetic:"DEE-heh",example:"A: ¿Qué le dijiste a tu jefe?\nB: Le dije que necesitaba vacaciones.\nA: ¿Y qué dijo él?\nB: Dijo que sí.",exampleEn:"A: What did you tell your boss?\nB: I told him I needed a vacation.\nA: And what did he say?\nB: He said yes.",note:"Decir changes to 'dij-' stem. The j replaces the c."},
{type:"teach",kind:"verb",nl:"dijo",en:"he/she said",phonetic:"DEE-ho",example:"A: ¿Qué dijo el doctor?\nB: Dijo que todo está bien.\nA: ¡Menos mal! Mi madre dijo que estaba preocupada.\nB: Dile que no hay problema.",exampleEn:"A: What did the doctor say?\nB: He said everything is fine.\nA: Thank goodness! My mother said she was worried.\nB: Tell her there's no problem.",note:"Third person singular. Very common in everyday Spanish."},
{type:"teach",kind:"verb",nl:"dijeron",en:"they said",phonetic:"dee-HEH-ron",example:"A: ¿Qué dijeron tus padres?\nB: Dijeron que sí.\nA: ¿De verdad? Mis amigos dijeron que no.\nB: Cada familia es diferente.",exampleEn:"A: What did your parents say?\nB: They said yes.\nA: Really? My friends said no.\nB: Every family is different.",note:"Note: dijeron, NOT dijieron. The j-stem drops the i in third person plural."},
{type:"tip",title:"The i-stem verbs",text:"Decir and querer share an 'i-stem' pattern:\n\ndecir: dij- (dije, dijiste, dijo, dijimos, dijeron)\nquerer: quis- (quise, quisiste, quiso, quisimos, quisieron)\n\nImportant: third person plural is -eron (not -ieron) after j:\ndijeron (not dijieron)\n\nQuerer in past tense can mean 'tried to' or 'refused to':\n- Quise llamar = I tried to call\n- No quise ir = I refused to go"},
{type:"teach",kind:"verb",nl:"quise",en:"I wanted / I tried to",phonetic:"KEE-seh",example:"A: ¿Por qué no fuiste a la fiesta?\nB: No quise ir.\nA: ¿No quisiste ir? ¿Por qué?\nB: Quise quedarme en casa.",exampleEn:"A: Why didn't you go to the party?\nB: I didn't want to go.\nA: You didn't want to go? Why?\nB: I wanted to stay at home.",note:"Querer changes to 'quis-' stem. In past: 'tried to' or 'refused to'."},
{type:"teach",kind:"verb",nl:"quiso",en:"he/she wanted / tried to",phonetic:"KEE-so",example:"A: ¿Tu hermano quiso venir?\nB: No, no quiso.\nA: ¿Quiso quedarse solo?\nB: Sí, quiso estudiar.",exampleEn:"A: Did your brother want to come?\nB: No, he didn't want to.\nA: Did he want to stay alone?\nB: Yes, he wanted to study.",note:"Third person singular. No quiso = he/she refused."},
{type:"verb_table",title:"Decir vs Querer: pretérito",label:"Two i-stem verbs",groups:[{label:"decir (dij-)",rows:[["yo","dije"],["tú","dijiste"],["él/ella","dijo"],["nosotros","dijimos"],["ellos","dijeron"]]},{label:"querer (quis-)",rows:[["yo","quise"],["tú","quisiste"],["él/ella","quiso"],["nosotros","quisimos"],["ellos","quisieron"]]}],note:"After j: third person plural ends in -eron (dijeron). After s: normal -ieron (quisieron)."},
{type:"mc",q:"¿Qué ___ el profesor? (decir)",opts:["dijo","dije","dijiste","dijeron"],ans:"dijo",hint:"Third person singular, what the teacher said"},
{type:"fb",s:"Yo no {1} comprar ese coche tan caro. (querer)",a:"quise",opts:["quise","quiso","quisimos","quisieron"],hint:"First person singular, I refused to buy it"},
{type:"mc",q:"Mis amigos me ___ la verdad. (decir)",opts:["dijeron","dijimos","dijo","dije"],ans:"dijeron",hint:"Third person plural, what friends told you"},
{type:"fb",s:"Ella {1} cambiar de trabajo. (querer)",a:"quiso",opts:["quiso","quise","quisiste","quisieron"],hint:"Third person singular, she wanted/tried to change"},
{type:"match",pairs:[{nl:"Dije que sí",en:"I said yes"},{nl:"No quiso ir",en:"He refused to go"},{nl:"¿Qué dijeron?",en:"What did they say?"},{nl:"Quisimos ayudar",en:"We tried to help"},{nl:"Dijiste la verdad",en:"You told the truth"}]},
{type:"mc",q:"Nosotros ___ invitarlos pero no pudimos. (querer)",opts:["quisimos","quisieron","quiso","quise"],ans:"quisimos",hint:"First person plural, we tried but couldn't"},
{type:"fb",s:"¿Qué {1} tú? No te escuché. (decir)",a:"dijiste",opts:["dijiste","dijo","dije","dijeron"],hint:"Asking the listener what they said"},
{type:"drag_fill",s:"Ella {1} que no {2} participar.",blanks:{"1":"dijo","2":"quiso"},pool:["dijo","quiso","dije","quise"],hint:"She said (decir) that she refused (querer)"},
{type:"fb",s:"¿Tú les {1} adiós a tus amigos? (decir)",a:"dijiste",opts:["dijiste","dijo","dije","dijeron"],hint:"Second person singular, asking if you said goodbye"},
{type:"mc",q:"Nadie ___ ayudarme con la mudanza. (querer)",opts:["quiso","quise","quisimos","quisieron"],ans:"quiso",hint:"Third person singular, nobody wanted to help"}
]},

// ===== LESSON 6: Venir, Dar, Traer =====
{id:"esp10l6",title:"Vine temprano",icon:"🎁",xp:15,board:true,steps:[
{type:"intro",title:"Vine temprano",desc:"Three more essential irregular verbs: venir (to come), dar (to give), and traer (to bring). Each has its own pattern.",goals:["Conjugate venir in pretérito (vine, viniste, vino...)","Conjugate dar in pretérito (di, diste, dio...)","Conjugate traer in pretérito (traje, trajiste, trajo...)"]},
{type:"teach",kind:"verb",nl:"vine",en:"I came",phonetic:"VEE-neh",example:"A: ¿A qué hora viniste?\nB: Vine a las ocho.\nA: ¡Viniste muy temprano!\nB: Sí, vine en taxi.",exampleEn:"A: What time did you come?\nB: I came at eight.\nA: You came very early!\nB: Yes, I came by taxi.",note:"Venir changes to 'vin-' stem. An i-stem verb like decir and querer."},
{type:"teach",kind:"verb",nl:"vino",en:"he/she came",phonetic:"VEE-no",example:"A: ¿Vino tu padre a la reunión?\nB: Sí, vino con mi madre.\nA: ¿También vino tu hermana?\nB: No, ella no vino.",exampleEn:"A: Did your father come to the meeting?\nB: Yes, he came with my mother.\nA: Did your sister come too?\nB: No, she didn't come.",note:"Third person singular. Same word as 'wine' (el vino) but different meaning!"},
{type:"teach",kind:"verb",nl:"di",en:"I gave",phonetic:"DEE",example:"A: ¿Qué le diste a tu madre?\nB: Le di flores.\nA: ¡Qué bonito! Yo le di un libro.\nB: Ella dio las gracias.",exampleEn:"A: What did you give your mother?\nB: I gave her flowers.\nA: How nice! I gave her a book.\nB: She gave thanks.",note:"Dar is short and unique. No accent on di/dio. Uses -er/-ir endings despite being -ar verb."},
{type:"teach",kind:"verb",nl:"dio",en:"he/she gave",phonetic:"DEE-o",example:"A: ¿Quién te dio este regalo?\nB: Me lo dio mi abuela.\nA: Tu abuela siempre dio los mejores regalos.\nB: ¡Es verdad!",exampleEn:"A: Who gave you this gift?\nB: My grandmother gave it to me.\nA: Your grandmother always gave the best gifts.\nB: That's true!",note:"Third person singular. No accent mark on dio."},
{type:"teach",kind:"verb",nl:"traje",en:"I brought",phonetic:"TRAH-heh",example:"A: ¿Trajiste el pastel?\nB: Sí, lo traje.\nA: ¡Perfecto! Yo traje las bebidas.\nB: ¿Quién trajo los platos?",exampleEn:"A: Did you bring the cake?\nB: Yes, I brought it.\nA: Perfect! I brought the drinks.\nB: Who brought the plates?",note:"Traer changes to 'traj-' stem. Like decir (dij-), uses j-stem."},
{type:"teach",kind:"verb",nl:"trajo",en:"he/she brought",phonetic:"TRAH-ho",example:"A: ¿Qué trajo María a la fiesta?\nB: Trajo una ensalada.\nA: Pedro trajo postre.\nB: ¡Todos trajeron algo!",exampleEn:"A: What did María bring to the party?\nB: She brought a salad.\nA: Pedro brought dessert.\nB: Everyone brought something!",note:"Third person singular. Like dijeron, third plural is trajeron (not trajieron)."},
{type:"tip",title:"Dar: a unique irregular",text:"Dar (to give) is special:\n\ndi, diste, dio, dimos, dieron\n\nIt's an -ar verb but uses -er/-ir endings in the past.\nNo accent marks on any form (di, dio).\nVery short forms, easy to memorize!"},
{type:"mc",q:"¿A qué hora ___ tú a la oficina? (venir)",opts:["viniste","vino","vine","vinieron"],ans:"viniste",hint:"Second person singular, asking when you arrived"},
{type:"fb",s:"Mi abuela me {1} un regalo increíble. (dar)",a:"dio",opts:["dio","di","dimos","dieron"],hint:"Third person singular, grandmother gave something"},
{type:"mc",q:"Nosotros ___ la comida para la fiesta. (traer)",opts:["trajimos","trajeron","trajo","traje"],ans:"trajimos",hint:"First person plural, we brought the food"},
{type:"fb",s:"¿Quién {1} a la reunión ayer? (venir)",a:"vino",opts:["vino","vine","vinimos","vinieron"],hint:"Third person singular, asking who arrived"},
{type:"match",pairs:[{nl:"Vine temprano",en:"I came early"},{nl:"Dio las gracias",en:"He/she gave thanks"},{nl:"Trajeron regalos",en:"They brought gifts"},{nl:"¿Viniste solo?",en:"Did you come alone?"},{nl:"Di mi opinión",en:"I gave my opinion"}]},
{type:"mc",q:"Ellos ___ muchas cosas a la fiesta. (traer)",opts:["trajeron","trajimos","trajo","traje"],ans:"trajeron",hint:"Third person plural, they brought many things"},
{type:"fb",s:"Le {1} un abrazo cuando la vi. (dar)",a:"di",opts:["di","dio","dimos","dieron"],hint:"First person singular, I gave a hug"},
{type:"drag_fill",s:"Él {1} temprano y {2} un pastel delicioso.",blanks:{"1":"vino","2":"trajo"},pool:["vino","trajo","vine","traje"],hint:"He came (venir) and brought (traer) something"},
{type:"mc",q:"Nosotros le ___ un consejo muy bueno. (dar)",opts:["dimos","dieron","dio","di"],ans:"dimos",hint:"First person plural, we gave advice"},
{type:"fb",s:"¿Tú {1} en coche o en autobús? (venir)",a:"viniste",opts:["viniste","vino","vine","vinieron"],hint:"Second person singular, asking how you traveled here"}
]},

// ===== LESSON 7: Mixing Regular & Irregular =====
{id:"esp10l7",title:"Un día especial",icon:"📝",xp:15,board:true,steps:[
{type:"intro",title:"Un día especial",desc:"Now let's mix regular and irregular past tense verbs to tell complete stories. This is how real Spanish works.",goals:["Combine regular and irregular pretérito verbs","Narrate a sequence of past events","Choose the correct form in context"]},
{type:"tip",title:"Telling stories in the past",text:"When narrating past events, you mix regular and irregular verbs freely:\n\nAyer me levanté temprano (regular -ar)\nFui al mercado (irregular: ir)\nCompré frutas (regular -ar)\nHice una ensalada (irregular: hacer)\nLa puse en la mesa (irregular: poner)\n\nThe key is using the correct form for each verb. Regular verbs keep their stem. Irregular verbs change their stem."},
{type:"teach",kind:"phrase",nl:"el fin de semana pasado",en:"last weekend",phonetic:"el feen deh seh-MAH-nah pah-SAH-do",example:"A: ¿Qué hiciste el fin de semana pasado?\nB: Fui a la montaña.\nA: ¿Y qué tal?\nB: Fue increíble.",exampleEn:"A: What did you do last weekend?\nB: I went to the mountain.\nA: And how was it?\nB: It was incredible.",note:"Common time expression for past narratives."},
{type:"teach",kind:"phrase",nl:"primero... luego... después",en:"first... then... after that",phonetic:"pree-MEH-ro... LWEH-go... des-PWEHS",example:"A: ¿Qué hiciste ayer?\nB: Primero fui al gimnasio.\nA: ¿Y luego?\nB: Luego comí y después estudié.",exampleEn:"A: What did you do yesterday?\nB: First I went to the gym.\nA: And then?\nB: Then I ate and after that I studied.",note:"Sequence words to structure past narratives."},
{type:"teach",kind:"phrase",nl:"por eso",en:"that's why / because of that",phonetic:"por EH-so",example:"A: ¿Por qué no viniste ayer?\nB: Estuve enfermo, por eso no vine.\nA: ¡Qué pena! ¿Ya estás mejor?\nB: Sí, gracias.",exampleEn:"A: Why didn't you come yesterday?\nB: I was sick, that's why I didn't come.\nA: What a shame! Are you better now?\nB: Yes, thank you.",note:"Useful connector for explaining reasons in a narrative."},
{type:"mc",q:"Ayer me levanté temprano y ___ al trabajo en bicicleta. (ir)",opts:["fui","fue","fuiste","fueron"],ans:"fui",hint:"First person singular, the speaker traveled somewhere"},
{type:"fb",s:"María compró los ingredientes y {1} la cena. (hacer)",a:"hizo",opts:["hizo","hice","hicieron","hicimos"],hint:"Third person singular, she prepared the meal"},
{type:"mc",q:"Primero ___ en el parque y luego comimos en un restaurante. (estar, nosotros)",opts:["estuvimos","estuvieron","estuvo","estuve"],ans:"estuvimos",hint:"First person plural, we were at a location first"},
{type:"fb",s:"Ellos {1} a la fiesta pero no {1} quedarse mucho tiempo.",a:"vinieron",opts:["vinieron","vinimos","vino","vine"],hint:"Third person plural, they arrived at the party"},
{type:"drag_fill",s:"Primero {1} la comida y luego la {2} en la mesa.",blanks:{"1":"hice","2":"puse"},pool:["hice","puse","hizo","puso"],hint:"First I made (hacer) the food, then I placed (poner) it"},
{type:"mc",q:"Mi amigo me ___ un secreto y yo no ___ nada a nadie.",opts:["dijo / dije","dijo / dijo","dije / dijo","dijeron / dijimos"],ans:"dijo / dije",hint:"He told me, then I told nobody. Third then first person."},
{type:"fb",s:"No {1} ir al cine porque tuve mucho trabajo. (poder)",a:"pude",opts:["pude","pudo","pudimos","pudieron"],hint:"First person singular, I was unable to go"},
{type:"match",pairs:[{nl:"Hice la tarea",en:"I did the homework"},{nl:"Fui al parque",en:"I went to the park"},{nl:"Dije la verdad",en:"I told the truth"},{nl:"Tuve suerte",en:"I was lucky"},{nl:"Vine temprano",en:"I came early"},{nl:"Puse la mesa",en:"I set the table"}]},
{type:"drag_fill",s:"Ayer {1} a casa, {2} la cena y luego {3} la tele.",blanks:{"1":"vine","2":"hice","3":"puse"},pool:["vine","hice","puse","fui","dije","tuve"],hint:"I came home, made dinner, then put on the TV"},
{type:"mc",q:"¿Qué ___ tus padres cuando lo ___? (decir / saber)",opts:["dijeron / supieron","dijimos / supimos","dijo / supo","dije / supe"],ans:"dijeron / supieron",hint:"Both third person plural: what they said when they found out"},
{type:"fb",s:"El profesor nos {1} un ejercicio muy difícil. (dar)",a:"dio",opts:["dio","di","dimos","dieron"],hint:"Third person singular, the teacher gave us something"},
{type:"mc",q:"Mis amigos ___ a mi casa y ___ pizza. (venir / traer)",opts:["vinieron / trajeron","vinimos / trajimos","vino / trajo","vine / traje"],ans:"vinieron / trajeron",hint:"Both third person plural: friends came and brought food"},
{type:"fb",s:"Anoche {1} muy cansada, por eso no pude salir. (estar)",a:"estuve",opts:["estuve","estuvo","estuvimos","estuvieron"],hint:"First person singular, I was in a certain state"}
]},

// ===== LESSON 8: Review & Practice =====
{id:"esp10l8",title:"Repaso: los irregulares",icon:"🏆",xp:20,board:true,steps:[
{type:"intro",title:"Repaso: los irregulares",desc:"Let's review all twelve irregular verbs from this unit. Can you remember them all?",goals:["Review all irregular pretérito forms","Distinguish u-stem, i-stem, and unique patterns","Use irregular verbs confidently in context"]},
{type:"tip",title:"Three irregular families",text:"Group 1: u-stem verbs (same endings: -e, -iste, -o, -imos, -ieron)\ntener: tuv-\nestar: estuv-\npoder: pud-\nponer: pus-\nsaber: sup-\n\nGroup 2: i-stem / j-stem verbs\ndecir: dij- (dijeron, not dijieron)\nquerer: quis-\nvenir: vin-\ntraer: traj- (trajeron, not trajieron)\n\nGroup 3: unique verbs\nser/ir: fui, fuiste, fue, fuimos, fueron\ndar: di, diste, dio, dimos, dieron"},
{type:"mc",q:"Ayer yo ___ una carta muy larga. (hacer)",opts:["hice","hizo","hiciste","hicieron"],ans:"hice",hint:"First person singular, the speaker created something"},
{type:"fb",s:"Ella {1} que no pudo venir. (decir)",a:"dijo",opts:["dijo","dije","dijeron","dijiste"],hint:"Third person singular, she communicated something"},
{type:"mc",q:"Nosotros no ___ dormir por el ruido. (poder)",opts:["pudimos","pudieron","pudo","pude"],ans:"pudimos",hint:"First person plural, we were unable to sleep"},
{type:"fb",s:"¿Tú {1} al concierto el sábado? (ir)",a:"fuiste",opts:["fuiste","fue","fui","fueron"],hint:"Second person singular, asking about going somewhere"},
{type:"match",pairs:[{nl:"tuve",en:"I had"},{nl:"hizo",en:"he/she did"},{nl:"dijeron",en:"they said"},{nl:"pude",en:"I could"},{nl:"vine",en:"I came"},{nl:"dio",en:"he/she gave"}]},
{type:"mc",q:"Mis abuelos ___ a España en 1960. (venir)",opts:["vinieron","vinimos","vino","vine"],ans:"vinieron",hint:"Third person plural, grandparents came somewhere"},
{type:"fb",s:"¿Quién {1} este pastel? ¡Está delicioso! (traer)",a:"trajo",opts:["trajo","traje","trajimos","trajeron"],hint:"Third person singular, asking who brought something"},
{type:"drag_fill",s:"Ella {1} en casa todo el día y no {2} salir.",blanks:{"1":"estuvo","2":"quiso"},pool:["estuvo","quiso","estuve","quise"],hint:"She was (estar) at home and refused (querer) to go out"},
{type:"mc",q:"¿Cuándo ___ tú la noticia? (saber)",opts:["supiste","supo","supe","supieron"],ans:"supiste",hint:"Second person singular, when did you find out"},
{type:"fb",s:"Los niños le {1} muchos besos a la abuela. (dar)",a:"dieron",opts:["dieron","dimos","dio","di"],hint:"Third person plural, the children gave something"},
{type:"drag_fill",s:"Primero {1} al mercado, luego {2} la comida y después {3} la mesa.",blanks:{"1":"fui","2":"hice","3":"puse"},pool:["fui","hice","puse","fue","hizo","puso"],hint:"First person: I went, I made, I set. Three different irregular verbs."},
{type:"mc",q:"La fiesta ___ increíble. Todos ___ muy contentos. (ser / estar)",opts:["fue / estuvieron","fue / estuvimos","fui / estuve","fueron / estuvimos"],ans:"fue / estuvieron",hint:"The party was (third singular) and everyone was (third plural)"},
{type:"fb",s:"Mi jefe me {1} que tengo vacaciones la semana que viene.",a:"dijo",opts:["dijo","dije","dijeron","dijiste"],hint:"Third person singular, the boss communicated news"},
{type:"match",pairs:[{nl:"Puse la radio",en:"I put on the radio"},{nl:"Supimos todo",en:"We found out everything"},{nl:"Quisieron ayudar",en:"They wanted to help"},{nl:"Trajiste flores",en:"You brought flowers"},{nl:"Estuve ocupado",en:"I was busy"}]},
{type:"drag_fill",s:"Ayer {1} a mi amigo Pedro. Me {2} que {3} un nuevo trabajo.",blanks:{"1":"vi","2":"dijo","3":"tuvo"},pool:["vi","dijo","tuvo","vine","dije","tuve"],hint:"I saw (ver, regular) a friend. He told me he got a new job."},
{type:"mc",q:"Nosotros les ___ un regalo y ellos nos ___ las gracias. (dar / dar)",opts:["dimos / dieron","dieron / dimos","dio / di","di / dio"],ans:"dimos / dieron",hint:"We gave (first plural) and they gave (third plural)"}
]}

]}
